import React, { useRef, useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Camera, RotateCcw, Check, X } from 'lucide-react';
import { useLanguage } from '@/contexts/LanguageContext';
import { toast } from '@/hooks/use-toast';

interface AttendanceCameraProps {
  onCapture: (imageData: string) => void;
  onCancel: () => void;
}

const AttendanceCamera: React.FC<AttendanceCameraProps> = ({ onCapture, onCancel }) => {
  const { t } = useLanguage();
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [photo, setPhoto] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  React.useEffect(() => {
    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: {
          facingMode: { ideal: 'user' },
          width: { ideal: 1280 },
          height: { ideal: 720 },
          frameRate: { ideal: 30 }
        },
        audio: false
      });
      
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        setStream(mediaStream);
        setIsLoading(false);
      }
    } catch (error) {
      toast({
        title: 'Camera Error',
        description: t.attendance.cameraRequired,
        variant: 'destructive',
      });
      onCancel();
    }
  };

  const capturePhoto = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        // Flip horizontally to correct the mirror effect from front camera
        // This ensures the captured image is in normal (non-mirrored) orientation
        context.save();
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        context.restore();
        
        const imageData = canvas.toDataURL('image/jpeg', 0.8);
        setPhoto(imageData);
        
        // Stop the camera stream after capturing to save resources
        if (stream) {
          stream.getTracks().forEach(track => track.stop());
        }
      }
    }
  }, [stream]);

  const retakePhoto = async () => {
    setPhoto(null);
    // Restart the camera if it was stopped
    if (!stream || !stream.active) {
      setIsLoading(true);
      await startCamera();
    }
  };

  const confirmPhoto = () => {
    if (photo) {
      onCapture(photo);
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    }
  };

  return (
    <Card className="p-6 max-w-2xl mx-auto">
      <div className="space-y-4">
        <h3 className="text-lg font-semibold text-center">{t.attendance.capturePhoto}</h3>
        
        <div className="relative rounded-lg overflow-hidden bg-muted aspect-[4/3]">
          {isLoading && (
            <div className="absolute inset-0 flex items-center justify-center">
              <div className="animate-pulse-slow">
                <Camera className="h-12 w-12 text-muted-foreground" />
              </div>
            </div>
          )}
          
          {!photo ? (
            <video
              ref={videoRef}
              autoPlay
              playsInline
              muted
              className="w-full h-full object-cover"
              style={{ display: isLoading ? 'none' : 'block', transform: 'scaleX(-1)' }}
            />
          ) : (
            <img src={photo} alt="Captured" className="w-full h-full object-cover" />
          )}
          
          <canvas ref={canvasRef} className="hidden" />
        </div>
        
        <div className="flex gap-3 justify-center">
          {!photo ? (
            <>
              <Button
                onClick={capturePhoto}
                disabled={isLoading}
                size="lg"
                className="gap-2"
              >
                <Camera className="h-5 w-5" />
                {t.attendance.capturePhoto}
              </Button>
              <Button
                onClick={onCancel}
                variant="outline"
                size="lg"
                className="gap-2"
              >
                <X className="h-5 w-5" />
                {t.common.cancel}
              </Button>
            </>
          ) : (
            <>
              <Button
                onClick={retakePhoto}
                variant="outline"
                size="lg"
                className="gap-2"
              >
                <RotateCcw className="h-5 w-5" />
                {t.attendance.retake}
              </Button>
              <Button
                onClick={confirmPhoto}
                size="lg"
                className="gap-2"
              >
                <Check className="h-5 w-5" />
                {t.attendance.usePhoto}
              </Button>
            </>
          )}
        </div>
      </div>
    </Card>
  );
};

export default AttendanceCamera;

import React, { useState, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useToast } from '@/components/ui/use-toast';
import { CheckCircle, Clock, MapPin, AlertCircle, Loader2 } from 'lucide-react';
import { getCurrentLocation as requestCurrentLocation } from '@/utils/geolocation';
import { nowIST } from '@/utils/timezone';

interface AttendanceWithLocationProps {
  userId: number;
  onCheckIn: (locationData: any) => Promise<{ success: boolean; error?: string }>;
  onCheckOut: (locationData: any) => Promise<{ success: boolean; error?: string }>;
  currentStatus: 'checked-in' | 'checked-out' | 'loading';
}

const AttendanceWithLocation: React.FC<AttendanceWithLocationProps> = ({
  userId,
  onCheckIn,
  onCheckOut,
  currentStatus
}) => {
  const { toast } = useToast();
  const [isLoading, setIsLoading] = useState(false);
  const [location, setLocation] = useState<{
    latitude: number;
    longitude: number;
    address?: string;
    placeName?: string;
    accuracy?: number;
    timestamp?: number;
  } | null>(null);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [isCheckingLocation, setIsCheckingLocation] = useState(false);

  const fetchLocation = useCallback(async () => {
    try {
      setIsCheckingLocation(true);
      setLocationError(null);
      
      const locationData = await requestCurrentLocation();
      setLocation(locationData);
      return locationData;
    } catch (error: any) {
      console.error('Error getting location:', error);
      const errorMessage = error?.message || 'Failed to get your location';
      setLocationError(errorMessage);
      toast({
        title: 'Location Error',
        description: errorMessage,
        variant: 'destructive',
      });
      throw error;
    } finally {
      setIsCheckingLocation(false);
    }
  }, [toast]);

  useEffect(() => {
    fetchLocation().catch(() => {
      // errors already surfaced via toast
    });
  }, [fetchLocation]);

  const handleCheckIn = async () => {
    try {
      setIsLoading(true);
      const locationData = await fetchLocation();
      if (!locationData) {
        throw new Error('Unable to read your current location');
      }
      
      const result = await onCheckIn({
        userId,
        locationData: {
          latitude: locationData.latitude,
          longitude: locationData.longitude,
          accuracy: locationData.accuracy,
          address: locationData.address,
          placeName: locationData.placeName,
          timestamp: nowIST().toISOString()
        }
      });
      
      if (result.success) {
        toast({
          title: 'Checked In',
          description: 'You have been successfully checked in!',
        });
      } else {
        throw new Error(result.error || 'Failed to check in');
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to check in',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleCheckOut = async () => {
    try {
      setIsLoading(true);
      const locationData = await fetchLocation();
      if (!locationData) {
        throw new Error('Unable to read your current location');
      }
      
      const result = await onCheckOut({
        userId,
        locationData: {
          latitude: locationData.latitude,
          longitude: locationData.longitude,
          accuracy: locationData.accuracy,
          address: locationData.address,
          placeName: locationData.placeName,
          timestamp: nowIST().toISOString()
        }
      });
      
      if (result.success) {
        toast({
          title: 'Checked Out',
          description: 'You have been successfully checked out!',
        });
        fetchLocation().catch(() => {
          // ignore refresh errors
        });
      } else {
        throw new Error(result.error || 'Failed to check out');
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to check out',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const renderLocationInfo = () => {
    if (isCheckingLocation) {
      return (
        <div className="flex items-center text-muted-foreground">
          <Loader2 className="mr-2 h-4 w-4 animate-spin" />
          <span>Detecting your location...</span>
        </div>
      );
    }

    if (locationError) {
      return (
        <div className="flex items-center text-destructive">
          <AlertCircle className="mr-2 h-4 w-4" />
          <span>{locationError}</span>
        </div>
      );
    }

    if (location) {
      return (
        <div className="space-y-2">
          <div className="flex items-center text-green-600">
            <CheckCircle className="mr-2 h-4 w-4" />
            <span>Location detected: {location.placeName || 'Current location'}</span>
          </div>
          <div className="flex items-center text-sm text-muted-foreground">
            <MapPin className="mr-2 h-3.5 w-3.5" />
            <span className="truncate">{location.address || 'Address not available'}</span>
          </div>
          <div className="flex items-center text-xs text-muted-foreground">
            <Clock className="mr-2 h-3 w-3" />
            <span>Accuracy: {location.accuracy ? `${Math.round(location.accuracy)}m` : 'Unknown'}</span>
          </div>
        </div>
      );
    }

    return (
      <div className="text-muted-foreground">
        <p>Your current location will be captured when you check in/out.</p>
        <p className="text-xs mt-1">Make sure location services are enabled.</p>
      </div>
    );
  };

  return (
    <Card className="w-full max-w-md">
      <CardHeader>
        <CardTitle>Attendance</CardTitle>
        <CardDescription>
          {currentStatus === 'checked-out' 
            ? 'Check in to start tracking your attendance' 
            : currentStatus === 'checked-in' 
              ? 'You are currently checked in' 
              : 'Loading...'}
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="p-4 border rounded-lg bg-muted/20">
          <h4 className="font-medium mb-2 flex items-center">
            <MapPin className="mr-2 h-4 w-4" />
            Location
          </h4>
          {renderLocationInfo()}
        </div>

        <div className="flex flex-col space-y-2">
          {currentStatus === 'checked-out' && (
            <Button 
              onClick={handleCheckIn}
              disabled={isLoading || isCheckingLocation}
              className="w-full"
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Checking In...
                </>
              ) : (
                'Check In'
              )}
            </Button>
          )}
          
          {currentStatus === 'checked-in' && (
            <Button 
              onClick={handleCheckOut}
              variant="outline"
              disabled={isLoading || isCheckingLocation}
              className="w-full"
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Checking Out...
                </>
              ) : (
                'Check Out'
              )}
            </Button>
          )}
        </div>
        
        <div className="text-xs text-muted-foreground text-center">
          <p>Your exact GPS location is required each time you check in or out.</p>
          <p>Enable precise location services on your device for best accuracy.</p>
        </div>
      </CardContent>
    </Card>
  );
};

export default AttendanceWithLocation;

import React, { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Clock, Timer, History, User } from 'lucide-react';
import { formatDateTimeIST } from '@/utils/timezone';
import { API_BASE_URL } from '@/lib/api';

interface OnlineStatusIndicatorProps {
  isOnline: boolean;
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
  clickable?: boolean;
  attendanceId?: number;
  userId?: number;
  userName?: string;
}

interface StatusHistoryItem {
  id: number;
  is_online: boolean;
  reason?: string;
  timestamp: string;
}

export const OnlineStatusIndicator: React.FC<OnlineStatusIndicatorProps> = ({
  isOnline,
  size = 'md',
  showLabel = false,
  clickable = false,
  attendanceId,
  userId,
  userName
}) => {
  const [showHistoryDialog, setShowHistoryDialog] = useState(false);
  const [statusHistory, setStatusHistory] = useState<StatusHistoryItem[]>([]);
  const [workingHours, setWorkingHours] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const sizeClasses = {
    sm: 'h-2 w-2',
    md: 'h-3 w-3',
    lg: 'h-4 w-4'
  };

  const dotSize = sizeClasses[size];

  const loadStatusHistory = async () => {
    if (!attendanceId) return;

    setLoading(true);
    try {
      const token = localStorage.getItem('token');

      // Load status history
      const historyResponse = await fetch(`${API_BASE_URL}/attendance/online-status/${attendanceId}`, {
        headers: {
          'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
          'Content-Type': 'application/json',
        },
      });

      if (historyResponse.ok) {
        const historyData = await historyResponse.json();
        setStatusHistory(historyData.status_history || []);
      }

      // Load working hours calculation
      const hoursResponse = await fetch(`${API_BASE_URL}/attendance/working-hours/${attendanceId}`, {
        headers: {
          'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
          'Content-Type': 'application/json',
        },
      });

      if (hoursResponse.ok) {
        const hoursData = await hoursResponse.json();
        setWorkingHours(hoursData);
      }
    } catch (error) {
      console.error('Failed to load status data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleClick = () => {
    if (clickable && attendanceId) {
      loadStatusHistory();
      setShowHistoryDialog(true);
    }
  };

  const formatTime = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);

    if (hours > 0) {
      return `${hours}h ${minutes}m`;
    } else {
      return `${minutes}m`;
    }
  };

  const formatWorkingHours = (decimalHours: number): string => {
    if (!decimalHours || decimalHours === 0) {
      return '0 hrs - 0 mins';
    }

    const hours = Math.floor(decimalHours);
    const minutes = Math.round((decimalHours - hours) * 60);

    if (hours === 0 && minutes === 0) {
      return '0 hrs - 0 mins';
    } else if (hours === 0) {
      return `0 hrs - ${minutes} mins`;
    } else if (minutes === 0) {
      return `${hours} hrs - 0 mins`;
    } else {
      return `${hours} hrs - ${minutes} mins`;
    }
  };

  const formatDateTime = (timestamp: string): string => {
    return formatDateTimeIST(timestamp, 'dd MMM HH:mm:ss');
  };

  return (
    <>
      <div
        className={`flex items-center gap-1.5 ${clickable ? 'cursor-pointer hover:opacity-80 transition-opacity' : ''}`}
        onClick={handleClick}
      >
        {/* Status dot with pulse animation for online */}
        <div className="relative">
          <div
            className={`${dotSize} rounded-full transition-colors duration-300 ${isOnline
              ? 'bg-green-500'
              : 'bg-gray-400 dark:bg-gray-600'
              }`}
          />
          {isOnline && (
            <div className={`${dotSize} rounded-full bg-green-500 absolute top-0 left-0 animate-ping opacity-75`} />
          )}
        </div>

        {showLabel && (
          <span
            className={`text-xs font-medium ${isOnline
              ? 'text-green-600 dark:text-green-400'
              : 'text-gray-500 dark:text-gray-400'
              }`}
          >
            {isOnline ? 'Online' : 'Offline'}
          </span>
        )}
      </div>

      {/* Status History Dialog */}
      <Dialog open={showHistoryDialog} onOpenChange={setShowHistoryDialog}>
        <DialogContent className="sm:max-w-[600px] max-h-[80vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                <User className="h-5 w-5 text-white" />
              </div>
              <div>
                <div className="text-lg font-semibold">{userName}'s Online Status</div>
                <div className="text-sm text-muted-foreground">Today's activity timeline</div>
              </div>
            </DialogTitle>
          </DialogHeader>

          {loading ? (
            <div className="flex items-center justify-center py-8">
              <div className="h-8 w-8 rounded-full border-4 border-blue-500 border-t-transparent animate-spin" />
            </div>
          ) : (
            <div className="space-y-6">
              {/* Working Hours Summary */}
              {workingHours && (
                <div className="grid grid-cols-2 gap-4 p-4 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-950 dark:to-indigo-950 rounded-xl border">
                  <div className="text-center">
                    <div className="flex items-center justify-center gap-2 mb-1">
                      <Clock className="h-4 w-4 text-blue-600" />
                      <span className="text-sm font-medium text-blue-600">Working Hours</span>
                    </div>
                    <div className="text-2xl font-bold text-blue-700 dark:text-blue-300">
                      {formatWorkingHours(workingHours.working_hours)}
                    </div>
                  </div>
                  <div className="text-center">
                    <div className="flex items-center justify-center gap-2 mb-1">
                      <Timer className="h-4 w-4 text-amber-600" />
                      <span className="text-sm font-medium text-amber-600">Status</span>
                    </div>
                    <Badge className={`${workingHours.is_currently_online ? 'bg-green-500' : 'bg-gray-500'} text-white`}>
                      {workingHours.is_currently_online ? 'Online' : 'Offline'}
                    </Badge>
                  </div>
                </div>
              )}

              {/* Status History */}
              <div>
                <div className="flex items-center gap-2 mb-3">
                  <History className="h-4 w-4 text-slate-600" />
                  <span className="font-medium">Status Timeline</span>
                </div>

                <div className="h-[300px] overflow-y-auto pr-4">
                  {statusHistory.length > 0 ? (
                    <div className="space-y-3">
                      {statusHistory.map((item, index) => (
                        <div key={item.id} className="flex items-start gap-3 p-3 rounded-lg border bg-card">
                          <div className="flex flex-col items-center">
                            <div className={`h-3 w-3 rounded-full ${item.is_online ? 'bg-green-500' : 'bg-gray-400'}`} />
                            {index < statusHistory.length - 1 && (
                              <div className="w-px h-8 bg-border mt-2" />
                            )}
                          </div>

                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-1">
                              <Badge
                                variant={item.is_online ? 'default' : 'secondary'}
                                className={`text-xs ${item.is_online ? 'bg-green-500' : 'bg-gray-500'} text-white`}
                              >
                                {item.is_online ? 'Went Online' : 'Went Offline'}
                              </Badge>
                              <span className="text-xs text-muted-foreground">
                                {formatDateTime(item.timestamp)}
                              </span>
                            </div>

                            {item.reason && (
                              <div className="text-sm text-muted-foreground bg-muted p-2 rounded mt-2">
                                <strong>Reason:</strong> {item.reason}
                              </div>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="text-center py-8 text-muted-foreground">
                      <History className="h-12 w-12 mx-auto mb-3 opacity-50" />
                      <p>No status changes recorded yet</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
};

export default OnlineStatusIndicator;

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/hooks/use-toast';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { AlertTriangle, Clock, FileText, Send } from 'lucide-react';
import { formatDateIST } from '@/utils/timezone';
import TruncatedText from '@/components/ui/TruncatedText';
import { API_BASE_URL } from '@/lib/api';

// Allow only letters, numbers, spaces, and new lines (no special characters)
const sanitizeAlphaNumText = (value: string) => value.replace(/[^a-zA-Z0-9 \n]/g, '');

interface OverdueTask {
  task_id: number;
  title: string;
  due_date: string;
  status: string;
  priority: string;
}

interface WorkSummaryDialogProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (workSummary: string, deadlineReason?: string) => Promise<void>;
  isSubmitting?: boolean;
}

const WorkSummaryDialog: React.FC<WorkSummaryDialogProps> = ({
  isOpen,
  onClose,
  onSubmit,
  isSubmitting = false
}) => {
  const { user } = useAuth();
  const { toast } = useToast();
  const [workSummary, setWorkSummary] = useState('');
  const [deadlineReason, setDeadlineReason] = useState('');
  const [overdueTasks, setOverdueTasks] = useState<OverdueTask[]>([]);
  const [isLoadingTasks, setIsLoadingTasks] = useState(false);
  const [reasonError, setReasonError] = useState('');

  const fetchOverdueTasks = async () => {
    if (!user?.id) return;

    const token = localStorage.getItem('token');
    if (!token) return;

    setIsLoadingTasks(true);
    try {
      const response = await fetch(`${API_BASE_URL}/tasks/deadline-warnings/${user.id}`, {
        headers: {
          'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
          'Content-Type': 'application/json',
        },
      });

      if (response.ok) {
        const data = await response.json();
        const todayTasks = data.warnings?.filter((w: any) => w.warning_type === 'due_today') || [];
        setOverdueTasks(todayTasks);
      }
    } catch (error) {
      console.error('Failed to fetch overdue tasks:', error);
    } finally {
      setIsLoadingTasks(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      fetchOverdueTasks();
      setWorkSummary('');
      setDeadlineReason('');
      setReasonError('');
    }
  }, [isOpen, user?.id]);

  const validateDeadlineReason = (reason: string): string => {
    const trimmedReason = reason.trim();

    if (!trimmedReason) {
      return 'Please provide a reason for not completing the task(s) due today.';
    }

    if (trimmedReason.length < 15) {
      return 'Reason must be at least 15 characters long.';
    }

    if (/^\d+$/.test(trimmedReason)) {
      return 'Reason cannot contain only numbers. Please provide a meaningful explanation.';
    }

    return '';
  };

  const handleDeadlineReasonChange = (value: string) => {
    const cleaned = sanitizeAlphaNumText(value);
    setDeadlineReason(cleaned);
    if (overdueTasks.length > 0) {
      const error = validateDeadlineReason(cleaned);
      setReasonError(error);
    }
  };

  const handleSubmit = async () => {
    if (!workSummary.trim()) {
      toast({
        title: 'Work summary required',
        description: 'Please provide a summary of your work before checking out.',
        variant: 'destructive',
      });
      return;
    }

    // Validate deadline reason if there are overdue tasks
    if (overdueTasks.length > 0) {
      const error = validateDeadlineReason(deadlineReason);
      if (error) {
        setReasonError(error);
        toast({
          title: 'Deadline reason required',
          description: error,
          variant: 'destructive',
        });
        return;
      }
    }

    try {
      await onSubmit(workSummary.trim(), overdueTasks.length > 0 ? deadlineReason.trim() : undefined);
      onClose();
    } catch (error) {
      // Error handling is done in the parent component
    }
  };

  const hasOverdueTasks = overdueTasks.length > 0;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5 text-blue-500" />
            Work Summary
          </DialogTitle>
          <DialogDescription>
            Please provide a summary of your work before checking out.
            {hasOverdueTasks && ' You also need to explain why tasks due today are not completed.'}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-6">
          {/* Overdue Tasks Warning */}
          {hasOverdueTasks && (
            <Card className="border-orange-200 bg-orange-50">
              <CardHeader className="pb-3">
                <CardTitle className="flex items-center gap-2 text-orange-800">
                  <AlertTriangle className="h-5 w-5" />
                  Tasks Due Today
                </CardTitle>
                <CardDescription className="text-orange-700">
                  You have {overdueTasks.length} task(s) due today that are not completed.
                  Please provide a reason below.
                </CardDescription>
              </CardHeader>
              <CardContent className="pt-0">
                <div className="space-y-2">
                  {overdueTasks.map((task) => (
                    <div key={task.task_id} className="flex items-center justify-between p-3 bg-white rounded-lg border border-orange-200">
                      <div className="flex-1">
                        <div className="font-medium text-gray-900">
                          <TruncatedText
                            text={task.title}
                            maxLength={40}
                            showToggle={false}
                          />
                        </div>
                        <p className="text-sm text-gray-600">
                          Due: {formatDateIST(task.due_date, 'MMM dd, yyyy')} • Status: {task.status}
                        </p>
                      </div>
                      <Badge variant="outline" className="text-orange-600 border-orange-300">
                        {task.priority}
                      </Badge>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Work Summary */}
          <div className="space-y-2">
            <Label htmlFor="work-summary" className="text-sm font-medium">
              Work Summary *
            </Label>
            <Textarea
              id="work-summary"
              placeholder="Describe what you accomplished today, key tasks completed, challenges faced, and any important updates..."
              value={workSummary}
              onChange={(e) => setWorkSummary(sanitizeAlphaNumText(e.target.value))}
              className="min-h-[120px] resize-none"
              disabled={isSubmitting}
            />
            <p className="text-xs text-gray-500">
              Provide a brief summary of your work activities for today.
            </p>
          </div>

          {/* Deadline Reason (only if there are overdue tasks) */}
          {hasOverdueTasks && (
            <div className="space-y-2">
              <Label htmlFor="deadline-reason" className="text-sm font-medium text-orange-800">
                Reason for Incomplete Tasks *
              </Label>
              <Textarea
                id="deadline-reason"
                placeholder="Explain why the task(s) due today could not be completed. Be specific about the challenges, dependencies, or circumstances that prevented completion..."
                value={deadlineReason}
                onChange={(e) => handleDeadlineReasonChange(e.target.value)}
                className={`min-h-[100px] resize-none ${reasonError ? 'border-red-300 focus:border-red-500' : ''}`}
                disabled={isSubmitting}
              />
              {reasonError && (
                <p className="text-sm text-red-600">{reasonError}</p>
              )}
              <p className="text-xs text-gray-500">
                Minimum 15 characters required. Cannot contain only numbers.
              </p>
            </div>
          )}

          {/* Loading State */}
          {isLoadingTasks && (
            <div className="flex items-center justify-center py-4">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600"></div>
              <span className="ml-2 text-sm text-gray-600">Checking for overdue tasks...</span>
            </div>
          )}
        </div>

        <div className="flex justify-end gap-2 pt-4 border-t">
          <Button
            variant="outline"
            onClick={onClose}
            disabled={isSubmitting}
          >
            Cancel
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={isSubmitting || !workSummary.trim() || (hasOverdueTasks && !!reasonError)}
            className="min-w-[120px]"
          >
            {isSubmitting ? (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                Checking Out...
              </>
            ) : (
              <>
                <Send className="h-4 w-4 mr-2" />
                Check Out
              </>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default WorkSummaryDialog;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Bell, Check, X, Clock, AlertCircle, CheckCircle, FileText, Calendar, Loader2, IndianRupee } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { useNotifications } from '@/contexts/NotificationContext';
import { useAuth } from '@/contexts/AuthContext';
import { formatBackendDateIST } from '@/utils/timezone';
import TruncatedText from '@/components/ui/TruncatedText';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

export const NotificationBell: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { notifications, unreadCount, isLoading, error, markAsRead, markAllAsRead, clearNotification } = useNotifications();
  const [isOpen, setIsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState('all');

  // ✅ REMOVED: No more API calls from UI component
  // Notifications are fetched ONLY from NotificationContext on:
  // 1. App initialization (user login)
  // 2. Page visibility change (when tab becomes visible)

  // Debug: Log notifications state (only in dev)
  useEffect(() => {
    if (import.meta.env.DEV) {
      console.log('[NotificationBell] Notifications count:', notifications.length);
      console.log('[NotificationBell] Unread count:', unreadCount);
    }
  }, [notifications.length, unreadCount]);

  // Check if notifications are enabled
  const areNotificationsEnabled = () => {
    const stored = localStorage.getItem('notificationsEnabled');
    return stored === null ? true : stored === 'true';
  };

  // Don't render the bell if notifications are disabled
  if (!areNotificationsEnabled()) {
    return null;
  }

  // Show ALL notifications - sorted by created_at (latest first)
  // Also prioritize unread notifications at the top
  const allNotifications = [...notifications].sort((a, b) => {
    // First sort by read status (unread first)
    if (a.read !== b.read) {
      return a.read ? 1 : -1;
    }
    // Then sort by date (newest first)
    return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
  });

  // Group notifications by type (maintaining sort order)
  const leaveNotifications = allNotifications.filter(n => n.type === 'leave');
  const taskNotifications = allNotifications.filter(n => n.type === 'task');
  const shiftNotifications = allNotifications.filter(n => n.type === 'shift');
  const otherNotifications = allNotifications.filter(n => !['leave', 'task', 'shift'].includes(n.type));

  const handleNotificationClick = async (notification: any) => {
    // Remove notification from list immediately (clearNotification handles marking as read)
    clearNotification(notification.id);

    const userRole = user?.role || 'employee';

    // Route based on notification type and metadata
    if (notification.type === 'leave' && notification.metadata?.leaveId) {
      // For leave notifications, go to role-based leaves page with approvals tab
      navigate(`/${userRole}/leaves?tab=approvals&leaveId=${notification.metadata.leaveId}`);
      setIsOpen(false);
    } else if (notification.type === 'task' && notification.metadata?.taskId) {
      // For task notifications, go to role-based tasks page with taskId
      navigate(`/${userRole}/tasks?taskId=${notification.metadata.taskId}`);
      setIsOpen(false);
    } else if (notification.type === 'shift') {
      // For shift notifications, redirect to Team page
      if (notification.actionUrl) {
        navigate(notification.actionUrl);
      } else {
        // Fallback based on role
        if (userRole === 'team_lead') {
          navigate('/team_lead/team');
        } else {
          navigate('/employee/team');
        }
      }
      setIsOpen(false);
    } else if (notification.actionUrl) {
      // Fallback to actionUrl if provided
      navigate(notification.actionUrl);
      setIsOpen(false);
    } else {
      // For info/warning notifications without specific routing, go to dashboard
      navigate(`/${userRole}/dashboard`);
      setIsOpen(false);
    }
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'leave':
        return <Calendar className="h-5 w-5 text-purple-500" />;
      case 'task':
        return <FileText className="h-5 w-5 text-blue-500" />;
      case 'shift':
        return <Clock className="h-5 w-5 text-orange-500" />;
      case 'warning':
        return <AlertCircle className="h-5 w-5 text-red-500" />;
      default:
        return <CheckCircle className="h-5 w-5 text-green-500" />;
    }
  };

  const getNotificationBgColor = (type: string) => {
    switch (type) {
      case 'leave':
        return 'bg-purple-50 dark:bg-purple-950/20 border-l-4 border-purple-500';
      case 'task':
        return 'bg-blue-50 dark:bg-blue-950/20 border-l-4 border-blue-500';
      case 'shift':
        return 'bg-orange-50 dark:bg-orange-950/20 border-l-4 border-orange-500';
      case 'warning':
        return 'bg-red-50 dark:bg-red-950/20 border-l-4 border-red-500';
      default:
        return 'bg-green-50 dark:bg-green-950/20 border-l-4 border-green-500';
    }
  };

  const getModuleLabel = (type: string) => {
    switch (type) {
      case 'leave':
        return 'Leave';
      case 'task':
        return 'Task';
      case 'shift':
        return 'Shift';
      default:
        return 'Other';
    }
  };

  const NotificationItem = ({ notification }: { notification: any }) => (
    <div
      className={`p-4 hover:bg-opacity-75 dark:hover:bg-opacity-30 cursor-pointer transition-all duration-200 hover:scale-[1.01] ${getNotificationBgColor(notification.type)} ${notification.read ? 'opacity-70' : 'opacity-100'}`}
      onClick={() => handleNotificationClick(notification)}
    >
      <div className="flex gap-3">
        <div className="flex-shrink-0 mt-0.5">
          {getNotificationIcon(notification.type)}
        </div>
        <div className="flex-1 space-y-1.5 min-w-0">
          <div className="flex items-start justify-between gap-2">
            <div className={`text-sm leading-tight ${notification.read ? 'font-normal text-muted-foreground' : 'font-semibold text-foreground'}`}>
              <TruncatedText
                text={notification.title || 'Notification'}
                maxLength={60}
                showToggle={false}
              />
            </div>
            {!notification.read && (
              <Badge className="h-5 text-[10px] px-1.5 bg-gradient-to-r from-blue-500 to-indigo-600 text-white border-0 shadow-md flex-shrink-0 animate-pulse">
                NEW
              </Badge>
            )}
          </div>
          {notification.message && (
            <div className="text-xs text-muted-foreground leading-relaxed">
              <TruncatedText
                text={notification.message}
                maxLength={100}
                showToggle={false}
              />
            </div>
          )}
          <div className="flex items-center justify-between pt-1 gap-2 flex-wrap">
            <div className="flex items-center gap-2 flex-wrap">
              <span className="inline-flex items-center rounded-full bg-slate-100 dark:bg-slate-800 px-2 py-0.5 text-[10px] font-medium uppercase tracking-wide text-slate-700 dark:text-slate-300">
                {getModuleLabel(notification.type)}
              </span>
              <p className="text-[10px] text-muted-foreground whitespace-nowrap">
                {(() => {
                  try {
                    if (notification.createdAt) {
                      return formatBackendDateIST(notification.createdAt, 'MMM dd, yyyy HH:mm');
                    }
                    return 'Just now';
                  } catch (error) {
                    console.error('Error formatting notification time:', error);
                    return 'Just now';
                  }
                })()}
              </p>
            </div>
            <Button
              variant="ghost"
              size="sm"
              className="h-6 w-6 p-0 hover:bg-red-100 hover:text-red-600 dark:hover:bg-red-900 transition-all rounded-md flex-shrink-0"
              onClick={(e) => {
                e.stopPropagation();
                clearNotification(notification.id);
              }}
            >
              <X className="h-3 w-3" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="relative h-10 w-10 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-950 transition-all duration-300 hover:scale-110"
        >
          <Bell className={`h-5 w-5 text-blue-600 dark:text-blue-400 ${unreadCount > 0 ? 'animate-shake' : ''}`} />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 h-5 w-5 rounded-full bg-gradient-to-r from-red-500 to-rose-600 text-[10px] font-bold text-white flex items-center justify-center animate-pulse shadow-lg border-2 border-white dark:border-gray-900">
              {unreadCount > 9 ? '9+' : unreadCount}
            </span>
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-[420px] max-h-[600px] bg-background z-50 border-2 shadow-2xl p-0">
        <div className="flex items-center justify-between p-4 border-b-2 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-950 dark:to-indigo-950 sticky top-0 z-10">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-md">
              <Bell className="h-4 w-4 text-white" />
            </div>
            <h3 className="font-bold text-lg">Notifications</h3>
            {isLoading && (
              <Loader2 className="h-4 w-4 animate-spin text-blue-500" />
            )}
          </div>
          <div className="flex items-center gap-1">
            {unreadCount > 0 && (
              <Button
                variant="ghost"
                size="sm"
                onClick={markAllAsRead}
                className="text-xs hover:bg-blue-100 dark:hover:bg-blue-900 transition-colors"
              >
                <Check className="h-3 w-3 mr-1" />
                Mark all
              </Button>
            )}
          </div>
        </div>

        {error ? (
          <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
            <div className="h-20 w-20 rounded-full bg-gradient-to-br from-red-100 to-orange-100 dark:from-red-900 dark:to-orange-900 flex items-center justify-center mb-4">
              <AlertCircle className="h-10 w-10 text-red-400 dark:text-red-600" />
            </div>
            <p className="text-sm font-medium text-red-600 dark:text-red-400">Unable to load notifications</p>
            <p className="text-xs text-muted-foreground mt-1">Please try again later</p>
          </div>
        ) : allNotifications.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
            <div className="h-20 w-20 rounded-full bg-gradient-to-br from-blue-100 to-indigo-100 dark:from-blue-900 dark:to-indigo-900 flex items-center justify-center mb-4">
              <Bell className="h-10 w-10 text-blue-400 dark:text-blue-600" />
            </div>
            <p className="text-sm font-medium">No notifications found</p>
            <p className="text-xs text-muted-foreground mt-1">You're all caught up!</p>
          </div>
        ) : (
          <Tabs defaultValue="all" value={activeTab} onValueChange={setActiveTab} className="w-full">
            <TabsList className="w-full justify-start border-b rounded-none bg-transparent p-0 h-auto">
              <TabsTrigger
                value="all"
                className="rounded-none border-b-2 border-transparent data-[state=active]:border-blue-500 data-[state=active]:bg-transparent px-4 py-2"
              >
                <span className="text-xs font-medium">All</span>
                {allNotifications.length > 0 && (
                  <Badge className="ml-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] bg-gray-500 text-white">
                    {allNotifications.length}
                  </Badge>
                )}
                {unreadCount > 0 && (
                  <Badge className="ml-1 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] bg-red-500 text-white">
                    {unreadCount}
                  </Badge>
                )}
              </TabsTrigger>

              {leaveNotifications.length > 0 && (
                <TabsTrigger
                  value="leave"
                  className="rounded-none border-b-2 border-transparent data-[state=active]:border-purple-500 data-[state=active]:bg-transparent px-4 py-2"
                >
                  <Calendar className="h-4 w-4 mr-1 text-purple-500" />
                  <span className="text-xs font-medium">Leave</span>
                  <Badge className="ml-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] bg-purple-500 text-white">
                    {leaveNotifications.length}
                  </Badge>
                </TabsTrigger>
              )}

              {taskNotifications.length > 0 && (
                <TabsTrigger
                  value="task"
                  className="rounded-none border-b-2 border-transparent data-[state=active]:border-blue-500 data-[state=active]:bg-transparent px-4 py-2"
                >
                  <FileText className="h-4 w-4 mr-1 text-blue-500" />
                  <span className="text-xs font-medium">Tasks</span>
                  <Badge className="ml-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] bg-blue-500 text-white">
                    {taskNotifications.length}
                  </Badge>
                </TabsTrigger>
              )}

              {shiftNotifications.length > 0 && (
                <TabsTrigger
                  value="shift"
                  className="rounded-none border-b-2 border-transparent data-[state=active]:border-orange-500 data-[state=active]:bg-transparent px-4 py-2"
                >
                  <Clock className="h-4 w-4 mr-1 text-orange-500" />
                  <span className="text-xs font-medium">Shifts</span>
                  <Badge className="ml-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] bg-orange-500 text-white">
                    {shiftNotifications.length}
                  </Badge>
                </TabsTrigger>
              )}
            </TabsList>

            <ScrollArea className="h-[400px]">
              <TabsContent value="all" className="m-0 divide-y">
                {allNotifications.length === 0 ? (
                  <div className="flex items-center justify-center py-8 text-muted-foreground">
                    <p className="text-sm">No notifications found</p>
                  </div>
                ) : (
                  allNotifications.map((notification) => (
                    <NotificationItem key={notification.id} notification={notification} />
                  ))
                )}
              </TabsContent>

              <TabsContent value="leave" className="m-0 divide-y">
                {leaveNotifications.length === 0 ? (
                  <div className="flex items-center justify-center py-8 text-muted-foreground">
                    <p className="text-sm">No leave notifications</p>
                  </div>
                ) : (
                  leaveNotifications.map((notification) => (
                    <NotificationItem key={notification.id} notification={notification} />
                  ))
                )}
              </TabsContent>

              <TabsContent value="task" className="m-0 divide-y">
                {taskNotifications.length === 0 ? (
                  <div className="flex items-center justify-center py-8 text-muted-foreground">
                    <p className="text-sm">No task notifications</p>
                  </div>
                ) : (
                  taskNotifications.map((notification) => (
                    <NotificationItem key={notification.id} notification={notification} />
                  ))
                )}
              </TabsContent>

              <TabsContent value="shift" className="m-0 divide-y">
                {shiftNotifications.length === 0 ? (
                  <div className="flex items-center justify-center py-8 text-muted-foreground">
                    <p className="text-sm">No shift notifications</p>
                  </div>
                ) : (
                  shiftNotifications.map((notification) => (
                    <NotificationItem key={notification.id} notification={notification} />
                  ))
                )}
              </TabsContent>
            </ScrollArea>
            <div className="p-3 border-t bg-slate-50 dark:bg-slate-900 sticky bottom-0">
              <Button
                variant="outline"
                size="sm"
                className="w-full text-xs font-bold hover:bg-blue-600 hover:text-white transition-all duration-300"
                onClick={() => {
                  navigate(`/${user?.role}/inbox`);
                  setIsOpen(false);
                }}
              >
                View All Notifications
              </Button>
            </div>
          </Tabs>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
};

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Calendar } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { FileText, FileSpreadsheet, Calendar as CalendarIcon, Download, Loader2 } from 'lucide-react';
import { format } from 'date-fns';
import { toast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { apiService } from '@/lib/api';

interface ExportDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  selectedEmployee?: { id: string; name: string } | null;
}

type ExportFormat = 'csv' | 'pdf';
type TimeRange = 'monthly' | 'last3months' | 'last6months' | 'yearly' | 'custom';

interface Employee {
  id: string;
  name: string;
  department: string;
}

export default function ExportDialog({ open, onOpenChange, selectedEmployee }: ExportDialogProps) {
  const [exportFormat, setExportFormat] = useState<ExportFormat>('csv');
  const [timeRange, setTimeRange] = useState<TimeRange>('monthly');
  const [customStartDate, setCustomStartDate] = useState<Date>();
  const [customEndDate, setCustomEndDate] = useState<Date>();
  const [isExporting, setIsExporting] = useState(false);
  const [selectedDepartment, setSelectedDepartment] = useState<string>('all');
  const [selectedUser, setSelectedUser] = useState<string>('all');
  const [departments, setDepartments] = useState<string[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoadingDepts, setIsLoadingDepts] = useState(false);
  const [isLoadingEmps, setIsLoadingEmps] = useState(false);

  // Load departments on mount
  useEffect(() => {
    loadDepartments();
  }, []);

  // Load employees when department changes
  useEffect(() => {
    if (selectedDepartment !== 'all') {
      loadEmployees(selectedDepartment);
    } else {
      loadAllEmployees();
    }
  }, [selectedDepartment]);

  const loadDepartments = async () => {
    setIsLoadingDepts(true);
    try {
      const data = await apiService.getReportDepartments();
      if (data && data.departments) {
        setDepartments(data.departments);
      }
    } catch (error) {
      console.error('Failed to load departments:', error);
    } finally {
      setIsLoadingDepts(false);
    }
  };

  const loadEmployees = async (department: string) => {
    setIsLoadingEmps(true);
    try {
      const data = await apiService.getEmployeesByDepartment(department);
      const emps = Array.isArray(data) ? data : data.employees || [];
      setEmployees(emps.map((emp: any) => ({
        id: emp.id || emp.user_id,
        name: emp.name,
        department: emp.department,
      })));
    } catch (error) {
      console.error('Failed to load employees:', error);
      setEmployees([]);
    } finally {
      setIsLoadingEmps(false);
    }
  };

  const loadAllEmployees = async () => {
    setIsLoadingEmps(true);
    try {
      const data = await apiService.getAllEmployees();
      const emps = Array.isArray(data) ? data : data.employees || [];
      setEmployees(emps.map((emp: any) => ({
        id: emp.id || emp.user_id,
        name: emp.name,
        department: emp.department,
      })));
    } catch (error) {
      console.error('Failed to load employees:', error);
      setEmployees([]);
    } finally {
      setIsLoadingEmps(false);
    }
  };

  const handleExport = async () => {
    setIsExporting(true);
    try {
      // Calculate date range based on selection
      let startDate: Date;
      let endDate: Date = new Date();

      switch (timeRange) {
        case 'monthly':
          startDate = new Date();
          startDate.setMonth(startDate.getMonth() - 1);
          break;
        case 'last3months':
          startDate = new Date();
          startDate.setMonth(startDate.getMonth() - 3);
          break;
        case 'last6months':
          startDate = new Date();
          startDate.setMonth(startDate.getMonth() - 6);
          break;
        case 'yearly':
          startDate = new Date();
          startDate.setFullYear(startDate.getFullYear() - 1);
          break;
        case 'custom':
          if (!customStartDate || !customEndDate) {
            toast({
              title: 'Error',
              description: 'Please select both start and end dates for custom range',
              variant: 'destructive',
            });
            setIsExporting(false);
            return;
          }
          startDate = customStartDate;
          endDate = customEndDate;
          break;
        default:
          startDate = new Date();
          startDate.setMonth(startDate.getMonth() - 1);
      }

      const blob = await apiService.exportPerformanceReport({
        format: exportFormat,
        start_date: format(startDate, 'yyyy-MM-dd'),
        end_date: format(endDate, 'yyyy-MM-dd'),
        employee_id: selectedEmployee?.id || (selectedUser !== 'all' ? selectedUser : undefined),
        department: selectedDepartment !== 'all' ? selectedDepartment : undefined,
      });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;

      let filename = 'performance_report';
      if (selectedEmployee) {
        filename = `performance_${selectedEmployee.name}_${format(startDate, 'yyyy-MM-dd')}_to_${format(endDate, 'yyyy-MM-dd')}`;
      } else if (selectedUser !== 'all') {
        const user = employees.find(e => e.id === selectedUser);
        filename = `performance_${user?.name || 'employee'}_${format(startDate, 'yyyy-MM-dd')}_to_${format(endDate, 'yyyy-MM-dd')}`;
      } else if (selectedDepartment !== 'all') {
        filename = `performance_${selectedDepartment}_${format(startDate, 'yyyy-MM-dd')}_to_${format(endDate, 'yyyy-MM-dd')}`;
      } else {
        filename = `performance_all_employees_${format(startDate, 'yyyy-MM-dd')}_to_${format(endDate, 'yyyy-MM-dd')}`;
      }

      a.download = `${filename}.${exportFormat}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);

      toast({
        title: 'Success',
        description: `Report exported successfully as ${exportFormat.toUpperCase()}`,
      });

      onOpenChange(false);
    } catch (error) {
      console.error('Export error:', error);
      toast({
        title: 'Error',
        description: 'Failed to export report. Please try again.',
        variant: 'destructive',
      });
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px] gap-0 p-0 overflow-hidden">
        <DialogHeader className="p-6 pb-2">
          <DialogTitle className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
            Export Performance Report
          </DialogTitle>
        </DialogHeader>

        <div className="p-6 pt-2 overflow-y-auto max-h-[60vh] scrollbar-thin">
          <div className="space-y-6">
            {/* Employee Info */}
            {selectedEmployee && (
              <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-4 border border-blue-200 dark:border-blue-800">
                <p className="text-sm font-medium text-muted-foreground mb-1">Exporting for:</p>
                <p className="text-lg font-bold text-slate-800 dark:text-white">{selectedEmployee.name}</p>
                <p className="text-xs text-muted-foreground">Employee ID: {selectedEmployee.id}</p>
              </div>
            )}

            {!selectedEmployee && (
              <div className="bg-purple-50 dark:bg-purple-900/20 rounded-lg p-4 border border-purple-200 dark:border-purple-800">
                <p className="text-sm font-medium text-purple-900 dark:text-purple-200">
                  Exporting data for all employees
                </p>
              </div>
            )}

            {/* Export Format */}
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Export Format</Label>
              <div className="grid grid-cols-2 gap-3">
                <button
                  onClick={() => setExportFormat('csv')}
                  className={cn(
                    'flex items-center gap-3 p-4 rounded-lg border-2 transition-all',
                    exportFormat === 'csv'
                      ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20'
                      : 'border-slate-200 dark:border-slate-700 hover:border-slate-300'
                  )}
                >
                  <FileSpreadsheet className={cn(
                    'h-6 w-6',
                    exportFormat === 'csv' ? 'text-blue-600' : 'text-slate-400'
                  )} />
                  <div className="text-left">
                    <p className="font-semibold text-sm">CSV</p>
                    <p className="text-xs text-muted-foreground">Spreadsheet</p>
                  </div>
                </button>

                <button
                  onClick={() => setExportFormat('pdf')}
                  className={cn(
                    'flex items-center gap-3 p-4 rounded-lg border-2 transition-all',
                    exportFormat === 'pdf'
                      ? 'border-red-500 bg-red-50 dark:bg-red-900/20'
                      : 'border-slate-200 dark:border-slate-700 hover:border-slate-300'
                  )}
                >
                  <FileText className={cn(
                    'h-6 w-6',
                    exportFormat === 'pdf' ? 'text-red-600' : 'text-slate-400'
                  )} />
                  <div className="text-left">
                    <p className="font-semibold text-sm">PDF</p>
                    <p className="text-xs text-muted-foreground">Document</p>
                  </div>
                </button>
              </div>
            </div>

            {/* Time Range */}
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Time Range</Label>
              <Select value={timeRange} onValueChange={(value) => setTimeRange(value as TimeRange)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="monthly">Last Month</SelectItem>
                  <SelectItem value="last3months">Last 3 Months</SelectItem>
                  <SelectItem value="last6months">Last 6 Months</SelectItem>
                  <SelectItem value="yearly">Last Year</SelectItem>
                  <SelectItem value="custom">Custom Date Range</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Department Selection */}
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Select Department</Label>
              <Select value={selectedDepartment} onValueChange={setSelectedDepartment} disabled={isLoadingDepts}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Departments</SelectItem>
                  {departments.map(dept => (
                    <SelectItem key={dept} value={dept}>{dept}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* User Selection */}
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Select User</Label>
              <Select value={selectedUser} onValueChange={setSelectedUser} disabled={isLoadingEmps}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Users</SelectItem>
                  {employees.map(emp => (
                    <SelectItem key={emp.id} value={emp.id}>{emp.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Custom Date Range */}
            {timeRange === 'custom' && (
              <div className="space-y-3">
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-2">
                    <Label className="text-xs font-medium">Start Date</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          className={cn(
                            'w-full justify-start text-left font-normal',
                            !customStartDate && 'text-muted-foreground'
                          )}
                        >
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {customStartDate ? format(customStartDate, 'PPP') : 'Pick date'}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0">
                        <Calendar
                          mode="single"
                          selected={customStartDate}
                          onSelect={setCustomStartDate}
                          initialFocus
                        />
                      </PopoverContent>
                    </Popover>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-xs font-medium">End Date</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          className={cn(
                            'w-full justify-start text-left font-normal',
                            !customEndDate && 'text-muted-foreground'
                          )}
                        >
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {customEndDate ? format(customEndDate, 'PPP') : 'Pick date'}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0">
                        <Calendar
                          mode="single"
                          selected={customEndDate}
                          onSelect={setCustomEndDate}
                          initialFocus
                        />
                      </PopoverContent>
                    </Popover>
                  </div>
                </div>
              </div>
            )}

            {/* Export Info */}
            <div className="bg-slate-50 dark:bg-slate-800 rounded-lg p-4 border border-slate-200 dark:border-slate-700">
              <p className="text-xs font-semibold text-slate-700 dark:text-slate-300 mb-2">Export will include:</p>
              <ul className="text-xs text-muted-foreground space-y-1">
                <li>• Employee performance records</li>
                <li>• Attendance report</li>
                <li>• Task completion report</li>
                <li>• Leave summary</li>
                <li>• Leave type breakdown</li>
                <li>• Performance metrics</li>
              </ul>
            </div>
          </div>
        </div>

        <div className="p-6 border-t bg-slate-50/50 dark:bg-slate-900/50 flex flex-col sm:flex-row gap-3">
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            className="flex-1 order-2 sm:order-1"
            disabled={isExporting}
          >
            Cancel
          </Button>
          <Button
            onClick={handleExport}
            className="flex-1 bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 order-1 sm:order-2"
            disabled={isExporting}
          >
            {isExporting ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Exporting...
              </>
            ) : (
              <>
                <Download className="h-4 w-4 mr-2" />
                Export {exportFormat.toUpperCase()}
              </>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/hooks/use-toast';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { AlertTriangle, Clock, Calendar, CheckCircle2 } from 'lucide-react';
import { formatDateIST } from '@/utils/timezone';
import TruncatedText from '@/components/ui/TruncatedText';
import { API_BASE_URL } from '@/lib/api';

// Helper component for View Tasks button with proper role-based navigation
const ViewTasksButton: React.FC = () => {
  const { user } = useAuth();

  const handleViewTasks = () => {
    const taskRoute = user?.role ? `/${user.role}/tasks` : '/employee/tasks';
    window.location.href = taskRoute;
  };

  return (
    <Button onClick={handleViewTasks}>
      View Tasks
    </Button>
  );
};

interface TaskWarning {
  task_id: number;
  title: string;
  due_date: string;
  status: string;
  priority: string;
  warning_type: 'overdue' | 'due_today' | 'upcoming';
  message: string;
  days_until_deadline: number;
}

interface TaskDeadlineWarningsProps {
  isOpen: boolean;
  onClose: () => void;
  userId?: string;
}

const TaskDeadlineWarnings: React.FC<TaskDeadlineWarningsProps> = ({
  isOpen,
  onClose,
  userId
}) => {
  const { user } = useAuth();
  const { toast } = useToast();
  const [warnings, setWarnings] = useState<TaskWarning[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const fetchWarnings = async () => {
    if (!user?.id) return;

    const targetUserId = userId || user.id;
    const token = localStorage.getItem('token');

    if (!token) {
      toast({
        title: 'Authentication required',
        description: 'Please log in again to check task deadlines.',
        variant: 'destructive',
      });
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch(`${API_BASE_URL}/tasks/deadline-warnings/${targetUserId}`, {
        headers: {
          'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch warnings: ${response.status}`);
      }

      const data = await response.json();
      setWarnings(data.warnings || []);
    } catch (error) {
      console.error('Failed to fetch task warnings:', error);
      toast({
        title: 'Warning fetch failed',
        description: 'Unable to load task deadline warnings.',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      fetchWarnings();
    }
  }, [isOpen, user?.id, userId]);

  const getWarningIcon = (warningType: string) => {
    switch (warningType) {
      case 'overdue':
        return <AlertTriangle className="h-5 w-5 text-red-500" />;
      case 'due_today':
        return <Clock className="h-5 w-5 text-orange-500" />;
      case 'upcoming':
        return <Calendar className="h-5 w-5 text-yellow-500" />;
      default:
        return <Clock className="h-5 w-5 text-gray-500" />;
    }
  };

  const getWarningColor = (warningType: string) => {
    switch (warningType) {
      case 'overdue':
        return 'bg-red-50 border-red-200';
      case 'due_today':
        return 'bg-orange-50 border-orange-200';
      case 'upcoming':
        return 'bg-yellow-50 border-yellow-200';
      default:
        return 'bg-gray-50 border-gray-200';
    }
  };

  const getPriorityBadge = (priority: string) => {
    const priorityColors = {
      'Low': 'bg-green-100 text-green-800',
      'Medium': 'bg-blue-100 text-blue-800',
      'High': 'bg-orange-100 text-orange-800',
      'Urgent': 'bg-red-100 text-red-800',
    };

    return (
      <Badge className={priorityColors[priority as keyof typeof priorityColors] || 'bg-gray-100 text-gray-800'}>
        {priority}
      </Badge>
    );
  };

  const formatDate = (dateString: string) => {
    try {
      return formatDateIST(dateString, 'MMM dd, yyyy');
    } catch {
      return dateString;
    }
  };

  const hasWarnings = warnings.length > 0;
  const overdueCount = warnings.filter(w => w.warning_type === 'overdue').length;
  const dueTodayCount = warnings.filter(w => w.warning_type === 'due_today').length;
  const upcomingCount = warnings.filter(w => w.warning_type === 'upcoming').length;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-orange-500" />
            Task Deadline Warnings
          </DialogTitle>
          <DialogDescription>
            {hasWarnings
              ? `You have ${warnings.length} task(s) with upcoming or overdue deadlines.`
              : 'All your tasks are on track! No deadline warnings at this time.'
            }
          </DialogDescription>
        </DialogHeader>

        {isLoading ? (
          <div className="flex items-center justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
            <span className="ml-2 text-gray-600">Loading warnings...</span>
          </div>
        ) : hasWarnings ? (
          <div className="space-y-4">
            {/* Summary Cards */}
            <div className="grid grid-cols-3 gap-4">
              {overdueCount > 0 && (
                <Card className="border-red-200 bg-red-50">
                  <CardContent className="p-4 text-center">
                    <div className="text-2xl font-bold text-red-600">{overdueCount}</div>
                    <div className="text-sm text-red-700">Overdue</div>
                  </CardContent>
                </Card>
              )}
              {dueTodayCount > 0 && (
                <Card className="border-orange-200 bg-orange-50">
                  <CardContent className="p-4 text-center">
                    <div className="text-2xl font-bold text-orange-600">{dueTodayCount}</div>
                    <div className="text-sm text-orange-700">Due Today</div>
                  </CardContent>
                </Card>
              )}
              {upcomingCount > 0 && (
                <Card className="border-yellow-200 bg-yellow-50">
                  <CardContent className="p-4 text-center">
                    <div className="text-2xl font-bold text-yellow-600">{upcomingCount}</div>
                    <div className="text-sm text-yellow-700">Upcoming</div>
                  </CardContent>
                </Card>
              )}
            </div>

            {/* Warning List */}
            <div className="space-y-3">
              {warnings.map((warning) => (
                <Card key={warning.task_id} className={`border ${getWarningColor(warning.warning_type)}`}>
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between">
                      <div className="flex items-start gap-3 flex-1">
                        {getWarningIcon(warning.warning_type)}
                        <div className="flex-1">
                          <h4 className="font-semibold text-gray-900 mb-1">
                            <TruncatedText
                              text={warning.title}
                              maxLength={40}
                              showToggle={false}
                            />
                          </h4>
                          <div className="text-sm text-gray-600 mb-2">
                            <TruncatedText
                              text={warning.message}
                              maxLength={100}
                              showToggle={false}
                            />
                          </div>
                          <div className="flex items-center gap-4 text-xs text-gray-500">
                            <span>Due: {formatDate(warning.due_date)}</span>
                            <span>Status: {warning.status}</span>
                          </div>
                        </div>
                      </div>
                      <div className="flex flex-col items-end gap-2">
                        {getPriorityBadge(warning.priority)}
                        {warning.warning_type === 'due_today' && (
                          <Badge variant="outline" className="text-orange-600 border-orange-300">
                            Due Today!
                          </Badge>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        ) : (
          <div className="text-center py-8">
            <CheckCircle2 className="h-12 w-12 text-green-500 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">All Good!</h3>
            <p className="text-gray-600">
              You don't have any tasks with upcoming deadlines. Keep up the great work!
            </p>
          </div>
        )}

        <div className="flex justify-end gap-2 pt-4 border-t">
          <Button variant="outline" onClick={onClose}>
            Close
          </Button>
          {hasWarnings && (
            <ViewTasksButton />
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default TaskDeadlineWarnings;

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
        xs: "h-7 rounded-md px-2",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
  VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
));
Command.displayName = CommandPrimitive.displayName;

interface CommandDialogProps extends DialogProps {}

const CommandDialog = ({ children, ...props }: CommandDialogProps) => {
  return (
