export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [otpSent, setOtpSent] = useState(false);
  const [showDeadlineWarnings, setShowDeadlineWarnings] = useState(false);
  const { toast } = useToast();
  const navigate = useNavigate();


  /**
   * Validates and restores user session from localStorage
   */
  const validateAndRestoreSession = async () => {
    setIsLoading(true);
    try {
      const storedToken = localStorage.getItem('token');
      const storedUser = localStorage.getItem('user');

      // If no token or user, clear everything
      if (!storedToken || !storedUser) {
        console.log('No stored token or user found');
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        localStorage.removeItem('userId');
        setUser(null);
        setIsLoading(false);
        return;
      }

      // First, do client-side validation (fast check)
      if (!isTokenValid(storedToken)) {
        console.warn('Restoration: Token is invalid or expired (client-side check)', {
          tokenPreview: storedToken.substring(0, 10) + '...',
          isValid: isTokenValid(storedToken)
        });
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        localStorage.removeItem('userId');
        setUser(null);
        setIsLoading(false);
        return;
      }

      // Optional: Verify with backend (uncomment if backend endpoint exists)
      // This provides server-side validation which is more secure
      // const verificationResult = await verifyTokenWithBackend(storedToken);
      // if (!verificationResult.valid) {
      //   console.warn('Token verification failed with backend:', verificationResult.message);
      //   localStorage.removeItem('token');
      //   localStorage.removeItem('user');
      //   localStorage.removeItem('userId');
      //   setUser(null);
      //   setIsLoading(false);
      //   return;
      // }

      // Token is valid, restore user session
      try {
        const user = JSON.parse(storedUser) as User;

        // Debug user object
        console.log('Restoration: Stored user object found:', {
          id: user.id,
          role: user.role,
          email: user.email
        });

        // Verify token payload matches stored user (optional extra check)
        const tokenUser = getUserFromToken(storedToken);
        console.log('Restoration: Token user data:', tokenUser);

        // Only reject if BOTH sides have non-empty values AND they definitively don't match.
        // If tokenUser.userId is undefined/null (JWT field not found), skip this check
        // to avoid false positives that log users out on every refresh.
        if (
          tokenUser &&
          tokenUser.userId &&
          user.id &&
          String(user.id) !== String(tokenUser.userId)
        ) {
          console.warn('Restoration: Token user ID does not match stored user ID', {
            tokenUserId: tokenUser.userId,
            storedUserId: user.id
          });
          // For now, let's be lenient if the user is already found in storage
          // to prevent refresh-logouts. Just log it.
          // In the future, we can re-enable strict matching if needed.
        }

        setUser(user);
        console.log('Restoration: Session restored successfully');
      } catch (parseError) {
        console.error('Restoration: Error parsing stored user data:', parseError);
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        localStorage.removeItem('userId');
        setUser(null);
      }
    } catch (error) {
      console.error('Error validating session:', error);
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      localStorage.removeItem('userId');
      setUser(null);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    // Validate and restore session on app initialization
    validateAndRestoreSession();
  }, []);

  // Map backend role values to frontend role values
  const mapRoleToFrontend = (backendRole: string): UserRole => {
    const roleMap: Record<string, UserRole> = {
      'admin': 'admin',
      'Admin': 'admin',
      'ADMIN': 'admin',
      'hr': 'hr',
      'HR': 'hr',
      'manager': 'manager',
      'Manager': 'manager',
      'MANAGER': 'manager',
      'teamlead': 'team_lead',
      'TeamLead': 'team_lead',
      'TEAM_LEAD': 'team_lead',
      'team_lead': 'team_lead',
      'employee': 'employee',
      'Employee': 'employee',
      'EMPLOYEE': 'employee',
    };

    const normalizedRole = backendRole?.trim();
    const mappedRole = roleMap[normalizedRole] || 'employee';
    console.log('Role mapping:', { backendRole, normalizedRole, mappedRole });
    return mappedRole;
  };

  const login = async (userData: LoginResponse) => {
    setIsLoading(true);
    try {
      console.log('AuthContext Login Data:', userData); // Debug log

      // Map backend role to frontend role format
      const frontendRole = mapRoleToFrontend(userData.role);

      // Create a user object from the API response
      const user: User = {
        id: userData.user_id,
        email: userData.email,
        name: userData.name,
        role: frontendRole,
        department: userData.department || '',
        designation: userData.designation || '',
        joiningDate: userData.joining_date || new Date().toISOString(),
        profilePhoto: userData.profile_photo ? `${API_BASE_URL}/${userData.profile_photo}` : undefined,
        status: 'active',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      };

      console.log('Processed User Data:', user); // Debug log

      // Validate token before storing
      if (!isTokenValid(userData.access_token)) {
        console.error('Invalid token received from backend');
        toast({
          title: 'Login Failed',
          description: 'Invalid authentication token. Please try again.',
          variant: 'destructive',
        });
        setIsLoading(false);
        return;
      }

      // Store the user data and token
      setUser(user);
      localStorage.setItem('user', JSON.stringify(user));
      localStorage.setItem('token', userData.access_token);
      localStorage.setItem('userId', user.id.toString()); // Store userId for language persistence

      toast({
        variant: 'success',
        title: 'Login Successful',
        description: `Welcome back, ${user.name}!`,
      });

      // Redirect to the appropriate dashboard based on role
      const roleRoutes: Record<UserRole, string> = {
        admin: '/admin',
        hr: '/hr',
        manager: '/manager',
        team_lead: '/team_lead',
        employee: '/employee',
      };

      const redirectPath = roleRoutes[user.role];
      console.log('Redirecting to:', redirectPath); // Debug log

      if (!redirectPath) {
        console.error('Invalid role:', user.role);
        toast({
          title: 'Navigation Error',
          description: 'Invalid user role. Please contact support.',
          variant: 'destructive',
        });
        return;
      }

      // Call login resume endpoint to handle pause/resume functionality
      try {
        await fetch(`${API_BASE_URL}/attendance/login-resume`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': userData.access_token ? (userData.access_token.startsWith('Bearer ') ? userData.access_token : `Bearer ${userData.access_token}`) : '',
          },
          body: JSON.stringify({
            user_id: parseInt(user.id),
            login_timestamp: new Date().toISOString(),
          }),
        });
      } catch (error) {
        // Don't block login if the resume API call fails
        console.warn('Failed to record login resume:', error);
      }

      // Show deadline warnings after successful login
      setTimeout(() => {
        setShowDeadlineWarnings(true);
      }, 1000); // Small delay to let the navigation complete

      navigate(redirectPath);
    } catch (error) {
      console.error('Login error:', error);
      toast({
        title: 'Login Failed',
        description: 'There was an error processing your login. Please try again.',
        variant: 'destructive',
      });
    }

    setIsLoading(false);
    setOtpSent(false);
  };

  const logout = async (showToast = true) => {
    // Before logging out, record logout timestamp for pause/resume functionality
    try {
      const token = localStorage.getItem('token');
      if (token && isTokenValid(token) && user?.id) {
        // Call the logout endpoint to record pause timestamp
        await fetch(`${API_BASE_URL}/attendance/logout`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
          },
          body: JSON.stringify({
            user_id: parseInt(user.id),
            logout_timestamp: new Date().toISOString(),
          }),
        });
      }
    } catch (error) {
      // Don't block logout if the API call fails
      console.warn('Failed to record logout timestamp:', error);
    }

    setUser(null);
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    localStorage.removeItem('userId'); // Clear userId for language persistence

    // Clear all session-related data
    sessionStorage.clear();

    if (showToast) {
      toast({
        title: 'Logged Out',
        description: 'You have been successfully logged out.',
      });
    }

    // Use replace to prevent going back to authenticated pages
    navigate('/login', { replace: true });
  };

  const updateUser = (updatedUser: User) => {
    setUser(updatedUser);
    localStorage.setItem('user', JSON.stringify(updatedUser));
  };

  const value = {
    user,
    isAuthenticated: !!user,
    isLoading,
    login,
    logout,
    updateUser,
    showDeadlineWarnings,
    setShowDeadlineWarnings,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Chat, ChatMessage, User } from '@/types';
import { chatService } from '@/services/chatService';
import { useAuth } from './AuthContext';
import { useToast } from '@/hooks/use-toast';

interface ChatContextType {
  chats: Chat[];
  activeChat: Chat | null;
  messages: ChatMessage[];
  availableUsers: User[];
  isLoading: boolean;
  unreadCount: number;
  setActiveChat: (chat: Chat | null) => void;
  sendMessage: (content: string, messageType?: 'text' | 'emoji', replyTo?: string) => Promise<void>;
  createChat: (type: 'individual' | 'group', participantIds: string[], name?: string, description?: string) => Promise<Chat>;
  loadChats: () => Promise<void>;
  loadMessages: (chatId: string, type?: 'individual' | 'group') => Promise<void>;
  loadAvailableUsers: () => Promise<void>;
  markAsRead: (chatId: string, messageIds: string[]) => Promise<void>;
  deleteMessage: (messageId: string) => Promise<void>;
  editMessage: (messageId: string, newContent: string) => Promise<void>;
  sendTyping: (chatId: string) => Promise<void>;
  updateGroupName: (chatId: string, newName: string) => Promise<void>;
  deleteGroup: (chatId: string) => Promise<void>;
  addParticipants: (chatId: string, userIds: string[]) => Promise<void>;
  removeParticipants: (chatId: string, userIds: string[]) => Promise<void>;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export const ChatProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [chats, setChats] = useState<Chat[]>([]);
  const [activeChat, setActiveChat] = useState<Chat | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [availableUsers, setAvailableUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();

  // RBAC Filtering logic
  const isUserVisible = useCallback((targetUser: { role: string; department: string; id: string }) => {
    if (!user) return false;
    if (user.id === targetUser.id) return true;

    const cr = user.role;
    const cd = user.department;
    const tr = targetUser.role;
    const td = targetUser.department;

    // Admin & HR: Can chat with everyone
    if (cr === 'admin' || cr === 'hr') return true;

    // Manager Visibility
    if (cr === 'manager') {
      // Admin, HR, All Managers
      if (['admin', 'hr', 'manager'].includes(tr)) return true;
      // Own department (TL, Employee)
      return td === cd;
    }

    // Team Lead Visibility
    if (cr === 'team_lead') {
      // Admin, HR
      if (['admin', 'hr'].includes(tr)) return true;
      // Own department (Manager, TL, Emp)
      return td === cd;
    }

    // Employee Visibility
    if (cr === 'employee') {
      // Admin, HR
      if (['admin', 'hr'].includes(tr)) return true;
      // Own department (Manager, TL, Emp)
      return td === cd;
    }

    return false;
  }, [user]);

  // Calculate total unread count
  const unreadCount = chats.reduce((total, chat) => total + chat.unreadCount, 0);

  // Load chats
  const loadChats = useCallback(async () => {
    if (!user) return;

    setIsLoading(true);
    try {
      const fetchedChats = await chatService.getChats();

      setChats(fetchedChats);
    } catch (error) {
      console.error('Failed to load chats:', error);
      toast({
        title: 'Error',
        description: 'Failed to load chats',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  }, [user, toast]);

  // Load messages for a specific chat
  const loadMessages = useCallback(async (chatId: string, type?: 'individual' | 'group') => {
    setIsLoading(true);
    try {
      // Priority 1: type argument
      // Priority 2: from existing activeChat
      // Priority 3: from chats list
      // Priority 4: inference from chatId (private chats usually have _ in them)
      let chatType = type;

      if (!chatType) {
        if (activeChat?.id === chatId) {
          chatType = activeChat.type;
        } else {
          const chat = chats.find(c => c.id === chatId);
          chatType = chat?.type || (chatId.includes('_') ? 'individual' : 'group');
        }
      }

      const fetchedMessages = await chatService.getChatMessages(chatId, chatType);
      setMessages(fetchedMessages);
    } catch (error) {
      console.error('Failed to load messages:', error);
      toast({
        title: 'Error',
        description: 'Failed to load messages',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  }, [chats, activeChat, toast]);

  // Load available users
  const loadAvailableUsers = useCallback(async () => {
    if (!user) return;

    try {
      const users = await chatService.getAvailableUsers();
      // Filter available users based on RBAC rules
      const filteredUsers = users.filter(u => isUserVisible(u));
      setAvailableUsers(filteredUsers);
    } catch (error) {
      console.error('Failed to load available users:', error);
      toast({
        title: 'Error',
        description: 'Failed to load available users',
        variant: 'destructive',
      });
    }
  }, [user, toast]);

  // Send message
  const sendMessage = useCallback(async (content: string, messageType: 'text' | 'emoji' = 'text', replyTo?: string) => {
    if (!activeChat || !user) return;

    try {
      const newMessage = await chatService.sendMessage(activeChat.id, activeChat.type, content, messageType, replyTo);
      setMessages(prev => [...prev, newMessage]);

      // Update the chat's last message
      setChats(prev => prev.map(chat =>
        chat.id === activeChat.id
          ? { ...chat, lastMessage: newMessage, updatedAt: newMessage.timestamp }
          : chat
      ));
    } catch (error) {
      console.error('Failed to send message:', error);
      toast({
        title: 'Error',
        description: 'Failed to send message',
        variant: 'destructive',
      });
    }
  }, [activeChat, user, toast]);

  // Create new chat
  const createChat = useCallback(async (
    type: 'individual' | 'group',
    participantIds: string[],
    name?: string,
    description?: string
  ): Promise<Chat> => {
    // Check if 1-to-1 chat already exists
    if (type === 'individual') {
      const targetUserId = participantIds[0];
      const existingChat = chats.find(c =>
        c.type === 'individual' &&
        c.participants.some(p => p.userId === targetUserId)
      );

      if (existingChat) {
        return existingChat;
      }
    }


    // Check if group with same name already exists
    if (type === 'group' && name) {
      // Normalize: remove all spaces and convert to lowercase for comparison
      const normalizedInput = name.toLowerCase().replace(/\s+/g, '');

      const existingGroup = chats.find(c =>
        c.type === 'group' &&
        c.name?.toLowerCase().replace(/\s+/g, '') === normalizedInput
      );

      if (existingGroup) {
        toast({
          title: 'Group Already Exists',
          description: `A group named "${existingGroup.name}" already exists. Please choose a different name.`,
          variant: 'destructive',
        });
        throw new Error('Duplicate group name');
      }
    }

    try {
      const newChat = await chatService.createChat({
        type,
        name,
        description,
        participantIds,
      });

      setChats(prev => [newChat, ...prev]);
      toast({
        title: 'Success',
        description: `${type === 'group' ? 'Group' : 'Chat'} created successfully`,
      });

      return newChat;
    } catch (error) {
      console.error('Failed to create chat:', error);

      // Don't show duplicate error toast again if we already showed it
      if (error instanceof Error && error.message === 'Duplicate group name') {
        throw error;
      }

      toast({
        title: 'Error',
        description: 'Failed to create chat',
        variant: 'destructive',
      });
      throw error;
    }
  }, [chats, toast]);

  // Mark messages as read
  // Now takes messageIds to mark specific messages
  const markAsRead = useCallback(async (chatId: string, messageIds: string[]) => {
    const chat = chats.find(c => c.id === chatId);
    if (!chat || messageIds.length === 0) return;

    try {
      // Parallelize requests if there are multiple. 
      // Note: In a real app with many messages, this might be loop-heavy, 
      // but API only supports single message read receipt.
      await Promise.all(messageIds.map(msgId => chatService.markMessageAsRead(chatId, chat.type, msgId)));

      // Update local state
      setChats(prev => prev.map(c =>
        c.id === chatId ? { ...c, unreadCount: Math.max(0, c.unreadCount - messageIds.length) } : c
      ));

      setMessages(prev => prev.map(message =>
        messageIds.includes(message.id) ? { ...message, isRead: true } : message
      ));
    } catch (error) {
      console.error('Failed to mark messages as read:', error);
    }
  }, [chats]);

  // Send typing status
  const sendTyping = useCallback(async (chatId: string) => {
    const chat = chats.find(c => c.id === chatId);
    if (!chat) return;
    try {
      await chatService.sendTypingStatus(chatId, chat.type);
    } catch (error) {
      console.error('Failed to send typing status:', error);
    }
  }, [chats]);

  // Delete message
  const deleteMessage = useCallback(async (messageId: string) => {
    if (!activeChat) return;

    try {
      await chatService.deleteMessage(activeChat.id, activeChat.type, messageId);
      setMessages(prev => prev.filter(message => message.id !== messageId));

      toast({
        title: 'Success',
        description: 'Message deleted',
      });
    } catch (error) {
      console.error('Failed to delete message:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete message',
        variant: 'destructive',
      });
    }
  }, [activeChat, toast]);

  // Edit message
  const editMessage = useCallback(async (messageId: string, newContent: string) => {
    if (!activeChat) return;

    try {
      const updatedMessage = await chatService.editMessage(activeChat.id, activeChat.type, messageId, newContent);
      setMessages(prev => prev.map(message =>
        message.id === messageId ? { ...message, ...updatedMessage, content: newContent, editedAt: new Date().toISOString() } : message
      ));

      toast({
        title: 'Success',
        description: 'Message updated',
      });
    } catch (error) {
      console.error('Failed to edit message:', error);
      toast({
        title: 'Error',
        description: 'Failed to edit message',
        variant: 'destructive',
      });
    }
  }, [activeChat, toast]);

  // Update group name
  const updateGroupName = useCallback(async (chatId: string, newName: string) => {
    try {
      await chatService.updateGroupName(chatId, newName);
      setChats(prev => prev.map(chat =>
        chat.id === chatId ? { ...chat, name: newName } : chat
      ));
      if (activeChat?.id === chatId) {
        setActiveChat(prev => prev ? { ...prev, name: newName } : null);
      }
      toast({
        title: 'Success',
        description: 'Group name updated',
      });
    } catch (error) {
      console.error('Failed to update group name:', error);
      toast({
        title: 'Error',
        description: 'Failed to update group name',
        variant: 'destructive',
      });
    }
  }, [activeChat, toast]);

  // Delete group
  const deleteGroup = useCallback(async (chatId: string) => {
    try {
      await chatService.deleteGroup(chatId);
      setChats(prev => prev.filter(chat => chat.id !== chatId));
      if (activeChat?.id === chatId) {
        setActiveChat(null);
      }
      toast({
        title: 'Success',
        description: 'Group deleted',
      });
    } catch (error) {
      console.error('Failed to delete group:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete group',
        variant: 'destructive',
      });
    }
  }, [activeChat, toast]);

  // Add participants
  const addParticipants = useCallback(async (chatId: string, userIds: string[]) => {
    try {
      await chatService.addParticipants(chatId, userIds);
      loadChats(); // Reload to get updated member list
      toast({
        title: 'Success',
        description: `Added ${userIds.length} members`,
      });
    } catch (error) {
      console.error('Failed to add participants:', error);
      toast({
        title: 'Error',
        description: 'Failed to add participants',
        variant: 'destructive',
      });
    }
  }, [loadChats, toast]);

  // Remove participants
  const removeParticipants = useCallback(async (chatId: string, userIds: string[]) => {
    try {
      await chatService.removeParticipant(chatId, userIds);
      loadChats(); // Reload to get updated member list
      toast({
        title: 'Success',
        description: `Removed ${userIds.length} members`,
      });
    } catch (error) {
      console.error('Failed to remove participants:', error);
      toast({
        title: 'Error',
        description: 'Failed to remove participants',
        variant: 'destructive',
      });
    }
  }, [loadChats, toast]);

  // Handle active chat change
  const handleSetActiveChat = useCallback((chat: Chat | null) => {
    setActiveChat(chat);
    if (chat) {
      loadMessages(chat.id, chat.type);
    } else {
      setMessages([]);
    }
  }, [loadMessages]);

  useEffect(() => {
    if (user) {
      loadChats();
      loadAvailableUsers();
    }
  }, [user, loadChats, loadAvailableUsers]);

  const value = {
    chats,
    activeChat,
    messages,
    availableUsers,
    isLoading,
    unreadCount,
    setActiveChat: handleSetActiveChat,
    sendMessage,
    createChat,
    loadChats,
    loadMessages,
    loadAvailableUsers,
    markAsRead,
    deleteMessage,
    editMessage,
    sendTyping,
    updateGroupName,
    deleteGroup,
    addParticipants,
    removeParticipants
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
};

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

// Safe version that returns null if provider is not available
export const useChatSafe = () => {
  const context = useContext(ChatContext);
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { isSameDay } from 'date-fns';
import { apiService } from '@/lib/api';
import { useAuth } from './AuthContext';

export interface Holiday {
  id?: number;
  date: Date;
  name: string;
  description?: string;
  is_recurring?: boolean;
  created_at?: string;
  updated_at?: string;
}

interface HolidayContextType {
  holidays: Holiday[];
  addHoliday: (holiday: Omit<Holiday, 'id' | 'created_at' | 'updated_at'>) => Promise<void>;
  removeHoliday: (id: number) => Promise<void>;
  updateHoliday: (id: number, holiday: Partial<Omit<Holiday, 'id' | 'created_at' | 'updated_at'>>) => Promise<void>;
  isHoliday: (date: Date) => boolean;
  getHolidayName: (date: Date) => string | undefined;
  refreshHolidays: () => Promise<void>;
  isLoading: boolean;
  error: string | null;
}

const HolidayContext = createContext<HolidayContextType | undefined>(undefined);

export const HolidayProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [holidays, setHolidays] = useState<Holiday[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Fetch holidays from backend - always fetch from backend, never use localStorage
  const fetchHolidays = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);
      const response = await apiService.getHolidays();
      
      // Convert API response to Holiday objects
      const convertedHolidays: Holiday[] = response.map((h: any) => ({
        id: h.id,
        date: new Date(h.date),
        name: h.name,
        description: h.description || '',
        is_recurring: h.is_recurring ?? false,
        created_at: h.created_at,
        updated_at: h.updated_at || undefined,
      }));
      
      // Remove duplicates by date - keep the first occurrence (by ID if available)
      const uniqueHolidays = convertedHolidays.reduce((acc: Holiday[], current) => {
        const existingIndex = acc.findIndex(h => isSameDay(h.date, current.date));
        if (existingIndex === -1) {
          // No duplicate found, add it
          acc.push(current);
        } else {
          // Duplicate found - keep the one with the lower ID (older/primary record)
          const existing = acc[existingIndex];
          if (current.id && existing.id && current.id < existing.id) {
            acc[existingIndex] = current;
          }
        }
        return acc;
      }, []);
      
      setHolidays(uniqueHolidays);
    } catch (err) {
      console.error('Failed to fetch holidays:', err);
      setError('Failed to fetch holidays from server');
      // Fallback to empty array if API fails - never use localStorage
      setHolidays([]);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Initial load on mount
  useEffect(() => {
    fetchHolidays();
  }, [fetchHolidays]);

  const addHoliday = useCallback(async (holiday: Omit<Holiday, 'id' | 'created_at' | 'updated_at'>) => {
    try {
      setError(null);
      
      // Check if user is admin
      if (user?.role !== 'admin') {
        throw new Error('Only administrators can add holidays.');
      }
      
      // Check if holiday already exists for this date (both in local state and backend)
      const existingHoliday = holidays.find(h => isSameDay(h.date, holiday.date));
      if (existingHoliday) {
        throw new Error(`A holiday "${existingHoliday.name}" already exists for this date.`);
      }

      // Format date as ISO string (YYYY-MM-DD) for API
      const dateStr = holiday.date.toISOString().split('T')[0];
      
      // Prepare data for API - ensure all required fields are present
      const holidayData = {
        date: dateStr,
        name: holiday.name.trim(),
        description: holiday.description?.trim() || '',
        is_recurring: holiday.is_recurring ?? false,
      };
      
      const response = await apiService.createHoliday(holidayData);

      // Refresh holidays from backend to ensure consistency and avoid duplicates
      await fetchHolidays();
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Failed to add holiday';
      setError(errorMsg);
      throw err;
    }
  }, [holidays, user?.role, fetchHolidays]);

  const removeHoliday = useCallback(async (id: number) => {
    try {
      setError(null);
      
      // Check if user is admin
      if (user?.role !== 'admin') {
        throw new Error('Only administrators can remove holidays.');
      }
      
      await apiService.deleteHoliday(id);
      
      // Refresh holidays from backend to ensure consistency
      await fetchHolidays();
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Failed to remove holiday';
      setError(errorMsg);
      throw err;
    }
  }, [user?.role, fetchHolidays]);

  const updateHoliday = useCallback(async (id: number, updates: Partial<Omit<Holiday, 'id' | 'created_at' | 'updated_at'>>) => {
    try {
      setError(null);
      
      // Check if user is admin
      if (user?.role !== 'admin') {
        throw new Error('Only administrators can update holidays.');
      }
      
      // Check for duplicate date if date is being updated
      if (updates.date) {
        const existingHoliday = holidays.find(h => h.id !== id && isSameDay(h.date, updates.date!));
        if (existingHoliday) {
          throw new Error(`A holiday "${existingHoliday.name}" already exists for this date.`);
        }
      }
      
      const updateData: any = {};
      if (updates.date) {
        updateData.date = updates.date.toISOString().split('T')[0];
      }
      if (updates.name) {
        updateData.name = updates.name;
      }
      if (updates.description !== undefined) {
        updateData.description = updates.description;
      }
      if (updates.is_recurring !== undefined) {
        updateData.is_recurring = updates.is_recurring;
      }

      await apiService.updateHoliday(id, updateData);

      // Refresh holidays from backend to ensure consistency
      await fetchHolidays();
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Failed to update holiday';
      setError(errorMsg);
      throw err;
    }
  }, [holidays, user?.role, fetchHolidays]);

  const isHoliday = (date: Date): boolean => {
    return holidays.some(h => isSameDay(h.date, date));
  };

  const getHolidayName = (date: Date): string | undefined => {
    const holiday = holidays.find(h => isSameDay(h.date, date));
    return holiday?.name;
  };

  const refreshHolidays = useCallback(async () => {
    await fetchHolidays();
  }, [fetchHolidays]);

  return (
    <HolidayContext.Provider
      value={{
        holidays,
        addHoliday,
        removeHoliday,
        updateHoliday,
        isHoliday,
        getHolidayName,
        refreshHolidays,
        isLoading,
        error,
      }}
    >
      {children}
    </HolidayContext.Provider>
  );
};

export const useHolidays = () => {
  const context = useContext(HolidayContext);
  if (!context) {
    throw new Error('useHolidays must be used within a HolidayProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { translations, Language, TranslationKey } from '@/i18n/translations';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: TranslationKey;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<Language>(() => {
    // Try to get user-specific language preference first
    const userId = localStorage.getItem('userId');
    if (userId) {
      const userLangKey = `language_${userId}`;
      const userSaved = localStorage.getItem(userLangKey);
      if (userSaved) {
        return (userSaved as Language);
      }
    }
    
    // Fallback to global language preference
    const saved = localStorage.getItem('language');
    return (saved as Language) || 'en';
  });

  useEffect(() => {
    // Save language preference for specific user if available
    const userId = localStorage.getItem('userId');
    if (userId) {
      const userLangKey = `language_${userId}`;
      localStorage.setItem(userLangKey, language);
    }
    
    // Also save global preference as fallback
    localStorage.setItem('language', language);
    document.documentElement.lang = language;
  }, [language]);

  // Update language when user changes (login/logout)
  useEffect(() => {
    const handleStorageChange = () => {
      const userId = localStorage.getItem('userId');
      if (userId) {
        const userLangKey = `language_${userId}`;
        const userSaved = localStorage.getItem(userLangKey);
        if (userSaved && userSaved !== language) {
          setLanguage(userSaved as Language);
        }
      }
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, [language]);

  const value = {
    language,
    setLanguage,
    t: translations[language],
  };

  return <LanguageContext.Provider value={value}>{children}</LanguageContext.Provider>;
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { useAuth } from './AuthContext';
import { apiService } from '@/lib/api';

export interface LeaveBalance {
  annual: { allocated: number; used: number; remaining: number };
  sick: { allocated: number; used: number; remaining: number };
  casual: { allocated: number; used: number; remaining: number };
  unpaid: { allocated: number; used: number; remaining: number };
}

interface LeaveBalanceContextType {
  leaveBalance: LeaveBalance;
  loadLeaveBalance: () => Promise<void>;
  isLoading: boolean;
}

const LeaveBalanceContext = createContext<LeaveBalanceContextType | undefined>(undefined);

const initialBalance: LeaveBalance = {
  annual: { allocated: 0, used: 0, remaining: 0 },
  sick: { allocated: 0, used: 0, remaining: 0 },
  casual: { allocated: 0, used: 0, remaining: 0 },
  unpaid: { allocated: 0, used: 0, remaining: 0 },
};

export const LeaveBalanceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();

  // Initialize from localStorage if available to prevent 0 flicker on refresh
  const [leaveBalance, setLeaveBalance] = useState<LeaveBalance>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('leaveBalance');
      if (stored) {
        try {
          return JSON.parse(stored);
        } catch (e) {
          console.error('Failed to parse leave balance from storage', e);
        }
      }
    }
    return initialBalance;
  });

  const [isLoading, setIsLoading] = useState(false);

  const loadLeaveBalance = useCallback(async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      // Fetch balance and try multiple allocation endpoints in parallel
      // We attempt to fetch for all roles because some managers/leads might have permission,
      // and we catch errors silently to avoid UI disruption.
      let currentConfig = null;
      let genericConfig = null;

      const balanceResponse = await apiService.getLeaveBalance();

      try {
        [currentConfig, genericConfig] = await Promise.all([
          apiService.getCurrentLeaveAllocation().catch(() => null),
          apiService.getLeaveAllocationConfig().catch(() => null)
        ]);
      } catch (e) {
        // Silently skip if endpoints are restricted
      }

      // Use whichever config is available - handle both object and array responses
      let allocationConfig = currentConfig || genericConfig;
      if (Array.isArray(allocationConfig)) {
        allocationConfig = allocationConfig[0];
      }

      const defaults: LeaveBalance = {
        annual: { allocated: 0, used: 0, remaining: 0 },
        sick: { allocated: 0, used: 0, remaining: 0 },
        casual: { allocated: 0, used: 0, remaining: 0 },
        unpaid: { allocated: 0, used: 0, remaining: 0 },
      };

      let unpaidCount = 0;

      if (balanceResponse && balanceResponse.balances) {
        balanceResponse.balances.forEach((item: any) => {
          // Normalize leave type key
          let key = item.leave_type.toLowerCase().trim();

          if (key.includes('sick')) key = 'sick';
          else if (key.includes('casual')) key = 'casual';
          else if (key.includes('annual') || key.includes('privilege')) key = 'annual';
          else if (key.includes('unpaid') || key.includes('loss of pay')) key = 'unpaid';

          if (key === 'unpaid') {
            unpaidCount = Number(item.used) || 0;
          } else if (key in defaults) {
            defaults[key as keyof typeof defaults] = {
              allocated: Number(item.allocated) || 0,
              used: Number(item.used) || 0,
              // We'll recompute remaining below to avoid negative values / drift
              remaining: 0,
            };
          }
        });
      }

      defaults.unpaid = {
        allocated: 0,
        used: unpaidCount,
        remaining: 0,
      };

      // Apply global allocation config if available (Admin's settings)
      // Allocation config is the source of truth for allocated values
      // Balance API is the source of truth for used/remaining values
      if (allocationConfig) {
        // Handle potential snake_case or camelCase
        const sickAlloc = allocationConfig.sick_leave_allocation ?? allocationConfig.sickLeaveAllocation;
        const casualAlloc = allocationConfig.casual_leave_allocation ?? allocationConfig.casualLeaveAllocation;
        const totalAlloc = allocationConfig.total_annual_leave ?? allocationConfig.totalAnnualLeave;

        // Always use allocation config for allocated values (if provided)
        // This ensures consistency with admin-configured allocations
        if (sickAlloc != null) {
          defaults.sick.allocated = Number(sickAlloc) || 0;
        }

        if (casualAlloc != null) {
          defaults.casual.allocated = Number(casualAlloc) || 0;
        }

        if (totalAlloc != null) {
          // Set annual leave allocation from config
          // The effective "Total Leaves" will be recomputed from sick+annual below
          defaults.annual.allocated = Number(totalAlloc) || 0;
        }
      }

      // Normalise and prevent negative balances for paid leave types
      (['annual', 'sick', 'casual'] as const).forEach((key) => {
        const alloc = Math.max(0, defaults[key].allocated);
        const used = Math.max(0, defaults[key].used);
        const remaining = Math.max(0, alloc - used);
        defaults[key] = { allocated: alloc, used, remaining };
      });

      // Unpaid leave: track only "days taken" and never deduct from paid balances
      defaults.unpaid = {
        allocated: 0,
        used: Math.max(0, unpaidCount),
        remaining: 0,
      };

      // Calculate Total Leaves from config or balance
      // If we have an allocation config, total_annual_leave is the authoritative sum
      // Otherwise fallback to summing specific categories from balance
      const totalAllocated = allocationConfig
        ? (Number(allocationConfig.total_annual_leave ?? allocationConfig.totalAnnualLeave) || 0)
        : (defaults.sick.allocated + defaults.annual.allocated + defaults.casual.allocated);

      const totalUsed = defaults.sick.used + defaults.annual.used + defaults.casual.used;
      const totalRemaining = Math.max(0, totalAllocated - totalUsed);

      defaults.annual = {
        allocated: totalAllocated,
        used: totalUsed,
        remaining: totalRemaining,
      };

      setLeaveBalance(defaults);
      localStorage.setItem('leaveBalance', JSON.stringify(defaults));
    } catch (error) {
      console.error('Error fetching leave balance:', error);
    } finally {
      setIsLoading(false);
    }
  }, [user]);

  // Load balance when user changes or initially
  useEffect(() => {
    if (user) {
      loadLeaveBalance();
    } else {
      // Clear balance if user logs out
      setLeaveBalance(initialBalance);
      localStorage.removeItem('leaveBalance');
    }
  }, [user, loadLeaveBalance]);

  return (
    <LeaveBalanceContext.Provider value={{ leaveBalance, loadLeaveBalance, isLoading }}>
      {children}
    </LeaveBalanceContext.Provider>
  );
};

export const useLeaveBalance = () => {
  const context = useContext(LeaveBalanceContext);
  if (!context) {
    throw new Error('useLeaveBalance must be used within LeaveBalanceProvider');
  }
  return context;
};

/* eslint-disable react-refresh/only-export-components */
import React, { createContext, useContext, useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useAuth } from './AuthContext';
import { API_BASE_URL } from '@/lib/api';
// Polling disabled - only fetch on app init/auth
const FETCH_INTERVAL_MS = 0; // Disabled
const POLLING_IDLE_TIMEOUT_MS = 10 * 60_000; // 10 minutes idle timeout
const RETRY_DELAY_MS = 10_000; // Retry after 10 seconds on failure
const MIN_FETCH_INTERVAL_MS = 30_000; // Minimum 30 seconds between fetches (except manual refresh)

export interface Notification {
  id: string;
  userId: string;
  title: string;
  message: string;
  type: 'leave' | 'task' | 'info' | 'warning' | 'shift';
  read: boolean;
  actionUrl?: string;
  createdAt: string;
  metadata?: {
    leaveId?: string;
    taskId?: string;
    requesterId?: string;
    requesterName?: string;
    shiftAssignmentId?: string;
  };
  backendId?: number;
  passDetails?: {
    from?: string;
    to?: string;
    note?: string;
  };
}

// Debug logging helper
const debugLog = (message: string, data?: unknown) => {
  // Disabled to keep console clean. Enable only for debugging notifications.
  if (import.meta.env.DEV && false) {
    console.log(`[NotificationContext] ${message}`, data !== undefined ? data : '');
  }
};

interface NotificationContextType {
  notifications: Notification[];
  unreadCount: number;
  isLoading: boolean;
  error: string | null;
  addNotification: (notification: Omit<Notification, 'id' | 'userId' | 'createdAt' | 'read'>) => void;
  markAsRead: (notificationId: string) => Promise<void>;
  markAllAsRead: () => Promise<void>;
  clearNotification: (notificationId: string) => void;
  clearAll: () => void;
  refreshNotifications: () => Promise<void>;
}

const NotificationContext = createContext<NotificationContextType | undefined>(undefined);

type BackendTaskNotification = {
  notification_id: number;
  user_id: number;
  task_id: number;
  notification_type: string;
  title: string;
  message: string;
  pass_details: string | {
    from?: number;
    to?: number;
    note?: string;
  } | null;
  is_read: boolean;
  created_at: string;
};

type BackendLeaveNotification = {
  notification_id: number;
  user_id: number;
  leave_id: number;
  notification_type: string;
  title: string;
  message: string;
  is_read: boolean;
  created_at: string;
};



type BackendShiftNotification = {
  notification_id: number;
  user_id: number;
  shift_assignment_id: number;
  notification_type: string;
  title: string;
  message: string;
  is_read: boolean;
  created_at: string;
};

const getAuthHeader = (): string | null => {
  const storedToken = localStorage.getItem('token') || '';
  if (!storedToken) return null;
  return storedToken.startsWith('Bearer ') ? storedToken : `Bearer ${storedToken}`;
};

export const NotificationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const audioRef = useRef<{ play: () => void } | null>(null);
  const pollIntervalRef = useRef<number | null>(null);
  const pollIdleTimeoutRef = useRef<number | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const retryTimeoutRef = useRef<number | null>(null);
  const lastFetchRef = useRef<number>(0);
  const previousUnreadCountRef = useRef<number>(0);
  const isFetchingRef = useRef<boolean>(false); // Prevent concurrent fetches
  const initialFetchDoneRef = useRef<boolean>(false); // Track if initial fetch is done

  // Check if notifications are enabled
  const areNotificationsEnabled = () => {
    const stored = localStorage.getItem('notificationsEnabled');
    return stored === null ? true : stored === 'true';
  };

  // Load notifications from localStorage on mount
  useEffect(() => {
    if (!user) {
      setNotifications([]);
      return;
    }

    const stored = localStorage.getItem(`notifications_${user.id}`);
    if (stored) {
      try {
        const parsed: Notification[] = JSON.parse(stored);
        debugLog('Loaded notifications from localStorage:', parsed.length);
        setNotifications(parsed);
      } catch (error) {
        console.error('Failed to parse stored notifications', error);
        localStorage.removeItem(`notifications_${user.id}`);
        setNotifications([]);
      }
    } else {
      debugLog('No stored notifications found');
      setNotifications([]);
    }
  }, [user?.id]);

  // Save notifications to localStorage
  useEffect(() => {
    if (!user) return;

    const localNotifications = notifications.filter((notification) => !notification.backendId);

    if (localNotifications.length > 0) {
      localStorage.setItem(`notifications_${user.id}`, JSON.stringify(localNotifications));
    } else {
      localStorage.removeItem(`notifications_${user.id}`);
    }
  }, [notifications, user]);

  // Initialize notification sound
  useEffect(() => {
    // Create a simple notification sound using Web Audio API
    const createNotificationSound = () => {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      const oscillator = audioContext.createOscillator();
      const gainNode = audioContext.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(audioContext.destination);

      oscillator.frequency.value = 800;
      oscillator.type = 'sine';

      gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.5);

      oscillator.start(audioContext.currentTime);
      oscillator.stop(audioContext.currentTime + 0.5);
    };

    audioRef.current = {
      play: createNotificationSound,
    };
  }, []);

  const playNotificationSound = useCallback(() => {
    try {
      if (audioRef.current) {
        audioRef.current.play();
      }
    } catch (error) {
      console.error('Error playing notification sound:', error);
    }
  }, []);

  const mapBackendTaskNotification = useCallback((notification: BackendTaskNotification, currentUserId?: string): Notification | null => {
    // Parse pass_details - can be string (JSON) or object
    let passDetails: { from?: number; to?: number; note?: string } | null = null;

    if (notification.pass_details) {
      if (typeof notification.pass_details === 'string') {
        try {
          passDetails = JSON.parse(notification.pass_details);
        } catch (error) {
          console.error('Failed to parse task pass details', error);
          passDetails = null;
        }
      } else if (typeof notification.pass_details === 'object' && notification.pass_details !== null) {
        // Already an object, use it directly
        passDetails = notification.pass_details;
      }
    }

    const fromValue = passDetails?.from;
    const toValue = passDetails?.to;
    const noteValue = passDetails?.note;

    // ✅ Filter: only show notifications for the current user
    const notificationUserId = String(notification.user_id);
    if (currentUserId && notificationUserId !== currentUserId) {
      // This notification is not for the current user, filter it out
      debugLog('Filtering out task notification - not for current user', { notificationUserId, currentUserId });
      return null;
    }

    // ✅ Filter: Don't show if user assigned task to themselves (from === to === user_id)
    // But still show if user received task from someone else (from !== user_id, to === user_id)
    if (fromValue !== undefined && toValue !== undefined &&
      String(fromValue) === notificationUserId && String(toValue) === notificationUserId) {
      debugLog('Filtering out task notification - self-assigned task', { fromValue, toValue, notificationUserId });
      return null;
    }

    debugLog('Mapping task notification', {
      id: notification.notification_id,
      title: notification.title,
      is_read: notification.is_read,
      from: fromValue,
      to: toValue
    });

    return {
      id: `backend-task-${notification.notification_id}`,
      backendId: notification.notification_id,
      userId: notificationUserId,
      title: notification.title,
      message: notification.message,
      type: 'task',
      read: notification.is_read,
      createdAt: notification.created_at,
      metadata: {
        taskId: String(notification.task_id),
        requesterId: fromValue !== undefined ? String(fromValue) : undefined,
      },
      passDetails: {
        from: fromValue !== undefined ? String(fromValue) : undefined,
        to: toValue !== undefined ? String(toValue) : undefined,
        note: typeof noteValue === 'string' ? noteValue : undefined,
      },
    };
  }, []);

  const mapBackendLeaveNotification = useCallback((notification: BackendLeaveNotification, currentUserId?: string): Notification | null => {
    // ✅ Filter out self-notifications: only show if the notification is for the current user
    const notificationUserId = String(notification.user_id);
    if (currentUserId && notificationUserId !== currentUserId) {
      // This notification is not for the current user, filter it out
      debugLog('Filtering out leave notification - not for current user', { notificationUserId, currentUserId });
      return null;
    }

    debugLog('Mapping leave notification', { id: notification.notification_id, title: notification.title, is_read: notification.is_read });

    return {
      id: `backend-leave-${notification.notification_id}`,
      backendId: notification.notification_id,
      userId: notificationUserId,
      title: notification.title,
      message: notification.message,
      type: 'leave',
      read: notification.is_read,
      createdAt: notification.created_at,
      metadata: {
        leaveId: String(notification.leave_id),
      },
    };
  }, []);

  const mapBackendShiftNotification = useCallback((notification: BackendShiftNotification, userRole?: string, currentUserId?: string): Notification | null => {
    // ✅ Filter out self-notifications: only show if the notification is for the current user
    const notificationUserId = String(notification.user_id);
    if (currentUserId && notificationUserId !== currentUserId) {
      // This notification is not for the current user, filter it out
      debugLog('Filtering out shift notification - not for current user', { notificationUserId, currentUserId });
      return null;
    }

    // Determine the team page route based on user role
    let teamRoute = '/employee/team';
    if (userRole === 'team_lead') {
      teamRoute = '/team_lead/team';
    } else if (userRole === 'employee') {
      teamRoute = '/employee/team';
    }

    debugLog('Mapping shift notification', { id: notification.notification_id, title: notification.title, is_read: notification.is_read });

    return {
      id: `backend-shift-${notification.notification_id}`,
      backendId: notification.notification_id,
      userId: notificationUserId,
      title: notification.title,
      message: notification.message,
      type: 'shift',
      read: notification.is_read,
      createdAt: notification.created_at,
      actionUrl: teamRoute,
      metadata: {
        shiftAssignmentId: String(notification.shift_assignment_id),
      },
    };
  }, []);

  const stopPolling = useCallback(() => {
    if (pollIntervalRef.current) {
      window.clearInterval(pollIntervalRef.current);
      pollIntervalRef.current = null;
    }
    if (pollIdleTimeoutRef.current) {
      window.clearTimeout(pollIdleTimeoutRef.current);
      pollIdleTimeoutRef.current = null;
    }
    if (retryTimeoutRef.current) {
      window.clearTimeout(retryTimeoutRef.current);
      retryTimeoutRef.current = null;
    }
  }, []);

  const fetchBackendNotifications = useCallback(async (isManualRefresh = false) => {
    if (!user) {
      debugLog('No user, skipping fetch');
      return;
    }

    // Check if notifications are enabled
    if (!areNotificationsEnabled()) {
      debugLog('Notifications disabled, skipping fetch');
      return;
    }

    const authHeader = getAuthHeader();
    if (!authHeader) {
      debugLog('No auth header, stopping polling');
      stopPolling();
      return;
    }

    // ✅ Validate token exists and is not empty
    const token = localStorage.getItem('token');
    if (!token || token.trim() === '') {
      debugLog('No token, stopping polling');
      stopPolling();
      return;
    }

    // ✅ CRITICAL: Prevent concurrent fetches - only one request at a time
    if (isFetchingRef.current) {
      debugLog('Fetch already in progress, skipping');
      return;
    }

    // Prevent too frequent fetches (minimum 30 seconds between fetches, except for manual refresh)
    const now = Date.now();
    const timeSinceLastFetch = now - lastFetchRef.current;
    if (!isManualRefresh && timeSinceLastFetch < MIN_FETCH_INTERVAL_MS) {
      debugLog(`Fetch throttled, ${Math.round((MIN_FETCH_INTERVAL_MS - timeSinceLastFetch) / 1000)}s remaining`);
      return;
    }

    // Mark as fetching
    isFetchingRef.current = true;
    lastFetchRef.current = now;

    // Cancel previous request if still pending (shouldn't happen with isFetchingRef check)
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    if (isManualRefresh) {
      setIsLoading(true);
    }
    setError(null);

    debugLog('Fetching notifications from API...');

    try {
      const [taskResult, leaveResult, shiftResult] = await Promise.allSettled([
        fetch(`${API_BASE_URL}/tasks/notifications`, {
          headers: {
            Authorization: authHeader,
          },
          signal,
        }).catch(err => {
          // Silently handle network errors and aborts
          if (import.meta.env.DEV && err.name !== 'AbortError') {
            console.warn('Task notifications fetch failed:', err.message);
          }
          return { ok: false, status: 0 } as Response;
        }),
        fetch(`${API_BASE_URL}/leave/notifications`, {
          headers: {
            Authorization: authHeader,
          },
          signal,
        }).catch(err => {
          // Silently handle network errors and aborts
          if (import.meta.env.DEV && err.name !== 'AbortError') {
            console.warn('Leave notifications fetch failed:', err.message);
          }
          return { ok: false, status: 0 } as Response;
        }),
        fetch(`${API_BASE_URL}/shift/notifications`, {
          headers: {
            Authorization: authHeader,
          },
          signal,
        }).catch(err => {
          // Silently handle network errors and aborts
          if (import.meta.env.DEV && err.name !== 'AbortError') {
            console.warn('Shift notifications fetch failed:', err.message);
          }
          return { ok: false, status: 0 } as Response;
        }),
      ]);

      // Check for 401 errors — just stop polling, never redirect.
      // Route guards in AuthContext handle session expiry redirects.
      const has401 =
        (taskResult.status === 'fulfilled' && taskResult.value.status === 401) ||
        (leaveResult.status === 'fulfilled' && leaveResult.value.status === 401) ||
        (shiftResult.status === 'fulfilled' && shiftResult.value.status === 401);

      if (has401) {
        console.warn('Notification polling: received 401, stopping polling silently');
        stopPolling();
        return;
      }


      const taskData: BackendTaskNotification[] = [];
      const leaveData: BackendLeaveNotification[] = [];
      const shiftData: BackendShiftNotification[] = [];

      // Handle task notifications
      if (taskResult.status === 'fulfilled' && taskResult.value.ok) {
        try {
          const data = await taskResult.value.json();
          debugLog('Task notifications API response:', data);

          // API returns direct array: [{ notification_id, user_id, task_id, ... }]
          if (Array.isArray(data)) {
            // Validate each item has required fields before adding
            const validNotifications = data.filter((item: unknown) =>
              item &&
              typeof item === 'object' &&
              'notification_id' in item &&
              'user_id' in item &&
              'task_id' in item &&
              'is_read' in item
            );
            taskData.push(...validNotifications as BackendTaskNotification[]);
          } else if (data && typeof data === 'object') {
            // Handle wrapped responses (fallback)
            if (Array.isArray(data.notifications)) {
              taskData.push(...(data.notifications as BackendTaskNotification[]));
            } else if (Array.isArray(data.data)) {
              taskData.push(...(data.data as BackendTaskNotification[]));
            }
          }
          debugLog('Parsed task notifications:', taskData.length);
        } catch (error) {
          // Silently handle parse errors and aborts
          if (import.meta.env.DEV && !(error instanceof Error && error.name === 'AbortError')) {
            console.error('Failed to parse task notifications', error);
          }
        }
      } else if (taskResult.status === 'rejected') {
        // Silently handle network errors and aborts for notifications
        if (import.meta.env.DEV && taskResult.reason?.name !== 'AbortError' && !taskResult.reason?.message?.includes('fetch')) {
          console.error('Failed to fetch task notifications:', taskResult.reason);
        }
      } else if (taskResult.status === 'fulfilled') {
        debugLog('Task notifications API returned non-OK status:', taskResult.value.status);
      }

      // Handle leave notifications
      if (leaveResult.status === 'fulfilled' && leaveResult.value.ok) {
        try {
          const data = await leaveResult.value.json();
          debugLog('Leave notifications API response:', data);

          // API returns direct array: [{ notification_id, user_id, leave_id, ... }]
          if (Array.isArray(data)) {
            // Validate each item has required fields before adding
            const validNotifications = data.filter((item: unknown) =>
              item &&
              typeof item === 'object' &&
              'notification_id' in item &&
              'user_id' in item &&
              'leave_id' in item &&
              'is_read' in item
            );
            leaveData.push(...validNotifications as BackendLeaveNotification[]);
          } else if (data && typeof data === 'object') {
            // Handle wrapped responses (fallback)
            if (Array.isArray(data.notifications)) {
              leaveData.push(...(data.notifications as BackendLeaveNotification[]));
            } else if (Array.isArray(data.data)) {
              leaveData.push(...(data.data as BackendLeaveNotification[]));
            }
          }
          debugLog('Parsed leave notifications:', leaveData.length);
        } catch (error) {
          // Silently handle parse errors and aborts
          if (import.meta.env.DEV && !(error instanceof Error && error.name === 'AbortError')) {
            console.error('Failed to parse leave notifications', error);
          }
        }
      } else if (leaveResult.status === 'rejected') {
        // Silently handle network errors and aborts for notifications
        if (import.meta.env.DEV && leaveResult.reason?.name !== 'AbortError' && !leaveResult.reason?.message?.includes('fetch')) {
          console.error('Failed to fetch leave notifications:', leaveResult.reason);
        }
      } else if (leaveResult.status === 'fulfilled') {
        debugLog('Leave notifications API returned non-OK status:', leaveResult.value.status);
      }

      // Handle shift notifications
      if (shiftResult.status === 'fulfilled' && shiftResult.value.ok) {
        try {
          const data = await shiftResult.value.json();
          debugLog('Shift notifications API response:', data);
          // Handle both array and object responses
          if (Array.isArray(data)) {
            shiftData.push(...data);
          } else if (data && typeof data === 'object') {
            if (Array.isArray(data.notifications)) {
              shiftData.push(...data.notifications);
            } else if (Array.isArray(data.data)) {
              shiftData.push(...data.data);
            }
          }
          debugLog('Parsed shift notifications:', shiftData);
        } catch (error) {
          // Silently handle parse errors and aborts
          if (import.meta.env.DEV && !(error instanceof Error && error.name === 'AbortError')) {
            console.error('Failed to parse shift notifications', error);
          }
        }
      } else if (shiftResult.status === 'rejected') {
        // Silently handle network errors and aborts for notifications
        if (import.meta.env.DEV && shiftResult.reason?.name !== 'AbortError' && !shiftResult.reason?.message?.includes('fetch')) {
          console.error('Failed to fetch shift notifications:', shiftResult.reason);
        }
      } else if (shiftResult.status === 'fulfilled') {
        debugLog('Shift notifications API returned non-OK status:', shiftResult.value.status);
      }

      // Map all notifications (including read ones for history)
      const backendNotifications = [
        ...taskData
          .map(n => mapBackendTaskNotification(n, user.id))
          .filter((n): n is Notification => n !== null),
        ...leaveData
          .map(n => mapBackendLeaveNotification(n, user.id))
          .filter((n): n is Notification => n !== null),
        ...shiftData
          .map(n => mapBackendShiftNotification(n, user.role, user.id))
          .filter((n): n is Notification => n !== null),
      ];

      // Get dismissed notification IDs from localStorage to filter them out
      const dismissedKey = `dismissed_notifications_${user.id}`;
      const dismissedIds = new Set<string>(
        JSON.parse(localStorage.getItem(dismissedKey) || '[]') as string[]
      );

      // Filter out dismissed notifications
      const filteredBackendNotifications = backendNotifications.filter((notification) => {
        if (notification.backendId) {
          return !dismissedIds.has(String(notification.backendId));
        }
        return true; // Keep local notifications without backend IDs
      });

      debugLog('Total backend notifications mapped:', backendNotifications.length);
      debugLog('Filtered dismissed notifications:', backendNotifications.length - filteredBackendNotifications.length);
      debugLog('Backend notifications after filtering:', filteredBackendNotifications.length);

      setNotifications((prev) => {
        const localOnly = prev.filter((notification) => !notification.backendId);
        const combined = [...filteredBackendNotifications, ...localOnly];
        const uniqueById = new Map<string, Notification>();
        combined.forEach((notification) => {
          if (!uniqueById.has(notification.id)) {
            uniqueById.set(notification.id, notification);
          }
        });
        const sortedNotifications = Array.from(uniqueById.values()).sort(
          (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
        );

        debugLog('Final notifications count:', sortedNotifications.length);
        debugLog('Unread count:', sortedNotifications.filter(n => !n.read).length);

        // Check for new unread notifications and play sound
        const newUnreadCount = sortedNotifications.filter(n => !n.read).length;
        if (newUnreadCount > previousUnreadCountRef.current && previousUnreadCountRef.current > 0) {
          playNotificationSound();
        }
        previousUnreadCountRef.current = newUnreadCount;

        return sortedNotifications;
      });

      // Clear any retry timeout on success
      if (retryTimeoutRef.current) {
        window.clearTimeout(retryTimeoutRef.current);
        retryTimeoutRef.current = null;
      }
    } catch (error) {
      // Only set error for non-abort errors
      if (error instanceof Error && error.name !== 'AbortError') {
        console.error('Failed to fetch notifications', error);
        setError('Failed to load notifications');

        // Schedule retry on failure
        if (!retryTimeoutRef.current) {
          retryTimeoutRef.current = window.setTimeout(() => {
            retryTimeoutRef.current = null;
            fetchBackendNotifications();
          }, RETRY_DELAY_MS);
        }
      }
    } finally {
      // ✅ CRITICAL: Always reset fetching flag
      isFetchingRef.current = false;
      if (isManualRefresh) {
        setIsLoading(false);
      }
    }
  }, [mapBackendLeaveNotification, mapBackendTaskNotification, mapBackendShiftNotification, user, stopPolling, playNotificationSound]);

  const schedulePollingStop = useCallback(() => {
    if (pollIdleTimeoutRef.current) {
      window.clearTimeout(pollIdleTimeoutRef.current);
    }
    pollIdleTimeoutRef.current = window.setTimeout(() => {
      stopPolling();
    }, POLLING_IDLE_TIMEOUT_MS);
  }, [stopPolling]);

  const startPolling = useCallback(() => {
    debugLog('startPolling called', { user: user?.id, visibility: document.visibilityState });

    if (!user || document.visibilityState === 'hidden') {
      debugLog('Stopping polling - no user or hidden');
      stopPolling();
      return;
    }

    // Check if notifications are enabled
    if (!areNotificationsEnabled()) {
      debugLog('Notifications disabled');
      stopPolling();
      return;
    }

    // Check if we have a valid token before starting
    const authHeader = getAuthHeader();
    if (!authHeader) {
      debugLog('No auth header available');
      stopPolling();
      return;
    }

    debugLog('Starting notification polling...');

    // Fetch immediately on start
    debugLog('Fetching notifications immediately on polling start');
    fetchBackendNotifications(true);

    // Set up polling interval only if FETCH_INTERVAL_MS > 0
    if (FETCH_INTERVAL_MS > 0 && !pollIntervalRef.current) {
      debugLog('Setting up polling interval');
      pollIntervalRef.current = window.setInterval(() => {
        debugLog('Polling interval triggered');
        fetchBackendNotifications();
      }, FETCH_INTERVAL_MS);
    } else if (FETCH_INTERVAL_MS === 0) {
      debugLog('Polling disabled - only fetching on demand');
    }

    schedulePollingStop();
  }, [fetchBackendNotifications, schedulePollingStop, stopPolling, user]);

  useEffect(() => {
    debugLog('User effect triggered', { userId: user?.id });

    if (!user) {
      debugLog('No user, stopping polling and resetting state');
      stopPolling();
      initialFetchDoneRef.current = false; // Reset on logout
      isFetchingRef.current = false;
      return;
    }

    // ✅ CRITICAL: Only fetch once on initial login/mount
    if (!initialFetchDoneRef.current) {
      debugLog('User logged in, fetching notifications once (initial fetch)');
      initialFetchDoneRef.current = true;
      fetchBackendNotifications(true);
    } else {
      debugLog('Initial fetch already done, skipping');
    }

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        debugLog('Page became visible, fetching notifications');
        // Use throttled fetch - will be skipped if called too recently
        fetchBackendNotifications(false);
      } else {
        debugLog('Page became hidden');
        stopPolling();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      stopPolling();
      // Abort any pending fetch requests
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
        isFetchingRef.current = false;
      }
    };
  }, [fetchBackendNotifications, stopPolling, user]);

  const addNotification = (notification: Omit<Notification, 'id' | 'userId' | 'createdAt' | 'read'>) => {
    if (!user) return;

    // Check if notifications are enabled
    if (!areNotificationsEnabled()) {
      return;
    }

    // ✅ Prevent self-notifications: check if the requester is the same as the current user
    // For task notifications, check if the requesterId matches the current user
    if (notification.type === 'task' && notification.metadata?.requesterId) {
      if (String(notification.metadata.requesterId) === String(user.id)) {
        // Don't show self-notification for task assignments
        return;
      }
    }

    // ✅ Prevent self-notifications: check if the requester is the same as the current user
    // For leave notifications, check if the requesterId matches the current user
    if (notification.type === 'leave' && notification.metadata?.requesterId) {
      if (String(notification.metadata.requesterId) === String(user.id)) {
        // Don't show self-notification for leave approvals
        return;
      }
    }

    const newNotification: Notification = {
      ...notification,
      id: Date.now().toString(),
      userId: user.id,
      read: false,
      createdAt: new Date().toISOString(),
    };

    setNotifications(prev => [newNotification, ...prev]);
    playNotificationSound();

    // Show browser notification if permitted
    if ('Notification' in window && window.Notification.permission === 'granted') {
      new window.Notification(notification.title, {
        body: notification.message,
        icon: '/favicon.ico',
        badge: '/favicon.ico',
      });
    }
  };

  const markAsRead = useCallback(async (notificationId: string) => {
    let backendId: number | undefined;
    let backendType: Notification['type'] | undefined;

    // Find the notification first
    let targetNotification: Notification | undefined;
    setNotifications((prev) => {
      targetNotification = prev.find(n => n.id === notificationId);
      return prev;
    });

    if (!targetNotification) {
      return;
    }

    backendId = targetNotification.backendId;
    backendType = targetNotification.type;

    // Mark as read in local state
    setNotifications((prev) =>
      prev.map((notif) => {
        if (notif.id === notificationId) {
          return { ...notif, read: true };
        }
        return notif;
      })
    );

    // If it's a local-only notification (no backend ID), we're done
    if (!user || !backendId || !backendType) {
      return;
    }

    const authHeader = getAuthHeader();
    if (!authHeader) {
      return;
    }

    try {
      let endpoint = '';
      if (backendType === 'task') {
        endpoint = `${API_BASE_URL}/tasks/notifications/${backendId}/read`;
      } else if (backendType === 'leave') {
        endpoint = `${API_BASE_URL}/leave/notifications/${backendId}/read`;
      } else if (backendType === 'shift') {
        endpoint = `${API_BASE_URL}/shift/notifications/${backendId}/read`;
      } else {
        return;
      }

      debugLog('Marking notification as read:', { endpoint, notificationId, backendId });

      const response = await fetch(endpoint, {
        method: 'PUT',
        headers: {
          'Authorization': authHeader,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          notification_id: backendId,
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to mark notification as read (${response.status})`);
      }

      debugLog('Successfully marked notification as read:', notificationId);

      // Keep notification in list but marked as read (don't remove it)
      // This allows the UI to update properly without flickering

    } catch (error) {
      console.error('Failed to mark notification as read', error);
      // Revert the read status if backend call failed
      setNotifications((prev) =>
        prev.map((notif) => {
          if (notif.id === notificationId) {
            return { ...notif, read: false };
          }
          return notif;
        })
      );
    }
  }, [user]);

  const markAllAsRead = useCallback(async () => {
    const taskIds: number[] = [];
    const leaveIds: number[] = [];
    const shiftIds: number[] = [];
    const notificationIdsToRemove: string[] = [];

    setNotifications((prev) =>
      prev.map((notif) => {
        if (!notif.read) {
          notificationIdsToRemove.push(notif.id);
          if (notif.backendId) {
            if (notif.type === 'leave') {
              leaveIds.push(notif.backendId);
            } else if (notif.type === 'task') {
              taskIds.push(notif.backendId);
            } else if (notif.type === 'shift') {
              shiftIds.push(notif.backendId);
            }
          }
        }
        if (notif.read) return notif;
        return { ...notif, read: true };
      })
    );

    if (!user || (taskIds.length === 0 && leaveIds.length === 0 && shiftIds.length === 0)) {
      // Still remove local notifications even if no backend IDs
      setTimeout(() => {
        setNotifications((prev) => prev.filter((notif) => !notificationIdsToRemove.includes(notif.id)));
      }, 500);
      return;
    }

    const authHeader = getAuthHeader();
    if (!authHeader) {
      return;
    }

    try {
      await Promise.all([
        ...taskIds.map((id) =>
          fetch(`${API_BASE_URL}/tasks/notifications/${id}/read`, {
            method: 'PUT',
            headers: {
              'Authorization': authHeader,
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              notification_id: id,
            }),
          })
        ),
        ...leaveIds.map((id) =>
          fetch(`${API_BASE_URL}/leave/notifications/${id}/read`, {
            method: 'PUT',
            headers: {
              'Authorization': authHeader,
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              notification_id: id,
            }),
          })
        ),
        ...shiftIds.map((id) =>
          fetch(`${API_BASE_URL}/shift/notifications/${id}/read`, {
            method: 'PUT',
            headers: {
              'Authorization': authHeader,
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              notification_id: id,
            }),
          })
        ),
      ]);

      // After successfully marking all as read, remove them from the list
      setTimeout(() => {
        setNotifications((prev) => prev.filter((notif) => !notificationIdsToRemove.includes(notif.id)));
      }, 500);

    } catch (error) {
      console.error('Failed to mark all notifications as read', error);
      // Revert the read status if backend call failed
      setNotifications((prev) =>
        prev.map((notif) => {
          if (notificationIdsToRemove.includes(notif.id)) {
            return { ...notif, read: false };
          }
          return notif;
        })
      );
      fetchBackendNotifications();
    }
  }, [fetchBackendNotifications, user]);

  const clearNotification = useCallback(async (notificationId: string) => {
    // Find the notification to get backend info
    let targetNotification: Notification | undefined;
    setNotifications((prev) => {
      targetNotification = prev.find(n => n.id === notificationId);
      return prev;
    });

    if (!targetNotification) {
      return;
    }

    // Mark as read in backend FIRST (before removing from UI) to ensure permanent removal
    if (user && targetNotification.backendId && targetNotification.type) {
      const authHeader = getAuthHeader();
      if (authHeader) {
        try {
          let endpoint = '';
          const backendType = targetNotification.type;
          const backendId = targetNotification.backendId;

          if (backendType === 'task') {
            endpoint = `${API_BASE_URL}/tasks/notifications/${backendId}/read`;
          } else if (backendType === 'leave') {
            endpoint = `${API_BASE_URL}/leave/notifications/${backendId}/read`;
          } else if (backendType === 'shift') {
            endpoint = `${API_BASE_URL}/shift/notifications/${backendId}/read`;
          }

          if (endpoint) {
            const response = await fetch(endpoint, {
              method: 'PUT',
              headers: {
                'Authorization': authHeader,
                'Content-Type': 'application/json',
              },
              body: JSON.stringify({
                notification_id: backendId,
              }),
            });

            if (!response.ok) {
              throw new Error(`Failed to mark notification as read (${response.status})`);
            }

            // Only remove from UI after successful backend update
            setNotifications((prev) => prev.filter((notif) => notif.id !== notificationId));

            // Store dismissed notification ID to prevent it from reappearing
            const dismissedKey = `dismissed_notifications_${user.id}`;
            const dismissed = JSON.parse(localStorage.getItem(dismissedKey) || '[]') as string[];
            if (!dismissed.includes(String(targetNotification.backendId))) {
              dismissed.push(String(targetNotification.backendId));
              // Keep only last 1000 dismissed IDs to prevent localStorage from growing too large
              if (dismissed.length > 1000) {
                dismissed.shift(); // Remove oldest
              }
              localStorage.setItem(dismissedKey, JSON.stringify(dismissed));
            }
          } else {
            // No backend ID, just remove from UI (local notification)
            setNotifications((prev) => prev.filter((notif) => notif.id !== notificationId));
          }
        } catch (error) {
          console.error('Failed to mark notification as read when clearing', error);
          // Still remove from UI even if backend call fails - user dismissed it
          setNotifications((prev) => prev.filter((notif) => notif.id !== notificationId));

          // Store dismissed notification ID anyway to prevent reappearing
          if (targetNotification.backendId) {
            const dismissedKey = `dismissed_notifications_${user.id}`;
            const dismissed = JSON.parse(localStorage.getItem(dismissedKey) || '[]') as string[];
            if (!dismissed.includes(String(targetNotification.backendId))) {
              dismissed.push(String(targetNotification.backendId));
              // Keep only last 1000 dismissed IDs to prevent localStorage from growing too large
              if (dismissed.length > 1000) {
                dismissed.shift(); // Remove oldest
              }
              localStorage.setItem(dismissedKey, JSON.stringify(dismissed));
            }
          }
        }
      } else {
        // No auth header, just remove from UI
        setNotifications((prev) => prev.filter((notif) => notif.id !== notificationId));
      }
    } else {
      // No backend ID or user, just remove from UI (local notification)
      setNotifications((prev) => prev.filter((notif) => notif.id !== notificationId));
    }
  }, [user]);

  const clearAll = () => {
    setNotifications([]);
    if (user) {
      localStorage.removeItem(`notifications_${user.id}`);
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  // ✅ CRITICAL: Memoize refreshNotifications to prevent re-renders from creating new function references
  const refreshNotifications = useCallback(() => {
    return fetchBackendNotifications(true);
  }, [fetchBackendNotifications]);

  // ✅ Memoize context value to prevent unnecessary re-renders
  const contextValue = useMemo(() => ({
    notifications,
    unreadCount,
    isLoading,
    error,
    addNotification,
    markAsRead,
    markAllAsRead,
    clearNotification,
    clearAll,
    refreshNotifications,
  }), [notifications, unreadCount, isLoading, error, markAsRead, markAllAsRead, clearNotification, refreshNotifications]);

  return (
    <NotificationContext.Provider value={contextValue}>
      {children}
    </NotificationContext.Provider>
  );
};

export const useNotifications = () => {
  const context = useContext(NotificationContext);
  if (!context) {
    throw new Error('useNotifications must be used within a NotificationProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';

export type ColorTheme = 'default' | 'purple' | 'green' | 'orange' | 'pink' | 'cyan';
export type ThemeMode = 'light' | 'dark' | 'system';

interface ThemeContextType {
  colorTheme: ColorTheme;
  setColorTheme: (theme: ColorTheme) => void;
  themeMode: ThemeMode;
  setThemeMode: (mode: ThemeMode) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [colorTheme, setColorThemeState] = useState<ColorTheme>(() => {
    const saved = localStorage.getItem('userColorTheme');
    return (saved as ColorTheme) || 'default';
  });

  const [themeMode, setThemeModeState] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('themeMode');
    return (saved as ThemeMode) || 'light';
  });

  // Handle theme mode (light/dark)
  useEffect(() => {
    const root = document.documentElement;
    
    // Remove existing theme mode classes
    root.classList.remove('light', 'dark');
    
    // Determine which theme to apply
    let effectiveTheme: 'light' | 'dark' = 'light';
    
    if (themeMode === 'system') {
      // Use system preference
      effectiveTheme = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    } else {
      effectiveTheme = themeMode;
    }
    
    // Apply theme
    root.classList.add(effectiveTheme);
    
    // Save to localStorage
    localStorage.setItem('themeMode', themeMode);
  }, [themeMode]);

  // Handle color theme
  useEffect(() => {
    // Remove all theme classes
    document.documentElement.classList.remove(
      'theme-default',
      'theme-purple',
      'theme-green',
      'theme-orange',
      'theme-pink',
      'theme-cyan'
    );
    
    // Add current theme class
    document.documentElement.classList.add(`theme-${colorTheme}`);
    
    // Save to localStorage
    localStorage.setItem('userColorTheme', colorTheme);
  }, [colorTheme]);

  // Listen for system theme changes
  useEffect(() => {
    if (themeMode === 'system') {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
      const handleChange = () => {
        const root = document.documentElement;
        root.classList.remove('light', 'dark');
        root.classList.add(mediaQuery.matches ? 'dark' : 'light');
      };
      
      mediaQuery.addEventListener('change', handleChange);
      return () => mediaQuery.removeEventListener('change', handleChange);
    }
  }, [themeMode]);

  const setColorTheme = (theme: ColorTheme) => {
    setColorThemeState(theme);
  };

  const setThemeMode = (mode: ThemeMode) => {
    setThemeModeState(mode);
  };

  return (
    <ThemeContext.Provider value={{ colorTheme, setColorTheme, themeMode, setThemeMode }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { apiService } from '@/lib/api';

interface WFHRequest {
  id: number;
  user_id: number;
  employee_name?: string;
  requester_role?: string;
  start_date: string;
  end_date: string;
  reason: string;
  wfh_type: 'full_day' | 'half_day';
  status: 'pending' | 'approved' | 'rejected';
  created_at: string;
  updated_at: string;
  rejection_reason?: string;
  approved_by?: string;
  manager_approval?: 'pending' | 'approved' | 'rejected';
  hr_approval?: 'pending' | 'approved' | 'rejected';
  admin_approval?: 'pending' | 'approved' | 'rejected';
  approval_log?: {
    role: string;
    action: 'approve' | 'reject';
    timestamp: string;
  }[];
}

interface WFHDecision {
  id: number;
  user_id: number;
  employee_name?: string;
  requester_role?: string;
  start_date: string;
  end_date: string;
  reason: string;
  wfh_type: 'full_day' | 'half_day';
  status: 'approved' | 'rejected';
  created_at: string;
  updated_at: string;
  rejection_reason?: string;
  approved_by?: string;
  approved_at?: string;
}

interface WFHContextType {
  wfhRequests: WFHRequest[];
  pendingApprovals: WFHRequest[];
  recentDecisions: WFHDecision[];
  isLoading: boolean;
  isLoadingDecisions: boolean;
  isLoadingPending: boolean;
  loadWFHRequests: () => Promise<void>;
  refreshWFHRequests: () => Promise<void>;
  loadRecentDecisions: () => Promise<void>;
  refreshRecentDecisions: () => Promise<void>;
  loadPendingApprovals: () => Promise<void>;
  approveRequest: (id: number) => Promise<void>;
  rejectRequest: (id: number, reason: string) => Promise<void>;
}

const WFHContext = createContext<WFHContextType | undefined>(undefined);

export const WFHProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [wfhRequests, setWfhRequests] = useState<WFHRequest[]>([]);
  const [recentDecisions, setRecentDecisions] = useState<WFHDecision[]>([]);
  const [pendingApprovals, setPendingApprovals] = useState<WFHRequest[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingDecisions, setIsLoadingDecisions] = useState(false);
  const [isLoadingPending, setIsLoadingPending] = useState(false);

  const loadWFHRequests = useCallback(async () => {
    if (!user?.id) return;
    setIsLoading(true);
    try {
      const response = await apiService.getMyWFHRequests();

      console.log('WFH Requests Raw Response:', response);

      // Handle response - ensure it's an array
      let requests = [];

      if (Array.isArray(response)) {
        requests = response;
      } else if (response && typeof response === 'object') {
        // Try different possible wrapper formats
        if (response.data && Array.isArray(response.data)) {
          requests = response.data;
        } else if (response.requests && Array.isArray(response.requests)) {
          requests = response.requests;
        } else if (response.wfh_requests && Array.isArray(response.wfh_requests)) {
          requests = response.wfh_requests;
        } else if (response.results && Array.isArray(response.results)) {
          requests = response.results;
        }
      }

      const formattedRequests = requests.map((req: any) => ({
        id: req.wfh_id || req.id,
        user_id: req.user_id,
        start_date: req.start_date,
        end_date: req.end_date,
        reason: req.reason,
        wfh_type: ((req.wfh_type || 'Full Day').toLowerCase().includes('full') ? 'full_day' : 'half_day') as 'full_day' | 'half_day',
        status: ((req.status || 'pending').toLowerCase()) as 'pending' | 'approved' | 'rejected',
        created_at: req.created_at,
        updated_at: req.updated_at,
        rejection_reason: req.rejection_reason,
        approved_by: req.approved_by,
      }));

      console.log('Formatted WFH Requests:', formattedRequests);
      setWfhRequests(formattedRequests);
    } catch (error) {
      console.error('Failed to load WFH requests:', error);
      setWfhRequests([]);
    } finally {
      setIsLoading(false);
    }
  }, [user?.id]);

  const loadRecentDecisions = useCallback(async () => {
    if (!user?.id) return;

    const privilegedRoles = ['admin', 'hr', 'manager', 'team_lead'];
    if (!privilegedRoles.includes(user.role || '')) {
      setRecentDecisions([]);
      return;
    }

    setIsLoadingDecisions(true);
    try {
      const response = await apiService.getWFHApprovals();
      let requests = [];

      if (Array.isArray(response)) {
        requests = response;
      } else if (response && typeof response === 'object') {
        if (response.data && Array.isArray(response.data)) {
          requests = response.data;
        } else if (response.requests && Array.isArray(response.requests)) {
          requests = response.requests;
        }
      }

      const decisions = requests
        .filter((req: any) => {
          const status = (req.status || 'pending').toLowerCase();
          return status === 'approved' || status === 'rejected';
        })
        .map((req: any) => ({
          id: req.wfh_id || req.id,
          user_id: req.user_id,
          employee_name: req.employee_name || req.name || 'Unknown',
          requester_role: req.role || req.requester_role || 'employee',
          start_date: req.start_date,
          end_date: req.end_date,
          reason: req.reason,
          wfh_type: ((req.wfh_type || 'Full Day').toLowerCase().includes('full') ? 'full_day' : 'half_day') as 'full_day' | 'half_day',
          status: ((req.status || 'pending').toLowerCase()) as 'approved' | 'rejected',
          created_at: req.created_at,
          updated_at: req.updated_at,
          rejection_reason: req.rejection_reason,
          approved_by: req.approved_by,
          approved_at: req.approved_at || req.updated_at,
        }))
        .sort((a: WFHDecision, b: WFHDecision) => {
          return new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime();
        });

      setRecentDecisions(decisions);
    } catch (error) {
      console.error('Failed to load WFH decisions:', error);
      setRecentDecisions([]);
    } finally {
      setIsLoadingDecisions(false);
    }
  }, [user?.id, user?.role]);

  const loadPendingApprovals = useCallback(async () => {
    if (!user?.id) return;

    const privilegedRoles = ['admin', 'hr', 'manager', 'team_lead'];
    if (!privilegedRoles.includes(user.role || '')) {
      setPendingApprovals([]);
      return;
    }

    setIsLoadingPending(true);
    try {
      const response = await apiService.getWFHApprovals();
      let requests = [];

      if (Array.isArray(response)) {
        requests = response;
      } else if (response && typeof response === 'object') {
        if (response.data && Array.isArray(response.data)) {
          requests = response.data;
        } else if (response.requests && Array.isArray(response.requests)) {
          requests = response.requests;
        }
      }

      const formattedPending = requests
        .filter((req: any) => (req.status || 'pending').toLowerCase() === 'pending')
        .map((req: any) => ({
          id: req.wfh_id || req.id,
          user_id: req.user_id,
          employee_name: req.employee_name || req.name || 'Unknown',
          requester_role: req.role || req.requester_role || 'employee',
          start_date: req.start_date,
          end_date: req.end_date,
          reason: req.reason,
          wfh_type: ((req.wfh_type || 'Full Day').toLowerCase().includes('full') ? 'full_day' : 'half_day') as 'full_day' | 'half_day',
          status: 'pending' as const,
          created_at: req.created_at,
          updated_at: req.updated_at,
          rejection_reason: req.rejection_reason,
          approved_by: req.approved_by,
          manager_approval: req.manager_approval || 'pending',
          hr_approval: req.hr_approval || 'pending',
          admin_approval: req.admin_approval || 'pending',
        }));

      setPendingApprovals(formattedPending);
    } catch (error) {
      console.error('Failed to load pending WFH approvals:', error);
      setPendingApprovals([]);
    } finally {
      setIsLoadingPending(false);
    }
  }, [user?.id, user?.role]);

  const approveRequest = async (id: number) => {
    try {
      await apiService.approveWFHRequest(id, true);
      await Promise.all([
        loadWFHRequests(),
        loadRecentDecisions(),
        loadPendingApprovals()
      ]);
    } catch (error) {
      console.error('Failed to approve WFH request:', error);
      throw error;
    }
  };

  const rejectRequest = async (id: number, reason: string) => {
    try {
      await apiService.approveWFHRequest(id, false, reason);
      await Promise.all([
        loadWFHRequests(),
        loadRecentDecisions(),
        loadPendingApprovals()
      ]);
    } catch (error) {
      console.error('Failed to reject WFH request:', error);
      throw error;
    }
  };

  const refreshWFHRequests = useCallback(async () => {
    await loadWFHRequests();
  }, [loadWFHRequests]);

  const refreshRecentDecisions = useCallback(async () => {
    await loadRecentDecisions();
  }, [loadRecentDecisions]);

  // Load WFH requests when user is authenticated
  useEffect(() => {
    if (!user?.id) {
      setWfhRequests([]);
      setRecentDecisions([]);
      return;
    }

    loadWFHRequests();
    loadRecentDecisions();
    loadPendingApprovals();

    // Also reload when the page becomes visible (tab focus)
    const handleVisibilityChange = () => {
      if (!document.hidden) {
        loadWFHRequests();
        loadRecentDecisions();
        loadPendingApprovals();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [user?.id]);

  const value = {
    wfhRequests,
    pendingApprovals,
    recentDecisions,
    isLoading,
    isLoadingDecisions,
    isLoadingPending,
    loadWFHRequests,
    refreshWFHRequests,
    loadRecentDecisions,
    refreshRecentDecisions,
    loadPendingApprovals,
    approveRequest,
    rejectRequest,
  };

  return <WFHContext.Provider value={value}>{children}</WFHContext.Provider>;
};

export const useWFH = () => {
  const context = useContext(WFHContext);
  if (!context) {
    throw new Error('useWFH must be used within a WFHProvider');
  }
  return context;
};

import { useState, useEffect, useCallback } from 'react';
import { debounce } from 'lodash';
import { API_BASE_URL } from '@/lib/api';

interface ValidationResult {
  available: boolean;
  message: string;
}

interface UseFieldValidationOptions {
  endpoint: string;
  debounceMs?: number;
  excludeUserId?: number;
  enabled?: boolean;
}

export const useFieldValidation = (options: UseFieldValidationOptions) => {
  const { endpoint, debounceMs = 500, excludeUserId, enabled = true } = options;
  const [isValidating, setIsValidating] = useState(false);
  const [validationResult, setValidationResult] = useState<ValidationResult | null>(null);
  const [error, setError] = useState<string>('');

  const validateField = useCallback(
    debounce(async (value: string) => {
      if (!enabled || !value || !value.trim()) {
        setValidationResult(null);
        setError('');
        setIsValidating(false);
        return;
      }

      setIsValidating(true);
      setError('');

      try {
        const encodedValue = encodeURIComponent(value.trim());
        const url = excludeUserId
          ? `${API_BASE_URL}/${endpoint}/${encodedValue}?exclude_user_id=${excludeUserId}`
          : `${API_BASE_URL}/${endpoint}/${encodedValue}`;

        const token = localStorage.getItem('token');
        const response = await fetch(url, {
          headers: {
            'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
            'Content-Type': 'application/json',
          },
        });

        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }

        const result: ValidationResult = await response.json();
        setValidationResult(result);
      } catch (err) {
        console.error('Validation error:', err);
        setError('Unable to validate field. Please try again.');
        setValidationResult(null);
      } finally {
        setIsValidating(false);
      }
    }, debounceMs),
    [endpoint, debounceMs, excludeUserId, enabled]
  );

  const clearValidation = useCallback(() => {
    setValidationResult(null);
    setError('');
    setIsValidating(false);
  }, []);

  return {
    validateField,
    clearValidation,
    isValidating,
    validationResult,
    error,
    isAvailable: validationResult?.available ?? true,
    validationMessage: validationResult?.message || error
  };
};

import { useEffect, useCallback, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';

/**
 * Custom hook to handle browser back/forward navigation and prevent
 * unauthorized access after logout
 */
export const useNavigationGuard = () => {
  const { isAuthenticated, isLoading, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const isHandlingNavigation = useRef(false);
  const hasShownLogoutConfirm = useRef(false);

  const handleBackNavigation = useCallback(() => {
    // Prevent multiple simultaneous confirmations
    if (isHandlingNavigation.current || hasShownLogoutConfirm.current) {
      return;
    }

    // Only show confirmation if user is authenticated and trying to go back
    if (isAuthenticated && location.pathname !== '/login') {
      isHandlingNavigation.current = true;
      hasShownLogoutConfirm.current = true;

      const confirmLogout = window.confirm(
        'Do you want to logout? Clicking "OK" will log you out of the system.'
      );

      if (confirmLogout) {
        // User confirmed logout
        logout();
        // Clear the flag after logout
        setTimeout(() => {
          hasShownLogoutConfirm.current = false;
          isHandlingNavigation.current = false;
        }, 100);
      } else {
        // User cancelled - push current state again to prevent back navigation
        window.history.pushState(null, '', window.location.href);
        hasShownLogoutConfirm.current = false;
        isHandlingNavigation.current = false;
      }
    }
  }, [isAuthenticated, location.pathname, logout]);

  useEffect(() => {
    // Prevent back navigation when authenticated
    if (isAuthenticated && location.pathname !== '/login') {
      // Push current state to prevent back button
      window.history.pushState(null, '', window.location.href);

      // Listen for popstate (back/forward button)
      const handlePopState = (event: PopStateEvent) => {
        event.preventDefault();
        handleBackNavigation();
      };

      window.addEventListener('popstate', handlePopState);

      return () => {
        window.removeEventListener('popstate', handlePopState);
      };
    }
  }, [isAuthenticated, location.pathname, handleBackNavigation]);

  useEffect(() => {
    // After logout, prevent forward navigation back into the app
    if (!isLoading && !isAuthenticated && location.pathname !== '/login' && location.pathname !== '/contact-support' && location.pathname !== '/') {
      // Clear any stored session data
      localStorage.removeItem('user');
      localStorage.removeItem('token');

      // Redirect to login with a message
      navigate('/login', {
        replace: true,
        state: { message: 'Please login to access the application.' }
      });
    }
  }, [isAuthenticated, location.pathname, navigate]);

  // Clear the confirmation flag when location changes
  useEffect(() => {
    hasShownLogoutConfirm.current = false;
    isHandlingNavigation.current = false;
  }, [location.pathname]);
};

