        firstDayOfMonth.setHours(0, 0, 0, 0);
        setWfhDecisionsStartDate(firstDayOfMonth);
        setWfhDecisionsEndDate(today);
        break;
      case 'last_month':
        setWfhDecisionsStartDate(subMonths(today, 1));
        setWfhDecisionsEndDate(today);
        break;
      case 'last_3_months':
        setWfhDecisionsStartDate(subMonths(today, 3));
        setWfhDecisionsEndDate(today);
        break;
      case 'last_6_months':
