                              </td>
                              <td className="p-3 whitespace-nowrap">
                                <div className="flex justify-center">
                                  {getStatusBadge(record.status, record.checkInTime, record.checkOutTime)}
                                </div>
                              </td>
                              <td className="p-3 text-xs text-slate-600 dark:text-slate-400 max-w-[280px]">
                                {record.workSummary ? (
                                  <button
                                    type="button"
                                    className="text-left hover:text-blue-600 dark:hover:text-blue-400 block w-full text-xs leading-relaxed"
                                    onClick={() => {
                                      setSelectedWorkSummary(record.workSummary || '');
                                      setSelectedOverdueReason('');
                                      setShowWorkSummaryDialog(true);
                                    }}
                                    title={record.workSummary}
                                    style={{
                                      wordBreak: 'break-word',
                                      overflowWrap: 'break-word',
                                      display: 'block',
                                      textAlign: 'left'
                                    }}
                                  >
                                    <span style={{
                                      display: '-webkit-box',
                                      WebkitLineClamp: 2,
                                      WebkitBoxOrient: 'vertical',
                                      overflow: 'hidden',
                                      textOverflow: 'ellipsis'
                                    }}>
                                      {record.workSummary}
                                    </span>
                                    {record.workSummary.length > 60 && (
                                      <span className="text-blue-600 dark:text-blue-400 font-medium mt-1 block">View more...</span>
                                    )}
                                  </button>
                                ) : (
                                  <span className="text-slate-400 dark:text-slate-500">—</span>
                                )}
                              </td>
                              <td className="p-3 whitespace-nowrap">
                                {record.workReport ? (
                                  <a
                                    href={record.workReport}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="text-xs text-blue-600 dark:text-blue-400 hover:underline"
                                  >
                                    {t.attendance.viewReport || 'View'}
                                  </a>
                                ) : (
                                  <span className="text-slate-400 dark:text-slate-500 text-xs">—</span>
                                )}
                              </td>
                              <td className="p-3 text-xs text-slate-600 dark:text-slate-400 max-w-[280px]">
                                {record.taskDeadlineReason ? (
                                  <div className="text-left w-full" title={record.taskDeadlineReason}>
                                    <TruncatedText
                                      text={record.taskDeadlineReason || ''}
                                      maxLength={40}
                                      showToggle={true}
                                    />
                                  </div>
                                ) : (
                                  <span className="text-slate-400 dark:text-slate-500">—</span>
                                )}
                              </td>
                            </tr>
                          ))
                      ) : (
                        <tr>
                          <td colSpan={13} className="h-64 text-center p-8">
                            <div className="flex flex-col items-center justify-center space-y-3">
                              <div className="h-16 w-16 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center">
                                <Search className="h-8 w-8 text-slate-400" />
                              </div>
                              <div className="space-y-1">
                                <p className="text-lg font-semibold text-slate-900 dark:text-white">No records found</p>
                                <p className="text-sm text-slate-500 dark:text-slate-400">Try adjusting your filters or date range</p>
                              </div>
                            </div>
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>

              {filteredEmployeeAttendanceData.length > 0 && (
                <div className="mt-6">
                  <Pagination
                    currentPage={currentPage}
                    totalPages={Math.ceil(filteredEmployeeAttendanceData.length / itemsPerPage)}
                    totalItems={filteredEmployeeAttendanceData.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={setItemsPerPage}
                    showItemsPerPage={true}
                  />
                </div>
              )}
            </CardContent>
          </Card>
        </>
      ) : viewMode === 'wfh_requests' ? (
        <>
          {/* Pending WFH Requests Section */}
          <Card className="border-0 shadow-lg">
            <CardHeader className="border-b bg-gradient-to-r from-purple-50 to-pink-50 dark:from-purple-950 dark:to-pink-950">
              <CardTitle className="text-xl font-semibold flex items-center gap-2">
                <FileText className="h-5 w-5 text-purple-600" />
                Pending WFH Requests
                {getPendingWfhCount() > 0 && (
                  <Badge variant="destructive" className="ml-2">
                    {getPendingWfhCount()}
                  </Badge>
                )}
              </CardTitle>
              <CardDescription>Review and approve/reject pending work from home requests</CardDescription>
            </CardHeader>
            <CardContent className="pt-6">
              {isLoadingWfhRequests ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-8 w-8 animate-spin text-purple-600" />
                  <span className="ml-2 text-muted-foreground">Loading requests...</span>
                </div>
              ) : allWfhRequests.filter(req => req.status === 'pending').length > 0 ? (
                <>
                  <div className="space-y-3">
                    {allWfhRequests
                      .filter(req => req.status === 'pending')
                      .slice((pendingWfhCurrentPage - 1) * pendingWfhItemsPerPage, pendingWfhCurrentPage * pendingWfhItemsPerPage)
                      .map((request) => (
                        <div key={request.id} className="border rounded-lg p-4 hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors">
                          <div className="flex items-start justify-between">
                            <div className="space-y-2 flex-1 min-w-0">
                              <div className="flex items-center gap-2 flex-wrap">
                                <div className="flex items-center gap-2">
                                  <User className="h-4 w-4 text-blue-600" />
                                  <span className="font-medium">{request.submittedBy}</span>
                                  <Badge variant="outline" className="text-xs">
                                    {formatRoleDisplay(request.role)}
                                  </Badge>
                                </div>
                                <div className="flex items-center gap-2">
                                  <Calendar className="h-4 w-4 text-green-600" />
                                  <span className="text-sm">
                                    {formatDateIST(request.startDate, 'dd MMM yyyy')} - {formatDateIST(request.endDate, 'dd MMM yyyy')}
                                  </span>
                                  <Badge variant="outline" className="text-xs">
                                    {request.type === 'full_day' ? 'Full Day' : 'Half Day'}
                                  </Badge>
                                </div>
                              </div>
                              <p className="text-sm text-muted-foreground break-words overflow-wrap-anywhere whitespace-pre-wrap">{request.reason}</p>
                              <div className="flex items-center gap-4 text-xs text-muted-foreground">
                                <span>Submitted: {formatRelativeTime(request.submittedAt)} ({formatDateTimeIST(request.submittedAt, 'dd MMM yyyy, hh:mm a')})</span>
                                <span>Department: {request.department}</span>
                              </div>
                            </div>
                            <div className="flex items-center gap-2 ml-4">
                              <Badge variant="secondary">Pending</Badge>
                              <div className="flex gap-2">
                                <Button
                                  size="sm"
                                  variant="outline"
                                  className="text-green-600 border-green-600 hover:bg-green-50 dark:hover:bg-green-950"
                                  onClick={() => handleWfhRequestAction(request.id, 'approve')}
                                  disabled={isProcessingWfhRequest}
                                >
                                  <CheckCircle className="h-4 w-4 mr-1" />
                                  Approve
                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  className="text-red-600 border-red-600 hover:bg-red-50 dark:hover:bg-red-950"
                                  onClick={() => {
                                    setSelectedWfhRequest(request);
                                    setShowWfhRequestDialog(true);
                                  }}
                                  disabled={isProcessingWfhRequest}
                                >
                                  <X className="h-4 w-4 mr-1" />
                                  Reject
                                </Button>
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                  </div>
                  {allWfhRequests.filter(req => req.status === 'pending').length > 0 && (
                    <div className="mt-4">
                      <Pagination
                        currentPage={pendingWfhCurrentPage}
                        totalPages={Math.ceil(allWfhRequests.filter(req => req.status === 'pending').length / pendingWfhItemsPerPage)}
                        totalItems={allWfhRequests.filter(req => req.status === 'pending').length}
                        itemsPerPage={pendingWfhItemsPerPage}
                        onPageChange={setPendingWfhCurrentPage}
                        onItemsPerPageChange={setPendingWfhItemsPerPage}
                        showItemsPerPage={true}
                      />
                    </div>
                  )}
                </>
              ) : (
                <div className="text-center py-8 text-muted-foreground">
                  <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>No pending WFH requests</p>
                  <p className="text-sm">All requests have been processed</p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Recent Decisions Section */}
          <Card className="border-0 shadow-lg">
            <CardHeader className="border-b bg-gradient-to-r from-slate-50 to-gray-50 dark:from-slate-900 dark:to-gray-800">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                    <History className="h-5 w-5 text-white" />
                  </div>
                  <div>
                    <CardTitle className="text-xl font-semibold">Recent Decisions</CardTitle>
                    <CardDescription>Approved and rejected WFH requests</CardDescription>
                  </div>
                </div>
              </div>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="space-y-4">
                {/* Filter Controls for Recent Decisions */}
                <div className="space-y-4">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-start">
                    <div className="flex flex-col gap-2">
                      <Label htmlFor="decision-status-filter" className="text-sm font-medium ml-1">Decision Status</Label>
                      <Select value={wfhRequestFilter} onValueChange={(value: any) => setWfhRequestFilter(value)}>
                        <SelectTrigger id="decision-status-filter" className="w-full h-11 bg-white dark:bg-gray-950 border-2">
                          <SelectValue placeholder="Select Status" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="all">All Decisions</SelectItem>
                          <SelectItem value="approved">Approved</SelectItem>
                          <SelectItem value="rejected">Rejected</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="flex flex-col gap-2">
                      <Label htmlFor="role-filter" className="text-sm font-medium ml-1">Role Filter</Label>
                      <Select value={wfhRoleFilter} onValueChange={(value: any) => setWfhRoleFilter(value)}>
                        <SelectTrigger id="role-filter" className="w-full h-11 bg-white dark:bg-gray-950 border-2">
                          <SelectValue placeholder="Select Role" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="all">All Roles</SelectItem>
                          {user?.role === 'admin' && <SelectItem value="hr">HR</SelectItem>}
                          {(user?.role === 'admin' || user?.role === 'hr') && <SelectItem value="manager">Manager</SelectItem>}
                          <SelectItem value="team_lead">Team Lead</SelectItem>
                          <SelectItem value="employee">Employee</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="flex flex-col gap-2">
                      <Label htmlFor="decision-time-filter" className="text-sm font-medium ml-1">Duration Filter</Label>
                      <Select value={wfhRequestTimeFilter} onValueChange={(value: any) => setWfhRequestTimeFilter(value)}>
                        <SelectTrigger id="decision-time-filter" className="w-full h-11 bg-white dark:bg-gray-950 border-2">
                          <Filter className="h-4 w-4 mr-2 text-muted-foreground" />
                          <SelectValue placeholder="Select Duration" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="all">All Time</SelectItem>
                          <SelectItem value="current_month">Current Month</SelectItem>
                          <SelectItem value="last_month">Last Month</SelectItem>
                          <SelectItem value="last_3_months">Last 3 Months</SelectItem>
                          <SelectItem value="last_6_months">Last 6 Months</SelectItem>
                          <SelectItem value="last_year">Last 1 Year</SelectItem>
                          <SelectItem value="custom">Custom Range</SelectItem>
                        </SelectContent>
                      </Select>

                      {wfhRequestTimeFilter === 'custom' && (
                        <div className="flex flex-col gap-3 mt-2 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800 animate-in fade-in slide-in-from-top-2 duration-300">
                          <div className="space-y-1">
                            <Label className="text-[10px] font-bold text-slate-500 uppercase ml-1">From Date</Label>
                            <DatePicker
                              date={wfhRequestStartDate || undefined}
                              onDateChange={setWfhRequestStartDate}
                              placeholder="From date"
                              className="h-10 w-full"
                            />
                          </div>
                          <div className="space-y-1">
                            <Label className="text-[10px] font-bold text-slate-500 uppercase ml-1">To Date</Label>
                            <DatePicker
                              date={wfhRequestEndDate || undefined}
                              onDateChange={setWfhRequestEndDate}
                              placeholder="To date"
                              fromDate={wfhRequestStartDate || undefined}
                              className="h-10 w-full"
                            />
                          </div>
                        </div>
                      )}
                    </div>
                    <div className="flex flex-col gap-2">
                      <Label className="text-sm font-medium ml-1">Summary</Label>
                      <div className="h-11 px-3 py-2 bg-muted rounded-md text-sm flex items-center justify-between">
                        <span>{filteredRecentDecisions.length} of {allWfhRequests.filter(req => req.status !== 'pending').length} decisions</span>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Recent Decisions Table */}
                {isLoadingWfhRequests ? (
                  <div className="flex items-center justify-center py-8">
                    <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
                    <span className="ml-2 text-muted-foreground">Loading decisions...</span>
                  </div>
                ) : filteredRecentDecisions.length > 0 ? (
                  <div className="space-y-4">
                    <div className="space-y-3">
                      {filteredRecentDecisions
                        .slice((recentDecisionsCurrentPage - 1) * recentDecisionsItemsPerPage, recentDecisionsCurrentPage * recentDecisionsItemsPerPage)
                        .map((request) => (
                          <div key={request.id} className="border rounded-lg p-4 hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors">
                            <div className="flex items-start justify-between">
                              <div className="space-y-2 flex-1 min-w-0">
                                <div className="flex items-center gap-2 flex-wrap">
                                  <div className="flex items-center gap-2">
                                    <User className="h-4 w-4 text-blue-600" />
                                    <span className="font-medium">{request.submittedBy}</span>
                                    <Badge variant="outline" className="text-xs">
                                      {formatRoleDisplay(request.role)}
                                    </Badge>
                                  </div>
                                  <div className="flex items-center gap-2">
                                    <Calendar className="h-4 w-4 text-green-600" />
                                    <span className="text-sm">
                                      {formatDateIST(request.startDate, 'dd MMM yyyy')} - {formatDateIST(request.endDate, 'dd MMM yyyy')}
                                    </span>
                                    <Badge variant="outline" className="text-xs">
                                      {request.type === 'full_day' ? 'Full Day' : 'Half Day'}
                                    </Badge>
                                  </div>
                                </div>
                                <p className="text-sm text-muted-foreground break-words overflow-wrap-anywhere whitespace-pre-wrap">{request.reason}</p>
                                <div className="flex items-center gap-4 text-xs text-muted-foreground">
                                  <span>Submitted: {formatDateTimeIST(request.submittedAt, 'dd MMM yyyy, hh:mm a')}</span>
                                  <span>Decision: {formatDateTimeIST(request.processedAt || request.submittedAt, 'dd MMM yyyy, hh:mm a')}</span>
                                  <span>Department: {request.department}</span>
                                </div>
                                {request.rejectionReason && (
                                  <div className="bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-lg p-2 mt-2">
                                    <p className="text-sm text-red-800 dark:text-red-200 break-words overflow-wrap-anywhere whitespace-pre-wrap">
                                      <strong>Rejection Reason:</strong> {request.rejectionReason}
                                    </p>
                                  </div>
                                )}
                              </div>
                              <div className="flex items-center gap-2 ml-4">
                                <Badge
                                  variant={request.status === 'approved' ? 'default' : 'destructive'}
                                  className={request.status === 'approved' ? 'bg-green-500' : ''}
                                >
                                  {request.status.charAt(0).toUpperCase() + request.status.slice(1)}
                                </Badge>
                              </div>
                            </div>
                          </div>
                        ))}
                    </div>

                    {filteredRecentDecisions.length > 0 && (
                      <div className="mt-6 border-t pt-4">
                        <Pagination
                          currentPage={recentDecisionsCurrentPage}
                          totalPages={Math.ceil(filteredRecentDecisions.length / recentDecisionsItemsPerPage)}
                          totalItems={filteredRecentDecisions.length}
                          itemsPerPage={recentDecisionsItemsPerPage}
                          onPageChange={setRecentDecisionsCurrentPage}
                          onItemsPerPageChange={setRecentDecisionsItemsPerPage}
                          showItemsPerPage={true}
                        />
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    <History className="h-12 w-12 mx-auto mb-4 opacity-50" />
                    <p>No decisions yet</p>
                    <p className="text-sm">
                      {wfhRequestTimeFilter === 'all' ? (wfhRequestFilter === 'all' ? 'No requests have been approved or rejected' : `No ${wfhRequestFilter} requests found`) : `No requests found for the selected duration`}
                    </p>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </>
      ) : (
        <>
          {/* Work From Home Request View */}
          <Card className="border-0 shadow-lg">
            <CardHeader className="border-b bg-gradient-to-r from-orange-50 to-red-50 dark:from-orange-950 dark:to-red-950">
              <CardTitle className="text-xl font-semibold flex items-center gap-2">
                <Home className="h-5 w-5 text-orange-600" />
                Apply for Work From Home
              </CardTitle>
              <CardDescription>Submit a request to work from home</CardDescription>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="space-y-6">
                {/* WFH Type removed as per request */}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="wfh-start-date">
                      Start Date <span className="text-red-500">*</span>
                    </Label>
                    <DatePicker
                      date={wfhStartDate}
                      onDateChange={(date) => {
                        setWfhStartDate(date);
                        if (date && (!wfhEndDate || wfhEndDate < date)) {
                          setWfhEndDate(date);
                        }
                      }}
                      placeholder="Select date"
                      disablePastDates={true}
                      fromDate={getTodayISTDate()}
                    />
                    {wfhStartDate && !isValidWfhDate(wfhStartDate) && (
                      <p className="text-xs text-red-500 mt-1">Date must be today or later</p>
                    )}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="wfh-end-date">End Date <span className="text-red-500">*</span></Label>
                    <DatePicker
                      date={wfhEndDate}
                      onDateChange={setWfhEndDate}
                      placeholder="Select end date"
                      disablePastDates={true}
                      fromDate={wfhStartDate || getTodayISTDate()}
                    />
                    {wfhEndDate && !isValidWfhDate(wfhEndDate) && (
                      <p className="text-xs text-red-500 mt-1">Date must be today or later</p>
                    )}
                    {wfhStartDate && wfhEndDate && wfhEndDate < wfhStartDate && (
                      <p className="text-xs text-red-500 mt-1">End date must be on or after start date</p>
                    )}
                  </div>
                </div>


                <div className="space-y-2">
                  <Label htmlFor="wfh-reason">Reason for WFH Request <span className="text-red-500">*</span></Label>
                  <Textarea
                    id="wfh-reason"
                    placeholder="Please provide a detailed reason for your work from home request."
                    value={wfhReason}
                    onChange={(e) => setWfhReason(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                    rows={4}
                    className="resize-none"
                  />
                  <div className="flex items-center justify-between">
                    <p className={`text-xs ${wfhReason.trim().length < 10 && wfhReason.length > 0 ? 'text-red-500' : 'text-gray-500'}`}>
                      Characters must be more than 10 (Current: {wfhReason.length})
                    </p>
                  </div>
                </div>

                <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-800 rounded-lg p-4">
                  <div className="flex items-start gap-3">
                    <AlertCircle className="h-5 w-5 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
                    <div className="text-sm text-blue-800 dark:text-blue-200">
                      <p className="font-medium mb-1">Request Guidelines:</p>
                      <ul className="list-disc list-inside space-y-1 text-xs">
                        <li>Submit requests in advance</li>
                        <li>Provide a clear and valid reason for the request</li>
                        <li>Ensure you have necessary equipment and internet connectivity</li>
                        <li>Your request will be reviewed by your {user?.role === 'employee' || user?.role === 'team_lead' ? 'manager and HR' : 'admin'}</li>
                      </ul>
                    </div>
                  </div>
                </div>

                <div className="flex gap-3 pt-4">
                  <Button
                    onClick={handleWfhSubmit}
                    disabled={isSubmittingWfh || !validateWfhForm().valid}
                    className="flex-1 bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-700 hover:to-red-700"
                  >
                    {isSubmittingWfh ? (
                      <>
                        <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                        Submitting...
                      </>
                    ) : (
                      <>
                        <Send className="h-4 w-4 mr-2" />
                        Submit WFH Request
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* WFH Request History */}
          <Card className="border-0 shadow-lg">
            <CardHeader className="border-b bg-gradient-to-r from-slate-50 to-gray-50 dark:from-slate-900 dark:to-gray-900">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-orange-500 to-red-600 flex items-center justify-center">
                  <History className="h-5 w-5 text-white" />
                </div>
                <div>
                  <CardTitle className="text-xl font-semibold">Your WFH Requests</CardTitle>
                  <CardDescription>Track the status of your work from home requests</CardDescription>
                </div>
              </div>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="space-y-4">
                <div className="flex flex-col md:flex-row justify-between items-end gap-4">
                  <div className="w-full md:w-auto">
                    <Label className="text-sm font-medium mb-1.5 block">Time Period</Label>
                    <Select value={wfhHistoryTimeFilter} onValueChange={(value: any) => setWfhHistoryTimeFilter(value)}>
                      <SelectTrigger className="w-full md:w-[200px] h-11 bg-white dark:bg-slate-950 border-2 border-slate-200 dark:border-slate-800 rounded-xl shadow-sm">
                        <Filter className="h-4 w-4 mr-2 text-blue-500" />
                        <SelectValue placeholder="Select Duration" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="all">All Requests</SelectItem>
                        <SelectItem value="current_month">Current Month</SelectItem>
                        <SelectItem value="last_month">Last Month</SelectItem>
                        <SelectItem value="last_3_months">Last 3 Months</SelectItem>
                        <SelectItem value="last_6_months">Last 6 Months</SelectItem>
                        <SelectItem value="last_year">Last 1 Year</SelectItem>
                        <SelectItem value="custom">Custom Range</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="text-sm text-slate-500 bg-slate-100 dark:bg-slate-800 px-3 py-2 rounded-lg font-medium">
                    Showing {filteredWfhHistory.length} requests
                  </div>
                </div>

                {wfhHistoryTimeFilter === 'custom' && (
                  <div className="flex flex-col sm:flex-row items-start sm:items-end gap-3 animate-in fade-in slide-in-from-top-2 duration-300 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800">
                    <div className="flex-1 w-full space-y-1.5">
                      <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wider ml-1">From Date</Label>
                      <DatePicker
                        date={wfhHistoryStartDate}
                        onDateChange={setWfhHistoryStartDate}
                        className="w-full border-2 border-slate-200 dark:border-slate-800 rounded-xl h-10 shadow-sm"
                        placeholder="From Date"
                      />
                    </div>
                    <div className="flex items-center justify-center h-10 px-2 text-slate-400 hidden sm:flex">
                      <History className="h-4 w-4 opacity-50" />
                    </div>
                    <div className="flex-1 w-full space-y-1.5">
                      <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wider ml-1">To Date</Label>
                      <DatePicker
                        date={wfhHistoryEndDate}
                        onDateChange={setWfhHistoryEndDate}
                        className="w-full border-2 border-slate-200 dark:border-slate-800 rounded-xl h-10 shadow-sm"
                        placeholder="To Date"
                        fromDate={wfhHistoryStartDate}
                      />
                    </div>
                  </div>
                )}
                {filteredWfhHistory.length > 0 ? (
                  <div className="space-y-3">
                    {paginatedWfhHistory.map((request) => (
                      <div key={request.id} className="border rounded-lg p-4 hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors">
                        <div className="flex items-start justify-between gap-4">
                          <div className="space-y-2 flex-1 min-w-0">
                            <div className="flex items-center gap-2">
                              <Calendar className="h-4 w-4 text-blue-600" />
                              <span className="font-medium">
                                {formatDateIST(request.startDate, 'dd MMM yyyy')} - {formatDateIST(request.endDate, 'dd MMM yyyy')}
                              </span>
                              <Badge variant="outline" className="text-xs">
                                {request.type === 'full_day' || request.type === 'Full Day' ? 'Full Day' : 'Half Day'}
                              </Badge>
                            </div>
                            <p className="text-sm text-muted-foreground break-words overflow-wrap-anywhere whitespace-pre-wrap">{request.reason}</p>
                            <p className="text-xs text-muted-foreground">
                              Submitted {formatRelativeTime(request.submittedAt)} ({formatDateTimeIST(request.submittedAt, 'dd MMM yyyy, hh:mm a')})
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <Badge
                              variant={request.status === 'approved' ? 'default' : request.status === 'rejected' ? 'destructive' : 'secondary'}
                              className={request.status === 'approved' ? 'bg-green-500' : ''}
                            >
                              {request.status.charAt(0).toUpperCase() + request.status.slice(1)}
                            </Badge>
                            {request.status === 'pending' && (
                              <div className="flex gap-1">
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onClick={() => handleEditWfh(request)}
                                  className="h-8 w-8 p-0"
                                  title="Edit request"
                                >
                                  <Edit className="h-4 w-4 text-blue-600 hover:text-blue-700" />
                                </Button>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onClick={() => handleDeleteWfh(request.id || request.wfhId)}
                                  disabled={isDeletingWfhId === (request.id || request.wfhId)}
                                  className="h-8 w-8 p-0"
                                  title="Delete request"
                                >
                                  <Trash2 className="h-4 w-4 text-red-600 hover:text-red-700" />
                                </Button>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}

                    {filteredWfhHistory.length > 0 && (
                      <div className="mt-6 pt-4 border-t">
                        <Pagination
                          currentPage={wfhHistoryPage}
                          totalPages={Math.ceil(filteredWfhHistory.length / wfhHistoryItemsPerPage)}
                          totalItems={filteredWfhHistory.length}
                          itemsPerPage={wfhHistoryItemsPerPage}
                          onPageChange={setWfhHistoryPage}
                          onItemsPerPageChange={setWfhHistoryItemsPerPage}
                          showItemsPerPage={true}
                        />
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    <Home className="h-12 w-12 mx-auto mb-4 opacity-50" />
                    <p>No WFH requests found for the selected period</p>
                    <p className="text-sm">Try adjusting your filters or submit a new request</p>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </>
      )
      }

      {/* Checkout Confirmation Dialog */}
      <Dialog open={showCheckoutDialog} onOpenChange={setShowCheckoutDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Confirm Check-out</DialogTitle>
            <DialogDescription>
              Please provide today's work summary before checking out. You can optionally upload a work report PDF.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div>
              <Label htmlFor="work-summary">Today's Work Summary <span className="text-red-500">*</span></Label>
              <Textarea
                id="work-summary"
                placeholder="Brief description of today's work."
                value={todaysWork}
                onChange={(e) => setTodaysWork(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                className="mt-2 resize-none"
                rows={4}
                required
              />
            </div>
            <div>
              <Label htmlFor="work-pdf">Upload Work Report PDF (Optional)</Label>
              <div className="mt-2 flex items-center gap-2">
                <Input
                  id="work-pdf"
                  type="file"
                  accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.txt"
                  onChange={handleFileUpload}
                />
                {workPdf && (
                  <Badge variant="outline">
                    <FileText className="h-3 w-3 mr-1" />
                    {workPdf.name}
                  </Badge>
                )}
              </div>
            </div>
            <div>
              <Label htmlFor="task-deadline-reason">Task Deadline Reason (Optional)</Label>
              <Textarea
                id="task-deadline-reason"
                placeholder="Reason for any task deadlines not met."
                value={taskDeadlineReason}
                onChange={(e) => setTaskDeadlineReason(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                className="mt-2 resize-none"
                rows={3}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCheckoutDialog(false)}>
              Cancel
            </Button>
            <Button onClick={confirmCheckOut}>
              Proceed to Check-out
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog
        open={exportModalOpen}
        onOpenChange={(open) => {
          setExportModalOpen(open);
          if (!open) {
            setExportType(null);
          }
        }}
      >
        <DialogContent className="sm:max-w-[600px] max-h-[90vh] flex flex-col overflow-visible">
          <DialogHeader>
            <DialogTitle>Export Attendance Report</DialogTitle>
            <DialogDescription>
              Configure your export preferences. Select date range and employee filter options.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 py-4 flex-1 overflow-y-auto overflow-x-visible pr-1">
            {/* Report Layout Selection */}
            <div className="space-y-2">
              <Label className="text-sm font-medium">Report Layout</Label>
              <div className="grid grid-cols-2 gap-3">
                <button
                  type="button"
                  onClick={() => setReportLayout('basic')}
                  className={`p-2.5 rounded-lg border transition-all ${reportLayout === 'basic'
                    ? 'border-blue-600 bg-blue-50 dark:bg-blue-950'
                    : 'border-gray-200 hover:border-blue-300 dark:border-gray-700'
                    }`}
                >
                  <div className="flex flex-col items-center gap-1.5">
                    <div className={`h-8 w-8 rounded-full flex items-center justify-center ${reportLayout === 'basic' ? 'bg-blue-100 text-blue-600' : 'bg-gray-100 text-gray-400'}`}>
                      <FileText className="h-4.5 w-4.5" />
                    </div>
                    <span className={`text-xs font-bold ${reportLayout === 'basic' ? 'text-blue-600' : 'text-gray-600'}`}>
                      Basic
                    </span>
                    <span className="text-[9px] text-muted-foreground text-center line-clamp-1">
                      Standard list
                    </span>
                  </div>
                </button>
                <button
                  type="button"
                  onClick={() => setReportLayout('grid')}
                  className={`p-2.5 rounded-lg border transition-all ${reportLayout === 'grid'
                    ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-950'
                    : 'border-gray-200 hover:border-indigo-300 dark:border-gray-700'
                    }`}
                >
                  <div className="flex flex-col items-center gap-1.5">
                    <div className={`h-8 w-8 rounded-full flex items-center justify-center ${reportLayout === 'grid' ? 'bg-indigo-100 text-indigo-600' : 'bg-gray-100 text-gray-400'}`}>
                      <Users className="h-4.5 w-4.5" />
                    </div>
                    <span className={`text-xs font-bold ${reportLayout === 'grid' ? 'text-indigo-600' : 'text-gray-600'}`}>
                      Grid
                    </span>
                    <span className="text-[9px] text-muted-foreground text-center line-clamp-1">
                      Monthly view
                    </span>
                  </div>
                </button>
                <button
                  type="button"
                  onClick={() => setReportLayout('detailed_grid')}
                  className={`p-2.5 rounded-lg border transition-all ${reportLayout === 'detailed_grid'
                    ? 'border-purple-600 bg-purple-50 dark:bg-purple-950'
                    : 'border-gray-200 hover:border-purple-300 dark:border-gray-700'
                    }`}
                >
                  <div className="flex flex-col items-center gap-1.5">
                    <div className={`h-8 w-8 rounded-full flex items-center justify-center ${reportLayout === 'detailed_grid' ? 'bg-purple-100 text-purple-600' : 'bg-gray-100 text-gray-400'}`}>
                      <History className="h-4.5 w-4.5" />
                    </div>
                    <span className={`text-xs font-bold ${reportLayout === 'detailed_grid' ? 'text-purple-600' : 'text-gray-600'}`}>
                      Detailed Grid
                    </span>
                    <span className="text-[9px] text-muted-foreground text-center line-clamp-1">
                      Full details
                    </span>
                  </div>
                </button>
              </div>
            </div>

            {/* Export Format Selection */}
            <div className="space-y-2">
              <Label className="text-sm font-medium">Export Format</Label>
              <div className="grid grid-cols-2 gap-3">
                <button
                  type="button"
                  onClick={() => setExportType('csv')}
                  className={`p-2.5 rounded-lg border transition-all ${exportType === 'csv'
                    ? 'border-green-600 bg-green-50 dark:bg-green-950'
                    : 'border-gray-200 hover:border-green-300 dark:border-gray-700'
                    }`}
                >
                  <div className="flex flex-col items-center gap-1.5">
                    <FileSpreadsheet className={`h-6 w-6 ${exportType === 'csv' ? 'text-green-600' : 'text-gray-400'}`} />
                    <span className={`text-xs font-bold ${exportType === 'csv' ? 'text-green-600' : 'text-gray-600'}`}>
                      CSV
                    </span>
                    <span className="text-[9px] text-muted-foreground text-center">
                      Excel file
                    </span>
                  </div>
                </button>
                <button
                  type="button"
                  onClick={() => setExportType('pdf')}
                  className={`p-2.5 rounded-lg border transition-all ${exportType === 'pdf'
                    ? 'border-red-600 bg-red-50 dark:bg-red-950'
                    : 'border-gray-200 hover:border-red-300 dark:border-gray-700'
                    }`}
                >
                  <div className="flex flex-col items-center gap-1.5">
                    <FileText className={`h-6 w-6 ${exportType === 'pdf' ? 'text-red-600' : 'text-gray-400'}`} />
                    <span className={`text-xs font-bold ${exportType === 'pdf' ? 'text-red-600' : 'text-gray-600'}`}>
                      PDF
                    </span>
                    <span className="text-[9px] text-muted-foreground text-center">
                      Print file
                    </span>
                  </div>
                </button>
              </div>
            </div>

            {/* Quick Filter Dropdown */}
            <div className="space-y-2">
              <Label htmlFor="quick-filter" className="text-sm font-medium">Quick Filter</Label>
              <Select value={quickFilter} onValueChange={handleQuickFilter}>
                <SelectTrigger
                  id="quick-filter"
                  className="w-full h-10 border-2 border-gray-300 hover:border-blue-400 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all"
                >
                  <SelectValue placeholder="Select Duration" />
                </SelectTrigger>
                <SelectContent
                  position="popper"
                  className="w-[var(--radix-select-trigger-width)] min-w-[200px] max-w-[400px] z-50"
                  sideOffset={5}
                  align="start"
                >
                  <SelectItem value="last_month">Last Month</SelectItem>
                  <SelectItem value="last_3_months">Last 3 Months</SelectItem>
                  <SelectItem value="last_6_months">Last 6 Months</SelectItem>
                  <SelectItem value="custom">Custom Range</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Date Range Selection */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="export-start" className="text-sm font-medium">Start Date</Label>
                <DatePicker
                  date={exportStartDate}
                  onDateChange={setExportStartDate}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="export-end" className="text-sm font-medium">End Date</Label>
                <DatePicker
                  date={exportEndDate}
                  onDateChange={setExportEndDate}
                />
              </div>
            </div>

            {/* Employee Filter */}
            <div className="space-y-2">
              <Label>Employee Filter</Label>
              <div className="flex gap-4">
                <div className="flex items-center space-x-2">
                  <input
                    type="radio"
                    id="export-all"
                    name="employee-export-filter"
                    className="h-4 w-4 text-blue-600"
                    checked={employeeExportFilter === 'all'}
                    onChange={() => {
                      setEmployeeExportFilter('all');
                      setSelectedExportEmployee(null);
                      setEmployeeExportSearch('');
                      if (!exportDepartments.length && !user?.department) setSelectedExportDepartment('');
                    }}
                  />
                  <Label htmlFor="export-all" className="cursor-pointer">
                    All Employees
                  </Label>
                </div>
                <div className="flex items-center space-x-2">
                  <input
                    type="radio"
                    id="export-specific"
                    name="employee-export-filter"
                    className="h-4 w-4 text-blue-600"
                    checked={employeeExportFilter === 'specific'}
                    onChange={() => setEmployeeExportFilter('specific')}
                  />
                  <Label htmlFor="export-specific" className="cursor-pointer">
                    Specific Employee
                  </Label>
                </div>
              </div>
            </div>

            {/* Employee Selection */}
            {employeeExportFilter === 'specific' && (
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="export-department">Department</Label>
                  <Select
                    value={selectedExportDepartment}
                    onValueChange={(value) => {
                      setSelectedExportDepartment(value);
                      setSelectedExportEmployee(null);
                      setEmployeeExportSearch('');
                    }}
                  >
                    <SelectTrigger id="export-department">
                      <SelectValue placeholder="Select department" />
                    </SelectTrigger>
                    <SelectContent>
                      {exportDepartments.length ? (
                        exportDepartments.map((dept) => (
                          <SelectItem key={dept} value={dept}>
                            {dept}
                          </SelectItem>
                        ))
                      ) : (
                        <SelectItem value="__empty" disabled>
                          No departments found
                        </SelectItem>
                      )}
                    </SelectContent>
                  </Select>
                </div>

                {selectedExportDepartment ? (
                  <div className="space-y-2">
                    <Label htmlFor="export-employee-search">Select Employee</Label>
                    <div className="relative">
                      <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                      <Input
                        id="export-employee-search"
                        placeholder="Search by name or employee ID..."
                        value={employeeExportSearch}
                        onChange={(e) => setEmployeeExportSearch(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                        className="pl-10"
                      />
                    </div>
                    <div className="border rounded-md max-h-40 overflow-y-auto mt-2">
                      {filteredExportEmployees.length ? (
                        filteredExportEmployees.map((emp) => {
                          const isSelected = selectedExportEmployee?.user_id === emp.user_id;
                          return (
                            <button
                              type="button"
                              key={emp.user_id}
                              onClick={() => setSelectedExportEmployee(emp)}
                              className={`w-full text-left p-3 border-b last:border-b-0 transition-colors ${isSelected
                                ? 'bg-blue-50 dark:bg-blue-900'
                                : 'hover:bg-gray-100 dark:hover:bg-gray-800'
                                }`}
                            >
                              <div className="font-medium">{emp.name}</div>
                              <div className="text-sm text-muted-foreground">
                                {emp.employee_id ? `ID: ${emp.employee_id}` : `User: ${emp.user_id}`}
                              </div>
                            </button>
                          );
                        })
                      ) : (
                        <div className="p-3 text-sm text-muted-foreground">
                          No employees found for this department.
                        </div>
                      )}
                    </div>
                    {selectedExportEmployee && (
                      <div className="mt-2 p-2 bg-blue-50 dark:bg-blue-900 rounded-md flex items-center justify-between">
                        <div>
                          <div className="font-medium">{selectedExportEmployee.name}</div>
                          {selectedExportEmployee.employee_id && (
                            <div className="text-sm text-muted-foreground">
                              ID: {selectedExportEmployee.employee_id}
                            </div>
                          )}
                        </div>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => {
                            setSelectedExportEmployee(null);
                            setEmployeeExportSearch('');
                          }}
                        >
                          Clear
                        </Button>
                      </div>
                    )}
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground">
                    Select a department to view its employees.
                  </p>
                )}
              </div>
            )}
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setExportModalOpen(false);
                setExportType(null);
              }}
              disabled={isExporting}
            >
              Cancel
            </Button>
            <Button
              onClick={performExport}
              disabled={
                isExporting ||
                (!exportStartDate && !exportEndDate) ||
                (employeeExportFilter === 'specific' && !selectedExportEmployee)
              }
              className={exportType === 'csv' ? 'bg-green-600 hover:bg-green-700' : exportType === 'pdf' ? 'bg-red-600 hover:bg-red-700' : ''}
            >
              {isExporting ? 'Exporting...' : exportType ? `Export ${exportType.toUpperCase()}` : 'Select Format'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Selfie Modal */}
      <Dialog open={showSelfieModal} onOpenChange={setShowSelfieModal}>
        <DialogContent className="sm:max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <User className="h-5 w-5" />
              {selectedRecord?.name || 'Employee'}'s Attendance
            </DialogTitle>
          </DialogHeader>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 py-4">
            {/* Check-in Selfie */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <div className="h-3 w-3 rounded-full bg-green-500"></div>
                <h3 className="font-medium">Check-in Selfie</h3>
              </div>
              <div className="relative aspect-[3/4] bg-gray-100 dark:bg-gray-800 rounded-lg overflow-hidden">
                {selectedRecord?.checkInSelfie ? (
                  <img
                    src={selectedRecord.checkInSelfie.startsWith('http') ? selectedRecord.checkInSelfie : `${API_BASE_URL}${selectedRecord.checkInSelfie}`}
                    alt="Check-in selfie"
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-gray-400">
                    <User className="h-12 w-12 mb-2" />
                    <p>No selfie available</p>
                  </div>
                )}
                <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/70 to-transparent p-4 text-white">
                  <p className="font-medium">Check-in: {selectedRecord?.checkInTime ? formatAttendanceTime(selectedRecord.date, selectedRecord.checkInTime) : 'N/A'}</p>
                  <p className="text-sm opacity-80">{selectedRecord?.checkInLocation?.address || 'Location not available'}</p>
                </div>
              </div>
            </div>

            {/* Check-out Selfie */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <div className="h-3 w-3 rounded-full bg-red-500"></div>
                <h3 className="font-medium">Check-out Selfie</h3>
              </div>
              <div className="relative aspect-[3/4] bg-gray-100 dark:bg-gray-800 rounded-lg overflow-hidden">
                {selectedRecord?.checkOutSelfie ? (
                  <img
                    src={selectedRecord.checkOutSelfie.startsWith('http') ? selectedRecord.checkOutSelfie : `${API_BASE_URL}${selectedRecord.checkOutSelfie}`}
                    alt="Check-out selfie"
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-gray-400">
                    <User className="h-12 w-12 mb-2" />
                    <p>No check-out selfie</p>
                    <p className="text-sm">Not checked out yet</p>
                  </div>
                )}
                {selectedRecord?.checkOutTime && (
                  <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/70 to-transparent p-4 text-white">
                    <p className="font-medium">Check-out: {formatAttendanceTime(selectedRecord.date, selectedRecord.checkOutTime)}</p>
                    <p className="text-sm opacity-80">{selectedRecord?.checkOutLocation?.address || 'Location not available'}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
          <div className="space-y-3 text-sm">
            <div>
              <p className="font-medium">Work Summary</p>
              <p className="text-muted-foreground">
                {selectedRecord?.workSummary || 'Not provided'}
              </p>
            </div>
            {selectedRecord?.taskDeadlineReason && (
              <div>
                <p className="font-medium">Overdue Reason</p>
                <p className="text-muted-foreground">
                  {selectedRecord.taskDeadlineReason}
                </p>
              </div>
            )}
            {selectedRecord?.workReport && (
              <div>
                <p className="font-medium">Work Report</p>
                <a
                  href={selectedRecord.workReport}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 hover:underline"
                >
                  View Document
                </a>
              </div>
            )}
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setShowSelfieModal(false)}
              className="gap-2"
            >
              <X className="h-4 w-4" />
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Location Details Modal */}
      <Dialog open={!!selectedRecord && !showSelfieModal} onOpenChange={(open) => !open && setSelectedRecord(null)}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <MapPin className="h-5 w-5 text-blue-600" />
              Location Details
            </DialogTitle>
            <DialogDescription>
              Check-in and check-out location information
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 py-4">
            {/* Check-in Location */}
            <div className="space-y-3">
              <div className="flex items-center gap-2">
                <div className="h-3 w-3 rounded-full bg-green-500"></div>
                <h3 className="font-semibold text-base">Check-in Location</h3>
              </div>
              <div className="bg-green-50 dark:bg-green-950/20 border-2 border-green-200 dark:border-green-800 rounded-xl p-4">
                <div className="flex items-start gap-3">
                  <MapPin className="h-5 w-5 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
                  <div className="flex-1">
                    <p className="text-sm font-medium text-green-900 dark:text-green-100 mb-1">
                      {formatAttendanceTime(selectedRecord?.date || '', selectedRecord?.checkInTime)}
                    </p>
                    <p className="text-sm text-green-700 dark:text-green-300 leading-relaxed">
                      {selectedRecord?.checkInLocation?.address || 'Location not available'}
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Check-out Location */}
            {selectedRecord?.checkOutTime ? (
              <div className="space-y-3">
                <div className="flex items-center gap-2">
                  <div className="h-3 w-3 rounded-full bg-red-500"></div>
                  <h3 className="font-semibold text-base">Check-out Location</h3>
                </div>
                <div className="bg-red-50 dark:bg-red-950/20 border-2 border-red-200 dark:border-red-800 rounded-xl p-4">
                  <div className="flex items-start gap-3">
                    <MapPin className="h-5 w-5 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                    <div className="flex-1">
                      <p className="text-sm font-medium text-red-900 dark:text-red-100 mb-1">
                        {formatAttendanceTime(selectedRecord?.date || '', selectedRecord?.checkOutTime)}
                      </p>
                      <p className="text-sm text-red-700 dark:text-red-300 leading-relaxed">
                        {selectedRecord?.checkOutLocation?.address || 'Location not available'}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-3">
                <div className="flex items-center gap-2">
                  <div className="h-3 w-3 rounded-full bg-slate-400"></div>
                  <h3 className="font-semibold text-base">Check-out Location</h3>
                </div>
                <div className="bg-slate-50 dark:bg-slate-900/20 border-2 border-slate-200 dark:border-slate-700 rounded-xl p-4">
                  <p className="text-sm text-slate-600 dark:text-slate-400 text-center py-2">
                    User has not checked out yet
                  </p>
                </div>
              </div>
            )}
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setSelectedRecord(null)}
              className="gap-2"
            >
              <X className="h-4 w-4" />
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      {/* Work Summary Dialog */}
      <Dialog open={showWorkSummaryDialog} onOpenChange={setShowWorkSummaryDialog}>
        <DialogContent className="sm:max-w-[600px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5 text-blue-600" />
              Attendance Details
            </DialogTitle>
            <DialogDescription>
              Detailed work summary and overdue reasons for the selected record
            </DialogDescription>
          </DialogHeader>

          <div className="py-2 space-y-4">
            <div className="bg-slate-50 dark:bg-slate-900 rounded-lg p-4 border">
              <h4 className="font-medium text-sm text-slate-700 dark:text-slate-300 mb-2">Work Summary</h4>
              <div className="text-sm text-slate-900 dark:text-slate-100 leading-relaxed whitespace-pre-wrap">
                {selectedWorkSummary || 'No work summary provided'}
              </div>
            </div>

            {selectedOverdueReason && (
              <div className="bg-orange-50 dark:bg-orange-950/20 rounded-lg p-4 border border-orange-200 dark:border-orange-800">
                <h4 className="font-medium text-sm text-orange-700 dark:text-orange-300 mb-2">Overdue Reason</h4>
                <div className="text-sm text-slate-900 dark:text-slate-100 leading-relaxed whitespace-pre-wrap">
                  {selectedOverdueReason}
                </div>
              </div>
            )}
          </div>

          <div className="flex justify-end">
            <Button variant="outline" onClick={() => setShowWorkSummaryDialog(false)}>
              Close
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Location Details Dialog */}
      <Dialog open={showLocationDialog} onOpenChange={setShowLocationDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <MapPin className="h-5 w-5 text-blue-600" />
              Location Details
            </DialogTitle>
            <DialogDescription>
              Check-in and check-out location information
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            {/* Check-in Location */}
            {selectedLocation.checkIn && (
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <div className="h-3 w-3 rounded-full bg-green-500"></div>
                  <h4 className="font-medium text-sm">Check-in Location</h4>
                </div>
                <div className="bg-green-50 dark:bg-green-950/20 border border-green-200 dark:border-green-800 rounded-lg p-3">
                  <div className="flex items-start gap-2">
                    <MapPin className="h-4 w-4 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
                    <p className="text-sm text-green-800 dark:text-green-200 leading-relaxed">
                      {selectedLocation.checkIn}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Check-out Location */}
            {selectedLocation.checkOut && selectedLocation.checkOut !== selectedLocation.checkIn && (
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <div className="h-3 w-3 rounded-full bg-red-500"></div>
                  <h4 className="font-medium text-sm">Check-out Location</h4>
                </div>
                <div className="bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-lg p-3">
                  <div className="flex items-start gap-2">
                    <MapPin className="h-4 w-4 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                    <p className="text-sm text-red-800 dark:text-red-200 leading-relaxed">
                      {selectedLocation.checkOut}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Same location message */}
            {selectedLocation.checkOut && selectedLocation.checkOut === selectedLocation.checkIn && (
              <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-800 rounded-lg p-3">
                <div className="flex items-center gap-2">
                  <MapPin className="h-4 w-4 text-blue-600 dark:text-blue-400" />
                  <p className="text-sm text-blue-800 dark:text-blue-200">
                    Same location used for both check-in and check-out
                  </p>
                </div>
              </div>
            )}
          </div>

          <div className="flex justify-end">
            <Button variant="outline" onClick={() => setShowLocationDialog(false)}>
              Close
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* WFH Request Rejection Dialog */}
      <Dialog open={showWfhRequestDialog} onOpenChange={setShowWfhRequestDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <X className="h-5 w-5 text-red-600" />
              Reject WFH Request
            </DialogTitle>
            <DialogDescription>
              Please provide a reason for rejecting this work from home request.
            </DialogDescription>
          </DialogHeader>

          {selectedWfhRequest && (
            <div className="space-y-4 py-4">
              <div className="bg-slate-50 dark:bg-slate-900 rounded-lg p-4 border">
                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <User className="h-4 w-4 text-blue-600" />
                    <span className="font-medium">{selectedWfhRequest.submittedBy}</span>
                    <Badge variant="outline" className="text-xs">
                      {formatRoleDisplay(selectedWfhRequest.role)}
                    </Badge>
                  </div>
                  <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-green-600" />
                    <span className="text-sm">
                      {formatDateIST(selectedWfhRequest.startDate, 'dd MMM yyyy')} - {formatDateIST(selectedWfhRequest.endDate, 'dd MMM yyyy')}
                    </span>
                  </div>
                  <p className="text-sm text-muted-foreground break-words overflow-wrap-anywhere whitespace-pre-wrap">{selectedWfhRequest.reason}</p>
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="rejection-reason">Rejection Reason <span className="text-red-500">*</span></Label>
                <Textarea
                  id="rejection-reason"
                  placeholder="Please provide a clear reason for rejecting this request."
                  value={selectedWfhRequest?.rejectionReason || ''}
                  rows={3}
                  className="resize-none"
                  onChange={(e) => {
                    setSelectedWfhRequest(prev => prev ? { ...prev, rejectionReason: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') } : null);
                  }}
                />
              </div>
            </div>
          )}

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setShowWfhRequestDialog(false);
                setSelectedWfhRequest(null);
              }}
              disabled={isProcessingWfhRequest}
            >
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={() => {
                if (selectedWfhRequest?.rejectionReason?.trim()) {
                  handleWfhRequestAction(selectedWfhRequest.id, 'reject', selectedWfhRequest.rejectionReason);
                } else {
                  toast({
                    title: 'Rejection Reason Required',
                    description: 'Please provide a reason for rejecting this request.',
                    variant: 'destructive',
                  });
                }
              }}
              disabled={isProcessingWfhRequest || !selectedWfhRequest?.rejectionReason?.trim()}
            >
              {isProcessingWfhRequest ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Rejecting...
                </>
              ) : (
                <>
                  <X className="h-4 w-4 mr-2" />
                  Reject Request
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Clear All WFH Requests Confirmation Dialog */}
      <AlertDialog open={showClearConfirmation} onOpenChange={setShowClearConfirmation}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Clear All WFH Requests</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to clear all requests? All pending requests will be automatically rejected.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                // Clear all WFH requests from the UI
                setAllWfhRequests([]);
                setShowClearConfirmation(false);
                toast({
                  title: 'Requests Cleared',
                  description: 'All WFH requests have been cleared and marked as rejected.',
                });
              }}
              className="bg-red-600 hover:bg-red-700"
            >
              Clear All
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Edit WFH Request Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Edit WFH Request</DialogTitle>
            <DialogDescription>Update your work from home request details</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className={wfhType === 'half_day' ? 'space-y-2' : 'grid grid-cols-2 gap-4'}>
              <div className="space-y-2">
                <Label>{wfhType === 'half_day' ? 'Date *' : 'Start Date *'}</Label>
                <DatePicker
                  date={wfhStartDate}
                  onDateChange={(date) => {
                    setWfhStartDate(date);
                    if (date && (!wfhEndDate || wfhEndDate < date)) {
                      setWfhEndDate(date);
                    }
                  }}
                  placeholder="Select date"
                  disablePastDates={true}
                  fromDate={getTodayISTDate()}
                />
              </div>
              {wfhType === 'full_day' && (
                <div className="space-y-2">
                  <Label>End Date *</Label>
                  <DatePicker
                    date={wfhEndDate}
                    onDateChange={setWfhEndDate}
                    placeholder="Select end date"
                    disablePastDates={true}
                    fromDate={wfhStartDate || getTodayISTDate()}
                  />
                </div>
              )}
            </div>
            {/* edit-wfh-type removed as per request */}

            <div className="space-y-2">
              <Label htmlFor="edit-wfh-reason">Reason *</Label>
              <Textarea
                id="edit-wfh-reason"
                placeholder="Enter reason for WFH request."
                value={wfhReason}
                onChange={(e) => setWfhReason(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                className="min-h-24"
              />
            </div>
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setIsEditDialogOpen(false);
                setEditingWfhId(null);
              }}
            >
              Cancel
            </Button>
            <Button
              onClick={handleUpdateWfh}
              disabled={isSubmittingWfh}
              className="bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700"
            >
              {isSubmittingWfh ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Updating...
                </>
              ) : (
                'Update Request'
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div >
  );
};

export default AttendanceWithToggle;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Send,
  Smile,
  Users,
  MessageCircle,
  X,
  Reply,
  MoreVertical,
  Check,
  CheckCheck,
  Edit,
  Trash2 as TrashIcon,
  AlertTriangle,
  Settings,
  UserPlus,
  UserMinus,
  LogOut,
  Info,
  Plus,
  Search
} from 'lucide-react';
import { useChat } from '@/contexts/ChatContext';
import { useAuth } from '@/contexts/AuthContext';
import { useTheme } from '@/contexts/ThemeContext';
import { useToast } from '@/hooks/use-toast';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { formatDateIST } from '@/utils/timezone';
import { cn } from '@/lib/utils';

import MessageBubble from '../../components/chat/MessageBubble';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Checkbox } from '@/components/ui/checkbox';
import { Textarea } from '@/components/ui/textarea';

const ChatBox: React.FC = () => {
  const { chatId } = useParams<{ chatId: string }>();
  const navigate = useNavigate();
  const {
    activeChat,
    messages,
    isLoading,
    sendMessage,
    setActiveChat,
    chats,
    availableUsers,
    markAsRead,
    sendTyping,
    deleteMessage,
    editMessage,
    updateGroupName,
    deleteGroup,
    addParticipants,
    removeParticipants
  } = useChat();
  const { user } = useAuth();
  const { themeMode } = useTheme();
  const { toast } = useToast();
  const [messageText, setMessageText] = useState('');

  const [replyingTo, setReplyingTo] = useState<string | null>(null);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [messageToDelete, setMessageToDelete] = useState<any>(null);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [messageToEdit, setMessageToEdit] = useState<any>(null);
  const [editText, setEditText] = useState('');
  const [isGroupSettingsOpen, setIsGroupSettingsOpen] = useState(false);
  const [isAddingMembers, setIsAddingMembers] = useState(false);
  const [newGroupName, setNewGroupName] = useState('');
  const [selectedNewUsers, setSelectedNewUsers] = useState<string[]>([]);
  const [isUpdatingGroup, setIsUpdatingGroup] = useState(false);
  const [isDeletingGroup, setIsDeletingGroup] = useState(false);
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const typingPulseRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);



  useEffect(() => {
    if (chatId && (!activeChat || activeChat.id !== chatId)) {
      const foundChat = chats.find(chat => chat.id?.toString() === chatId?.toString());
      if (foundChat) {
        setActiveChat(foundChat);
      }
    }
  }, [chatId, activeChat, chats, setActiveChat]);

  useEffect(() => {
    if (activeChat && messages.length > 0) {
      const unreadMessageIds = messages
        .filter(m => !m.isRead && m.senderId?.toString() !== user?.id?.toString())
        .map(m => m.id);

      if (unreadMessageIds.length > 0) {
        markAsRead(activeChat.id, unreadMessageIds);
      }
    }
  }, [activeChat, messages, markAsRead, user?.id]);

  const handleTyping = () => {
    if (!activeChat) return;
    if (typingPulseRef.current) return;
    sendTyping(activeChat.id);
    typingPulseRef.current = setTimeout(() => {
      typingPulseRef.current = null;
    }, 2000);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const sanitizedValue = e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '');
    setMessageText(sanitizedValue);
    handleTyping();
  };

  const handleSendMessage = async () => {
    if (!messageText.trim() || !activeChat) return;
    try {
      await sendMessage(messageText, 'text', replyingTo || undefined);
      setMessageText('');
      setReplyingTo(null);

    } catch (error) {
      console.error('Failed to send message:', error);
    }
  };

  const handleEditClick = (message: any) => {
    // Check if within 2 minutes
    const sentTime = new Date(message.timestamp).getTime();
    const now = new Date().getTime();
    const diffMins = (now - sentTime) / (1000 * 60);

    if (diffMins > 2) {
      toast({
        title: "Edit restricted",
        description: "Messages can only be edited within 2 minutes of sending.",
        variant: "destructive"
      });
      return;
    }

    setMessageToEdit(message);
    setEditText(message.content);
    setIsEditDialogOpen(true);
  };

  const handleConfirmEdit = async () => {
    if (!messageToEdit || !editText.trim()) return;
    try {
      await editMessage(messageToEdit.id, editText);
      setIsEditDialogOpen(false);
      setMessageToEdit(null);
      setEditText('');
    } catch (error) {
      console.error('Failed to edit message:', error);
    }
  };

  const handleDeleteClick = (message: any) => {
    // Check if within 5 minutes
    const sentTime = new Date(message.timestamp).getTime();
    const now = new Date().getTime();
    const diffMins = (now - sentTime) / (1000 * 60);

    if (diffMins > 5) {
      toast({
        title: "Delete restricted",
        description: "Messages can only be deleted within 5 minutes of sending.",
        variant: "destructive"
      });
      return;
    }

    setMessageToDelete(message);
    setIsDeleteDialogOpen(true);
  };

  const handleConfirmDelete = async () => {
    if (!messageToDelete) return;
    try {
      await deleteMessage(messageToDelete.id);
      setIsDeleteDialogOpen(false);
      setMessageToDelete(null);
    } catch (error) {
      console.error('Failed to delete message:', error);
    }
  };

  const handleUpdateGroupName = async () => {
    if (!activeChat || !newGroupName.trim() || newGroupName === activeChat.name) return;
    setIsUpdatingGroup(true);
    try {
      await updateGroupName(activeChat.id, newGroupName);
      setIsGroupSettingsOpen(false);
    } catch (error) {
      console.error('Failed to update group name:', error);
    } finally {
      setIsUpdatingGroup(false);
    }
  };

  const handleDeleteGroup = async () => {
    if (!activeChat) return;
    try {
      await deleteGroup(activeChat.id);
      setIsGroupSettingsOpen(false);
      setIsDeletingGroup(false);
      navigate(`/${user?.role}/chat`);
    } catch (error) {
      console.error('Failed to delete group:', error);
    }
  };

  const handleAddMembers = async () => {
    if (!activeChat || selectedNewUsers.length === 0) return;
    setIsUpdatingGroup(true);
    try {
      await addParticipants(activeChat.id, selectedNewUsers);
      setSelectedNewUsers([]);
      setIsAddingMembers(false);
    } catch (error) {
      console.error('Failed to add members:', error);
    } finally {
      setIsUpdatingGroup(false);
    }
  };

  const handleRemoveMember = async (userId: string) => {
    if (!activeChat) return;
    try {
      await removeParticipants(activeChat.id, [userId]);
    } catch (error) {
      console.error('Failed to remove member:', error);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };



  const chatName = useMemo(() => {
    if (!activeChat) return '';
    if (activeChat.name && activeChat.name !== 'string' && activeChat.name !== 'null') return activeChat.name;
    const currentUserId = user?.id?.toString();
    const otherParticipant = activeChat.participants?.find((p: any) => p.userId?.toString() !== currentUserId);
    if (otherParticipant) {
      const u = availableUsers?.find(u => u.id?.toString() === otherParticipant.userId?.toString());
      return u?.name || otherParticipant.userName || 'Chat User';
    }
    return activeChat.type === 'group' ? 'Group Chat' : 'Chat User';
  }, [activeChat, availableUsers, user]);

  const chatAvatar = useMemo(() => {
    if (!activeChat) return '';
    if (activeChat.type === 'group') return activeChat.groupAvatar || '';
    const currentUserId = user?.id?.toString();
    const otherParticipant = activeChat.participants?.find((p: any) => p.userId?.toString() !== currentUserId);
    if (otherParticipant && availableUsers) {
      const userData = availableUsers.find(u => u.id?.toString() === otherParticipant.userId?.toString());
      return userData?.profilePhoto || '';
    }
    return '';
  }, [activeChat, availableUsers, user]);

  const enrichedMessages = useMemo(() => {
    return messages.map(msg => {
      const isOwn = msg.senderId?.toString() === user?.id?.toString();
      if (isOwn) {
        return {
          ...msg,
          senderName: 'You',
          senderRole: user?.role,
          senderAvatar: user?.profilePhoto
        };
      }

      const userDetails = availableUsers?.find(u => u.id?.toString() === msg.senderId?.toString());
      const participantDetails = activeChat?.participants?.find(p => p.userId?.toString() === msg.senderId?.toString());

      return {
        ...msg,
        senderName: userDetails?.name || participantDetails?.userName || msg.senderName || 'Team Member',
        senderRole: userDetails?.role || participantDetails?.userRole || msg.senderRole || 'employee',
        senderAvatar: userDetails?.profilePhoto || msg.senderAvatar
      };
    });
  }, [messages, availableUsers, activeChat, user]);

  const isDark = themeMode === 'dark' || (themeMode === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  const themeClasses = {
    background: isDark ? 'bg-[#0a1628]' : 'bg-white',
    headerBg: isDark ? 'bg-[#0f172a]' : 'bg-gray-50/50',
    inputBg: isDark ? 'bg-[#0f172a]' : 'bg-gray-50/50',
    inputFieldBg: isDark ? 'bg-[#1e293b]' : 'bg-white',
    text: isDark ? 'text-slate-100' : 'text-slate-900',
    textSecondary: isDark ? 'text-slate-400' : 'text-slate-500',
    border: isDark ? 'border-slate-800' : 'border-slate-100',
  };

  if (isLoading && !activeChat) {
    return (
      <div className={cn("flex items-center justify-center h-full", themeClasses.background)}>
        <div className="flex flex-col items-center gap-3">
          <div className="animate-spin rounded-full h-10 w-10 border-4 border-green-500 border-t-transparent shadow-lg shadow-green-500/20"></div>
          <p className={cn("text-xs font-bold uppercase tracking-widest opacity-50", themeClasses.text)}>Loading Session...</p>
        </div>
      </div>
    );
  }

  if (!activeChat) return null;

  return (
    <div className={cn("flex flex-col h-full relative overflow-hidden", themeClasses.background)}>
      {/* Dynamic Background Patterns */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.03] dark:opacity-[0.05]">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(#22c55e_1px,transparent_1px)] [background-size:24px_24px]" />
      </div>

      {/* Modern Header */}
      <div className={cn(
        "flex-shrink-0 flex items-center justify-between p-3.5 px-6 relative z-10 border-b transition-colors",
        themeClasses.headerBg,
        themeClasses.border
      )}>
        <div className="flex items-center space-x-3.5">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => navigate(`/${user?.role}/chat`)}
            className="sm:hidden p-2 rounded-full hover:bg-slate-200/50 dark:hover:bg-slate-800/50"
          >
            <ArrowLeft className={cn("h-5 w-5", themeClasses.text)} />
          </Button>

          <div className="relative group">
            <Avatar className="h-10 w-10 border shadow-lg shadow-green-500/5 group-hover:scale-105 transition-transform">
              <AvatarImage src={chatAvatar} />
              <AvatarFallback className="bg-gradient-to-br from-green-500 to-green-600 text-white font-black text-xs">{chatName.charAt(0).toUpperCase()}</AvatarFallback>
            </Avatar>
            <div className="absolute -bottom-0.5 -right-0.5 h-3 w-3 bg-green-500 border-2 border-white dark:border-[#0f172a] rounded-full shadow-sm" />
          </div>

          <div className="flex-1 min-w-0">
            <h2 className={cn("font-black truncate text-[15px] tracking-tight leading-none", themeClasses.text)}>{chatName}</h2>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="h-1.5 w-1.5 rounded-full bg-green-500 animate-pulse" />
              <p className="text-[10px] font-black text-green-500 uppercase tracking-widest leading-none">
                Online
              </p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-1">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" size="icon" className="rounded-full text-slate-400 hover:text-green-500 hover:bg-green-500/10 transition-colors">
                <MoreVertical className="h-5 w-5" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-56 rounded-2xl border-2 shadow-xl p-2">
              <DropdownMenuLabel className="flex items-center gap-2 px-3 py-2 text-[10px] font-black uppercase tracking-widest text-slate-500">
                <Info className="h-3 w-3" />
                Chat Options
              </DropdownMenuLabel>
              <DropdownMenuSeparator />
              {activeChat.type === 'group' && (
                <>
                  <DropdownMenuItem
                    onClick={() => {
                      setNewGroupName(activeChat.name || '');
                      setIsGroupSettingsOpen(true);
                    }}
                    className="flex items-center gap-3 px-3 py-2.5 rounded-xl cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                  >
                    <Settings className="h-4 w-4 text-slate-500" />
                    <span className="font-bold text-sm">Group Settings</span>
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    onClick={() => {
                      setSelectedNewUsers([]);
                      setIsAddingMembers(true);
                    }}
                    className="flex items-center gap-3 px-3 py-2.5 rounded-xl cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                  >
                    <UserPlus className="h-4 w-4 text-slate-500" />
                    <span className="font-bold text-sm">Add Members</span>
                  </DropdownMenuItem>
                </>
              )}
              <DropdownMenuItem
                onClick={() => navigate(`/${user?.role}/chat`)}
                className="flex items-center gap-3 px-3 py-2.5 rounded-xl cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
              >
                <LogOut className="h-4 w-4 text-slate-500" />
                <span className="font-bold text-sm">Exit Chat</span>
              </DropdownMenuItem>
              {activeChat.type === 'group' && activeChat.participants.find(p => p.userId === user?.id)?.isAdmin && (
                <>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    onClick={() => setIsDeletingGroup(true)}
                    className="flex items-center gap-3 px-3 py-2.5 rounded-xl cursor-pointer text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 transition-colors"
                  >
                    <TrashIcon className="h-4 w-4" />
                    <span className="font-bold text-sm">Delete Group</span>
                  </DropdownMenuItem>
                </>
              )}
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>

      {/* Messages Scroll Area */}
      <div className="flex-1 min-h-0 overflow-y-auto px-6 py-6 relative z-10 custom-scrollbar">
        {enrichedMessages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full space-y-4 animate-in fade-in zoom-in duration-500">
            <div className="p-6 rounded-full bg-slate-100 dark:bg-slate-800/40 text-slate-400">
              <MessageCircle className="h-12 w-12 opacity-50" />
            </div>
            <div className="text-center">
              <p className={cn("text-base font-bold", themeClasses.text)}>No messages yet</p>
              <p className={cn("text-xs opacity-60", themeClasses.textSecondary)}>Start the conversation with your team member</p>
            </div>
          </div>
        ) : (
          <div className="space-y-4 pb-4">
            {enrichedMessages.map((message, index) => {
              const showDateSeparator = index === 0 || formatDateIST(message.timestamp, 'yyyy-MM-dd') !== formatDateIST(enrichedMessages[index - 1].timestamp, 'yyyy-MM-dd');
              return (
                <div key={message.id} className="animate-in slide-in-from-bottom-2 fade-in duration-300">
                  {showDateSeparator && (
                    <div className="flex justify-center my-8 relative">
                      <div className="absolute inset-0 flex items-center" aria-hidden="true">
                        <div className="w-full border-t border-slate-100 dark:border-slate-800/50"></div>
                      </div>
                      <span className={cn(
                        "relative text-[10px] uppercase tracking-widest font-black px-4 py-1.5 rounded-full border shadow-sm backdrop-blur-md",
                        isDark ? "bg-[#0f172a] border-slate-800 text-slate-400" : "bg-white border-slate-100 text-slate-500"
                      )}>
                        {formatDateIST(message.timestamp, 'MMMM d, yyyy')}
                      </span>
                    </div>
                  )}
                  <MessageBubble
                    message={message}
                    isOwn={message.senderId?.toString() === user?.id?.toString()}
                    onReply={() => setReplyingTo(message.id)}
                    onEdit={() => handleEditClick(message)}
                    onDelete={() => handleDeleteClick(message)}
                    replyMessage={message.replyTo ? enrichedMessages.find(m => m.id === message.replyTo) : undefined}
                  />
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* Input Section */}
      <div className={cn("p-4 px-6 relative z-20 transition-all", themeClasses.inputBg)}>
        {replyingTo && (
          <div className={cn(
            "flex items-center justify-between p-3.5 border-l-[3.5px] border-lime-500 mb-4 rounded-r-2xl animate-in slide-in-from-bottom-4 fade-in duration-300 shadow-sm transition-all",
            isDark ? "bg-[#1a1b1e]/80" : "bg-slate-50/80"
          )}>
            <div className="min-w-0 pr-6">
              <div className="flex items-center gap-2 mb-1">
                <Reply className="h-3 w-3 text-lime-500" />
                <p className="text-[10px] text-lime-600 dark:text-lime-500 font-black uppercase tracking-widest">
                  Replying to {enrichedMessages.find(m => m.id === replyingTo)?.senderName || 'Message'}
                </p>
              </div>
              <p className={cn("text-[13px] truncate opacity-80 font-medium italic", themeClasses.text)}>
                "{enrichedMessages.find(m => m.id === replyingTo)?.content}"
              </p>
            </div>
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 rounded-full hover:bg-red-500/10 hover:text-red-500 transition-all active:scale-90"
              onClick={() => setReplyingTo(null)}
            >
              <X className="h-4.5 w-4.5" />
            </Button>
          </div>
        )}

        <div className="flex items-end space-x-3">
          <div className={cn(
            "flex-1 relative rounded-[28px] px-4 py-1.5 flex items-center transition-all shadow-lg ring-1 ring-slate-200 dark:ring-slate-800 focus-within:ring-green-500/50",
            themeClasses.inputFieldBg
          )}>

            <Input
              ref={inputRef}
              value={messageText}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              placeholder="Type your message..."
              className="border-0 bg-transparent focus-visible:ring-0 shadow-none text-[15px] h-11 placeholder:text-slate-400 dark:placeholder:text-slate-500 font-medium"
            />


          </div>

          <Button
            onClick={handleSendMessage}
            disabled={!messageText.trim()}
            className={cn(
              "rounded-full h-[52px] w-[52px] shadow-xl transition-all hover:scale-105 active:scale-95 p-0",
              messageText.trim() ? "bg-green-500 hover:bg-green-600 shadow-green-500/20" : "bg-slate-100 dark:bg-slate-800 text-slate-400"
            )}
          >
            <Send className={cn("h-5 w-5 transition-transform", messageText.trim() && "translate-x-0.5 -translate-y-0.5 rotate-[-15deg]")} />
          </Button>
        </div>


      </div>

      {/* Custom Confirmation Dialog for Deletion */}
      <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <AlertDialogContent className="border-2 shadow-2xl">
          <AlertDialogHeader>
            <div className="flex items-center gap-3 mb-2">
              <div className="h-10 w-10 rounded-full bg-red-100 flex items-center justify-center text-red-600">
                <AlertTriangle className="h-6 w-6" />
              </div>
              <AlertDialogTitle className="text-xl font-bold">Delete Message?</AlertDialogTitle>
            </div>
            <AlertDialogDescription className="text-slate-600 dark:text-slate-400">
              Are you sure you want to delete this message? This action cannot be undone and the message will be removed for everyone in the chat.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="gap-2 sm:gap-0">
            <AlertDialogCancel className="font-bold border-2">Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              className="bg-red-600 hover:bg-red-700 text-white font-bold"
            >
              Delete for Everyone
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Small Edit Form Modal */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="sm:max-w-[425px] border-2 shadow-2xl">
          <DialogHeader>
            <div className="flex items-center gap-3 mb-2">
              <div className="h-10 w-10 rounded-full bg-amber-100 flex items-center justify-center text-amber-600">
                <Edit className="h-5 w-5" />
              </div>
              <DialogTitle className="text-xl font-bold">Edit Message</DialogTitle>
            </div>
            <DialogDescription className="text-slate-600 dark:text-slate-400">
              Update your message content. Only the content will be changed.
            </DialogDescription>
          </DialogHeader>
          <div className="py-4">
            <Textarea
              value={editText}
              onChange={(e) => setEditText(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
              placeholder="Type updated message..."
              className="min-h-[100px] border-2 focus:ring-green-500/50 resize-none font-medium text-[15px]"
              autoFocus
            />
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsEditDialogOpen(false)}
              className="font-bold border-2"
            >
              Cancel
            </Button>
            <Button
              onClick={handleConfirmEdit}
              disabled={!editText.trim() || editText === messageToEdit?.content}
              className="bg-green-600 hover:bg-green-700 text-white font-bold min-w-[80px]"
            >
              Save Changes
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Group Settings Dialog */}
      <Dialog open={isGroupSettingsOpen} onOpenChange={setIsGroupSettingsOpen}>
        <DialogContent className="sm:max-w-[500px] border-2 shadow-2xl p-0 overflow-hidden rounded-[28px]">
          <DialogHeader className="p-6 pb-0">
            <div className="flex items-center gap-4 mb-2">
              <div className="h-12 w-12 rounded-2xl bg-green-500 shadow-lg shadow-green-500/20 flex items-center justify-center text-white">
                <Settings className="h-6 w-6" />
              </div>
              <div>
                <DialogTitle className="text-2xl font-black tracking-tight">Group Settings</DialogTitle>
                <DialogDescription className="font-medium">Manage members and group identity</DialogDescription>
              </div>
            </div>
          </DialogHeader>

          <div className="p-6 space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Group Name</label>
              <div className="flex gap-2">
                <Input
                  value={newGroupName}
                  onChange={(e) => setNewGroupName(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                  className="rounded-xl border-2 font-bold"
                  placeholder="Enter group name"
                />
                <Button
                  onClick={handleUpdateGroupName}
                  disabled={isUpdatingGroup || !newGroupName.trim() || newGroupName === activeChat?.name}
                  className="bg-green-500 hover:bg-green-600 text-white font-black rounded-xl"
                >
                  {isUpdatingGroup ? '...' : 'Update'}
                </Button>
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between px-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Members ({activeChat?.participants.length})</label>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setIsAddingMembers(true)}
                  className="h-7 px-2 text-[10px] font-black text-green-600 hover:bg-green-50 rounded-lg uppercase tracking-wider"
                >
                  <Plus className="h-3 w-3 mr-1" /> Add New
                </Button>
              </div>

              <ScrollArea className="h-[200px] rounded-2xl border-2 p-2">
                <div className="space-y-1">
                  {activeChat?.participants.map((p) => (
                    <div key={p.userId} className="flex items-center justify-between p-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors group">
                      <div className="flex items-center gap-3">
                        <Avatar className="h-9 w-9">
                          <AvatarImage src={availableUsers.find(u => u.id === p.userId)?.profilePhoto} />
                          <AvatarFallback className="bg-slate-100 font-bold text-xs">{p.userName.charAt(0)}</AvatarFallback>
                        </Avatar>
                        <div>
                          <p className="text-sm font-bold leading-none mb-1">{p.userName} {p.userId === user?.id && <span className="text-[10px] text-green-500 font-black ml-1">(You)</span>}</p>
                          <p className="text-[10px] font-medium text-slate-500 uppercase tracking-tighter">{p.department} • {p.userRole}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {p.isAdmin && (
                          <Badge variant="outline" className="text-[8px] font-black uppercase bg-amber-50 text-amber-600 border-amber-200">Admin</Badge>
                        )}
                        {activeChat.participants.find(part => part.userId === user?.id)?.isAdmin && p.userId !== user?.id && (
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleRemoveMember(p.userId)}
                            className="h-8 w-8 rounded-full text-slate-300 hover:text-red-500 hover:bg-red-50 opacity-0 group-hover:opacity-100 transition-all"
                          >
                            <UserMinus className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </ScrollArea>
            </div>
          </div>

          <div className="p-6 bg-slate-50 dark:bg-slate-900 border-t mt-auto">
            <Button
              variant="outline"
              className="w-full rounded-xl font-bold border-2"
              onClick={() => setIsGroupSettingsOpen(false)}
            >
              Close Settings
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Add Members Dialog */}
      <Dialog open={isAddingMembers} onOpenChange={setIsAddingMembers}>
        <DialogContent className="sm:max-w-[450px] border-2 shadow-2xl p-0 overflow-hidden rounded-[28px]">
          <DialogHeader className="p-6 pb-0">
            <div className="flex items-center gap-4 mb-2">
              <div className="h-12 w-12 rounded-2xl bg-blue-500 shadow-lg shadow-blue-500/20 flex items-center justify-center text-white">
                <UserPlus className="h-6 w-6" />
              </div>
              <div>
                <DialogTitle className="text-2xl font-black tracking-tight">Add Members</DialogTitle>
                <DialogDescription className="font-medium">Invite teammates to this group</DialogDescription>
              </div>
            </div>
          </DialogHeader>

          <div className="p-6 space-y-4">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <Input
                placeholder="Search teammates..."
                className="pl-9 h-11 rounded-xl border-2"
                value={memberSearchTerm}
                onChange={(e) => setMemberSearchTerm(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
              />
            </div>

            <ScrollArea className="h-[250px] rounded-2xl border-2 p-2">
              <div className="space-y-1">
                {availableUsers
                  .filter(u =>
                    !activeChat?.participants.some(p => p.userId === u.id) &&
                    (u.name.toLowerCase().includes(memberSearchTerm.toLowerCase()) ||
                      u.department.toLowerCase().includes(memberSearchTerm.toLowerCase()))
                  )
                  .map((u) => (
                    <div
                      key={u.id}
                      className={cn(
                        "flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all",
                        selectedNewUsers.includes(u.id) ? "bg-blue-500/10 border border-blue-200" : "hover:bg-slate-50 dark:hover:bg-slate-800"
                      )}
                      onClick={() => {
                        setSelectedNewUsers(prev => prev.includes(u.id) ? prev.filter(id => id !== u.id) : [...prev, u.id]);
                      }}
                    >
                      <div className="flex items-center gap-3">
                        <Avatar className="h-9 w-9">
                          <AvatarImage src={u.profilePhoto} />
                          <AvatarFallback className="bg-slate-100 font-bold text-xs">{u.name.charAt(0)}</AvatarFallback>
                        </Avatar>
                        <div>
                          <p className="text-sm font-bold leading-none mb-1">{u.name}</p>
                          <p className="text-[10px] font-medium text-slate-500 uppercase tracking-tighter">{u.department} • {u.role}</p>
                        </div>
                      </div>
                      <Checkbox checked={selectedNewUsers.includes(u.id)} onCheckedChange={() => { }} />
                    </div>
                  ))}
              </div>
            </ScrollArea>
          </div>

          <div className="p-6 flex gap-3 border-t">
            <Button variant="outline" className="flex-1 rounded-xl font-bold border-2" onClick={() => setIsAddingMembers(false)}>Cancel</Button>
            <Button
              className="flex-1 rounded-xl font-black bg-blue-500 hover:bg-blue-600 text-white"
              onClick={handleAddMembers}
              disabled={selectedNewUsers.length === 0 || isUpdatingGroup}
            >
              {isUpdatingGroup ? 'Adding...' : `Add ${selectedNewUsers.length} Members`}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Group Confirmation */}
      <AlertDialog open={isDeletingGroup} onOpenChange={setIsDeletingGroup}>
        <AlertDialogContent className="border-2 shadow-2xl rounded-[28px]">
          <AlertDialogHeader>
            <div className="flex items-center gap-4 mb-2">
              <div className="h-12 w-12 rounded-2xl bg-red-100 flex items-center justify-center text-red-600">
                <TrashIcon className="h-6 w-6" />
              </div>
              <div>
                <AlertDialogTitle className="text-2xl font-black tracking-tight text-red-600">Delete Group?</AlertDialogTitle>
                <AlertDialogDescription className="font-medium text-slate-600">
                  This will permanently delete the group <span className="font-black text-slate-900">"{activeChat?.name}"</span> and all its message history for everyone.
                </AlertDialogDescription>
              </div>
            </div>
          </AlertDialogHeader>
          <AlertDialogFooter className="gap-3 sm:gap-0 mt-4">
            <AlertDialogCancel className="font-bold border-2 rounded-xl h-11">Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteGroup}
              className="bg-red-600 hover:bg-red-700 text-white font-black rounded-xl h-11"
            >
              Yes, Delete Permanently
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default ChatBox;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Plus, Search, Users, MessageCircle, Settings2 } from 'lucide-react';
import { useChat } from '@/contexts/ChatContext';
import { useAuth } from '@/contexts/AuthContext';
import { useTheme } from '@/contexts/ThemeContext';
import { chatService } from '@/services/chatService';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { formatChatTimestampIST } from '@/utils/timezone';
import { cn } from '@/lib/utils';
import AddChatModal from '../../components/chat/AddChatModal';
import ChatTypeSelectorModal from '../../components/chat/ChatTypeSelectorModal';

const ChatList: React.FC = () => {
  const navigate = useNavigate();
  const { chatId: activeChatId } = useParams();
  const { chats, isLoading, setActiveChat, availableUsers } = useChat();
  const { user } = useAuth();
  const { themeMode } = useTheme();
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddChatModal, setShowAddChatModal] = useState(false);
  const [showTypeSelector, setShowTypeSelector] = useState(false);
  const [selectedType, setSelectedType] = useState<'individual' | 'group'>('individual');
  const [filter, setFilter] = useState<'all' | 'individual' | 'group'>('all');

  const permissions = user ? chatService.getChatPermissions(user.role) : null;
  const isDark = themeMode === 'dark' || (themeMode === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  const themeClasses = {
    background: isDark ? 'bg-[#0a1628]' : 'bg-white',
    headerBg: isDark ? 'bg-[#0f172a]' : 'bg-gray-50/50',
    inputBg: isDark ? 'bg-gray-800/50' : 'bg-gray-100/50',
    text: isDark ? 'text-slate-100' : 'text-slate-900',
    textSecondary: isDark ? 'text-slate-400' : 'text-slate-500',
    border: isDark ? 'border-slate-800' : 'border-slate-100',
    activeBg: isDark ? 'bg-green-500/10' : 'bg-green-50',
    activeBorder: 'border-green-500/50',
  };

  const getChatName = (chat: any) => {
    if (chat.name && chat.name !== 'string' && chat.name !== 'null') return chat.name;
    if (chat.type === 'individual' || !chat.name) {
      const currentUserId = user?.id?.toString();
      const otherParticipant = chat.participants?.find((p: any) => p.userId?.toString() !== currentUserId);
      if (otherParticipant) {
        // Try to find in availableUsers
        const userDetails = availableUsers?.find(u => u.id?.toString() === otherParticipant.userId?.toString());
        if (userDetails?.name) return userDetails.name;

        // Fallback to participant userName if it exists
        if (otherParticipant.userName && otherParticipant.userName !== 'string') return otherParticipant.userName;

        // Final fallback: Use part of ID or "User {id}" to be more specific than "Chat User"
        return `User ${otherParticipant.userId}`;
      }
    }
    return chat.type === 'group' ? (chat.name || 'Group Chat') : 'Chat User';
  };

  const getChatAvatar = (chat: any) => {
    if (chat.type === 'group') return chat.groupAvatar || '';
    const currentUserId = user?.id?.toString();
    const otherParticipant = chat.participants?.find((p: any) => p.userId?.toString() !== currentUserId);
    if (otherParticipant && availableUsers) {
      const userData = availableUsers.find(u => u.id?.toString() === otherParticipant.userId?.toString());
      return userData?.profilePhoto || '';
    }
    return '';
  };

  // Show all chats from API without de-duplication - sorted by most recent
  const filteredChats = useMemo(() => {
    // Sort chats by updatedAt (most recent first)
    const sortedChats = [...chats].sort((a, b) => {
      const dateA = new Date(a.updatedAt || a.createdAt).getTime();
      const dateB = new Date(b.updatedAt || b.createdAt).getTime();
      return dateB - dateA;
    });

    return sortedChats.filter(chat => {
      // Type filter
      if (filter !== 'all' && chat.type !== filter) return false;

      // Search filter
      const name = getChatName(chat).toLowerCase();
      return name.includes(searchTerm.toLowerCase());
    });
  }, [chats, searchTerm, availableUsers, user, filter]);

  // Calculate counts directly from API response - no de-duplication
  const chatCounts = useMemo(() => {
    let individualCount = 0;
    let groupCount = 0;

    chats.forEach(chat => {
      if (chat.type === 'individual') {
        individualCount++;
      } else if (chat.type === 'group') {
        groupCount++;
      }
    });

    return {
      all: chats.length,
      individual: individualCount,
      group: groupCount
    };
  }, [chats]);

  const handleChatClick = (chat: any) => {
    setActiveChat(chat);
    navigate(`/${user?.role}/chat/${chat.id}`);
  };

  const getLastMessagePreview = (chat: any) => {
    if (!chat.lastMessage) return 'No messages yet';

    // If content is empty, show a placeholder
    const content = chat.lastMessage.content;
    if (!content || content.trim() === '') return 'No messages yet';

    let senderName = '';
    if (chat.type === 'group') {
      const isOwn = chat.lastMessage.senderId?.toString() === user?.id?.toString();
      if (isOwn) {
        senderName = 'You: ';
      } else {
        const senderId = chat.lastMessage.senderId?.toString();
        const userDetails = availableUsers?.find(u => u.id?.toString() === senderId);
        const participantDetails = chat.participants?.find((p: any) => p.userId?.toString() === senderId);
        senderName = `${userDetails?.name || participantDetails?.userName || 'Member'}: `;
      }
    }

    const fullPreview = `${senderName}${content}`;
    return fullPreview.length > 65 ? `${fullPreview.substring(0, 65)}...` : fullPreview;
  };

  if (isLoading && chats.length === 0) {
    return (
      <div className="flex flex-col h-full bg-inherit">
        <div className="p-6 space-y-4">
          <div className="flex justify-between items-center mb-6">
            <div className="h-8 w-24 bg-slate-200 dark:bg-slate-800 animate-pulse rounded-lg" />
            <div className="h-8 w-8 bg-slate-200 dark:bg-slate-800 animate-pulse rounded-full" />
          </div>
          {[1, 2, 3, 4, 5].map(i => (
            <div key={i} className="flex items-center space-x-3">
              <div className="h-12 w-12 bg-slate-200 dark:bg-slate-800 animate-pulse rounded-full" />
              <div className="flex-1 space-y-2">
                <div className="h-4 w-1/2 bg-slate-200 dark:bg-slate-800 animate-pulse rounded" />
                <div className="h-3 w-3/4 bg-slate-200 dark:bg-slate-800 animate-pulse rounded" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className={cn("flex flex-col h-full overflow-hidden", themeClasses.background)}>
      {/* Header Area */}
      <div className={cn("p-4 lg:p-5 border-b", themeClasses.headerBg, themeClasses.border)}>
        <div className="flex items-center justify-between mb-5">
          <div className="flex items-center gap-2.5">
            <div className="flex items-center justify-center h-9 w-9 rounded-xl bg-green-500 shadow-lg shadow-green-500/20">
              <MessageCircle className="h-4.5 w-4.5 text-white" />
            </div>
            <h1 className={cn("text-lg font-black tracking-tight", themeClasses.text)}>Messages</h1>
          </div>
          <Button
            variant="ghost"
            size="icon"
            onClick={() => setShowTypeSelector(true)}
            className="h-9 w-9 rounded-full hover:bg-green-500/10 hover:text-green-500 transition-colors"
          >
            <Plus className="h-4.5 w-4.5" />
          </Button>
        </div>

        <div className="relative group">
          <Search className={cn("absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 transition-colors",
            searchTerm ? "text-green-500" : themeClasses.textSecondary)} />
          <Input
            placeholder="Search team..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
            className={cn(
              "pl-9 pr-3 py-4.5 rounded-xl border-0 shadow-inner text-xs font-semibold focus-visible:ring-1 focus-visible:ring-green-500/30 transition-all",
              themeClasses.inputBg,
              themeClasses.text
            )}
          />
        </div>

        <div className="flex gap-2 mt-4 overflow-x-auto pb-1 custom-scrollbar-hide no-scrollbar">
          {[
            { id: 'all', label: 'All', icon: MessageCircle, count: chatCounts.all },
            { id: 'individual', label: 'Direct', icon: MessageCircle, count: chatCounts.individual },
            { id: 'group', label: 'Groups', icon: Users, count: chatCounts.group },
          ].map((type) => {
            const Icon = type.icon;
            const isSelected = filter === type.id;
            return (
              <button
                key={type.id}
                onClick={() => setFilter(type.id as any)}
                className={cn(
                  "flex items-center gap-2 px-3.5 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all duration-300 border flex-shrink-0 animate-in fade-in slide-in-from-left-2",
                  isSelected
                    ? "bg-green-500 border-green-500 text-white shadow-lg shadow-green-500/20"
                    : isDark
                      ? "bg-slate-800/40 border-slate-700/50 text-slate-400 hover:border-slate-600 hover:bg-slate-800/60"
                      : "bg-white border-slate-200 text-slate-500 hover:border-slate-300 hover:bg-gray-50"
                )}
              >
                <Icon className={cn("h-3 w-3", isSelected ? "text-white" : "text-green-500")} />
                <span>{type.label}</span>
                {type.count > 0 && (
                  <span className={cn(
                    "ml-1 px-1.5 py-0.5 rounded-md text-[9px] font-black",
                    isSelected ? "bg-white/20 text-white" : "bg-green-500/10 text-green-500"
                  )}>
                    {type.count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Conversations List */}
      <div className="flex-1 overflow-y-auto px-4 py-2 space-y-1 custom-scrollbar">
        {filteredChats.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-center px-4">
            <div className="p-5 rounded-2xl bg-slate-100 dark:bg-slate-800/50 mb-4">
              <Users className="h-10 w-10 text-slate-400" />
            </div>
            <p className={cn("text-sm font-semibold mb-1", themeClasses.text)}>No conversations</p>
            <p className={cn("text-xs leading-relaxed", themeClasses.textSecondary)}>
              Connect with your colleagues to start collaborating.
            </p>
          </div>
        ) : (
          filteredChats.map((chat) => {
            const isActive = activeChatId === chat.id?.toString();
            return (
              <div
                key={chat.id}
                onClick={() => handleChatClick(chat)}
                className={cn(
                  "flex items-center p-3 rounded-xl cursor-pointer transition-all duration-300 group relative border-transparent border",
                  isActive
                    ? cn(themeClasses.activeBg, themeClasses.activeBorder, "shadow-sm shadow-green-500/5")
                    : "hover:bg-slate-100 dark:hover:bg-slate-800/40"
                )}
              >
                {isActive && (
                  <div className="absolute left-0 top-1/4 bottom-1/4 w-1 bg-green-500 rounded-r-full" />
                )}

                <div className="relative flex-shrink-0">
                  <Avatar className={cn(
                    "h-10 w-10 border transition-transform duration-300 group-hover:scale-105",
                    isActive ? "border-green-500/40" : "border-slate-100 dark:border-slate-800"
                  )}>
                    <AvatarImage src={getChatAvatar(chat)} />
                    <AvatarFallback className="bg-gradient-to-br from-green-500 to-green-600 text-white font-black text-xs">
                      {getChatName(chat).charAt(0).toUpperCase()}
                    </AvatarFallback>
                  </Avatar>
                  <div className={cn(
                    "absolute -bottom-0.5 -right-0.5 h-3 w-3 border rounded-full",
                    isDark ? "border-[#0a1628]" : "border-white",
                    chat.type === 'group' ? "bg-indigo-500" : "bg-green-400"
                  )}>
                    {chat.type === 'group' && <Users className="h-1.5 w-1.5 text-white absolute inset-0 m-auto" />}
                  </div>
                </div>

                <div className="flex-1 ml-3 min-w-0">
                  <div className="flex items-center justify-between mb-0.5">
                    <h3 className={cn(
                      "font-bold truncate text-[13px] tracking-tight transition-colors",
                      isActive ? "text-green-500" : themeClasses.text
                    )}>
                      {getChatName(chat)}
                    </h3>
                    {chat.lastMessage && (
                      <span className={cn("text-[10px] font-medium opacity-50", themeClasses.textSecondary)}>
                        {formatChatTimestampIST(chat.lastMessage.timestamp)}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center justify-between">
                    <p className={cn("text-[11px] truncate font-medium max-w-[200px] lg:max-w-[280px]",
                      isActive ? "text-slate-500" : themeClasses.textSecondary)}>
                      {getLastMessagePreview(chat)}
                    </p>
                    {chat.unreadCount > 0 && (
                      <Badge className="h-4 min-w-[16px] px-1 bg-green-500 hover:bg-green-600 text-[9px] font-black pointer-events-none">
                        {chat.unreadCount}
                      </Badge>
                    )}
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      <ChatTypeSelectorModal
        isOpen={showTypeSelector}
        onClose={() => setShowTypeSelector(false)}
        onSelect={(type) => {
          setSelectedType(type);
          setShowTypeSelector(false);
          setShowAddChatModal(true);
        }}
        canCreateGroups={permissions?.canCreateGroups || false}
      />

      <AddChatModal
        isOpen={showAddChatModal}
        onClose={() => setShowAddChatModal(false)}
        permissions={permissions}
        initialTab={selectedType}
      />
    </div>
  );
};

export default ChatList;

import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from '@/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { Pagination } from '@/components/ui/pagination';
import { toast } from '@/hooks/use-toast';
import {
  Plus,
  Edit,
  Trash2,
  Building2,
  Users,
  Search,
  ChevronRight,
  Eye,
  Loader2,
  CheckCircle2,
  AlertCircle,
  Filter,
} from 'lucide-react';
import { Department } from '@/types';
import { useLanguage } from '@/contexts/LanguageContext';
import { formatDateIST } from '@/utils/timezone';
import { apiService, type Department as ApiDepartment } from '@/lib/api';

interface ExtendedDepartment extends Department {
  employeeCount?: number;
  location?: string;
}

interface ManagerOption {
  id: string;
  name: string;
  email?: string;
  department?: string | null;
  role?: string;
}

export default function DepartmentManagement() {
  const { t } = useLanguage();
  const [departments, setDepartments] = useState<ExtendedDepartment[]>([]);
  const [managers, setManagers] = useState<ManagerOption[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isManagersLoading, setIsManagersLoading] = useState(false);
  const [managerLoadError, setManagerLoadError] = useState<string | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedStatus, setSelectedStatus] = useState('all');
  const [selectedManagerFilter, setSelectedManagerFilter] = useState<'all' | string>('all');
  const [sortBy, setSortBy] = useState<'name' | 'employees'>('name');
  const [isViewDialogOpen, setIsViewDialogOpen] = useState(false);
  const [viewDepartment, setViewDepartment] = useState<ExtendedDepartment | null>(null);
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [selectedDepartment, setSelectedDepartment] = useState<ExtendedDepartment | null>(null);
  const [formData, setFormData] = useState<Partial<ExtendedDepartment>>({
    name: '',
    code: '',
    managerId: '',
    description: '',
    status: 'active',
    employeeCount: undefined,
    location: ''
  });
  const [allEmployees, setAllEmployees] = useState<any[]>([]);

  // Pagination states
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(20);

  const managerName = (managerId?: string) => {
    if (!managerId) return undefined;
    const found = allEmployees.find((emp) =>
      String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(managerId)
    );
    return found?.name || found?.full_name;
  };

  const filteredDepartments = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    let result = departments.filter((dept) => {
      const matchesSearch =
        dept.name.toLowerCase().includes(query) ||
        dept.code.toLowerCase().includes(query) ||
        (dept.description || '').toLowerCase().includes(query) ||
        (dept.location || '').toLowerCase().includes(query);

      const matchesStatus = selectedStatus === 'all' || dept.status === selectedStatus;
      const matchesManager =
        selectedManagerFilter === 'all' ||
        String(dept.managerId ?? '') === selectedManagerFilter;

      return matchesSearch && matchesStatus && matchesManager;
    });

    result = [...result].sort((a, b) => {
      if (sortBy === 'name') {
        return a.name.localeCompare(b.name);
      }
      if (sortBy === 'employees') {
        return (b.employeeCount || 0) - (a.employeeCount || 0);
      }
      return 0;
    });

    return result;
  }, [departments, searchQuery, selectedStatus, selectedManagerFilter, sortBy]);

  const paginatedDepartments = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = startIndex + itemsPerPage;
    return filteredDepartments.slice(startIndex, endIndex);
  }, [filteredDepartments, currentPage, itemsPerPage]);

  const totalPages = Math.ceil(filteredDepartments.length / itemsPerPage);

  // Reset to first page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery, selectedStatus, selectedManagerFilter, sortBy]);

  // Reset to first page when items per page changes
  useEffect(() => {
    setCurrentPage(1);
  }, [itemsPerPage]);

  const handleCreateDepartment = () => {
    if (!formData.name || !formData.code) {
      toast({
        title: 'Error',
        description: 'Please fill in department name and code',
        variant: 'destructive'
      });
      return;
    }

    setIsSaving(true);
    apiService
      .createDepartment({
        name: formData.name!,
        code: formData.code!,
        manager_id: formData.managerId ? Number(formData.managerId) : undefined,
        description: formData.description || '',
        status: formData.status || 'active',
        employee_count: formData.employeeCount ?? 0,
        location: formData.location || '',
      })
      .then((created: ApiDepartment) => {
        const mapped: ExtendedDepartment = {
          id: created.id,
          name: created.name,
          code: created.code,
          managerId: created.manager_id?.toString() ?? '',
          description: created.description ?? '',
          status: (created.status as 'active' | 'inactive') || 'active',
          employeeCount: created.employee_count ?? 0,
          location: created.location ?? '',
          createdAt: created.created_at,
          updatedAt: created.updated_at,
        };
        setDepartments((prev) => [...prev, mapped]);
        setIsCreateDialogOpen(false);
        resetForm();
        toast({
          title: 'Success',
          description: 'Department created successfully',
        });
      })
      .catch((error) => {
        console.error('Failed to create department:', error);
        toast({
          title: 'Error',
          description:
            error instanceof Error ? error.message : 'Failed to create department',
          variant: 'destructive',
        });
      })
      .finally(() => {
        setIsSaving(false);
      });
  };

  const handleUpdateDepartment = () => {
    if (!selectedDepartment) return;

    const oldManagerId = selectedDepartment.managerId;
    const newManagerId = formData.managerId;
    const managerChanged = oldManagerId !== newManagerId;

    setIsSaving(true);
    apiService
      .updateDepartment(Number(selectedDepartment.id), {
        name: formData.name,
        code: formData.code,
        manager_id: formData.managerId ? Number(formData.managerId) : undefined,
        description: formData.description,
        status: formData.status,
        employee_count: formData.employeeCount,
        location: formData.location,
      })
      .then((updated: ApiDepartment) => {
        setDepartments((prev) =>
          prev.map((dept) =>
            dept.id === selectedDepartment.id
              ? {
                ...dept,
                name: updated.name,
                code: updated.code,
                managerId: updated.manager_id?.toString() ?? '',
                description: updated.description ?? '',
                status: updated.status as 'active' | 'inactive',
                employeeCount: updated.employee_count ?? dept.employeeCount,
                location: updated.location ?? '',
                updatedAt: updated.updated_at,
              }
              : dept,
          ),
        );
        setIsEditDialogOpen(false);
        resetForm();

        // Reload managers to reflect any role changes
        loadManagers();

        let successMessage = 'Department updated successfully';
        if (managerChanged) {
          const newManager = managers.find(m => m.id === newManagerId);
          const oldManager = managers.find(m => m.id === oldManagerId);

          if (newManager && oldManager) {
            successMessage += `. Manager changed from ${oldManager.name} to ${newManager.name}. User roles have been updated automatically.`;
          } else if (newManager) {
            successMessage += `. ${newManager.name} has been assigned as manager and promoted to Manager role.`;
          } else if (oldManager) {
            successMessage += `. ${oldManager.name} has been removed as manager. Their role may have been updated.`;
          }
        }

        toast({
          title: 'Success',
          description: successMessage,
        });
      })
      .catch((error) => {
        console.error('Failed to update department:', error);
        toast({
          title: 'Error',
          description:
            error instanceof Error ? error.message : 'Failed to update department',
          variant: 'destructive',
        });
      })
      .finally(() => setIsSaving(false));
  };

  const handleDeleteDepartment = (id: string) => {
    const dept = departments.find(d => String(d.id) === id);
    if (dept && (dept.employeeCount || 0) > 0) {
      toast({
        title: 'Error',
        description: 'Cannot delete department with active employees',
        variant: 'destructive'
      });
      return;
    }

    apiService
      .deleteDepartment(Number(id))
      .then(() => {
        setDepartments((prev) => prev.filter((dept) => String(dept.id) !== id));
        toast({
          title: 'Success',
          description: 'Department deleted successfully',
          variant: 'success',
        });
      })
      .catch((error) => {
        console.error('Failed to delete department:', error);
        toast({
          title: 'Error',
          description:
            error instanceof Error ? error.message : 'Failed to delete department',
          variant: 'destructive',
        });
      });
  };

  const resetForm = useCallback(() => {
    setFormData({
      name: '',
      code: '',
      managerId: '',
      description: '',
      status: 'active',
      employeeCount: undefined,
      location: ''
    });
    setSelectedDepartment(null);
  }, []);

  const handleCreateCancel = useCallback(() => {
    setIsCreateDialogOpen(false);
    resetForm();
  }, [resetForm]);

  const handleEditCancel = useCallback(() => {
    setIsEditDialogOpen(false);
    resetForm();
  }, [resetForm]);

  const openEditDialog = (department: ExtendedDepartment) => {
    setSelectedDepartment(department);
    setFormData({
      ...department,
      managerId: department.managerId ? String(department.managerId) : '',
    });
    setIsEditDialogOpen(true);
  };

  const openViewDialog = (department: ExtendedDepartment) => {
    setViewDepartment(department);
    setIsViewDialogOpen(true);
  };

  // Compute real employee count from actual employee records (not stale DB field)
  const totalEmployees = allEmployees.length;

  // Per-department live count: match employees whose department name equals dept name
  const getEmployeeCountForDept = (deptName: string) =>
    allEmployees.filter((emp: any) =>
      (emp.department || '').toLowerCase().trim() === deptName.toLowerCase().trim()
    ).length;

  const activeDepartments = departments.filter(dept => dept.status === 'active').length;

  // Stable handlers to prevent input focus loss
  const handleNameChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData((prev) => ({ ...prev, name: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }));
  }, []);

  const handleCodeChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    // Sanitize and convert to uppercase
    setFormData((prev) => ({ ...prev, code: e.target.value.toUpperCase().replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }));
  }, []);

  const handleManagerChange = useCallback((value: string) => {
    setFormData((prev) => ({ ...prev, managerId: value }));
  }, []);

  const handleStatusChange = useCallback((value: string) => {
    setFormData((prev) => ({ ...prev, status: value as 'active' | 'inactive' }));
  }, []);

  const handleEmployeeCountChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const { value } = e.target;
    setFormData((prev) => ({
      ...prev,
      employeeCount: value === '' ? undefined : Number(value),
    }));
  }, []);

  const handleLocationChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData((prev) => ({ ...prev, location: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }));
  }, []);

  const handleDescriptionChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setFormData((prev) => ({ ...prev, description: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }));
  }, []);

  const loadDepartments = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await apiService.getDepartments();
      const mapped: ExtendedDepartment[] = (data || []).map((dept: ApiDepartment) => ({
        id: dept.id,
        name: dept.name,
        code: dept.code,
        managerId: dept.manager_id?.toString() ?? '',
        description: dept.description ?? '',
        status: (dept.status as 'active' | 'inactive') || 'active',
        employeeCount: dept.employee_count ?? 0,
        location: dept.location ?? '',
        createdAt: dept.created_at,
        updatedAt: dept.updated_at,
      }));
      setDepartments(mapped);
    } catch (error) {
      console.error('Failed to load departments:', error);
      toast({
        title: 'Error',
        description:
          error instanceof Error ? error.message : 'Failed to load departments',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleSyncDepartments = useCallback(async () => {
    setIsLoading(true);
    try {
      const result = await apiService.syncDepartmentsFromUsers();

      // Reload departments after sync
      await loadDepartments();

      toast({
        variant: 'success',
        title: 'Sync Completed',
        description: `Created ${result.created} new departments, updated ${result.updated} existing departments.`,
      });
    } catch (error) {
      console.error('Failed to sync departments:', error);
      toast({
        title: 'Error',
        description:
          error instanceof Error ? error.message : 'Failed to sync departments',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  }, [loadDepartments]);

  useEffect(() => {
    // Auto-sync departments from users on mount, then load
    const initializeDepartments = async () => {
      try {
        await apiService.syncDepartmentsFromUsers();
      } catch (error) {
        // Silently fail sync, still load existing departments
        console.warn('Auto-sync failed:', error);
      }
      await loadDepartments();
    };

    initializeDepartments();
  }, [loadDepartments]);

  // Load all employees for auto-calculation
  useEffect(() => {
    const loadEmployees = async () => {
      try {
        const employees = await apiService.getEmployees();
        setAllEmployees(employees || []);
      } catch (error) {
        console.error('Failed to load employees:', error);
      }
    };
    loadEmployees();
  }, []);

  const loadManagers = useCallback(async () => {
    setIsManagersLoading(true);
    try {
      setManagerLoadError(null);

      let managerSource: any[] | null = null;

      try {
        managerSource = await apiService.getDepartmentManagers();
      } catch (fallbackError) {
        if (import.meta.env.DEV) {
          console.warn('Falling back to employees endpoint for managers:', fallbackError);
        }
      }

      if (!Array.isArray(managerSource) || managerSource.length === 0) {
        managerSource = await apiService.getEmployees();
      }

      const normalizedManagers: ManagerOption[] = (managerSource || [])
        .filter((entry: any) => {
          const role = (entry.role || '').toString().toLowerCase().trim();
          const designation = (entry.designation || '').toString().toLowerCase().trim();

          // Aggressive exclusion of Team Leads/TLs/Leads
          const isLeadOrTeam =
            role.includes('team') ||
            role.includes('lead') ||
            role === 'tl' ||
            designation.includes('team') ||
            designation.includes('lead') ||
            designation === 'tl';

          if (isLeadOrTeam) {
            return false;
          }

          // Must be exactly 'manager' or have 'manager' in the designation/role
          return role === 'manager' || role.includes('manager') || designation.includes('manager');
        })
        .map((entry: any) => {
          const idCandidate =
            entry.id ??
            entry.user_id ??
            entry.userId ??
            entry.employee_id ??
            entry.employeeId;

          return {
            id: idCandidate ? String(idCandidate) : '',
            name: entry.name || entry.full_name || '',
            email: entry.email || entry.work_email,
            department: entry.department ?? null,
            role: entry.role,
          };
        })
        .filter((mgr: ManagerOption) => mgr.id && mgr.name)
        .sort((a, b) => a.name.localeCompare(b.name));

      if (normalizedManagers.length === 0) {
        setManagerLoadError('No active managers available. Please add a manager first.');
      }

      setManagers(normalizedManagers);
    } catch (error) {
      console.error('Failed to load managers:', error);
      const message =
        error instanceof Error ? error.message : 'Failed to load managers list';
      setManagerLoadError(message);
      toast({
        title: 'Error',
        description: message,
        variant: 'destructive',
      });
    } finally {
      setIsManagersLoading(false);
    }
  }, []);

  useEffect(() => {
    loadManagers();
  }, [loadManagers]);

  // Auto-calculate employee count when department name changes
  useEffect(() => {
    if (formData.name && allEmployees.length > 0) {
      const count = allEmployees.filter((emp: any) => {
        const empDept = (emp.department || '').toLowerCase().trim();
        const formDept = (formData.name || '').toLowerCase().trim();
        return empDept === formDept;
      }).length;

      // Only update if different to avoid infinite loops
      if (count !== formData.employeeCount) {
        setFormData(prev => ({ ...prev, employeeCount: count }));
      }
    }
  }, [formData.name, allEmployees]);


  return (
    <div className="w-full space-y-6 pb-24">
      {/* Header */}
      <div className="bg-white dark:bg-slate-900 rounded-lg p-6 shadow-md border border-slate-200 dark:border-slate-700">
        <div className="flex flex-col lg:flex-row items-start lg:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="h-12 w-12 rounded-lg bg-blue-600 dark:bg-blue-500 flex items-center justify-center">
              <Building2 className="h-6 w-6 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-slate-900 dark:text-white">
                Department Management
              </h1>
              <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">
                Organize teams, assign managers, and maintain your company structure.
              </p>
            </div>
          </div>
          <div className="flex flex-wrap gap-3">
            <Button
              variant="outline"
              onClick={handleSyncDepartments}
              disabled={isLoading}
              className="gap-2 border-slate-300 dark:border-slate-600 hover:bg-slate-50 dark:hover:bg-slate-800"
            >
              {isLoading ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Users className="h-4 w-4" />
              )}
              Sync from Users
            </Button>
            <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
              <DialogTrigger asChild>
                <Button className="gap-2 bg-blue-600 hover:bg-blue-700 text-white">
                  <Plus className="h-4 w-4" />
                  New Department
                </Button>
              </DialogTrigger>
              <DialogContent className="w-[95vw] max-w-2xl max-h-[85vh] p-0 border-2 shadow-2xl flex flex-col">
                <div className="px-6 pt-6 pb-2">
                  <DialogHeader>
                    <DialogTitle className="text-xl font-semibold">
                      Create New Department
                    </DialogTitle>
                  </DialogHeader>
                </div>
                <div className="overflow-y-auto px-6 pb-6 flex-1">
                  <DepartmentForm
                    mode="create"
                    formData={formData}
                    managers={managers}
                    managerLoadError={managerLoadError}
                    isManagersLoading={isManagersLoading}
                    isSaving={isSaving}
                    selectedDepartment={selectedDepartment}
                    onNameChange={handleNameChange}
                    onCodeChange={handleCodeChange}
                    onManagerChange={handleManagerChange}
                    onStatusChange={handleStatusChange}
                    onEmployeeCountChange={handleEmployeeCountChange}
                    onLocationChange={handleLocationChange}
                    onDescriptionChange={handleDescriptionChange}
                    onCancel={handleCreateCancel}
                    onSubmit={handleCreateDepartment}
                  />
                </div>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
          <Card className="border border-slate-200 dark:border-slate-700">
            <CardContent className="p-5">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-600 dark:text-slate-400 font-medium">
                    Total Departments
                  </p>
                  <p className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{departments.length}</p>
                </div>
                <div className="h-10 w-10 rounded-lg bg-blue-100 dark:bg-blue-900 flex items-center justify-center">
                  <Building2 className="h-5 w-5 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border border-slate-200 dark:border-slate-700">
            <CardContent className="p-5">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-600 dark:text-slate-400 font-medium">
                    Active Departments
                  </p>
                  <p className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{activeDepartments}</p>
                  <p className="text-xs text-slate-500 dark:text-slate-500 mt-1">
                    {departments.length > 0 ? Math.round((activeDepartments / departments.length) * 100) : 0}% active
                  </p>
                </div>
                <div className="h-10 w-10 rounded-lg bg-green-100 dark:bg-green-900 flex items-center justify-center">
                  <ChevronRight className="h-5 w-5 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border border-slate-200 dark:border-slate-700">
            <CardContent className="p-5">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-600 dark:text-slate-400 font-medium">
                    Total Employees
                  </p>
                  <p className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{totalEmployees}</p>
                </div>
                <div className="h-10 w-10 rounded-lg bg-purple-100 dark:bg-purple-900 flex items-center justify-center">
                  <Users className="h-5 w-5 text-purple-600 dark:text-purple-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Main Management Card */}
      <Card className="border border-slate-200 dark:border-slate-700 shadow-md">
        <CardHeader className="border-b border-slate-200 dark:border-slate-700 px-6 py-4">
          <div className="flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4">
            <div>
              <CardTitle className="text-lg font-semibold text-slate-900 dark:text-white">Departments</CardTitle>
              <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">
                Search, filter, and manage departments across your organization.
              </p>
            </div>
            <div className="flex flex-wrap gap-4 w-full xl:w-auto">
              <div className="flex flex-col gap-2 flex-1 min-w-[200px]">
                <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Search</Label>
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  <Input
                    placeholder="Search departments..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                    className="pl-10 border-slate-300 dark:border-slate-600 h-10"
                  />
                </div>
              </div>
              <div className="flex flex-col gap-2">
                <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Status</Label>
                <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                  <SelectTrigger className="w-[140px] border-slate-300 dark:border-slate-600 h-10">
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Status</SelectItem>
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Manager</Label>
                <Select
                  value={selectedManagerFilter}
                  onValueChange={(value) =>
                    setSelectedManagerFilter(value as 'all' | string)
                  }
                >
                  <SelectTrigger className="w-[170px] border-slate-300 dark:border-slate-600 h-10">
                    <SelectValue placeholder="Manager" />
                  </SelectTrigger>
                  <SelectContent className="max-h-64 overflow-y-auto">
                    <SelectItem value="all">All Managers</SelectItem>
                    {managers.map((m) => (
                      <SelectItem key={m.id} value={m.id}>
                        {m.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Sort By</Label>
                <Select
                  value={sortBy}
                  onValueChange={(value) =>
                    setSortBy(value as 'name' | 'employees')
                  }
                >
                  <SelectTrigger className="w-[150px] border-slate-300 dark:border-slate-600 h-10">
                    <SelectValue placeholder="Sort by" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="name">Name (A-Z)</SelectItem>
                    <SelectItem value="employees">Employees</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader className="bg-slate-50 dark:bg-slate-800">
                <TableRow>
                  <TableHead className="w-[100px] px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Code</TableHead>
                  <TableHead className="px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Department</TableHead>
                  <TableHead className="px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Manager</TableHead>
                  <TableHead className="px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Employees</TableHead>
                  <TableHead className="px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Location</TableHead>
                  <TableHead className="px-6 py-3 text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Status</TableHead>
                  <TableHead className="px-6 py-3 text-center text-xs font-semibold text-slate-700 dark:text-slate-300 uppercase">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={7} className="py-16 text-center">
                      <div className="flex flex-col items-center gap-3">
                        <Loader2 className="h-8 w-8 animate-spin text-blue-500" />
                        <p className="text-sm text-slate-500 dark:text-slate-400">Loading departments...</p>
                      </div>
                    </TableCell>
                  </TableRow>
                ) : filteredDepartments.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} className="py-16 text-center">
                      <div className="flex flex-col items-center gap-3">
                        <Building2 className="h-12 w-12 text-slate-300 dark:text-slate-600" />
                        <p className="text-sm text-slate-500 dark:text-slate-400">No departments match your filters.</p>
                      </div>
                    </TableCell>
                  </TableRow>
                ) : (
                  paginatedDepartments.map((department) => {
                    const manager = allEmployees.find(
                      (emp) => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(department.managerId ?? ''),
                    );
                    const managerNameStr = manager ? (manager.name || manager.full_name || '') : '';
                    const isActive = department.status === 'active';
                    return (
                      <TableRow
                        key={department.id}
                        className="hover:bg-slate-50 dark:hover:bg-slate-800/50"
                      >
                        <TableCell className="px-6 py-4">
                          <Badge variant="outline" className="font-semibold">
                            {department.code}
                          </Badge>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <div className="space-y-1">
                            <p className="font-medium text-slate-900 dark:text-slate-100">{department.name}</p>
                            {department.description && (
                              <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 max-w-xs">
                                {department.description}
                              </p>
                            )}
                          </div>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            {managerNameStr ? (
                              <>
                                <div className="h-6 w-6 rounded-full bg-green-100 dark:bg-green-900 flex items-center justify-center">
                                  <span className="text-xs font-semibold text-green-700 dark:text-green-300">
                                    {managerNameStr.charAt(0).toUpperCase()}
                                  </span>
                                </div>
                                <span className="text-sm text-slate-700 dark:text-slate-300">
                                  {managerNameStr}
                                </span>
                              </>
                            ) : (
                              <span className="text-sm text-slate-400 dark:text-slate-500 italic">Unassigned</span>
                            )}
                          </div>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <Badge variant="secondary">
                            {getEmployeeCountForDept(department.name)}
                          </Badge>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <span className="text-sm text-slate-700 dark:text-slate-300">
                            {department.location || <span className="text-slate-400 dark:text-slate-500 italic">Not specified</span>}
                          </span>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <Badge
                            className={
                              isActive
                                ? 'bg-green-600 text-white'
                                : 'bg-slate-500 text-white'
                            }
                          >
                            {department.status.charAt(0).toUpperCase() + department.status.slice(1)}
                          </Badge>
                        </TableCell>
                        <TableCell className="px-6 py-4">
                          <div className="flex justify-center gap-2">
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => openViewDialog(department)}
                              className="h-8 w-8 p-0 hover:bg-blue-100 dark:hover:bg-blue-900"
                              title="View details"
                            >
                              <Eye className="h-4 w-4" />
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => openEditDialog(department)}
                              className="h-8 w-8 p-0 hover:bg-amber-100 dark:hover:bg-amber-900"
                              title="Edit department"
                            >
                              <Edit className="h-4 w-4" />
                            </Button>
                            <Button
                              size="sm"
                              variant={isActive ? 'outline' : 'default'}
                              className={
                                isActive
                                  ? 'border-green-600 text-green-600 hover:bg-green-50 dark:text-green-400 dark:border-green-400'
                                  : ''
                              }
                              onClick={() => {
                                const nextStatus =
                                  department.status === 'active' ? 'inactive' : 'active';
                                apiService
                                  .updateDepartment(Number(department.id), {
                                    status: nextStatus,
                                  })
                                  .then(() => {
                                    setDepartments((prev) =>
                                      prev.map((dept) =>
                                        dept.id === department.id
                                          ? { ...dept, status: nextStatus }
                                          : dept,
                                      ),
                                    );
                                  })
                                  .catch((error) => {
                                    console.error(
                                      'Failed to update department status:',
                                      error,
                                    );
                                    toast({
                                      title: 'Error',
                                      description:
                                        error instanceof Error
                                          ? error.message
                                          : 'Failed to update status',
                                      variant: 'destructive',
                                    });
                                  });
                              }}
                            >
                              {isActive ? 'Deactivate' : 'Activate'}
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleDeleteDepartment(String(department.id))}
                              className="h-8 w-8 p-0 hover:bg-red-100 dark:hover:bg-red-900"
                              title="Delete department"
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                        </TableCell>
                      </TableRow>
                    );
                  })
                )}
              </TableBody>
            </Table>
          </div>

          <div className="mt-6">
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalItems={filteredDepartments.length}
              itemsPerPage={itemsPerPage}
              onPageChange={setCurrentPage}
              onItemsPerPageChange={setItemsPerPage}
              showItemsPerPage={true}
            />
          </div>
        </CardContent>
      </Card>

      {/* Edit Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="w-[95vw] max-w-2xl max-h-[85vh] p-0 flex flex-col">
          <div className="px-6 pt-6 pb-2">
            <DialogHeader>
              <DialogTitle className="text-xl font-semibold">Edit Department</DialogTitle>
            </DialogHeader>
          </div>
          <div className="overflow-y-auto px-6 pb-6 flex-1">
            <DepartmentForm
              mode="edit"
              formData={formData}
              managers={managers}
              managerLoadError={managerLoadError}
              isManagersLoading={isManagersLoading}
              isSaving={isSaving}
              selectedDepartment={selectedDepartment}
              onNameChange={handleNameChange}
              onCodeChange={handleCodeChange}
              onManagerChange={handleManagerChange}
              onStatusChange={handleStatusChange}
              onEmployeeCountChange={handleEmployeeCountChange}
              onLocationChange={handleLocationChange}
              onDescriptionChange={handleDescriptionChange}
              onCancel={handleEditCancel}
              onSubmit={handleUpdateDepartment}
            />
          </div>
        </DialogContent>
      </Dialog>

      {/* View Dialog */}
      <Dialog open={isViewDialogOpen} onOpenChange={setIsViewDialogOpen}>
        <DialogContent className="w-[95vw] max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-blue-600 dark:bg-blue-500 flex items-center justify-center">
                <Building2 className="h-5 w-5 text-white" />
              </div>
              <div>
                <span>Department Details</span>
                <p className="text-sm text-slate-500 dark:text-slate-400 font-normal mt-1">
                  Complete information about this department
                </p>
              </div>
            </DialogTitle>
          </DialogHeader>
          {viewDepartment && (
            <div className="space-y-6 py-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Department Name</Label>
                    <p className="text-base font-semibold text-slate-900 dark:text-white mt-1 bg-slate-50 dark:bg-slate-800 px-3 py-2 rounded border border-slate-200 dark:border-slate-700">
                      {viewDepartment.name}
                    </p>
                  </div>
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Department Code</Label>
                    <div className="mt-1">
                      <Badge variant="outline" className="font-mono font-bold">
                        {viewDepartment.code}
                      </Badge>
                    </div>
                  </div>
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Status</Label>
                    <div className="mt-1">
                      <Badge
                        className={
                          viewDepartment.status === 'active'
                            ? 'bg-green-600 text-white'
                            : 'bg-slate-500 text-white'
                        }
                      >
                        {viewDepartment.status.charAt(0).toUpperCase() + viewDepartment.status.slice(1)}
                      </Badge>
                    </div>
                  </div>
                </div>
                <div className="space-y-4">
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Manager</Label>
                    <div className="flex items-center gap-2 mt-1 bg-slate-50 dark:bg-slate-800 px-3 py-2 rounded border border-slate-200 dark:border-slate-700">
                      {allEmployees.find(emp => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(viewDepartment.managerId)) ? (
                        <>
                          <div className="h-8 w-8 rounded-full bg-green-600 flex items-center justify-center">
                            <span className="text-sm font-bold text-white">
                              {(allEmployees.find(emp => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(viewDepartment.managerId))?.name ||
                                allEmployees.find(emp => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(viewDepartment.managerId))?.full_name || '').charAt(0).toUpperCase()}
                            </span>
                          </div>
                          <span className="text-base font-medium text-slate-900 dark:text-white">
                            {allEmployees.find(emp => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(viewDepartment.managerId))?.name ||
                              allEmployees.find(emp => String(emp.id || emp.user_id || emp.userId || emp.employee_id || emp.employeeId) === String(viewDepartment.managerId))?.full_name}
                          </span>
                        </>
                      ) : (
                        <span className="text-slate-500 dark:text-slate-400 italic">Unassigned</span>
                      )}
                    </div>
                  </div>
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Employee Count</Label>
                    <div className="flex items-center gap-2 mt-1">
                      <Users className="h-4 w-4 text-slate-500" />
                      <span className="text-base font-medium text-slate-900 dark:text-white">
                        {viewDepartment.employeeCount || 0} employees
                      </span>
                    </div>
                  </div>
                  <div>
                    <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Location</Label>
                    <p className="text-base text-slate-700 dark:text-slate-300 mt-1 bg-slate-50 dark:bg-slate-800 px-3 py-2 rounded border border-slate-200 dark:border-slate-700">
                      {viewDepartment.location || 'Not specified'}
                    </p>
                  </div>
                </div>
              </div>
              {viewDepartment.description && (
                <div>
                  <Label className="text-sm font-medium text-slate-600 dark:text-slate-400">Description</Label>
                  <div className="text-sm text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-800 p-3 rounded border border-slate-200 dark:border-slate-700 mt-1">
                    {viewDepartment.description}
                  </div>
                </div>
              )}
              <div className="flex items-center justify-between pt-4 border-t border-slate-200 dark:border-slate-700">
                <div className="text-xs text-slate-500 dark:text-slate-400">
                  Created: {viewDepartment.createdAt ? formatDateIST(viewDepartment.createdAt, 'MMM dd, yyyy') : 'Unknown'}
                </div>
                <div className="text-xs text-slate-500 dark:text-slate-400">
                  Updated: {viewDepartment.updatedAt ? formatDateIST(viewDepartment.updatedAt, 'MMM dd, yyyy') : 'Unknown'}
                </div>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsViewDialogOpen(false)}>
              Close
            </Button>
            <Button
              onClick={() => {
                setIsViewDialogOpen(false);
                if (viewDepartment) {
                  openEditDialog(viewDepartment);
                }
              }}
              className="bg-blue-600 hover:bg-blue-700 text-white"
            >
              Edit Department
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

interface DepartmentFormProps {
  mode: 'create' | 'edit';
  formData: Partial<ExtendedDepartment>;
  managers: ManagerOption[];
  managerLoadError: string | null;
  isManagersLoading: boolean;
  isSaving: boolean;
  selectedDepartment: ExtendedDepartment | null;
  onNameChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onCodeChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onManagerChange: (value: string) => void;
  onStatusChange: (value: string) => void;
  onEmployeeCountChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onLocationChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onDescriptionChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void;
  onCancel: () => void;
  onSubmit: () => void;
}

function DepartmentForm({
  mode,
  formData,
  managers,
  managerLoadError,
  isManagersLoading,
  isSaving,
  selectedDepartment,
  onNameChange,
  onCodeChange,
  onManagerChange,
  onStatusChange,
  onEmployeeCountChange,
  onLocationChange,
  onDescriptionChange,
  onCancel,
  onSubmit,
}: DepartmentFormProps) {
  const isCreateMode = mode === 'create';
  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!isSaving) {
      onSubmit();
    }
  };

  return (
    <form className="space-y-6" onSubmit={handleSubmit}>
      {/* General Details Section */}
      <div className="border border-slate-200 dark:border-slate-700 rounded-lg p-5 space-y-4">
        <div className="flex items-center gap-3 pb-3 border-b border-slate-200 dark:border-slate-700">
          <Building2 className="h-5 w-5 text-blue-600 dark:text-blue-400" />
          <div>
            <p className="text-base font-semibold text-slate-900 dark:text-white">
              General Details
            </p>
            <p className="text-xs text-slate-500 dark:text-slate-400">
              Give this department a distinctive name and code
            </p>
          </div>
        </div>
        <div className="grid sm:grid-cols-2 gap-5">
          <div className="space-y-2.5">
            <Label htmlFor="name" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Department Name <span className="text-red-500">*</span>
            </Label>
            <Input
              id="name"
              value={formData.name}
              onChange={onNameChange}
              placeholder="e.g., Engineering"
              className="border-slate-300 dark:border-slate-600"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="code" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Department Code <span className="text-red-500">*</span>
            </Label>
            <Input
              id="code"
              value={formData.code}
              onChange={onCodeChange}
              placeholder="ENG"
              maxLength={5}
              className="uppercase tracking-wide border-slate-300 dark:border-slate-600"
            />
          </div>
        </div>
      </div>

      {/* Leadership & Status Section */}
      <div className="border border-slate-200 dark:border-slate-700 rounded-lg p-5 space-y-4">
        <div className="flex items-center justify-between pb-3 border-b border-slate-200 dark:border-slate-700">
          <div className="flex items-center gap-3">
            <Users className="h-5 w-5 text-green-600 dark:text-green-400" />
            <div>
              <p className="text-base font-semibold text-slate-900 dark:text-white">
                Leadership & Status
              </p>
              <p className="text-xs text-slate-500 dark:text-slate-400">
                Assign a manager and define operational status
              </p>
            </div>
          </div>
          {!isCreateMode && selectedDepartment?.updatedAt && (
            <p className="text-xs text-slate-500 dark:text-slate-400">
              Updated {formatDateIST(selectedDepartment.updatedAt, 'MMM dd, yyyy')}
            </p>
          )}
        </div>
        <div className="grid sm:grid-cols-2 gap-5">
          <div className="space-y-2.5">
            <Label htmlFor="manager" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Department Manager
            </Label>
            <Select
              value={formData.managerId}
              onValueChange={onManagerChange}
              disabled={isManagersLoading || managers.length === 0}
            >
              <SelectTrigger className="border-slate-300 dark:border-slate-600">
                <SelectValue
                  placeholder={
                    isManagersLoading
                      ? 'Loading managers...'
                      : managers.length === 0
                        ? managerLoadError ?? 'No eligible managers'
                        : 'Select manager'
                  }
                />
              </SelectTrigger>
              <SelectContent>
                {isManagersLoading && (
                  <SelectItem value="loading" disabled>
                    Loading...
                  </SelectItem>
                )}
                {!isManagersLoading && managers.length === 0 && (
                  <SelectItem value="none" disabled>
                    {managerLoadError ?? 'No eligible managers'}
                  </SelectItem>
                )}
                {!isManagersLoading &&
                  managers.length > 0 &&
                  managers.map((manager) => (
                    <SelectItem key={manager.id} value={manager.id}>
                      <div className="flex flex-col">
                        <span>{manager.name}</span>
                        {manager.email && (
                          <span className="text-xs text-slate-400">{manager.email}</span>
                        )}
                      </div>
                    </SelectItem>
                  ))}
              </SelectContent>
            </Select>
            {managerLoadError && !isManagersLoading && (
              <p className="text-xs text-amber-600 bg-amber-50 dark:bg-amber-950/20 p-2 rounded-lg">{managerLoadError}</p>
            )}
            <p className="text-xs text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-800 p-2 rounded-lg">
              💡 When you assign a manager, their role will be automatically updated to "Manager" in the Employee Management system.
            </p>
          </div>
          <div className="space-y-2.5">
            <Label htmlFor="status" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Status
            </Label>
            <Select value={formData.status} onValueChange={onStatusChange}>
              <SelectTrigger className="border-slate-300 dark:border-slate-600">
                <SelectValue placeholder="Select status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="active">Active</SelectItem>
                <SelectItem value="inactive">Inactive</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {/* Department Size Section */}
      <div className="border border-slate-200 dark:border-slate-700 rounded-lg p-5 space-y-4">
        <div className="flex items-center gap-3 pb-3 border-b border-slate-200 dark:border-slate-700">
          <Users className="h-5 w-5 text-purple-600 dark:text-purple-400" />
          <div>
            <p className="text-base font-semibold text-slate-900 dark:text-white">Department Size</p>
            <p className="text-xs text-slate-500 dark:text-slate-400">
              Track headcount for this department
            </p>
          </div>
        </div>
        <div className="space-y-2.5">
          <Label htmlFor="employeeCount" className="flex items-center gap-2 text-sm font-medium text-slate-700 dark:text-slate-300">
            Number of Employees
            <Badge variant="secondary" className="text-xs bg-purple-100 dark:bg-purple-900/50 text-purple-700 dark:text-purple-300 px-2 py-0.5">Auto-calculated</Badge>
          </Label>
          <Input
            id="employeeCount"
            type="number"
            min="0"
            value={formData.employeeCount ?? 0}
            onChange={onEmployeeCountChange}
            className="bg-slate-50 dark:bg-slate-800 border-slate-300 dark:border-slate-600"
            readOnly
            disabled
          />
          <p className="text-xs text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-800 p-2 rounded-lg">
            Automatically counted from employees in this department
          </p>
        </div>
      </div>

      {/* Location & Description Section */}
      <div className="border border-slate-200 dark:border-slate-700 rounded-lg p-5 space-y-4">
        <div className="flex items-center gap-3 pb-3 border-b border-slate-200 dark:border-slate-700">
          <Building2 className="h-5 w-5 text-amber-600 dark:text-amber-400" />
          <div>
            <p className="text-base font-semibold text-slate-900 dark:text-white">
              Location & Description
            </p>
            <p className="text-xs text-slate-500 dark:text-slate-400">
              Help employees know where this department operates from
            </p>
          </div>
        </div>
        <div className="space-y-4">
          <div className="space-y-2.5">
            <Label htmlFor="location" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Location
            </Label>
            <Input
              id="location"
              value={formData.location}
              onChange={onLocationChange}
              placeholder="Building A, Floor 3"
              className="border-slate-300 dark:border-slate-600"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="description" className="text-sm font-medium text-slate-700 dark:text-slate-300">
              Description
            </Label>
            <Textarea
              id="description"
              value={formData.description}
              onChange={onDescriptionChange}
              placeholder="Brief description of the department's responsibilities..."
              rows={4}
              className="resize-none border-slate-300 dark:border-slate-600"
            />
          </div>
        </div>
      </div>

      <DialogFooter className="gap-3 pt-4 border-t border-slate-200 dark:border-slate-700">
        <Button
          type="button"
          variant="outline"
          onClick={onCancel}
        >
          Cancel
        </Button>
        <Button
          type="submit"
          disabled={isSaving}
          className="bg-blue-600 hover:bg-blue-700 text-white"
        >
          {isSaving ? (
            <>
              <Loader2 className="h-4 w-4 animate-spin mr-2" />
              Saving...
            </>
          ) : (
            <>{isCreateMode ? 'Create Department' : 'Save Changes'}</>
          )}
        </Button>
      </DialogFooter>
    </form>
  );
}

import React from 'react';
import { useEffect, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLanguage } from '@/contexts/LanguageContext';
import { useLeaveBalance } from '@/contexts/LeaveBalanceContext';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import {
  Clock,
  CalendarDays,
  ClipboardList,
  TrendingUp,
  Activity,
  CheckCircle2,
  AlertCircle,
  Award,
  Target,
  Circle,
  XCircle,
  AlertTriangle,
  ArrowRight,
  Calendar
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { formatIST, nowIST, todayIST, parseToIST } from '@/utils/timezone';
import { apiService } from '@/lib/api';
import { cn } from '@/lib/utils';
import TruncatedText from '@/components/ui/TruncatedText';

const EmployeeDashboard: React.FC = () => {
  const { user } = useAuth();
  const { t, language } = useLanguage();
  const { leaveBalance } = useLeaveBalance();
  const navigate = useNavigate();

  const [stats, setStats] = useState({
    tasksAssigned: 0,
    tasksCompleted: 0,
    tasksPending: 0,
    leavesAvailable: 0,
    leavesTaken: 0,
    attendancePercentage: 0,
    currentMonthHours: 0,
  });

  interface ActivityItem {
    id: string | number;
    action: string;
    description: string;
    time: string;
    type: 'success' | 'warning' | 'info' | 'error';
    timestamp: number; // For sorting
  }

  const [myTasks, setMyTasks] = useState<any[]>([]);
  const [recentActivities, setRecentActivities] = useState<ActivityItem[]>([]);

  useEffect(() => {
    const loadDashboard = async () => {
      try {
        const [dashboardData, tasksData] = await Promise.all([
          apiService.getEmployeeDashboard(),
          apiService.getMyTasks()
        ]);

        // If task counts are 0, calculate from actual tasks
        let tasksAssigned = dashboardData.tasksAssigned || 0;
        let tasksCompleted = dashboardData.tasksCompleted || 0;
        let tasksPending = dashboardData.tasksPending || 0;

        if (tasksAssigned === 0 && tasksData.length > 0) {
          tasksAssigned = tasksData.length;
          tasksCompleted = tasksData.filter((task: any) =>
            task.status === 'Completed' || task.status === 'completed'
          ).length;
          tasksPending = tasksData.filter((task: any) =>
            task.status !== 'Completed' &&
            task.status !== 'completed' &&
            task.status !== 'Cancelled' &&
            task.status !== 'cancelled'
          ).length;
        }

        setStats({
          ...dashboardData,
          tasksAssigned,
          tasksCompleted,
          tasksPending,
        });
        setMyTasks(tasksData);

        // --- Fetch & Build Recent Activities (for Today) ---
        const today = todayIST(); // YYYY-MM-DD
        const activities: ActivityItem[] = [];

        // 1. Attendance
        try {
          // We try to get today's attendance record
          // We can reuse getAttendanceRecords or maybe getAttendanceStatus is better/faster
          const attendanceResp = await apiService.getAttendanceRecords({ date: today });
          let todayRecord: any = null;

          if (Array.isArray(attendanceResp)) {
            todayRecord = attendanceResp.find((r: any) => r.date === today || (r.check_in && r.check_in.startsWith(today)));
          } else if (attendanceResp?.data && Array.isArray(attendanceResp.data)) {
            todayRecord = attendanceResp.data.find((r: any) => r.date === today || (r.check_in && r.check_in.startsWith(today)));
          }

          if (todayRecord) {
            // Check In
            if (todayRecord.check_in) {
              const checkInTime = new Date(todayRecord.check_in);
              activities.push({
                id: `check-in-${todayRecord.id}`,
                action: 'Checked In',
                description: 'Marked attendance',
                time: formatIST(checkInTime, 'hh:mm a'),
                type: 'info',
                timestamp: checkInTime.getTime()
              });
            }
            // Check Out
            if (todayRecord.check_out) {
              const checkOutTime = new Date(todayRecord.check_out);
              activities.push({
                id: `check-out-${todayRecord.id}`,
                action: 'Checked Out',
                description: 'Marked attendance',
                time: formatIST(checkOutTime, 'hh:mm a'),
                type: 'info',
                timestamp: checkOutTime.getTime()
              });
            }
          }
        } catch (e) {
          console.error("Error fetching attendance activity", e);
        }

        // 2. Tasks (Updated or Created Today)
        try {
          // Filter tasks where updated_at or created_at is today
          // Note: tasksData is already fetched
          const todaysTasks = tasksData.filter((t: any) => {
            const updated = t.updated_at ? t.updated_at.split('T')[0] : '';
            const created = t.created_at ? t.created_at.split('T')[0] : '';
            return updated === today || created === today;
          });

          todaysTasks.forEach((t: any) => {
            const isCreatedToday = t.created_at && t.created_at.startsWith(today);
            const isUpdatedToday = t.updated_at && t.updated_at.startsWith(today);

            // Time to display
            const rawTime = isUpdatedToday ? t.updated_at : t.created_at;
            const timeObj = rawTime ? new Date(rawTime) : new Date();
            const timeStr = formatIST(timeObj, 'hh:mm a');

            if (isCreatedToday) {
              activities.push({
                id: `task-new-${t.id}`,
                action: 'New Task Assigned',
                description: t.title,
                time: timeStr,
                type: 'warning',
                timestamp: timeObj.getTime()
              });
            } else if (isUpdatedToday && (t.status === 'completed' || t.status === 'Completed')) {
              activities.push({
                id: `task-comp-${t.id}`,
                action: 'Task Completed',
                description: t.title,
                time: timeStr,
                type: 'success',
                timestamp: timeObj.getTime()
              });
            } else if (isUpdatedToday) {
              activities.push({
                id: `task-upd-${t.id}`,
                action: 'Task Updated',
                description: `${t.title} - ${t.status}`,
                time: timeStr,
                type: 'info',
                timestamp: timeObj.getTime()
              });
            }
          });
        } catch (e) {
          console.error("Error processing task activity", e);
        }

        // 3. Leaves (Applied Today)
        try {
          const empId = (user as any)?.employee_id || (user as any)?.employeeId || user?.id;
          if (empId) {
            const leaves = await apiService.getLeaveRequestsByEmployee(String(empId));
            // Filter for leaves applied today (created_at)
            const todaysLeaves = leaves.filter((l: any) => l.created_at && l.created_at.startsWith(today));

            todaysLeaves.forEach((l: any) => {
              const timeObj = new Date(l.created_at);
              activities.push({
                id: `leave-${l.id}`,
                action: 'Leave Request',
                description: `Applied for ${l.leave_type}`,
                time: formatIST(timeObj, 'hh:mm a'),
                type: 'warning',
                timestamp: timeObj.getTime()
              });
            });
          }
        } catch (e) {
          console.error("Error fetching leave activity", e);
        }

        // 4. Interviews (Scheduled for Today)
        try {
          const empId = user?.id;
          if (empId) {
            // Convert to number for API compatibility
            const memberId = typeof empId === 'string' ? parseInt(empId) : empId;

            // Using a simple check to see if we have interview records
            const data = await apiService.getInterviews({ panel_member_id: memberId });
            const interviews = Array.isArray(data) ? data : (data?.interviews || []);

            // Filter for interviews today
            const todaysInterviews = interviews.filter((i: any) =>
              i.start_time && i.start_time.startsWith(today)
            );

            todaysInterviews.forEach((i: any) => {
              const timeObj = new Date(i.start_time);
              activities.push({
                id: `interview-${i.id || i.interview_id}`,
                action: 'Interview Schedule',
                description: `${i.candidate_name || 'Candidate'} - ${i.round_type || 'Technical'}`,
                time: formatIST(timeObj, 'hh:mm a'),
                type: 'info',
                timestamp: timeObj.getTime()
              });
            });
          }
        } catch (e) {
          console.error("Error fetching interview activity", e);
        }

        // Sort by timestamp descending
        activities.sort((a, b) => b.timestamp - a.timestamp);
        setRecentActivities(activities);

      } catch (error) {
        console.error('Failed to load dashboard:', error);
      }
    };

    loadDashboard();
  }, []);

  const formatWorkHours = (hours: number) => {
    if (!hours || hours === 0) {
      return '0 hrs - 0 mins';
    }

    const parsed = Number(hours);
    if (Number.isNaN(parsed)) return '0 hrs - 0 mins';

    const totalHours = Math.floor(parsed);
    const minutes = Math.round((parsed - totalHours) * 60);

    if (totalHours === 0 && minutes === 0) {
      return '0 hrs - 0 mins';
    } else if (totalHours === 0) {
      return `0 hrs - ${minutes} mins`;
    } else if (minutes === 0) {
      return `${totalHours} hrs - 0 mins`;
    } else {
      return `${totalHours} hrs - ${minutes} mins`;
    }
  };






  return (
    <div className="space-y-6">
      <div className="relative overflow-hidden flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 p-8 rounded-3xl bg-white dark:bg-gray-900 border shadow-md mt-1 mb-8">
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 bg-indigo-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-64 w-64 bg-purple-500/10 rounded-full blur-3xl" />

        <div className="relative flex items-center gap-5">
          <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-rose-500 to-pink-600 flex items-center justify-center shadow-lg shadow-rose-200 dark:shadow-none">
            <Award className="h-8 w-8 text-white" />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-gray-900 dark:text-gray-100">
              {t.common.welcome}, <span className="text-rose-600">{user?.name}!</span>
            </h1>
            <p className="text-muted-foreground font-medium flex items-center gap-2 mt-1">
              <CalendarDays className="h-4 w-4 text-rose-500" />
              {formatIST(nowIST(), 'EEEE, MMMM dd, yyyy')}
            </p>
          </div>
        </div>

        <div className="relative flex gap-3">
          <Button
            onClick={() => navigate('/employee/attendance')}
            size="lg"
            className="rounded-xl px-6 h-12 bg-rose-600 hover:bg-rose-700 text-white shadow-lg shadow-rose-200 dark:shadow-none transition-all active:scale-95 gap-2"
          >
            <Clock className="h-4 w-4" />
            {t.dashboard.markAttendance}
          </Button>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          {
            label: t.dashboard.myTasks,
            value: stats.tasksAssigned,
            sub: `${stats.tasksCompleted} Completed`,
            icon: ClipboardList,
            color: 'indigo',
            bg: 'bg-indigo-50 text-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400',
            cardBg: 'bg-indigo-50/40 dark:bg-indigo-950/10',
            borderColor: 'border-indigo-300/80 dark:border-indigo-700/50',
            hoverBorder: 'group-hover:border-indigo-500 dark:group-hover:border-indigo-400',
            path: '/employee/tasks'
          },
          {
            label: t.dashboard.attendanceRate,
            value: `${stats.attendancePercentage}%`,
            sub: 'Monthly Performance',
            icon: Target,
            color: 'emerald',
            bg: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400',
            cardBg: 'bg-emerald-50/40 dark:bg-emerald-950/10',
            borderColor: 'border-emerald-300/80 dark:border-emerald-700/50',
            hoverBorder: 'group-hover:border-emerald-500 dark:group-hover:border-emerald-400',
            path: '/employee/attendance'
          },
          {
            label: t.dashboard.leavesAvailable,
            value: leaveBalance.annual.remaining,
            sub: `${leaveBalance.annual.used} Used This Year`,
            icon: CalendarDays,
            color: 'cyan',
            bg: 'bg-cyan-50 text-cyan-600 dark:bg-cyan-900/20 dark:text-cyan-400',
            cardBg: 'bg-cyan-50/40 dark:bg-cyan-950/10',
            borderColor: 'border-cyan-300/80 dark:border-cyan-700/50',
            hoverBorder: 'group-hover:border-cyan-500 dark:group-hover:border-cyan-400',
            path: '/employee/leaves'
          },
          {
            label: t.dashboard.workHoursThisMonth,
