type ShiftType = 'general' | 'morning' | 'afternoon' | 'night' | 'rotational';

interface EmployeeRecord extends User {
  employeeId: string;
  photoUrl?: string;
  resignationDate?: string;
  gender?: 'male' | 'female' | 'other';
  employeeType?: 'contract' | 'permanent';
  countryCode?: string;
