interface Vacancy {
  vacancy_id: number;
  title: string;
  department: string;
  description: string;
  requirements: string;
  responsibilities?: string;
  nice_to_have_skills?: string;
  location: string;
  employment_type: string;
  salary_range?: string;
  status: string;
  candidates_count: number;
  created_at: string;
  updated_at: string;
  posted_on_linkedin?: boolean;
  posted_on_naukri?: boolean;
  posted_on_indeed?: boolean;
  posted_on_other?: boolean;
  social_media_links?: string;
}

interface Candidate {
  candidate_id: number;
  vacancy_id: number;
  vacancy_title?: string;
  vacancy_department?: string;
  first_name?: string;
  last_name?: string;
  name: string;
  email: string;
  phone?: string;
  address?: string;
  linkedin_url?: string;
  portfolio_url?: string;
  resume_url?: string;
  resume_external_url?: string;
  cover_letter?: string;
  status: string;
  interview_date?: string;
  interview_time?: string;
  interview_mode?: string;
  location_or_link?: string;
  interviewer_name?: string;
  applied_at: string;
  updated_at: string;
}

interface Interview {
  interview_id: number;
  candidate_id: number;
  candidate_name?: string;
  vacancy_id: number;
  vacancy_title?: string;
  vacancy_department?: string;
  start_time: string;
  end_time: string;
  mode: 'remote' | 'onsite' | 'phone';
  location: string;
  round_type: string;
  panel_members: number[];
  status: 'scheduled' | 'completed' | 'cancelled' | 'rescheduled' | 'no_show' | 'selected' | 'rejected';
  scheduled_by?: number;
  scheduled_at: string;
  updated_at: string | null;
  notes?: string;
  interviewer_name?: string;
  duration_minutes?: number;
}

interface InterviewFeedback {
  id: number; // API field
  feedback_id?: number; // Keep for compatibility if needed elsewhere
  interview_id: number;
  panel_member_id?: number;
  panel_member_name?: string;
  panel_member_role?: string;
  interviewer_id?: number;
  interviewer_name?: string;
  feedback_summary?: string;
  rating: number;
  technical_rating?: number;
  communication_rating?: number;
  strengths?: string;
  weaknesses?: string;
  recommendation: 'hire' | 'reject' | 'hold';
  comments?: string;
  created_at: string;
  updated_at: string;
}

export default function HiringManagement() {
  const { t } = useLanguage();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('vacancies');
  const [vacancies, setVacancies] = useState<Vacancy[]>([]);
  const [candidates, setCandidates] = useState<Candidate[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [candidateInterviews, setCandidateInterviews] = useState<Interview[]>([]);
  const [vacancyInterviews, setVacancyInterviews] = useState<Interview[]>([]);
  const [feedback, setFeedback] = useState<InterviewFeedback[]>([]);
  const [departments, setDepartments] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isDeleting, setIsDeleting] = useState<number | null>(null);
  const [allEmployees, setAllEmployees] = useState<any[]>([]);

  // Filters
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDepartment, setSelectedDepartment] = useState('all');
  const [selectedStatus, setSelectedStatus] = useState('all');

  // Dialogs
  const [isVacancyDialogOpen, setIsVacancyDialogOpen] = useState(false);
  const [isViewVacancyDialogOpen, setIsViewVacancyDialogOpen] = useState(false);
  const [isSocialMediaDialogOpen, setIsSocialMediaDialogOpen] = useState(false);
  const [isViewCandidateDialogOpen, setIsViewCandidateDialogOpen] = useState(false);
  const [isInterviewDialogOpen, setIsInterviewDialogOpen] = useState(false);
  const [isFeedbackDialogOpen, setIsFeedbackDialogOpen] = useState(false);
  const [isViewInterviewDialogOpen, setIsViewInterviewDialogOpen] = useState(false);
  const [selectedVacancy, setSelectedVacancy] = useState<Vacancy | null>(null);
  const [selectedCandidate, setSelectedCandidate] = useState<Candidate | null>(null);
  const [selectedInterview, setSelectedInterview] = useState<Interview | null>(null);
  const [selectedFeedback, setSelectedFeedback] = useState<InterviewFeedback | null>(null);

  // Form data
  const [vacancyFormData, setVacancyFormData] = useState({
    title: '',
    department: user?.role === 'hr' ? (user.department || '') : '',
    description: '',
    requirements: '',
    responsibilities: '',
    nice_to_have_skills: '',
    location: '',
    employment_type: 'full-time',
    salary_range: '',
    status: 'open',
    posted_on_linkedin: false,
    posted_on_naukri: false,
    posted_on_indeed: false,
    posted_on_other: false,
  });

  const [socialMediaData, setSocialMediaData] = useState({
    platforms: [] as string[],
    links: {} as Record<string, string>,
  });

  const [isCandidateDialogOpen, setIsCandidateDialogOpen] = useState(false);
  const [candidateFormData, setCandidateFormData] = useState({
    first_name: '',
    last_name: '',
    email: '',
    phone: '',
    address: '',
    linkedin_url: '',
    portfolio_url: '',
    vacancy_id: '',
    resume_external_url: '',
    status: 'applied',
  });
  const [candidateResumeFile, setCandidateResumeFile] = useState<File | null>(null);

  const [interviewFormData, setInterviewFormData] = useState({
    candidate_id: '',
    vacancy_id: '',
    start_time: '',
    end_time: '',
    mode: 'remote' as Interview['mode'],
    location: '',
    round_type: 'Technical',
    interviewer_name: '',
    duration_minutes: 60,
    panel_members: [] as number[],
    status: 'scheduled' as Interview['status'],
    notes: '',
  });

  const [feedbackFormData, setFeedbackFormData] = useState({
    rating: 3,
    feedback_summary: '',
    technical_rating: 3,
    communication_rating: 3,
    strengths: '',
    weaknesses: '',
    recommendation: 'hold' as InterviewFeedback['recommendation'],
    comments: '',
  });

  const [isShortlistDialogOpen, setIsShortlistDialogOpen] = useState(false);
  const [shortlistFormData, setShortlistFormData] = useState({
    interview_date: '',
    interview_time: '',
    interview_mode: 'remote',
    location_or_link: '',
    interviewer_name: '',
  });

  const [isUpdateResumeDialogOpen, setIsUpdateResumeDialogOpen] = useState(false);
  const [resumeUpdateData, setResumeUpdateData] = useState({
    resume_external_url: '',
  });
  const [newResumeFile, setNewResumeFile] = useState<File | null>(null);

  type RichTextField =
    | 'description'
    | 'responsibilities'
    | 'requirements'
    | 'nice_to_have_skills';

  const descriptionRef = useRef<HTMLTextAreaElement | null>(null);
  const responsibilitiesRef = useRef<HTMLTextAreaElement | null>(null);
  const requirementsRef = useRef<HTMLTextAreaElement | null>(null);
  const niceToHaveRef = useRef<HTMLTextAreaElement | null>(null);

  const richTextRefs = useMemo(
    () => ({
      description: descriptionRef,
      responsibilities: responsibilitiesRef,
      requirements: requirementsRef,
      nice_to_have_skills: niceToHaveRef,
    }),
    [],
  );

  // Fetch core departments from the Departments API (not scraped from employees)
  useEffect(() => {
    const fetchDepartments = async () => {
      try {
        const data = await apiService.getDepartments();
        const activeDeptNames = (data || [])
          .filter((dept: any) => dept.status === 'active')
          .map((dept: any) => dept.name as string)
          .sort();
        setDepartments(activeDeptNames);
      } catch (error) {
        console.error('Failed to fetch departments:', error);
      }
    };
    fetchDepartments();
  }, []);


  // Fetch vacancies
  const fetchVacancies = async () => {
    setIsLoading(true);
    try {
      const dept = selectedDepartment !== 'all' ? selectedDepartment : undefined;
      const status = selectedStatus !== 'all' ? selectedStatus : undefined;
      const data = await apiService.getVacancies(dept, status);
      setVacancies(Array.isArray(data) ? data : data?.vacancies || []);
    } catch (error: any) {
      console.error('Failed to fetch vacancies:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to load vacancies',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  // Fetch candidates
  const fetchCandidates = async () => {
    setIsLoading(true);
    try {
      const status = selectedStatus !== 'all' ? selectedStatus : undefined;
      const data = await apiService.getCandidates(undefined, status);
      setCandidates(Array.isArray(data) ? data : data?.candidates || []);
    } catch (error: any) {
      console.error('Failed to fetch candidates:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to load candidates',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  // Fetch interviews
  const fetchInterviews = async () => {
    setIsLoading(true);
    try {
      const status = selectedStatus !== 'all' ? selectedStatus : undefined;
      const data = await apiService.getInterviews({ status_filter: status });
      setInterviews(Array.isArray(data) ? data : data?.interviews || []);
    } catch (error: any) {
      console.error('Failed to fetch interviews:', error);
      setInterviews([]);
      toast({
        title: 'Error',
        description: error.message || 'Failed to load interviews',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  // Fetch employees for interviewer selection
  const fetchEmployees = async () => {
    try {
      const data = await apiService.getAllEmployees();
      const employees = Array.isArray(data) ? data : [];
      // Ensure each employee has an id field (mapping from user_id if necessary)
      const mappedData = employees.map((emp: any) => ({
        ...emp,
        id: emp.id || emp.user_id
      }));
      setAllEmployees(mappedData);
    } catch (error) {
      console.error('Failed to fetch employees:', error);
      setAllEmployees([]);
    }
  };

  // Fetch candidate's interview history
  const fetchCandidateInterviews = async (candidateId: number) => {
    try {
      const data = await apiService.getCandidateInterviews(candidateId);
      setCandidateInterviews(Array.isArray(data) ? data : data?.interviews || []);
    } catch (error) {
      console.error('Failed to fetch candidate interviews:', error);
      setCandidateInterviews([]);
    }
  };

  // Fetch vacancy's interviews
  const fetchVacancyInterviews = async (vacancyId: number) => {
    try {
      const data = await apiService.getVacancyInterviews(vacancyId);
      setVacancyInterviews(Array.isArray(data) ? data : data?.interviews || []);
    } catch (error) {
      console.error('Failed to fetch vacancy interviews:', error);
      setVacancyInterviews([]);
    }
  };

  useEffect(() => {
    // Initial fetch of all necessary data
    fetchVacancies();
    fetchCandidates();
    fetchInterviews();
    fetchEmployees();
  }, [selectedDepartment, selectedStatus]);

  useEffect(() => {
    // Refresh data when switching tabs as a fallback
    if (activeTab === 'vacancies') {
      fetchVacancies();
    } else if (activeTab === 'candidates') {
      fetchCandidates();
    } else if (activeTab === 'interviews') {
      fetchInterviews();
      fetchEmployees();
    }
  }, [activeTab]);

  const filteredVacancies = vacancies.filter((vacancy) => {
    if (!vacancy) return false;
    const query = (searchQuery || '').toLowerCase();
    return (
      (vacancy.title || '').toLowerCase().includes(query) ||
      (vacancy.department || '').toLowerCase().includes(query) ||
      (vacancy.location || '').toLowerCase().includes(query) ||
      (vacancy.description || '').toLowerCase().includes(query)
    );
  });

  const filteredCandidates = candidates.filter((candidate) => {
    if (!candidate) return false;
    const query = (searchQuery || '').toLowerCase();
    return (
      (candidate.name || '').toLowerCase().includes(query) ||
      (candidate.email || '').toLowerCase().includes(query) ||
      (candidate.vacancy_title || '').toLowerCase().includes(query) ||
      (candidate.phone || '').toLowerCase().includes(query)
    );
  });

  const filteredInterviews = interviews.filter((interview) => {
    if (!interview) return false;
    const query = (searchQuery || '').toLowerCase();
    return (
      (interview.candidate_name || '').toLowerCase().includes(query) ||
      (interview.vacancy_title || '').toLowerCase().includes(query) ||
      (interview.round_type || '').toLowerCase().includes(query) ||
      (interview.location || '').toLowerCase().includes(query)
    );
  });

  const handleCreateVacancy = async () => {
    if (!vacancyFormData.title || !vacancyFormData.department || !vacancyFormData.description) {
      toast({
        title: 'Error',
        description: 'Please fill in all required fields',
        variant: 'destructive',
      });
      return;
    }

    setIsCreating(true);
    try {
      await apiService.createVacancy(vacancyFormData);
      toast({
        title: 'Success',
        description: 'Vacancy created successfully',
      });
      setIsVacancyDialogOpen(false);
      resetVacancyForm();
      fetchVacancies();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to create vacancy',
        variant: 'destructive',
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleUpdateVacancy = async () => {
    if (!selectedVacancy) return;

    setIsUpdating(true);
    try {
      await apiService.updateVacancy(selectedVacancy.vacancy_id, vacancyFormData);
      toast({
        title: 'Success',
        description: 'Vacancy updated successfully',
      });
      setIsVacancyDialogOpen(false);
      setSelectedVacancy(null);
      resetVacancyForm();
      fetchVacancies();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to update vacancy',
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDeleteVacancy = async (vacancyId: number) => {
    if (!confirm('Are you sure you want to delete this vacancy?')) return;

    setIsDeleting(vacancyId);
    try {
      await apiService.deleteVacancy(vacancyId);
      toast({
        title: 'Success',
        description: 'Vacancy deleted successfully',
      });
      fetchVacancies();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to delete vacancy',
        variant: 'destructive',
      });
    } finally {
      setIsDeleting(null);
    }
  };

  const handlePostToSocialMedia = async () => {
    if (!selectedVacancy || socialMediaData.platforms.length === 0) {
      toast({
        title: 'Error',
        description: 'Please select at least one platform',
        variant: 'destructive',
      });
      return;
    }

    try {
      await apiService.postVacancyToSocialMedia(
        selectedVacancy.vacancy_id,
        socialMediaData.platforms,
        socialMediaData.links
      );
      toast({
        title: 'Success',
        description: 'Vacancy posted to social media platforms',
      });
      setIsSocialMediaDialogOpen(false);
      setSocialMediaData({ platforms: [], links: {} });
      fetchVacancies();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to post to social media',
        variant: 'destructive',
      });
    }
  };

  const handleUpdateCandidateStatus = async (candidateId: number, newStatus: string) => {
    try {
      await apiService.updateCandidateStatus(candidateId, newStatus);
      toast({
        title: 'Success',
        description: 'Candidate status updated',
      });
      fetchCandidates();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to update candidate status',
        variant: 'destructive',
      });
    }
  };

  const handleCreateCandidate = async () => {
    if (!candidateFormData.first_name || !candidateFormData.last_name || !candidateFormData.email || !candidateFormData.vacancy_id || !candidateFormData.phone) {
      toast({
        title: 'Error',
        description: 'Please fill in all required fields, including phone number',
        variant: 'destructive',
      });
      return;
    }

    // Mobile number validation (Starting with 6, 7, 8, 9 and exactly 10 digits)
    const mobileRegex = /^[6-9]\d{9}$/;
    if (!mobileRegex.test(candidateFormData.phone)) {
      toast({
        title: 'Invalid Mobile Number',
        description: 'Mobile number must be 10 digits and start with 6, 7, 8, or 9',
        variant: 'destructive',
      });
      return;
    }

    // Email validation (Must be @gmail.com)
    if (!candidateFormData.email.toLowerCase().endsWith('@gmail.com')) {
      toast({
        title: 'Invalid Email',
        description: 'Only @gmail.com email addresses are allowed',
        variant: 'destructive',
      });
      return;
    }

    // Duplicate mobile number check
    const isDuplicatePhone = candidates.some(c => c.phone === candidateFormData.phone);
    if (isDuplicatePhone) {
      toast({
        title: 'Duplicate Mobile Number',
        description: 'A candidate with this mobile number already exists',
        variant: 'destructive',
      });
      return;
    }

    setIsCreating(true);
    try {
      const payload = {
        ...candidateFormData,
        name: `${candidateFormData.first_name} ${candidateFormData.last_name}`,
      };
      await apiService.createCandidate(payload, candidateResumeFile || undefined);
      toast({
        title: 'Success',
        description: 'Candidate created successfully',
      });
      setIsCandidateDialogOpen(false);
      resetCandidateForm();
      fetchCandidates();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to create candidate',
        variant: 'destructive',
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleShortlistCandidate = async () => {
    if (!selectedCandidate || !shortlistFormData.interview_date || !shortlistFormData.interviewer_name) {
      toast({
        title: 'Error',
        description: 'Please provide interview date and interviewer name',
        variant: 'destructive',
      });
      return;
    }

    setIsUpdating(true);
    try {
      await apiService.shortlistCandidate(selectedCandidate.candidate_id, shortlistFormData);
      toast({
        title: 'Success',
        description: 'Candidate shortlisted for interview',
      });
      setIsShortlistDialogOpen(false);
      fetchCandidates();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to shortlist candidate',
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  };

  const handleUpdateResume = async () => {
    if (!selectedCandidate || (!newResumeFile && !resumeUpdateData.resume_external_url)) {
      toast({
        title: 'Error',
        description: 'Please provide a file or an external URL',
        variant: 'destructive',
      });
      return;
    }

    setIsUpdating(true);
    try {
      await apiService.updateCandidateResume(
        selectedCandidate.candidate_id,
        newResumeFile || undefined,
        resumeUpdateData.resume_external_url
      );
      toast({
        title: 'Success',
        description: 'Resume updated successfully',
      });
      setIsUpdateResumeDialogOpen(false);
      setNewResumeFile(null);
      setResumeUpdateData({ resume_external_url: '' });
      fetchCandidates();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to update resume',
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDeleteCandidate = async (candidateId: number) => {
    if (!confirm('Are you sure you want to delete this candidate?')) return;

    setIsDeleting(candidateId);
    try {
      await apiService.deleteCandidate(candidateId);
      toast({
        title: 'Success',
        description: 'Candidate deleted successfully',
      });
      fetchCandidates();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to delete candidate',
        variant: 'destructive',
      });
    } finally {
      setIsDeleting(null);
    }
  };

  const handleCreateInterview = async () => {
    const { candidate_id, vacancy_id, start_time, end_time, mode, location, round_type, interviewer_name, duration_minutes, notes, status } = interviewFormData;

    if (!candidate_id || !vacancy_id || !start_time || !end_time || !round_type || !interviewer_name) {
      toast({
        title: 'Error',
        description: 'Please fill in all required fields (Candidate, Start Time, End Time, Round, Interviewer)',
        variant: 'destructive',
      });
      return;
    }

    const startDate = new Date(start_time);
    const endDate = new Date(end_time);

    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
      toast({
        title: 'Error',
        description: 'Invalid dates selected',
        variant: 'destructive',
      });
      return;
    }

    if (startDate >= endDate) {
      toast({
        title: 'Error',
        description: 'End time must be after start time',
        variant: 'destructive',
      });
      return;
    }

    setIsCreating(true);
    try {
      // Precise payload as per USER spec
      const payload = {
        candidate_id: parseInt(candidate_id),
        vacancy_id: parseInt(vacancy_id),
        start_time: startDate.toISOString(),
        end_time: endDate.toISOString(),
        mode,
        location,
        round_type,
        panel_members: interviewFormData.panel_members,
      };

      await apiService.createInterview(payload);
      toast({
        title: 'Success',
        description: 'Interview scheduled successfully',
      });
      setIsInterviewDialogOpen(false);
      resetInterviewForm();
      fetchInterviews();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to schedule interview',
        variant: 'destructive',
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleUpdateInterview = async () => {
    if (!selectedInterview) return;

    const { candidate_id, vacancy_id, start_time, end_time, mode, location, round_type, interviewer_name, duration_minutes, notes, status } = interviewFormData;

    if (!start_time || !end_time || !round_type || !interviewer_name) {
      toast({
        title: 'Error',
        description: 'Please fill in all required fields',
        variant: 'destructive',
      });
      return;
    }

    const startDate = new Date(start_time);
    const endDate = new Date(end_time);

    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
      toast({
        title: 'Error',
        description: 'Invalid dates selected',
        variant: 'destructive',
      });
      return;
    }

    if (startDate >= endDate) {
      toast({
        title: 'Error',
        description: 'End time must be after start time',
        variant: 'destructive',
      });
      return;
    }

    setIsUpdating(true);
    try {
      // Precise payload as per USER spec
      const payload = {
        start_time: startDate.toISOString(),
        end_time: endDate.toISOString(),
        mode,
        location,
        round_type,
        status,
        notes,
        panel_members: interviewFormData.panel_members,
      };

      await apiService.updateInterview(selectedInterview.interview_id, payload);
      toast({
        title: 'Success',
        description: 'Interview updated successfully',
      });
      setIsInterviewDialogOpen(false);
      setSelectedInterview(null);
      resetInterviewForm();
      fetchInterviews();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to update interview',
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  };

