                      placeholder="Search candidates..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                </div>
                <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                  <SelectTrigger className="w-full sm:w-[180px] bg-white dark:bg-slate-950">
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Status</SelectItem>
                    <SelectItem value="applied">Applied</SelectItem>
                    <SelectItem value="screening">Screening</SelectItem>
                    <SelectItem value="interview">Interview</SelectItem>
                    <SelectItem value="shortlisted">Shortlisted</SelectItem>
                    <SelectItem value="rejected">Rejected</SelectItem>
                    <SelectItem value="hired">Hired</SelectItem>
                    <SelectItem value="on-hold">On Hold</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Candidates Table */}
          <Card className="border border-slate-200 dark:border-slate-700 shadow-md rounded-3xl">
            <CardHeader className="border-b bg-slate-50 dark:bg-slate-800 rounded-t-3xl">
              <div className="flex items-center justify-between gap-2">
                <div>
                  <CardTitle className="text-base sm:text-lg">Candidate Applications</CardTitle>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Track applicants across stages and manage interviews.
                  </p>
                </div>
                <Badge variant="outline" className="hidden sm:inline-flex gap-1">
                  <Users className="h-3 w-3" />
                  {filteredCandidates.length} candidates
                </Badge>
              </div>
            </CardHeader>
            <CardContent>
              {isLoading ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
              ) : filteredCandidates.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  No candidates found
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Name</TableHead>
                        <TableHead>Email</TableHead>
                        <TableHead>Phone</TableHead>
                        <TableHead>Position</TableHead>
                        <TableHead>Department</TableHead>
                        <TableHead>Applied Date</TableHead>
                        <TableHead>Status</TableHead>
                        <TableHead className="text-right">Actions</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {filteredCandidates.map((candidate) => (
                        <TableRow key={candidate.candidate_id}>
                          <TableCell className="font-medium">{candidate.name}</TableCell>
                          <TableCell>{candidate.email}</TableCell>
                          <TableCell>{candidate.phone || '-'}</TableCell>
                          <TableCell>{candidate.vacancy_title || '-'}</TableCell>
                          <TableCell>{candidate.vacancy_department || '-'}</TableCell>
                          <TableCell>
                            {candidate.applied_at ? formatDateIST(candidate.applied_at, 'MMM dd, yyyy') : 'N/A'}
                          </TableCell>
                          <TableCell>
                            <Select
                              value={candidate.status}
                              onValueChange={(value) =>
                                handleUpdateCandidateStatus(candidate.candidate_id, value)
                              }
                            >
                              <SelectTrigger className="w-[140px]">
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="applied">Applied</SelectItem>
                                <SelectItem value="screening">Screening</SelectItem>
                                <SelectItem value="shortlisted">Shortlisted</SelectItem>
                                <SelectItem value="interview">Interview</SelectItem>
                                <SelectItem value="offered">Offered</SelectItem>
                                <SelectItem value="rejected">Rejected</SelectItem>
                                <SelectItem value="hired">Hired</SelectItem>
                                <SelectItem value="on-hold">On Hold</SelectItem>
                              </SelectContent>
                            </Select>
                          </TableCell>
                          <TableCell className="text-right">
                            <div className="flex items-center justify-end gap-1">
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => {
                                  setSelectedCandidate(candidate);
                                  fetchCandidateInterviews(candidate.candidate_id);
                                  setIsViewCandidateDialogOpen(true);
                                }}
                                title="View Details"
                              >
                                <Eye className="h-4 w-4" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => {
                                  setSelectedCandidate(candidate);
                                  setShortlistFormData({
                                    interview_date: '',
                                    interview_time: '',
                                    interview_mode: 'remote',
                                    location_or_link: '',
                                    interviewer_name: '',
                                  });
                                  setIsShortlistDialogOpen(true);
                                }}
                                title="Shortlist for Interview"
                              >
                                <Calendar className="h-4 w-4 text-blue-600" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => {
                                  setSelectedCandidate(candidate);
                                  setResumeUpdateData({
                                    resume_external_url: candidate.resume_external_url || '',
                                  });
                                  setIsUpdateResumeDialogOpen(true);
                                }}
                                title="Update Resume"
                              >
                                <FileText className="h-4 w-4 text-green-600" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => handleDeleteCandidate(candidate.candidate_id)}
                                disabled={isDeleting === candidate.candidate_id}
                                title="Delete Candidate"
                              >
                                {isDeleting === candidate.candidate_id ? (
                                  <Loader2 className="h-4 w-4 animate-spin" />
                                ) : (
                                  <Trash2 className="h-4 w-4 text-destructive" />
                                )}
                              </Button>
                            </div>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* Interviews Tab */}
        <TabsContent value="interviews" className="space-y-4">
          {/* Filters */}
          <Card className="border border-slate-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
            <CardContent className="pt-5">
              <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
                <div className="flex-1">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Search interviews by candidate, vacancy or interviewer..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                </div>
                <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                  <SelectTrigger className="w-full sm:w-[180px] bg-white dark:bg-slate-950">
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Status</SelectItem>
                    <SelectItem value="scheduled">Scheduled</SelectItem>
                    <SelectItem value="completed">Completed</SelectItem>
                    <SelectItem value="cancelled">Cancelled</SelectItem>
                    <SelectItem value="rescheduled">Rescheduled</SelectItem>
                    <SelectItem value="no_show">No Show</SelectItem>
                    <SelectItem value="selected">Selected</SelectItem>
                    <SelectItem value="rejected">Rejected</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Interviews Table */}
          <Card className="border border-slate-200 dark:border-slate-700 shadow-md rounded-3xl">
            <CardHeader className="border-b bg-slate-50 dark:bg-slate-800 rounded-t-3xl">
              <div className="flex items-center justify-between gap-2">
                <div>
                  <CardTitle className="text-base sm:text-lg">Interview Schedule</CardTitle>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Coordinate and monitor all candidate interviews.
                  </p>
                </div>
                <Badge variant="outline" className="hidden sm:inline-flex gap-1">
                  <Calendar className="h-3 w-3" />
                  {filteredInterviews.length} interviews
                </Badge>
              </div>
            </CardHeader>
            <CardContent>
              {isLoading ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
              ) : filteredInterviews.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  No interviews found
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Candidate</TableHead>
                        <TableHead>Vacancy</TableHead>
                        <TableHead>Date & Time</TableHead>
                        <TableHead>Mode/Location</TableHead>
                        <TableHead>Interviewer</TableHead>
                        <TableHead>Status</TableHead>
                        <TableHead className="text-right">Actions</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {filteredInterviews.map((interview) => (
                        <TableRow key={interview.interview_id}>
                          <TableCell className="font-medium">{interview.candidate_name}</TableCell>
                          <TableCell>{interview.vacancy_title}</TableCell>
                          <TableCell>
                            <div className="flex flex-col">
                              <span className="text-sm font-medium">
                                {interview.start_time ? formatDateIST(interview.start_time, 'MMM dd, yyyy') : 'N/A'}
                              </span>
                              <span className="text-xs text-muted-foreground">
                                {interview.start_time ? formatDateIST(interview.start_time, 'hh:mm a') : ''}
                                {interview.end_time ? ` - ${formatDateIST(interview.end_time, 'hh:mm a')}` : ''}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex flex-col max-w-[150px]">
                              <Badge variant="secondary" className="w-fit text-[10px] capitalize mb-1">
                                {interview.mode}
                              </Badge>
                              <span className="text-xs truncate" title={interview.location}>
                                {interview.location}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex flex-col">
                              {interview.interviewer_name ? (
                                <span className="text-sm font-medium">{interview.interviewer_name}</span>
                              ) : interview.panel_members && interview.panel_members.length > 0 ? (
                                <span className="text-xs text-muted-foreground">ID: {interview.panel_members.join(', ')}</span>
                              ) : (
                                <span className="text-xs text-muted-foreground italic">Not assigned</span>
                              )}
                              <span className="text-[10px] text-muted-foreground opacity-70 serif">{interview.round_type}</span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <Select
                              value={interview.status}
                              onValueChange={(value) =>
                                handleUpdateInterviewStatus(interview.interview_id, value)
                              }
                            >
                              <SelectTrigger className="w-[130px] h-8 text-xs capitalize">
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="scheduled">Scheduled</SelectItem>
                                <SelectItem value="completed">Completed</SelectItem>
                                <SelectItem value="cancelled">Cancelled</SelectItem>
                                <SelectItem value="rescheduled">Rescheduled</SelectItem>
                                <SelectItem value="no_show">No Show</SelectItem>
                                <SelectItem value="selected">Selected</SelectItem>
                                <SelectItem value="rejected">Rejected</SelectItem>
                              </SelectContent>
                            </Select>
                          </TableCell>
                          <TableCell className="text-right">
                            <div className="flex items-center justify-end gap-1">
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 text-violet-600 hover:text-violet-700 hover:bg-violet-50"
                                onClick={async () => {
                                  try {
                                    setIsLoading(true);
                                    const freshInterview = await apiService.getInterview(interview.interview_id);
                                    setSelectedInterview(freshInterview);
                                    await fetchFeedbackList(interview.interview_id);
                                    setIsViewInterviewDialogOpen(true);
                                  } catch (error) {
                                    console.error('Failed to fetch interview details:', error);
                                    // Fallback to existing data if fetch fails
                                    setSelectedInterview(interview);
                                    fetchFeedbackList(interview.interview_id);
                                    setIsViewInterviewDialogOpen(true);
                                  } finally {
                                    setIsLoading(false);
                                  }
                                }}
                                title="View Details & Feedback"
                              >
                                <Eye className="h-4 w-4" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                                onClick={() => {
                                  setSelectedInterview(interview);
                                  setInterviewFormData({
                                    candidate_id: String(interview.candidate_id),
                                    vacancy_id: String(interview.vacancy_id),
                                    start_time: interview.start_time.slice(0, 16), // datetime-local format
                                    end_time: interview.end_time.slice(0, 16),
                                    mode: interview.mode,
                                    location: interview.location,
                                    round_type: interview.round_type,
                                    interviewer_name: interview.interviewer_name || '',
                                    duration_minutes: interview.duration_minutes || 60,
                                    panel_members: interview.panel_members,
                                    status: interview.status,
                                    notes: interview.notes || '',
                                  });
                                  setIsInterviewDialogOpen(true);
                                }}
                                title="Edit Interview"
                              >
                                <Edit className="h-4 w-4" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 text-destructive hover:bg-red-50"
                                onClick={() => handleDeleteInterview(interview.interview_id)}
                                disabled={isDeleting === interview.interview_id}
                                title="Delete Interview"
                              >
                                {isDeleting === interview.interview_id ? (
                                  <Loader2 className="h-4 w-4 animate-spin" />
                                ) : (
                                  <Trash2 className="h-4 w-4" />
                                )}
                              </Button>
                            </div>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Create/Edit Vacancy Dialog */}
      <Dialog open={isVacancyDialogOpen} onOpenChange={setIsVacancyDialogOpen}>
        <DialogContent className="w-[95vw] max-w-4xl max-h-[90vh] overflow-y-auto rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-950 shadow-2xl">
          <DialogHeader className="border-b border-slate-200/60 dark:border-slate-800/60 pb-4 mb-4">
            <div className="flex items-start justify-between gap-3">
              <div className="flex items-center gap-3">
                <div className="h-11 w-11 rounded-2xl bg-blue-100 dark:bg-blue-900 flex items-center justify-center shadow-sm">
                  <Briefcase className="h-5 w-5 text-blue-600 dark:text-blue-400" />
                </div>
                <div>
                  <DialogTitle className="text-lg sm:text-xl font-semibold tracking-tight">
                    {selectedVacancy ? 'Edit Vacancy' : 'Create New Vacancy'}
                  </DialogTitle>
                  <DialogDescription className="text-xs sm:text-sm mt-1">
                    {selectedVacancy
                      ? 'Polish the details for this role before publishing.'
                      : 'Craft a compelling job post with clear responsibilities and requirements.'}
                  </DialogDescription>
                </div>
              </div>
              <div className="hidden sm:flex flex-col items-end gap-1">
                <Badge
                  variant="outline"
                  className="gap-1 px-2 py-0.5 text-[11px] border-indigo-500/40 text-indigo-700 dark:text-indigo-300"
                >
                  <Clock className="h-3 w-3" />
                  {selectedVacancy ? 'Editing existing role' : 'New opportunity'}
                </Badge>
                {vacancyFormData.status && (
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">
                    Status: {vacancyFormData.status.replace('-', ' ')}
                  </span>
                )}
              </div>
            </div>
          </DialogHeader>

          <div className="space-y-6">
            {/* Role Snapshot */}
            <div className="rounded-2xl border border-slate-200 dark:border-slate-800 bg-slate-50/70 dark:bg-slate-900/40 p-4 sm:p-5 space-y-4">
              <div className="flex items-start justify-between gap-3">
                <div>
                  <p className="text-xs font-semibold uppercase tracking-wide text-slate-500 dark:text-slate-400">
                    Role Snapshot
                  </p>
                  <p className="text-[12px] text-muted-foreground">
                    Give this vacancy a clear title and connect it to the right department.
                  </p>
                </div>
              </div>
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="title">Job Title *</Label>
                  <Input
                    id="title"
                    value={vacancyFormData.title}
                    onChange={(e) =>
                      setVacancyFormData({ ...vacancyFormData, title: e.target.value })
                    }
                    placeholder="e.g., Senior Software Engineer"
                    className="h-10"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="department">Department *</Label>
                  <Select
                    value={vacancyFormData.department}
                    onValueChange={(value) =>
                      setVacancyFormData({ ...vacancyFormData, department: value })
                    }
                    disabled={isHR}
                  >
                    <SelectTrigger className="h-10">
                      <SelectValue placeholder="Select department" />
                    </SelectTrigger>
                    <SelectContent>
                      {departments.map((dept) => (
                        <SelectItem key={dept} value={dept}>
                          {dept}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {isHR && (
                    <p className="text-xs text-muted-foreground">
                      You can only create vacancies for your department.
                    </p>
                  )}
                </div>
              </div>

              <div className="grid gap-4 md:grid-cols-3">
                <div className="space-y-2">
                  <Label htmlFor="location">Location *</Label>
                  <Input
                    id="location"
                    value={vacancyFormData.location}
                    onChange={(e) =>
                      setVacancyFormData({ ...vacancyFormData, location: e.target.value })
                    }
                    placeholder="e.g., Mumbai, India"
                    className="h-10"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="employment_type">Employment Type *</Label>
                  <Select
                    value={vacancyFormData.employment_type}
                    onValueChange={(value) =>
                      setVacancyFormData({ ...vacancyFormData, employment_type: value })
                    }
                  >
                    <SelectTrigger className="h-10">
                      <SelectValue placeholder="Select type" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="full-time">Full Time</SelectItem>
                      <SelectItem value="part-time">Part Time</SelectItem>
                      <SelectItem value="contract">Contract</SelectItem>
                      <SelectItem value="internship">Internship</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="salary_range">Salary Range</Label>
                  <div className="relative">
                    <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 h-3 w-3 text-muted-foreground" />
                    <Input
                      id="salary_range"
                      value={vacancyFormData.salary_range}
                      onChange={(e) =>
                        setVacancyFormData({ ...vacancyFormData, salary_range: e.target.value })
                      }
                      placeholder="e.g., ₹5L - ₹10L"
                      className="pl-7 h-10"
                    />
                  </div>
                </div>
              </div>

              <div className="grid gap-4 md:grid-cols-3">
                <div className="space-y-2">
                  <Label htmlFor="status">Status *</Label>
                  <Select
                    value={vacancyFormData.status}
                    onValueChange={(value) =>
                      setVacancyFormData({ ...vacancyFormData, status: value })
                    }
                  >
                    <SelectTrigger className="h-10">
                      <SelectValue placeholder="Select status" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="open">Open</SelectItem>
                      <SelectItem value="closed">Closed</SelectItem>
                      <SelectItem value="on-hold">On Hold</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="hidden md:block" />
                <div className="hidden md:block" />
              </div>
            </div>

            {/* Role Narrative */}
            <div className="rounded-2xl border border-slate-200 dark:border-slate-800 bg-white/90 dark:bg-slate-950/70 p-4 sm:p-5 space-y-5">
              <div className="flex items-start justify-between gap-3">
                <div>
                  <p className="text-xs font-semibold uppercase tracking-wide text-slate-500 dark:text-slate-400">
                    Role Narrative
                  </p>
                  <p className="text-[12px] text-muted-foreground">
                    Use rich descriptions, responsibilities, and requirements to attract the right
                    talent.
                  </p>
                </div>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="description">📝 Job Description *</Label>
                  {renderFormattingToolbar('description')}
                  <Textarea
                    id="description"
                    ref={descriptionRef}
                    value={vacancyFormData.description}
                    onChange={(e) =>
                      setVacancyFormData({ ...vacancyFormData, description: e.target.value })
                    }
                    placeholder="Describe the role, mission, and impact of this position..."
                    rows={4}
                  />
                  {vacancyFormData.description && (
                    <div className="mt-1">
                      <p className="text-[11px] uppercase tracking-wide text-muted-foreground mb-1">
                        Live Preview
                      </p>
                      {renderRichText(vacancyFormData.description)}
                    </div>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="responsibilities">🔧 Responsibilities</Label>
                  {renderFormattingToolbar('responsibilities')}
                  <Textarea
                    id="responsibilities"
                    ref={responsibilitiesRef}
                    value={vacancyFormData.responsibilities}
                    onChange={(e) =>
                      setVacancyFormData({ ...vacancyFormData, responsibilities: e.target.value })
                    }
                    placeholder="Outline the day-to-day responsibilities..."
                    rows={4}
                  />
                  {vacancyFormData.responsibilities && (
                    <div className="mt-1">
                      <p className="text-[11px] uppercase tracking-wide text-muted-foreground mb-1">
                        Live Preview
                      </p>
                      {renderRichText(vacancyFormData.responsibilities)}
                    </div>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="requirements">🎯 Requirements</Label>
                  {renderFormattingToolbar('requirements')}
                  <Textarea
                    id="requirements"
                    ref={requirementsRef}
                    value={vacancyFormData.requirements}
                    onChange={(e) =>
                      setVacancyFormData({ ...vacancyFormData, requirements: e.target.value })
                    }
                    placeholder="List the required skills, qualifications, and experience..."
                    rows={4}
                  />
                  {vacancyFormData.requirements && (
                    <div className="mt-1">
                      <p className="text-[11px] uppercase tracking-wide text-muted-foreground mb-1">
                        Live Preview
                      </p>
                      {renderRichText(vacancyFormData.requirements)}
                    </div>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="nice_to_have_skills">✨ Nice-to-Have Skills</Label>
                  {renderFormattingToolbar('nice_to_have_skills')}
                  <Textarea
                    id="nice_to_have_skills"
                    ref={niceToHaveRef}
                    value={vacancyFormData.nice_to_have_skills}
                    onChange={(e) =>
                      setVacancyFormData({
                        ...vacancyFormData,
                        nice_to_have_skills: e.target.value,
                      })
                    }
                    placeholder="Share any bonus skills or experience that would make candidates stand out..."
                    rows={3}
                  />
                  {vacancyFormData.nice_to_have_skills && (
                    <div className="mt-1">
                      <p className="text-[11px] uppercase tracking-wide text-muted-foreground mb-1">
                        Live Preview
                      </p>
                      {renderRichText(vacancyFormData.nice_to_have_skills)}
                    </div>
                  )}
                </div>
              </div>
            </div>

          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => {
              setIsVacancyDialogOpen(false);
              resetVacancyForm();
              setSelectedVacancy(null);
            }}>
              Cancel
            </Button>
            <Button
              onClick={selectedVacancy ? handleUpdateVacancy : handleCreateVacancy}
              disabled={isCreating || isUpdating}
            >
              {isCreating || isUpdating ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  {selectedVacancy ? 'Updating...' : 'Creating...'}
                </>
              ) : (
                selectedVacancy ? 'Update' : 'Create'
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* View Vacancy Dialog */}
      <Dialog open={isViewVacancyDialogOpen} onOpenChange={setIsViewVacancyDialogOpen}>
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{selectedVacancy?.title}</DialogTitle>
            <DialogDescription>
              {selectedVacancy?.department} • {selectedVacancy?.location}
            </DialogDescription>
          </DialogHeader>
          {selectedVacancy && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-muted-foreground">Employment Type</Label>
                  <p className="capitalize">{(selectedVacancy.employment_type || '').replace('-', ' ')}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Status</Label>
                  <div className="mt-1">{getStatusBadge(selectedVacancy.status)}</div>
                </div>
                {selectedVacancy.salary_range && (
                  <div>
                    <Label className="text-muted-foreground">Salary Range</Label>
                    <p>{selectedVacancy.salary_range}</p>
                  </div>
                )}
                <div>
                  <Label className="text-muted-foreground">Candidates</Label>
                  <p>{selectedVacancy.candidates_count} applications</p>
                </div>
              </div>
              <div>
                <Label className="text-muted-foreground">📝 Job Description</Label>
                {renderRichText(selectedVacancy.description) || (
                  <p className="mt-1 text-sm text-muted-foreground">No description provided.</p>
                )}
              </div>
              {selectedVacancy.responsibilities && (
                <div>
                  <Label className="text-muted-foreground">🔧 Responsibilities</Label>
                  {renderRichText(selectedVacancy.responsibilities)}
                </div>
              )}
              {selectedVacancy.requirements && (
                <div>
                  <Label className="text-muted-foreground">🎯 Requirements</Label>
                  {renderRichText(selectedVacancy.requirements)}
                </div>
              )}
              {selectedVacancy.nice_to_have_skills && (
                <div>
                  <Label className="text-muted-foreground">✨ Nice-to-Have Skills</Label>
                  {renderRichText(selectedVacancy.nice_to_have_skills)}
                </div>
              )}

              {/* Vacancy Interview History */}
              <div className="space-y-3 pt-4 border-t border-slate-100 dark:border-slate-800">
                <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                  <Calendar className="h-3 w-3" />
                  Recent Interviews for this Role
                </Label>
                {vacancyInterviews.length > 0 ? (
                  <div className="space-y-2">
                    {vacancyInterviews.map((int) => (
                      <div key={int.interview_id} className="p-3 rounded-lg border border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 flex items-center justify-between text-xs">
                        <div className="flex flex-col gap-1">
                          <span className="font-semibold">{int.candidate_name} • {int.round_type}</span>
                          <span className="text-muted-foreground">
                            {formatDateTimeIST(int.start_time, 'MMM dd, yyyy')} • {formatDateTimeIST(int.start_time, 'hh:mm a')}
                          </span>
                        </div>
                        <div className="flex items-center gap-3">
                          <Badge variant="outline" className={cn(
                            "capitalize text-[10px] py-1 border-opacity-50",
                            int.status === 'scheduled' && "bg-blue-50 text-blue-700 border-blue-200",
                            int.status === 'completed' && "bg-emerald-50 text-emerald-700 border-emerald-200",
                            int.status === 'cancelled' && "bg-red-50 text-red-700 border-red-200",
                            int.status === 'rescheduled' && "bg-amber-50 text-amber-700 border-amber-200",
                            int.status === 'no_show' && "bg-slate-50 text-slate-700 border-slate-200"
                          )}>
                            {int.status.replace('_', ' ')}
                          </Badge>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-xs text-muted-foreground italic">No interview records found for this vacancy.</p>
                )}
              </div>
            </div>

          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsViewVacancyDialogOpen(false)}>
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>



      {/* View Candidate Dialog */}
      < Dialog open={isViewCandidateDialogOpen} onOpenChange={setIsViewCandidateDialogOpen} >
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Candidate Profile: {selectedCandidate?.name}</DialogTitle>
            <DialogDescription>{selectedCandidate?.email}</DialogDescription>
          </DialogHeader>
          {selectedCandidate && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800">
                  <div className="flex items-center justify-between">
                    <Label className="text-muted-foreground">Status</Label>
                    <Select
                      value={selectedCandidate.status}
                      onValueChange={(value) => {
                        handleUpdateCandidateStatus(selectedCandidate.candidate_id, value);
                        setSelectedCandidate({ ...selectedCandidate, status: value });
                        fetchCandidateInterviews(selectedCandidate.candidate_id);
                      }}
                    >
                      <SelectTrigger className="w-[140px] h-8 text-xs">
                        <SelectValue placeholder="Status" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="applied">Applied</SelectItem>
                        <SelectItem value="screening">Screening</SelectItem>
                        <SelectItem value="shortlisted">Shortlisted</SelectItem>
                        <SelectItem value="interview">Interview</SelectItem>
                        <SelectItem value="offered">Offered</SelectItem>
                        <SelectItem value="rejected">Rejected</SelectItem>
                        <SelectItem value="hired">Hired</SelectItem>
                        <SelectItem value="on-hold">On Hold</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <h4 className="text-sm font-semibold flex items-center gap-2">
                    <Briefcase className="h-4 w-4 text-blue-500" />
                    Applied Position
                  </h4>
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800">
                    <p className="text-sm font-medium">{selectedCandidate.vacancy_title || '-'}</p>
                    <p className="text-xs text-muted-foreground mt-1">{selectedCandidate.vacancy_department || '-'}</p>
                    <p className="text-xs text-muted-foreground mt-3">
                      Applied on {selectedCandidate.applied_at ? formatDateTimeIST(selectedCandidate.applied_at, 'MMM dd, yyyy') : 'N/A'}
                    </p>
                  </div>
                </div>

                <div className="space-y-3">
                  <h4 className="text-sm font-semibold flex items-center gap-2">
                    <MapPin className="h-4 w-4 text-orange-500" />
                    Contact Information
                  </h4>
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800 space-y-2">
                    {selectedCandidate.phone && (
                      <div className="flex items-center gap-2 text-xs">
                        <span className="text-muted-foreground">Phone:</span>
                        <span>{selectedCandidate.phone}</span>
                      </div>
                    )}
                    {selectedCandidate.address && (
                      <div className="flex items-start gap-2 text-xs">
                        <span className="text-muted-foreground">Address:</span>
                        <span className="flex-1">{selectedCandidate.address}</span>
                      </div>
                    )}
                    {(selectedCandidate.linkedin_url || selectedCandidate.portfolio_url) && (
                      <div className="flex gap-3 pt-2">
                        {selectedCandidate.linkedin_url && (
                          <a href={selectedCandidate.linkedin_url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:opacity-80 transition-opacity">
                            <Linkedin className="h-4 w-4" />
                          </a>
                        )}
                        {selectedCandidate.portfolio_url && (
                          <a href={selectedCandidate.portfolio_url} target="_blank" rel="noopener noreferrer" className="text-slate-600 dark:text-slate-400 hover:opacity-80 transition-opacity">
                            <ExternalLink className="h-4 w-4" />
                          </a>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {selectedCandidate.status === 'interview' && selectedCandidate.interview_date && (
                <div className="bg-blue-50/50 dark:bg-blue-900/20 p-4 rounded-xl border border-blue-100 dark:border-blue-800/50 space-y-3">
                  <h4 className="text-sm font-semibold flex items-center gap-2 text-blue-700 dark:text-blue-400">
                    <Calendar className="h-4 w-4" />
                    Scheduled Interview
                  </h4>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-xs">
                    <div>
                      <span className="text-muted-foreground block mb-1">Date</span>
                      <span className="font-medium">
                        {selectedCandidate.interview_date ? formatDateIST(selectedCandidate.interview_date, 'MMM dd, yyyy') : 'N/A'}
                      </span>
                    </div>
                    <div>
                      <span className="text-muted-foreground block mb-1">Time</span>
                      <span className="font-medium">{selectedCandidate.interview_time || '-'}</span>
                    </div>
                    <div>
                      <span className="text-muted-foreground block mb-1">Mode</span>
                      <Badge variant="secondary" className="capitalize text-[10px] py-0">{selectedCandidate.interview_mode || '-'}</Badge>
                    </div>
                    <div>
                      <span className="text-muted-foreground block mb-1">Interviewer</span>
                      <span className="font-medium text-blue-600 dark:text-blue-400">{selectedCandidate.interviewer_name || '-'}</span>
                    </div>
                  </div>
                  {selectedCandidate.location_or_link && (
                    <div className="pt-2 border-t border-blue-100 dark:border-blue-800/50">
                      <span className="text-muted-foreground text-xs block mb-1">Location / Join Link</span>
                      <p className="text-xs break-all text-blue-600 underline">
                        {selectedCandidate.location_or_link.startsWith('http') ? (
                          <a href={selectedCandidate.location_or_link} target="_blank" rel="noopener noreferrer">{selectedCandidate.location_or_link}</a>
                        ) : selectedCandidate.location_or_link}
                      </p>
                    </div>
                  )}
                </div>
              )}

              {selectedCandidate.cover_letter && (
                <div className="space-y-2">
                  <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Cover Letter</Label>
                  <p className="text-sm bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800 whitespace-pre-wrap">
                    {selectedCandidate.cover_letter}
                  </p>
                </div>
              )}

              <div className="space-y-3">
                <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Resume</Label>
                <div className="flex flex-wrap gap-2">
                  {selectedCandidate.resume_url && (
                    <Button
                      variant="outline"
                      className="h-9 px-4 rounded-lg bg-green-50/50 dark:bg-green-900/10 border-green-200 dark:border-green-800/50 text-green-700 dark:text-green-400 hover:bg-green-100"
                      onClick={() => {
                        const url = selectedCandidate.resume_url!;
                        const fullUrl = url.startsWith('http') ? url : `${API_BASE_URL}${url.startsWith('/') ? '' : '/'}${url}`;
                        window.open(fullUrl, '_blank');
                      }}
                    >
                      <FileText className="mr-2 h-4 w-4" />
                      View Uploaded Resume
                      <ExternalLink className="ml-2 h-3 w-3" />
                    </Button>
                  )}
                  {selectedCandidate.resume_external_url && (
                    <Button
                      variant="outline"
                      className="h-9 px-4 rounded-lg bg-indigo-50/50 dark:bg-indigo-900/10 border-indigo-200 dark:border-indigo-800/50 text-indigo-700 dark:text-indigo-400 hover:bg-indigo-100"
                      onClick={() => window.open(selectedCandidate.resume_external_url, '_blank')}
                    >
                      <ExternalLink className="mr-2 h-4 w-4" />
                      View Portfolio/External Resume
                    </Button>
                  )}
                  {!selectedCandidate.resume_url && !selectedCandidate.resume_external_url && (
                    <p className="text-xs text-muted-foreground italic">No resume provided</p>
                  )}
                </div>
              </div>

              {/* Candidate Interview History */}
              <div className="space-y-3 pt-4 border-t border-slate-100 dark:border-slate-800">
                <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                  <Calendar className="h-3 w-3" />
                  Interview History
                </Label>
                {candidateInterviews.length > 0 ? (
                  <div className="space-y-2">
                    {candidateInterviews.map((int) => (
                      <div key={int.interview_id} className="p-3 rounded-lg border border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 flex items-center justify-between text-xs">
                        <div className="flex flex-col gap-1">
                          <span className="font-semibold">{int.round_type}</span>
                          <span className="text-muted-foreground">
                            {formatDateTimeIST(int.start_time, 'MMM dd, yyyy')} • {formatDateTimeIST(int.start_time, 'hh:mm a')}
                          </span>
                        </div>
                        <div className="flex items-center gap-3">
                          <div className="text-right flex flex-col gap-1">
                            <span className="text-muted-foreground">Interviewer</span>
                            <span className="font-medium">{int.interviewer_name || '-'}</span>
                          </div>
                          <Badge variant="outline" className={cn(
                            "capitalize text-[10px] py-1 border-opacity-50",
                            int.status === 'scheduled' && "bg-blue-50 text-blue-700 border-blue-200",
                            int.status === 'completed' && "bg-emerald-50 text-emerald-700 border-emerald-200",
                            int.status === 'cancelled' && "bg-red-50 text-red-700 border-red-200",
                            int.status === 'rescheduled' && "bg-amber-50 text-amber-700 border-amber-200",
                            int.status === 'no_show' && "bg-slate-50 text-slate-700 border-slate-200"
                          )}>
                            {int.status.replace('_', ' ')}
                          </Badge>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-xs text-muted-foreground italic">No interview history found for this candidate.</p>
                )}
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsViewCandidateDialogOpen(false)}>
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >

      {/* Create Candidate Dialog */}
      < Dialog open={isCandidateDialogOpen} onOpenChange={setIsCandidateDialogOpen} >
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Add New Candidate</DialogTitle>
            <DialogDescription>Enter candidate information and link them to a vacancy.</DialogDescription>
          </DialogHeader>
          <div className="grid gap-6 py-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="c_first_name">First Name *</Label>
                <Input
                  id="c_first_name"
                  value={candidateFormData.first_name}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, first_name: e.target.value })}
                  placeholder="John"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="c_last_name">Last Name *</Label>
                <Input
                  id="c_last_name"
                  value={candidateFormData.last_name}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, last_name: e.target.value })}
                  placeholder="Doe"
                />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="c_email">Email *</Label>
                <Input
                  id="c_email"
                  type="email"
                  value={candidateFormData.email}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, email: e.target.value })}
                  placeholder="example@gmail.com"
                />
                <p className="text-[10px] text-muted-foreground italic">Must be a @gmail.com address</p>
              </div>
              <div className="space-y-2">
                <Label htmlFor="c_phone">Phone Number *</Label>
                <Input
                  id="c_phone"
                  value={candidateFormData.phone}
                  onChange={(e) => {
                    const val = e.target.value.replace(/\D/g, '').slice(0, 10);
                    setCandidateFormData({ ...candidateFormData, phone: val });
                  }}
                  placeholder="10-digit number (starts with 6, 7, 8, or 9)"
                  maxLength={10}
                />
                <p className="text-[10px] text-muted-foreground italic">Starts with 6, 7, 8, or 9</p>
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="c_vacancy">Vacancy *</Label>
              <Select
                value={candidateFormData.vacancy_id}
                onValueChange={(value) => setCandidateFormData({ ...candidateFormData, vacancy_id: value })}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select a job opening" />
                </SelectTrigger>
                <SelectContent>
                  {vacancies.filter(v => v.status === 'open').length > 0 ? (
                    vacancies.filter(v => v.status === 'open').map((v) => (
                      <SelectItem key={v.vacancy_id} value={String(v.vacancy_id)}>
                        {v.title} ({v.department})
                      </SelectItem>
                    ))
                  ) : (
                    <SelectItem value="none" disabled>No open vacancies found</SelectItem>
                  )}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="c_address">Address</Label>
              <Input
                id="c_address"
                value={candidateFormData.address}
                onChange={(e) => setCandidateFormData({ ...candidateFormData, address: e.target.value })}
                placeholder="State, City, Country"
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="c_linkedin">LinkedIn Profile URL</Label>
                <Input
                  id="c_linkedin"
                  value={candidateFormData.linkedin_url}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, linkedin_url: e.target.value })}
                  placeholder="https://linkedin.com/in/..."
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="c_portfolio">Portfolio URL</Label>
                <Input
                  id="c_portfolio"
                  value={candidateFormData.portfolio_url}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, portfolio_url: e.target.value })}
                  placeholder="https://github.com/..."
                />
              </div>
            </div>
            <div className="border-t pt-4 space-y-4">
              <h4 className="text-sm font-semibold">Resume Submission</h4>
              <div className="space-y-2">
                <Label htmlFor="c_resume_file">Upload Resume (PDF/DOCX)</Label>
                <Input
                  id="c_resume_file"
                  type="file"
                  accept=".pdf,.doc,.docx"
                  onChange={(e) => setCandidateResumeFile(e.target.files?.[0] || null)}
                />
              </div>
              <div className="relative">
                <div className="absolute inset-0 flex items-center">
                  <span className="w-full border-t" />
                </div>
                <div className="relative flex justify-center text-xs uppercase">
                  <span className="bg-white px-2 text-muted-foreground">Or provide link</span>
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="c_resume_url">External Resume/Google Drive Link</Label>
                <Input
                  id="c_resume_url"
                  value={candidateFormData.resume_external_url}
                  onChange={(e) => setCandidateFormData({ ...candidateFormData, resume_external_url: e.target.value })}
                  placeholder="https://drive.google.com/..."
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsCandidateDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleCreateCandidate} disabled={isCreating}>
              {isCreating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Save Candidate
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >

      {/* Shortlist Dialog */}
      < Dialog open={isShortlistDialogOpen} onOpenChange={setIsShortlistDialogOpen} >
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Shortlist for Interview</DialogTitle>
            <DialogDescription>Schedule an interview for {selectedCandidate?.name}.</DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="int_date">Interview Date *</Label>
              <Input
                id="int_date"
                type="date"
                value={shortlistFormData.interview_date}
                onChange={(e) => setShortlistFormData({ ...shortlistFormData, interview_date: e.target.value })}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="int_time">Interview Time</Label>
              <Input
                id="int_time"
                type="time"
                value={shortlistFormData.interview_time}
                onChange={(e) => setShortlistFormData({ ...shortlistFormData, interview_time: e.target.value })}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="int_mode">Interview Mode *</Label>
              <Select
                value={shortlistFormData.interview_mode}
                onValueChange={(value) => setShortlistFormData({ ...shortlistFormData, interview_mode: value })}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="remote">Remote (Online)</SelectItem>
                  <SelectItem value="onsite">On-site (Office)</SelectItem>
                  <SelectItem value="phone">Phone Call</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="int_location">Meeting Link / Location</Label>
              <Input
                id="int_location"
                value={shortlistFormData.location_or_link}
                onChange={(e) => setShortlistFormData({ ...shortlistFormData, location_or_link: e.target.value })}
                placeholder="Zoom link or Office Address"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="int_interviewer">Interviewer Name *</Label>
              <Select
                value={shortlistFormData.interviewer_name}
                onValueChange={(value) => {
                  const emp = allEmployees.find(e => e.name === value);
                  setShortlistFormData({ ...shortlistFormData, interviewer_name: value });
                  // If we wanted to sync this to a common state, we could, 
                  // but shortlistFormData is separate.
                }}
              >
                <SelectTrigger id="int_interviewer">
                  <SelectValue placeholder="Select interviewer from employees" />
                </SelectTrigger>
                <SelectContent className="max-h-[300px]">
                  {allEmployees.length > 0 ? (
                    allEmployees.map((emp) => {
                      const empId = emp.id || emp.user_id;
                      return (
                        <SelectItem key={empId || emp.name} value={emp.name}>
                          <div className="flex flex-col">
                            <span className="font-medium text-sm">{emp.name}</span>
                            <span className="text-[10px] text-muted-foreground">{emp.department} • {emp.designation}</span>
                          </div>
                        </SelectItem>
                      );
                    })
                  ) : (
                    <div className="p-2 text-xs text-muted-foreground text-center">No employees found</div>
                  )}
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsShortlistDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleShortlistCandidate} disabled={isUpdating}>
              {isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Confirm Shortlist
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >

      {/* Update Resume Dialog */}
      < Dialog open={isUpdateResumeDialogOpen} onOpenChange={setIsUpdateResumeDialogOpen} >
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Update Resume</DialogTitle>
            <DialogDescription>Update the resume or portfolio link for {selectedCandidate?.name}.</DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="up_resume_file">Upload New Resume (File)</Label>
              <Input
                id="up_resume_file"
                type="file"
                accept=".pdf,.doc,.docx"
                onChange={(e) => setNewResumeFile(e.target.files?.[0] || null)}
              />
            </div>
            <div className="relative my-2">
              <div className="absolute inset-0 flex items-center">
                <span className="w-full border-t" />
              </div>
              <div className="relative flex justify-center text-xs uppercase">
                <span className="bg-white px-2 text-muted-foreground">Or</span>
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="up_resume_url">Update External Link</Label>
              <Input
                id="up_resume_url"
                value={resumeUpdateData.resume_external_url}
                onChange={(e) => setResumeUpdateData({ ...resumeUpdateData, resume_external_url: e.target.value })}
                placeholder="https://drive.google.com/..."
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsUpdateResumeDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleUpdateResume} disabled={isUpdating}>
              {isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Update Resume
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >
      {/* Schedule/Edit Interview Dialog */}
      < Dialog open={isInterviewDialogOpen} onOpenChange={setIsInterviewDialogOpen} >
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{selectedInterview ? 'Edit Interview' : 'Schedule Interview'}</DialogTitle>
            <DialogDescription>
              {selectedInterview ? 'Update the details for this interview.' : 'Schedule a new interview for a candidate.'}
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="i_candidate">Candidate *</Label>
              <Select
                value={interviewFormData.candidate_id}
                onValueChange={(value) => {
                  const candidate = candidates.find(c => String(c.candidate_id) === value);
                  setInterviewFormData({
                    ...interviewFormData,
                    candidate_id: value,
                    vacancy_id: candidate ? String(candidate.vacancy_id) : '',
                  });
                }}
                disabled={!!selectedInterview}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select candidate" />
                </SelectTrigger>
                <SelectContent>
                  {candidates.length > 0 ? (
                    candidates.map((c) => (
                      <SelectItem key={c.candidate_id} value={String(c.candidate_id)}>
                        {c.name} ({c.vacancy_title || 'No Vacancy'})
                      </SelectItem>
                    ))
                  ) : (
                    <SelectItem value="none" disabled>No candidates found</SelectItem>
                  )}
                </SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-1 gap-4">
              <div className="space-y-2">
                <Label htmlFor="i_start_time">Start Time *</Label>
                <Input
                  id="i_start_time"
                  type="datetime-local"
                  value={interviewFormData.start_time}
                  onChange={(e) => setInterviewFormData({ ...interviewFormData, start_time: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="i_end_time">End Time *</Label>
                <Input
                  id="i_end_time"
                  type="datetime-local"
                  value={interviewFormData.end_time}
                  onChange={(e) => setInterviewFormData({ ...interviewFormData, end_time: e.target.value })}
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="i_mode">Mode *</Label>
                <Select
                  value={interviewFormData.mode}
                  onValueChange={(value: any) => setInterviewFormData({ ...interviewFormData, mode: value })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="remote">Remote</SelectItem>
                    <SelectItem value="onsite">On-site</SelectItem>
                    <SelectItem value="phone">Phone Call</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="i_status">Status</Label>
                <Select
                  value={interviewFormData.status}
                  onValueChange={(value: any) => setInterviewFormData({ ...interviewFormData, status: value })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="scheduled">Scheduled</SelectItem>
                    <SelectItem value="completed">Completed</SelectItem>
                    <SelectItem value="cancelled">Cancelled</SelectItem>
                    <SelectItem value="rescheduled">Rescheduled</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="i_location">Location / Meeting Link</Label>
              <Input
                id="i_location"
                value={interviewFormData.location}
                onChange={(e) => setInterviewFormData({ ...interviewFormData, location: e.target.value })}
                placeholder="Zoom link or Office Address"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="i_round">Round Type *</Label>
              <Input
                id="i_round"
                value={interviewFormData.round_type}
                onChange={(e) => setInterviewFormData({ ...interviewFormData, round_type: e.target.value })}
                placeholder="e.g. Technical, HR, Management"
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="i_interviewer">Interviewer Name *</Label>
                <Select
                  value={interviewFormData.panel_members[0]?.toString() || ''}
                  onValueChange={(value) => {
                    const emp = allEmployees.find(e => {
                      const id = e.id || e.user_id;
                      return id?.toString() === value;
                    });
                    setInterviewFormData({
                      ...interviewFormData,
                      interviewer_name: emp ? emp.name : '',
                      panel_members: emp ? [parseInt(emp.id || emp.user_id)] : []
                    });
                  }}
                >
                  <SelectTrigger id="i_interviewer">
                    <SelectValue placeholder="Select interviewer" />
                  </SelectTrigger>
                  <SelectContent className="max-h-[250px]">
                    {allEmployees.length > 0 ? (
                      allEmployees.map((emp) => {
                        const empId = emp.id || emp.user_id;
                        return (
                          <SelectItem key={empId || Math.random()} value={empId?.toString() || ''}>
                            <div className="flex flex-col">
                              <span className="font-medium text-xs">{emp.name}</span>
                              <span className="text-[10px] text-muted-foreground">{emp.department} • {emp.designation}</span>
                            </div>
                          </SelectItem>
                        );
                      })
                    ) : (
                      <div className="p-2 text-xs text-muted-foreground text-center">No employees found</div>
                    )}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="i_duration">Duration (minutes)</Label>
                <Input
                  id="i_duration"
                  type="number"
                  min="15"
                  max="240"
                  step="15"
                  value={interviewFormData.duration_minutes}
                  onChange={(e) => setInterviewFormData({ ...interviewFormData, duration_minutes: parseInt(e.target.value) || 60 })}
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="i_notes">Additional Notes</Label>
              <Textarea
                id="i_notes"
                value={interviewFormData.notes}
                onChange={(e) => setInterviewFormData({ ...interviewFormData, notes: e.target.value })}
                placeholder="Any special instructions or notes..."
                rows={3}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsInterviewDialogOpen(false)}>Cancel</Button>
            <Button onClick={selectedInterview ? handleUpdateInterview : handleCreateInterview} disabled={isCreating || isUpdating}>
              {isCreating || isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {selectedInterview ? 'Update Interview' : 'Schedule Interview'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >

      {/* View Interview & Feedback Dialog */}
      < Dialog open={isViewInterviewDialogOpen} onOpenChange={setIsViewInterviewDialogOpen} >
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <div className="flex items-center justify-between gap-4">
              <div>
                <DialogTitle>Interview Details</DialogTitle>
                <DialogDescription>
                  {selectedInterview?.candidate_name} • {selectedInterview?.vacancy_title}
                </DialogDescription>
              </div>
              <Badge className="capitalize">
                {selectedInterview?.status ? selectedInterview.status.replace('-', ' ') : 'Unknown'}
              </Badge>
            </div>
          </DialogHeader>

          {selectedInterview && (
            <div className="space-y-6 py-4">
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800">
                <div className="col-span-2">
                  <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Schedule</span>
                  <p className="text-sm font-medium">
                    {selectedInterview.start_time ? formatDateIST(selectedInterview.start_time, 'MMM dd, yyyy') : 'N/A'} |
                    {selectedInterview.start_time ? formatDateIST(selectedInterview.start_time, 'hh:mm a') : ''}
                    {selectedInterview.end_time ? ` - ${formatDateIST(selectedInterview.end_time, 'hh:mm a')}` : ''}
                  </p>
                </div>
                <div>
                  <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Mode</span>
                  <p className="text-sm font-medium capitalize">{selectedInterview.mode}</p>
                </div>
                <div>
                  <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Round</span>
                  <p className="text-sm font-medium">{selectedInterview.round_type}</p>
                </div>
              </div>

              {selectedInterview.location && (
                <div className="space-y-2">
                  <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Location / Link</Label>
                  <p className="text-sm">
                    {selectedInterview.location.startsWith('http') ? (
                      <a href={selectedInterview.location} target="_blank" rel="noopener noreferrer" className="text-blue-600 underline break-all">
                        {selectedInterview.location}
                      </a>
                    ) : selectedInterview.location}
                  </p>
                </div>
              )}

              {selectedInterview.notes && (
                <div className="space-y-2">
                  <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Notes</Label>
                  <p className="text-sm bg-slate-50 dark:bg-slate-900/50 p-3 rounded-lg border border-slate-100 dark:border-slate-800 whitespace-pre-wrap italic">
                    {selectedInterview.notes}
                  </p>
                </div>
              )}

              <div className="border-t pt-6">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-lg font-semibold flex items-center gap-2">
                    <Star className="h-5 w-5 text-yellow-500" />
                    Interview Feedback
                  </h3>
                  <Button
                    size="sm"
                    className="gap-2"
                    onClick={() => {
                      resetFeedbackForm();
                      setSelectedFeedback(null);
                      setIsFeedbackDialogOpen(true);
                    }}
                  >
                    <Plus className="h-4 w-4" />
                    {feedback.length > 0 ? 'Add Another Feedback' : 'Submit Feedback'}
                  </Button>
                </div>

                {isLoading ? (
                  <div className="flex justify-center py-4">
                    <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                  </div>
                ) : feedback.length === 0 ? (
                  <div className="text-center py-10 bg-slate-50 dark:bg-slate-900/20 rounded-xl border border-dashed">
                    <p className="text-sm text-muted-foreground">No feedback submitted yet for this interview.</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {feedback.map((f) => (
                      <Card key={f.feedback_id} className="overflow-hidden border-slate-200 dark:border-slate-800">
                        <div className="bg-slate-50 dark:bg-slate-800/50 px-4 py-2 flex items-center justify-between border-b border-slate-200 dark:border-slate-800">
                          <span className="text-sm font-medium text-slate-700 dark:text-slate-300">
                            By {f.interviewer_name || 'Interviewer'}
                          </span>
                          <div className="flex items-center gap-1">
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-7 w-7 text-blue-600"
                              onClick={() => {
                                setSelectedFeedback(f);
                                setFeedbackFormData({
                                  rating: f.rating,
                                  feedback_summary: f.feedback_summary || '',
                                  technical_rating: f.technical_rating || 3,
                                  communication_rating: f.communication_rating || 3,
                                  strengths: f.strengths || '',
                                  weaknesses: f.weaknesses || '',
                                  recommendation: f.recommendation,
                                  comments: f.comments || '',
                                });
                                setIsFeedbackDialogOpen(true);
                              }}
                            >
                              <Edit className="h-3.5 w-3.5" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-7 w-7 text-destructive"
                              onClick={() => handleDeleteFeedback(f.feedback_id)}
                            >
                              <Trash2 className="h-3.5 w-3.5" />
                            </Button>
                          </div>
                        </div>
                        <CardContent className="pt-4 space-y-4">
                          <div className="space-y-3">
                            {f.feedback_summary && (
                              <div className="bg-blue-50/50 dark:bg-blue-900/10 p-3 rounded-lg border border-blue-100 dark:border-blue-800/50">
                                <span className="text-[10px] uppercase font-bold text-blue-700 dark:text-blue-400 block mb-1">Feedback Summary</span>
                                <p className="text-sm font-medium">{f.feedback_summary}</p>
                              </div>
                            )}

                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                              <div>
                                <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Overall Rating</span>
                                <div className="flex items-center gap-1">
                                  <span className="font-bold">{f.rating}/5</span>
                                  <Star className="h-3 w-3 text-yellow-500 fill-yellow-500" />
                                </div>
                              </div>
                              <div>
                                <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Recommendation</span>
                                <Badge className={
                                  f.recommendation === 'hire' ? 'bg-green-100 text-green-700 hover:bg-green-100 dark:bg-green-900/30 dark:text-green-400' :
                                    f.recommendation === 'reject' ? 'bg-red-100 text-red-700 hover:bg-red-100 dark:bg-red-900/30 dark:text-red-400' :
                                      'bg-yellow-100 text-yellow-700 hover:bg-yellow-100 dark:bg-yellow-900/30 dark:text-yellow-400'
                                }>
                                  {f.recommendation}
                                </Badge>
                              </div>
                              {f.technical_rating !== undefined && f.technical_rating !== null && (
                                <div>
                                  <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Technical</span>
                                  <span className="text-sm font-medium">{f.technical_rating}/5</span>
                                </div>
                              )}
                              {f.communication_rating !== undefined && f.communication_rating !== null && (
                                <div>
                                  <span className="text-[10px] uppercase font-bold text-muted-foreground block mb-1">Communication</span>
                                  <span className="text-sm font-medium">{f.communication_rating}/5</span>
                                </div>
                              )}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              {f.strengths && (
                                <div className="space-y-1">
                                  <span className="text-[10px] uppercase font-bold text-muted-foreground">Strengths</span>
                                  <p className="text-xs text-slate-600 dark:text-slate-400">{f.strengths}</p>
                                </div>
                              )}
                              {f.weaknesses && (
                                <div className="space-y-1">
                                  <span className="text-[10px] uppercase font-bold text-muted-foreground">Areas for Improvement</span>
                                  <p className="text-xs text-slate-600 dark:text-slate-400">{f.weaknesses}</p>
                                </div>
                              )}
                            </div>

                            {f.comments && (
                              <div className="space-y-1">
                                <span className="text-[10px] uppercase font-bold text-muted-foreground">Detailed Comments</span>
                                <p className="text-xs text-slate-600 dark:text-slate-400 italic">"{f.comments}"</p>
                              </div>
                            )}
                          </div>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={() => setIsViewInterviewDialogOpen(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >

      {/* Submit/Edit Feedback Dialog */}
      < Dialog open={isFeedbackDialogOpen} onOpenChange={setIsFeedbackDialogOpen} >
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{selectedFeedback ? 'Edit Feedback' : 'Submit Interview Feedback'}</DialogTitle>
            <DialogDescription>
              Evaluate the candidate based on their performance in the interview.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-6 py-4">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <Label htmlFor="f_rating">Overall Rating (1-5) *</Label>
                <div className="flex items-center gap-2">
                  <Input
                    id="f_rating"
                    type="number"
                    min="1"
                    max="5"
                    value={feedbackFormData.rating}
                    onChange={(e) => setFeedbackFormData({ ...feedbackFormData, rating: parseInt(e.target.value) })}
                  />
                  <Star className="h-5 w-5 text-yellow-500 fill-yellow-500" />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="f_tech_rating">Technical Rating (1-5)</Label>
                <Input
                  id="f_tech_rating"
                  type="number"
                  min="1"
                  max="5"
                  value={feedbackFormData.technical_rating}
                  onChange={(e) => setFeedbackFormData({ ...feedbackFormData, technical_rating: parseInt(e.target.value) })}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="f_comm_rating">Communication (1-5)</Label>
                <Input
                  id="f_comm_rating"
                  type="number"
                  min="1"
                  max="5"
                  value={feedbackFormData.communication_rating}
                  onChange={(e) => setFeedbackFormData({ ...feedbackFormData, communication_rating: parseInt(e.target.value) })}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="f_summary">Feedback Summary *</Label>
              <Input
                id="f_summary"
                value={feedbackFormData.feedback_summary}
                onChange={(e) => setFeedbackFormData({ ...feedbackFormData, feedback_summary: e.target.value })}
                placeholder="e.g. Cleared HR phone round"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="f_recommendation">Final Recommendation *</Label>
              <Select
                value={feedbackFormData.recommendation}
                onValueChange={(value: any) => setFeedbackFormData({ ...feedbackFormData, recommendation: value })}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="hire">Hire</SelectItem>
                  <SelectItem value="reject">Reject</SelectItem>
                  <SelectItem value="hold">On Hold</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="f_strengths">Strengths</Label>
                <Textarea
                  id="f_strengths"
                  value={feedbackFormData.strengths}
                  onChange={(e) => setFeedbackFormData({ ...feedbackFormData, strengths: e.target.value })}
                  placeholder="What did the candidate do well?"
                  rows={4}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="f_weaknesses">Weaknesses / Areas for Improvement</Label>
                <Textarea
                  id="f_weaknesses"
                  value={feedbackFormData.weaknesses}
                  onChange={(e) => setFeedbackFormData({ ...feedbackFormData, weaknesses: e.target.value })}
                  placeholder="Where did the candidate fall short?"
                  rows={4}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="f_comments">Additional Comments</Label>
              <Textarea
                id="f_comments"
                value={feedbackFormData.comments}
                onChange={(e) => setFeedbackFormData({ ...feedbackFormData, comments: e.target.value })}
                placeholder="Overall impression and any other feedback..."
                rows={3}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsFeedbackDialogOpen(false)}>Cancel</Button>
            <Button onClick={selectedFeedback ? handleUpdateFeedback : handleCreateFeedback} disabled={isCreating || isUpdating}>
              {isCreating || isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {selectedFeedback ? 'Update Feedback' : 'Submit Feedback'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog >
    </div >
  );
}

import React from 'react';
import { useEffect, useMemo, useState } from 'react';
import { useLanguage } from '@/contexts/LanguageContext';
import { useAuth } from '@/contexts/AuthContext';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { Pagination } from '@/components/ui/pagination';
import { ChevronLeft, ChevronRight as ChevronRightIcon } from 'lucide-react';
import {
  Users,
  UserPlus,
  Clock,
  CalendarDays,
  ClipboardList,
  AlertCircle,
  Activity,
  FileText,
  UserCheck,
  Home,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { formatTimeIST, formatIST } from '@/utils/timezone';
import { apiService } from '@/lib/api';
import { toast } from '@/hooks/use-toast';
import TruncatedText from '@/components/ui/TruncatedText';

type HRActivity = {
  id: string | number;
  type: string;
  user: string;
  time?: string;
  status?: string;
  description?: string;
};

const HRDashboard: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();
  const navigate = useNavigate();

  const [stats, setStats] = useState({
    totalEmployees: 0,
    presentToday: 0,
    onLeave: 0,
    lateArrivals: 0,
    pendingLeaves: 0,
    newJoinersThisMonth: 0,
    exitingThisMonth: 0,
    openPositions: 0,
    activeTasks: 0,
    completedTasks: 0,
  });
  const [recentActivities, setRecentActivities] = useState<HRActivity[]>([]);
  const [isLoadingActivities, setIsLoadingActivities] = useState(true);
  const [activitiesPage, setActivitiesPage] = useState(1);
  const ACTIVITIES_PER_PAGE = 15;

  // WFH Requests state
  const [wfhRequests, setWfhRequests] = useState<any[]>([]);
  const [isLoadingWfhRequests, setIsLoadingWfhRequests] = useState(false);
  const [isProcessingWfhRequest, setIsProcessingWfhRequest] = useState(false);
  const [selectedWfhRequest, setSelectedWfhRequest] = useState<any>(null);
  const [showWfhRequestDialog, setShowWfhRequestDialog] = useState(false);
  const [wfhRejectionReason, setWfhRejectionReason] = useState('');

  useEffect(() => {
    let isMounted = true;
    const loadDashboard = async () => {
      try {
        const data = await apiService.getHRDashboard();
        if (!isMounted || !data) return;
        const { recentActivities: activityFeed = [], ...statSnapshot } = data;

        setStats((prev) => ({ ...prev, ...statSnapshot }));

        // Filter for Today's activities only
        const today = new Date();
        const startOfDay = new Date(today.setHours(0, 0, 0, 0));
        const endOfDay = new Date(today.setHours(23, 59, 59, 999));

        const todaysActivities = (Array.isArray(activityFeed) ? activityFeed : []).filter((activity: HRActivity) => {
          if (!activity.time) return false;
          const activityTime = new Date(activity.time);
          return activityTime >= startOfDay && activityTime <= endOfDay;
        });

        // Sort by time (most recent first)
        todaysActivities.sort((a, b) => {
          const timeA = a.time ? new Date(a.time).getTime() : 0;
          const timeB = b.time ? new Date(b.time).getTime() : 0;
          return timeB - timeA;
        });

        setRecentActivities(todaysActivities);
      } catch (error) {
        console.error('Failed to load HR dashboard', error);
      } finally {
        if (isMounted) {
          setIsLoadingActivities(false);
        }
      }
    };

    loadDashboard();
    return () => {
      isMounted = false;
    };
  }, []);

  // Load WFH requests for HR (both own and employee/team lead requests)
  useEffect(() => {
    const loadWFHRequests = async () => {
      setIsLoadingWfhRequests(true);
      try {
        // Fetch all WFH requests using the new API method
        const response = await apiService.getAllWFHRequests();

        // Handle response - it's always an array
        let requests = Array.isArray(response) ? response : [];

        // Transform API response to match our UI format
        // The API returns requests with fields like: wfh_id, user_id, start_date, end_date, wfh_type, reason, status, employee_id, name, department, role, approver_name
        const formattedRequests = requests.map((req: any) => ({
          id: req.wfh_id || req.id,
          user_id: req.user_id,
          user_name: req.name || req.employee_name || 'Unknown',
          employee_id: req.employee_id || '',
          start_date: req.start_date,
          end_date: req.end_date,
          reason: req.reason,
          wfh_type: (req.wfh_type || 'Full Day').toLowerCase().includes('full') ? 'full_day' : 'half_day',
          status: (req.status || 'Pending').toLowerCase(),
          created_at: req.created_at,
          updated_at: req.updated_at,
          rejection_reason: req.rejection_reason,
          approved_by: req.approver_name || req.approved_by,
          department: req.department || 'Unknown',
          user_role: (req.role || 'employee').toLowerCase(),
        }));
        setWfhRequests(formattedRequests);
      } catch (error) {
        // Silently fail - endpoint may not be implemented yet
        // The API method already handles errors gracefully
        setWfhRequests([]);
      } finally {
        setIsLoadingWfhRequests(false);
      }
    };

    loadWFHRequests();
  }, []);

  const safePercentage = (value: number, total: number): number => {
    if (!total || total <= 0) return 0;
    const percent = (value / total) * 100;
    if (!Number.isFinite(percent)) return 0;
    return Math.min(100, Math.max(0, percent));
  };

  // Handle WFH request approval/rejection for HR
  const handleWfhRequestAction = async (requestId: number, action: 'approve' | 'reject', reason?: string) => {
    setIsProcessingWfhRequest(true);
    try {
      const approved = action === 'approve';
      await apiService.approveWFHRequest(requestId, approved, reason);

      // Update local state optimistically
      const currentTime = new Date();
      setWfhRequests(prev =>
        prev.map(req =>
          req.id === requestId
            ? {
              ...req,
              status: action === 'approve' ? 'approved' : 'rejected',
              updated_at: currentTime.toISOString(),
              approved_by: user?.name || 'HR',
              rejection_reason: action === 'reject' ? reason : undefined
            }
            : req
        )
      );

      toast({
        title: `Request ${action === 'approve' ? 'Approved' : 'Rejected'}`,
        description: `WFH request has been ${action === 'approve' ? 'approved' : 'rejected'} successfully.`,
        variant: 'default',
      });

      setShowWfhRequestDialog(false);
      setSelectedWfhRequest(null);
      setWfhRejectionReason('');
    } catch (error) {
      console.error('Error processing WFH request:', error);
      toast({
        title: 'Action Failed',
        description: `Failed to ${action} the request. Please try again.`,
        variant: 'destructive',
      });
    } finally {
      setIsProcessingWfhRequest(false);
    }
  };

  const formatActivityTime = (value?: string) => {
    if (!value) return '—';
    // Parse the ISO string and convert to IST, then format time only
    return formatTimeIST(value, 'hh:mm a');
  };

  const formatActivityDescription = (activity: HRActivity) => {
    if (activity.description) return activity.description;
    if (activity.type === 'leave') return 'Leave request';
    if (activity.type === 'join') return 'New employee joined';
    if (activity.type === 'attendance') return 'Checked in';
    if (activity.type === 'document') return 'Document update';
    return 'Activity update';
  };

  const formatStatusLabel = (status?: string) =>
    status ? status.replace(/[-_]/g, ' ') : 'update';

  const formatShortDate = (value?: string) => {
    if (!value) return '—';
    try {
      return formatIST(new Date(value), 'MMM dd');
    } catch {
      return '—';
    }
  };

  // Calculate correct attendance status based on check-in time and grace period
  const getCorrectAttendanceStatus = (activity: HRActivity) => {
    if (activity.type !== 'attendance') {
      return activity.status;
    }

    // Default scheduled check-in time is 10:00 AM
    const SCHEDULED_CHECK_IN_HOUR = 10;
    const SCHEDULED_CHECK_IN_MINUTE = 0;
    const GRACE_PERIOD_MINUTES = 15;

    try {
      if (!activity.time) {
        return activity.status;
      }

      // Parse the check-in time
      const checkInDate = new Date(activity.time);
      const checkInHour = checkInDate.getHours();
      const checkInMinute = checkInDate.getMinutes();

      // Calculate scheduled check-in time in minutes
      const scheduledTimeInMinutes = SCHEDULED_CHECK_IN_HOUR * 60 + SCHEDULED_CHECK_IN_MINUTE;
      const checkInTimeInMinutes = checkInHour * 60 + checkInMinute;
      const gracePeriodEndInMinutes = scheduledTimeInMinutes + GRACE_PERIOD_MINUTES;

      // Determine status
      if (checkInTimeInMinutes <= gracePeriodEndInMinutes) {
        return 'on-time';
      } else {
        return 'late';
      }
    } catch (error) {
      return activity.status;
    }
  };

  const getActivityBadgeVariant = (status?: string) => {
    const normalized = (status || '').toLowerCase();
    if (['approved', 'new-joiner', 'completed', 'on-time'].includes(normalized)) {
      return 'default' as const;
    }
    if (['pending', 'submitted', 'requested'].includes(normalized)) {
      return 'secondary' as const;
    }
    if (['late', 'rejected', 'cancelled'].includes(normalized)) {
      return 'destructive' as const;
    }
    return 'outline' as const;
  };

  const getActivityIconClasses = (type: string) => {
    switch (type) {
      case 'leave':
        return 'bg-gradient-to-br from-amber-400 to-orange-500';
      case 'join':
        return 'bg-gradient-to-br from-green-400 to-emerald-500';
      case 'attendance':
        return 'bg-gradient-to-br from-blue-400 to-indigo-500';
      case 'document':
        return 'bg-gradient-to-br from-cyan-400 to-blue-500';
      default:
        return 'bg-gradient-to-br from-slate-400 to-gray-500';
    }
  };

  const renderActivityIcon = (type: string) => {
    switch (type) {
      case 'leave':
        return <CalendarDays className="h-5 w-5 text-white" />;
      case 'join':
        return <UserPlus className="h-5 w-5 text-white" />;
      case 'attendance':
        return <Clock className="h-5 w-5 text-white" />;
      case 'document':
        return <FileText className="h-5 w-5 text-white" />;
      default:
        return <Activity className="h-5 w-5 text-white" />;
    }
  };

  const activityFeedContent = useMemo(() => {
    if (isLoadingActivities) {
      return (
        <div className="p-6 text-center text-muted-foreground text-sm">
          Loading recent activities...
        </div>
      );
    }

    if (!recentActivities.length) {
      return (
        <div className="p-6 text-center text-muted-foreground text-sm">
          No recent activities available yet.
        </div>
      );
    }

    const paginatedActivities = recentActivities.slice(
      (activitiesPage - 1) * ACTIVITIES_PER_PAGE,
      activitiesPage * ACTIVITIES_PER_PAGE
    );

    return (
      <>
        {paginatedActivities.map((activity) => (
          <div
            key={activity.id}
            className="flex items-start gap-3 p-3 rounded-lg border hover:bg-white/50 dark:hover:bg-gray-800/50 transition-colors"
          >
            <div
              className={`h-10 w-10 rounded-xl flex items-center justify-center flex-shrink-0 shadow-sm ${getActivityIconClasses(
                activity.type,
              )}`}
            >
              {renderActivityIcon(activity.type)}
            </div>
            <div className="flex-1 space-y-1">
              <p className="text-sm font-medium">{activity.user}</p>
              <div className="text-xs text-muted-foreground">
                <TruncatedText
                  text={formatActivityDescription(activity)}
                  maxLength={60}
                  showToggle={false}
                />
              </div>
            </div>
            <div className="text-right">
              <p className="text-xs text-muted-foreground">
                {formatActivityTime(activity.time)}
              </p>
              <Badge
                variant={getActivityBadgeVariant(getCorrectAttendanceStatus(activity))}
                className="text-xs mt-1 capitalize"
              >
                {formatStatusLabel(getCorrectAttendanceStatus(activity))}
              </Badge>
            </div>
          </div>
        ))}
        {recentActivities.length > ACTIVITIES_PER_PAGE && (
          <div className="mt-6">
            <Pagination
              currentPage={activitiesPage}
              totalPages={Math.ceil(recentActivities.length / ACTIVITIES_PER_PAGE)}
              totalItems={recentActivities.length}
              itemsPerPage={ACTIVITIES_PER_PAGE}
              onPageChange={setActivitiesPage}
              showItemsPerPage={false} // Activities feed usually has fixed limit on dashboard
            />
          </div>
        )}
      </>
    );
  }, [isLoadingActivities, recentActivities, activitiesPage]);

  const wfhSummary = useMemo(() => {
    const total = wfhRequests.length;
    const pending = wfhRequests.filter(r => (r.status || '').toLowerCase() === 'pending').length;
    const approved = wfhRequests.filter(r => (r.status || '').toLowerCase() === 'approved').length;
    const rejected = wfhRequests.filter(r => (r.status || '').toLowerCase() === 'rejected').length;

    const pendingList = wfhRequests
      .filter(r => (r.status || '').toLowerCase() === 'pending')
      .sort((a, b) => {
        const tA = a.created_at ? new Date(a.created_at).getTime() : 0;
        const tB = b.created_at ? new Date(b.created_at).getTime() : 0;
        return tB - tA;
      })
      .slice(0, 5);

    return { total, pending, approved, rejected, pendingList };
  }, [wfhRequests]);

  const openRejectDialog = (req: any) => {
    setSelectedWfhRequest(req);
    setWfhRejectionReason('');
    setShowWfhRequestDialog(true);
  };

  return (
    <div className="space-y-6">
      <div className="relative overflow-hidden flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 p-8 rounded-3xl bg-white dark:bg-gray-900 border shadow-sm mt-1">
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 bg-purple-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-64 w-64 bg-indigo-500/5 rounded-full blur-3xl" />

        <div className="relative flex items-center gap-5">
          <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-purple-200 dark:shadow-none">
            <Users className="h-8 w-8 text-white" />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-gray-900 dark:text-gray-100">
              {t.common.welcome}, <span className="text-purple-600">{user?.name}</span>
            </h1>
            <p className="text-muted-foreground font-medium flex items-center gap-2 mt-1">
              <CalendarDays className="h-4 w-4 text-purple-500" />
              {formatIST(new Date(), 'EEEE, MMMM dd, yyyy')}
            </p>
          </div>
        </div>

        <div className="relative flex gap-3">
          <Button
            onClick={() => navigate('/hr/employees/new/')}
            size="lg"
            className="rounded-xl px-6 h-12 bg-purple-600 hover:bg-purple-700 text-white shadow-lg shadow-purple-200 dark:shadow-none transition-all active:scale-95 gap-2"
          >
            <UserPlus className="h-4 w-4" />
            {t.employee.addEmployee}
          </Button>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          {
            label: t.dashboard.totalEmployees,
            value: stats.totalEmployees,
            sub: 'View All Employees',
            icon: Users,
            color: 'blue',
            bg: 'bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400',
            cardBg: 'bg-blue-50/40 dark:bg-blue-950/10',
            borderColor: 'border-blue-300/80 dark:border-blue-700/50',
            hoverBorder: 'group-hover:border-blue-500 dark:group-hover:border-blue-400',
            path: '/hr/employees'
          },
          {
            label: t.dashboard.presentToday,
            value: stats.presentToday,
            sub: 'View Attendance',
            icon: UserCheck,
            color: 'emerald',
            bg: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400',
            cardBg: 'bg-emerald-50/40 dark:bg-emerald-950/10',
            borderColor: 'border-emerald-300/80 dark:border-emerald-700/50',
            hoverBorder: 'group-hover:border-emerald-500 dark:group-hover:border-emerald-400',
            path: '/hr/attendance',
            pathState: { viewMode: 'employee' }
          },
          {
            label: t.dashboard.pendingApprovals,
            value: stats.pendingLeaves,
            sub: 'Review Requests',
            icon: AlertCircle,
            color: 'amber',
            bg: 'bg-amber-50 text-amber-600 dark:bg-amber-900/20 dark:text-amber-400',
            cardBg: 'bg-amber-50/40 dark:bg-amber-950/10',
            borderColor: 'border-amber-300/80 dark:border-amber-700/50',
            hoverBorder: 'group-hover:border-amber-500 dark:group-hover:border-amber-400',
            path: '/hr/leaves',
            pathState: { viewMode: 'approvals' }
          },
          {
            label: 'Active Tasks',
            value: stats.activeTasks,
            sub: `${stats.completedTasks} Completed Today`,
            icon: ClipboardList,
            color: 'purple',
            bg: 'bg-purple-50 text-purple-600 dark:bg-purple-900/20 dark:text-purple-400',
            cardBg: 'bg-purple-50/40 dark:bg-purple-950/10',
            borderColor: 'border-purple-300/80 dark:border-purple-700/50',
            hoverBorder: 'group-hover:border-purple-500 dark:group-hover:border-purple-400',
            path: '/hr/tasks'
          }
        ].map((item, i) => (
          <Card
            key={i}
            className={`border-2 ${item.borderColor} ${item.hoverBorder} shadow-sm ${item.cardBg} backdrop-blur-sm hover:shadow-md transition-all duration-300 group overflow-hidden relative cursor-pointer`}
            onClick={() => navigate(item.path, { state: item.pathState })}
          >
            {/* Background Accent */}
            <div className={`absolute -right-4 -top-4 w-24 h-24 rounded-full opacity-5 group-hover:opacity-10 transition-opacity ${item.bg.split(' ')[0]}`} />

            <CardContent className="p-4 relative">
              <div className="flex justify-between items-start mb-2">
                <div className={`p-2.5 rounded-xl ${item.bg} shadow-sm group-hover:scale-110 transition-transform duration-300`}>
                  <item.icon className="h-5 w-5" />
                </div>
              </div>
              <div className="space-y-1">
                <h3 className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest leading-none">{item.label}</h3>
                <div className="text-xl font-black text-gray-900 dark:text-gray-100 tracking-tight">{item.value}</div>
                <div className="inline-flex items-center gap-1.5 px-2 py-1 rounded-md bg-white/50 dark:bg-gray-900/30 border border-black/5 dark:border-white/5">
                  <div className={`h-1.5 w-1.5 rounded-full ${item.color === 'blue' ? 'bg-blue-500' :
                    item.color === 'emerald' ? 'bg-emerald-500' :
                      item.color === 'amber' ? 'bg-amber-500' :
                        'bg-purple-500'
                    }`} />
                  <span className="text-[10px] font-bold text-muted-foreground uppercase">{item.sub}</span>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Recent Activities */}
        <Card className="lg:col-span-2 border-0 shadow-lg bg-gradient-to-br from-slate-50 to-gray-100 dark:from-slate-900 dark:to-gray-800">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center">
                <Activity className="h-5 w-5 text-white" />
              </div>
              {t.dashboard.recentActivities}
            </CardTitle>
            <CardDescription className="text-base">Latest HR activities and requests</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">{activityFeedContent}</CardContent>
        </Card>

        {/* WFH Requests */}
        <Card className="border-0 shadow-lg bg-gradient-to-br from-slate-50 to-gray-100 dark:from-slate-900 dark:to-gray-800">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                <Home className="h-5 w-5 text-white" />
              </div>
              WFH Requests
            </CardTitle>
            <CardDescription className="text-base">Review pending work-from-home requests</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-4 gap-2">
              <div className="rounded-lg border bg-white/60 dark:bg-gray-900/30 p-3">
                <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Total</div>
                <div className="text-lg font-black text-gray-900 dark:text-gray-100">{wfhSummary.total}</div>
              </div>
              <div className="rounded-lg border bg-white/60 dark:bg-gray-900/30 p-3">
                <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Pending</div>
                <div className="text-lg font-black text-gray-900 dark:text-gray-100">{wfhSummary.pending}</div>
              </div>
              <div className="rounded-lg border bg-white/60 dark:bg-gray-900/30 p-3">
                <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Approved</div>
                <div className="text-lg font-black text-gray-900 dark:text-gray-100">{wfhSummary.approved}</div>
              </div>
              <div className="rounded-lg border bg-white/60 dark:bg-gray-900/30 p-3">
                <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Rejected</div>
                <div className="text-lg font-black text-gray-900 dark:text-gray-100">{wfhSummary.rejected}</div>
              </div>
            </div>

            <div className="flex items-center justify-between">
              <div className="text-sm font-semibold">Pending (latest)</div>
              <Button
                variant="outline"
                size="sm"
                onClick={() => navigate('/hr/attendance?tab=wfh_requests')}
                className="h-8"
              >
                View All
                <ChevronRightIcon className="h-4 w-4 ml-1" />
              </Button>
            </div>

            {isLoadingWfhRequests ? (
              <div className="p-4 text-center text-muted-foreground text-sm">Loading WFH requests...</div>
            ) : !wfhSummary.pendingList.length ? (
              <div className="p-4 text-center text-muted-foreground text-sm">No pending requests.</div>
            ) : (
              <div className="space-y-2">
                {wfhSummary.pendingList.map((req: any) => (
                  <div
                    key={req.id}
                    className="rounded-lg border bg-white/60 dark:bg-gray-900/30 p-3 flex items-start justify-between gap-3"
                  >
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <div className="text-sm font-semibold truncate">{req.user_name}</div>
                        <Badge variant="secondary" className="text-xs capitalize">
                          {formatStatusLabel(req.status)}
                        </Badge>
                      </div>
                      <div className="text-xs text-muted-foreground mt-1">
                        {formatShortDate(req.start_date)} → {formatShortDate(req.end_date)} • {req.department}
                      </div>
                      {req.reason ? (
                        <div className="text-xs text-muted-foreground mt-1">
                          <TruncatedText
                            text={req.reason}
                            maxLength={80}
                            showToggle={false}
                          />
                        </div>
                      ) : null}
                    </div>
                    <div className="flex gap-2 flex-shrink-0">
                      <Button
                        size="sm"
                        disabled={isProcessingWfhRequest}
                        onClick={() => handleWfhRequestAction(Number(req.id), 'approve')}
                        className="h-8"
                      >
                        Approve
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        disabled={isProcessingWfhRequest}
                        onClick={() => openRejectDialog(req)}
                        className="h-8"
                      >
                        Reject
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <Dialog open={showWfhRequestDialog} onOpenChange={setShowWfhRequestDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Reject WFH Request</DialogTitle>
            <DialogDescription>
              Provide a brief reason. This will be shared with the employee.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-2">
            <div className="text-sm font-medium">
              {selectedWfhRequest?.user_name || 'Employee'}
            </div>
            <Textarea
              value={wfhRejectionReason}
              onChange={(e) => setWfhRejectionReason(e.target.value)}
              placeholder="Reason for rejection..."
              className="min-h-[110px]"
            />
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setShowWfhRequestDialog(false);
                setSelectedWfhRequest(null);
                setWfhRejectionReason('');
              }}
              disabled={isProcessingWfhRequest}
            >
              Cancel
            </Button>
            <Button
              variant="destructive"
              disabled={isProcessingWfhRequest || !selectedWfhRequest?.id}
              onClick={() =>
                handleWfhRequestAction(Number(selectedWfhRequest.id), 'reject', wfhRejectionReason?.trim() || undefined)
              }
            >
              Reject
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>


    </div>
  );
};

export default HRDashboard;

