        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
        break;
      case 'last_3_months':
        startDate = new Date(now.getFullYear(), now.getMonth() - 3, 1, 0, 0, 0);
        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
        break;
      case 'last_6_months':
        startDate = new Date(now.getFullYear(), now.getMonth() - 6, 1, 0, 0, 0);
        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
        break;
      case 'last_1_year':
        startDate = new Date(now.getFullYear() - 1, now.getMonth(), 1, 0, 0, 0);
        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
        break;
      case 'custom':
        if (!leaveHistoryCustomStartDate || !leaveHistoryCustomEndDate) {
          return userLeaves.sort((a, b) => {
            const timeA = new Date(a.startDate).getTime();
            const timeB = new Date(b.startDate).getTime();
            return timeB - timeA;
          });
        }
        startDate = new Date(leaveHistoryCustomStartDate.getFullYear(), leaveHistoryCustomStartDate.getMonth(), leaveHistoryCustomStartDate.getDate(), 0, 0, 0);
        endDate = new Date(leaveHistoryCustomEndDate.getFullYear(), leaveHistoryCustomEndDate.getMonth(), leaveHistoryCustomEndDate.getDate(), 23, 59, 59);
        break;
      default:
        return userLeaves.sort((a, b) => {
          const timeA = new Date(a.startDate).getTime();
          const timeB = new Date(b.startDate).getTime();
          return timeB - timeA;
        });
    }

    const filtered = userLeaves.filter(request => {
      const requestDate = new Date(request.startDate);
      return requestDate >= startDate && requestDate <= endDate;
    });

    return filtered.sort((a, b) => {
      const timeA = new Date(a.startDate).getTime();
      const timeB = new Date(b.startDate).getTime();
      return timeB - timeA;
    });
  }, [leaveRequests, user?.id, leaveHistoryPeriod, leaveHistoryCustomStartDate, leaveHistoryCustomEndDate]);

  return (
    <div className="w-full space-y-6">
      {/* Modern Header */}
      <div className="relative overflow-hidden flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 p-8 rounded-3xl bg-white dark:bg-gray-900 border shadow-sm mt-1">
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 bg-indigo-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-64 w-64 bg-purple-500/5 rounded-full blur-3xl" />

        <div className="relative flex items-center gap-5">
          <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-200 dark:shadow-none">
            <CalendarDays className="h-8 w-8 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white sm:text-3xl">
              Leave Management
            </h1>
            <p className="text-muted-foreground font-medium flex items-center gap-2 mt-1">
              <Clock className="h-4 w-4 text-indigo-500" />
              Manage leave requests and view calendar
            </p>
          </div>
        </div>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className={`grid w-full ${colsClass} h-14 bg-gradient-to-r from-slate-100 to-gray-100 dark:from-slate-800 dark:to-gray-800 border-2 border-slate-200 dark:border-slate-700 rounded-lg p-1 gap-1 shadow-sm`}>
          {canApply && (
            <TabsTrigger
              value="request"
              className="data-[state=active]:bg-gradient-to-r data-[state=active]:from-blue-600 data-[state=active]:to-indigo-600 data-[state=active]:text-white data-[state=active]:shadow-lg data-[state=active]:font-semibold data-[state=inactive]:text-slate-600 dark:data-[state=inactive]:text-slate-300 data-[state=inactive]:hover:bg-slate-200 dark:data-[state=inactive]:hover:bg-slate-700 transition-all duration-300 rounded-md"
            >
              Apply Leave
            </TabsTrigger>
          )}
          {(canApproveLeaves || canViewTeamLeaves) && (
            <TabsTrigger
              value="approvals"
              className="data-[state=active]:bg-gradient-to-r data-[state=active]:from-green-600 data-[state=active]:to-emerald-600 data-[state=active]:text-white data-[state=active]:shadow-lg data-[state=active]:font-semibold data-[state=inactive]:text-slate-600 dark:data-[state=inactive]:text-slate-300 data-[state=inactive]:hover:bg-slate-200 dark:data-[state=inactive]:hover:bg-slate-700 transition-all duration-300 rounded-md"
            >
              {canApproveLeaves ? 'Approvals' : 'Team Leaves'}
            </TabsTrigger>
          )}
          <TabsTrigger
            value="calendar"
            className="data-[state=active]:bg-gradient-to-r data-[state=active]:from-purple-600 data-[state=active]:to-pink-600 data-[state=active]:text-white data-[state=active]:shadow-lg data-[state=active]:font-semibold data-[state=inactive]:text-slate-600 dark:data-[state=inactive]:text-slate-300 data-[state=inactive]:hover:bg-slate-200 dark:data-[state=inactive]:hover:bg-slate-700 transition-all duration-300 rounded-md"
          >
            Leave Calendar
          </TabsTrigger>
        </TabsList>

        {canApply && (
          <TabsContent value="request" className="space-y-4">
            {/* Leave Balance Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              {[
                {
                  label: 'Total Leaves',
                  value: `${leaveBalance.annual.remaining}/${leaveBalance.annual.allocated}`,
                  sub: `${leaveBalance.annual.used} used`,
                  icon: CalendarDays,
                  color: 'blue',
                  bg: 'bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400',
                  cardBg: 'bg-blue-50/40 dark:bg-blue-950/10',
                  borderColor: 'border-blue-300/80 dark:border-blue-700/50',
                  hoverBorder: 'group-hover:border-blue-500 dark:group-hover:border-blue-400',
                },
                {
                  label: 'Sick Leave',
                  value: `${leaveBalance.sick.remaining}/${leaveBalance.sick.allocated}`,
                  sub: `${leaveBalance.sick.used} used`,
                  icon: AlertCircle,
                  color: 'rose',
                  bg: 'bg-rose-50 text-rose-600 dark:bg-rose-900/20 dark:text-rose-400',
                  cardBg: 'bg-rose-50/40 dark:bg-rose-950/10',
                  borderColor: 'border-rose-300/80 dark:border-rose-700/50',
                  hoverBorder: 'group-hover:border-rose-500 dark:group-hover:border-rose-400',
                },
                {
                  label: 'Casual Leave',
                  value: `${leaveBalance.casual.remaining}/${leaveBalance.casual.allocated}`,
                  sub: `${leaveBalance.casual.used} used`,
                  icon: Clock,
                  color: 'emerald',
                  bg: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400',
                  cardBg: 'bg-emerald-50/40 dark:bg-emerald-950/10',
                  borderColor: 'border-emerald-300/80 dark:border-emerald-700/50',
                  hoverBorder: 'group-hover:border-emerald-500 dark:group-hover:border-emerald-400',
                },
                {
                  label: 'Unpaid Leave',
                  value: leaveBalance.unpaid.used,
                  sub: 'days taken',
                  icon: FileText,
                  color: 'slate',
                  bg: 'bg-slate-100 text-slate-600 dark:bg-slate-900/40 dark:text-slate-400',
                  cardBg: 'bg-slate-50/40 dark:bg-slate-950/10',
                  borderColor: 'border-slate-300/80 dark:border-slate-700/50',
                  hoverBorder: 'group-hover:border-slate-500 dark:group-hover:border-slate-400',
                }
              ].map((item, i) => (
                <Card
                  key={i}
                  className={`border-2 ${item.borderColor} ${item.hoverBorder} shadow-sm ${item.cardBg} backdrop-blur-sm hover:shadow-md transition-all duration-300 group overflow-hidden relative cursor-pointer`}
                >
                  {/* Background Accent */}
                  <div className={`absolute -right-4 -top-4 w-24 h-24 rounded-full opacity-5 group-hover:opacity-10 transition-opacity ${item.bg.split(' ')[0]}`} />

                  <CardContent className="p-4 relative">
                    <div className="flex justify-between items-start mb-2">
                      <div className={`p-2.5 rounded-xl ${item.bg} shadow-sm group-hover:scale-110 transition-transform duration-300`}>
                        <item.icon className="h-5 w-5" />
                      </div>
                    </div>
                    <div className="space-y-1">
                      <h3 className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest leading-none">{item.label}</h3>
                      <div className="text-xl font-black text-gray-900 dark:text-gray-100 tracking-tight">{item.value}</div>
                      <div className="inline-flex items-center gap-1.5 px-2 py-1 rounded-md bg-white/50 dark:bg-gray-900/30 border border-black/5 dark:border-white/5">
                        <div className={`h-1.5 w-1.5 rounded-full ${item.color === 'blue' ? 'bg-blue-500' :
                          item.color === 'rose' ? 'bg-rose-500' :
                            item.color === 'emerald' ? 'bg-emerald-500' :
                              'bg-slate-500'
                          }`} />
                        <span className="text-[10px] font-bold text-muted-foreground uppercase">{item.sub}</span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>

            {/* Leave Request Form */}
            <Card className="border-0 shadow-lg">
              <CardHeader className="border-b bg-gradient-to-r from-slate-50 to-gray-50 dark:from-slate-900 dark:to-gray-900">
                <CardTitle className="text-xl font-semibold">Request Leave</CardTitle>
                <div className="mt-2 space-y-3">
                  <div className="p-3 bg-blue-50 dark:bg-blue-950 border border-blue-200 dark:border-blue-800 rounded-lg">
                    <p className="text-sm text-blue-800 dark:text-blue-200">
                      <strong>Note:</strong> Sick and Casual leave requests will deduct from your Annual Leave balance. Only Unpaid Leave does not affect your Annual Leave balance.
                    </p>
                  </div>
                  <div className="p-3 bg-amber-50 dark:bg-amber-950 border border-amber-200 dark:border-amber-800 rounded-lg">
                    <p className="text-sm text-amber-800 dark:text-amber-200 flex items-center gap-2 mb-2">
                      <AlertCircle className="h-4 w-4" />
                      <strong>Leave Restrictions:</strong>
                    </p>
                    <div className="text-xs text-amber-700 dark:text-amber-300 space-y-2 pl-1">
                      <div className="flex items-start gap-2">
                        <div className="h-1 w-1 rounded-full bg-amber-500 mt-1.5 flex-shrink-0" />
                        <p><strong>Sick Leave:</strong> {user?.role === 'admin' && "Must be for 3 or more days. "}Must be applied in between 2 hours and 24 hours before office working hours.</p>
                      </div>
                      <div className="flex items-start gap-2">
                        <div className="h-1 w-1 rounded-full bg-amber-500 mt-1.5 flex-shrink-0" />
                        <p><strong>Casual Leave:</strong> For shorter durations (1-2 days). Must be applied at least 24 hours in advance.</p>
                      </div>
                      <div className="flex items-start gap-2">
                        <div className="h-1 w-1 rounded-full bg-amber-500 mt-1.5 flex-shrink-0" />
                        <p><strong>Other Leaves:</strong> Annual, Maternity, Paternity must be applied at least 24 hours in advance.</p>
                      </div>
                    </div>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Leave Type</Label>
                    <Select
                      value={formData.type}
                      onValueChange={(value) => setFormData({ ...formData, type: value })}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select Leave Type" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="sick" disabled={isLeaveTypeDisabled('sick', leaveBalance)}>
                          Sick Leave {leaveBalance.sick.remaining <= 0 ? '(No balance)' : `(${leaveBalance.sick.remaining} days)`}
                        </SelectItem>
                        <SelectItem value="casual" disabled={isLeaveTypeDisabled('casual', leaveBalance)}>
                          Casual Leave {leaveBalance.casual.remaining <= 0 ? '(No balance)' : `(${leaveBalance.casual.remaining} days)`}
                        </SelectItem>
                        <SelectItem value="maternity">Maternity Leave</SelectItem>
                        <SelectItem value="paternity">Paternity Leave</SelectItem>
                        <SelectItem value="unpaid">Unpaid Leave</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Duration</Label>
                    <div className="flex gap-2">
                      <div className="flex-1">
                        <DatePicker
                          date={formData.startDate}
                          onDateChange={(date) => date && setFormData({ ...formData, startDate: date })}
                        />
                      </div>
                      <div className="flex-1">
                        <DatePicker
                          date={formData.endDate}
                          onDateChange={(date) => date && setFormData({ ...formData, endDate: date })}
                        />
                      </div>
                    </div>
                  </div>
                </div>

                {/* Dynamic validation feedback */}
                {(() => {
                  const leaveDays = Math.ceil((formData.endDate.getTime() - formData.startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1;
                  const now = new Date();
                  const startDate = new Date(formData.startDate);
                  const timeDifference = startDate.getTime() - now.getTime();
                  const hoursDifference = timeDifference / (1000 * 60 * 60);

                  const validationMessages: { type: 'error' | 'success'; message: string }[] = [];

                  // Check advance notice requirements
                  if (formData.type === 'sick') {
                    // For non-admin roles, skip the minimum 3 days requirement check entirely
                    const officeStartTime = new Date(formData.startDate);
                    officeStartTime.setHours(9, 30, 0, 0);
                    const diffToOfficeHours = (officeStartTime.getTime() - now.getTime()) / (1000 * 60 * 60);

                    // Admin: enforce 3-day minimum; HR/Manager/TeamLead/Employee: skip this check
                    if (user?.role === 'admin' && leaveDays < 3) {
                      validationMessages.push({
                        type: 'error',
                        message: `Sick leave requires minimum 3 days. Current selection: ${leaveDays} day${leaveDays === 1 ? '' : 's'}. Consider using Casual Leave for shorter periods.`
                      });
                    } else if (diffToOfficeHours < 2 || diffToOfficeHours > 24) {
                      validationMessages.push({
                        type: 'error',
                        message: 'Sick leave must be applied in between 2 hours and 24 hours before office working hours.'
                      });
                    }
                  } else {
                    // Other leaves require 24 hours advance notice
                    if (hoursDifference < 24 && hoursDifference >= 0) {
                      const hoursRemaining = Math.ceil(24 - hoursDifference);
                      validationMessages.push({
                        type: 'error',
                        message: `Leave must be applied 24 hours in advance. Please select a date at least ${hoursRemaining} hours from now.`
                      });
                    }
                  }

                  // Show success message when valid
                  if (validationMessages.length === 0 && leaveDays > 0) {
                    if (formData.type === 'sick') {
                      const officeStartTime = new Date(formData.startDate);
                      officeStartTime.setHours(9, 30, 0, 0);
                      const diffToOfficeHours = (officeStartTime.getTime() - now.getTime()) / (1000 * 60 * 60);
                      validationMessages.push({
                        type: 'success',
                        message: `Valid sick leave request for ${leaveDays} day${leaveDays === 1 ? '' : 's'}. Applied ${diffToOfficeHours.toFixed(1)} hours before office hours.`
                      });
                    } else if (hoursDifference >= 24) {
                      validationMessages.push({
                        type: 'success',
                        message: `Valid leave request with ${Math.floor(hoursDifference)} hours advance notice.`
                      });
                    }
                  }

                  return validationMessages.length > 0 ? (
                    <div className="space-y-2">
                      {validationMessages.map((msg, index) => (
                        <div
                          key={index}
                          className={`p-3 rounded-lg border text-sm flex items-center gap-2 ${msg.type === 'error'
                            ? 'bg-red-50 dark:bg-red-950 border-red-200 dark:border-red-800 text-red-800 dark:text-red-200'
                            : 'bg-green-50 dark:bg-green-950 border-green-200 dark:border-green-800 text-green-800 dark:text-green-200'
                            }`}
                        >
                          {msg.type === 'error' ? (
                            <AlertCircle className="h-4 w-4 flex-shrink-0" />
                          ) : (
                            <CheckCircle className="h-4 w-4 flex-shrink-0" />
                          )}
                          {msg.message}
                        </div>
                      ))}
                    </div>
                  ) : null;
                })()}

                <div className="space-y-2">
                  <Label>Reason *</Label>
                  <Textarea
                    maxLength={200}
                    value={formData.reason}
                    onChange={(e) => setFormData({ ...formData, reason: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                    placeholder="Please provide a reason for your leave request (minimum 10 characters)."
                    rows={3}
                    className={formData.reason.trim().length > 0 && formData.reason.trim().length < 10 ? 'border-red-500' : ''}
                  />
                  <div className="flex justify-between text-sm">
                    <span className={`${formData.reason.trim().length < 10 ? 'text-red-500' : 'text-green-600'}`}>
                      {formData.reason.trim().length < 10
                        ? `${formData.reason.trim().length}/10 characters (minimum required)`
                        : `${formData.reason.trim().length}/200 characters`
                      }
                    </span>
                    {formData.reason.trim().length < 10 && formData.reason.trim().length > 0 && (
                      <span className="text-red-500 text-xs">Minimum 10 characters required</span>
                    )}
                  </div>
                </div>
                <Button
                  onClick={handleSubmitRequest}
                  disabled={isSubmitting || formData.reason.trim().length < 10}
                  className="gap-2 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 shadow-md disabled:opacity-50"
                >
                  <CalendarIcon className="h-4 w-4" />
                  {isSubmitting ? 'Submitting...' : 'Submit Request'}
                </Button>
              </CardContent>
            </Card>

            {/* My Leave History - Premium UI */}
            <Card className="border-0 shadow-xl bg-gradient-to-br from-white to-slate-50 dark:from-slate-900 dark:to-slate-800 overflow-hidden">
              <CardHeader className="border-b bg-gradient-to-r from-indigo-50 via-purple-50 to-pink-50 dark:from-indigo-950 dark:via-purple-950 dark:to-pink-950">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg">
                      <CalendarDays className="h-6 w-6 text-white" />
                    </div>
                    <div>
                      <CardTitle className="text-2xl font-bold bg-gradient-to-r from-indigo-600 to-purple-600 dark:from-indigo-400 dark:to-purple-400 bg-clip-text text-transparent">
                        My Leave History
                      </CardTitle>
                      <p className="text-sm text-muted-foreground mt-1">
                        Track all your leave requests and their status
                      </p>
                    </div>
                  </div>
                  <Select
                    value={leaveHistoryPeriod}
                    onValueChange={(value) => setLeaveHistoryPeriod(value)}
                  >
                    <SelectTrigger className="w-[220px] bg-white dark:bg-slate-800 border-2 shadow-md hover:shadow-lg transition-all">
                      <SelectValue placeholder="Select period" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All History</SelectItem>
                      <SelectItem value="current_month">Current Month</SelectItem>
                      <SelectItem value="last_3_months">Last 3 Months</SelectItem>
                      <SelectItem value="last_6_months">Last 6 Months</SelectItem>
                      <SelectItem value="last_1_year">Last 1 Year</SelectItem>
                      <SelectItem value="custom">Custom Range</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </CardHeader>
              {leaveHistoryPeriod === 'custom' && (
                <div className="border-b bg-slate-50 dark:bg-slate-900 p-4">
                  <div className="flex items-center gap-3 flex-wrap">
                    <div className="flex-1 min-w-[150px]">
                      <Label className="text-xs mb-1 block">From Date</Label>
                      <Input
                        type="date"
                        value={leaveHistoryCustomStartDate ? format(leaveHistoryCustomStartDate, 'yyyy-MM-dd') : ''}
                        onChange={(e) => {
                          if (e.target.value) {
                            const [y, m, d] = e.target.value.split('-').map(Number);
                            setLeaveHistoryCustomStartDate(new Date(y, m - 1, d));
                          } else {
                            setLeaveHistoryCustomStartDate(undefined);
                          }
                        }}
                        className="h-11 border-2 focus:ring-2 focus:ring-violet-500 transition-all w-full"
                      />
                    </div>
                    <div className="flex-1 min-w-[150px]">
                      <Label className="text-xs mb-1 block">To Date</Label>
                      <Input
                        type="date"
                        value={leaveHistoryCustomEndDate ? format(leaveHistoryCustomEndDate, 'yyyy-MM-dd') : ''}
                        onChange={(e) => {
                          if (e.target.value) {
                            const [y, m, d] = e.target.value.split('-').map(Number);
                            setLeaveHistoryCustomEndDate(new Date(y, m - 1, d));
                          } else {
                            setLeaveHistoryCustomEndDate(undefined);
                          }
                        }}
                        min={leaveHistoryCustomStartDate ? format(leaveHistoryCustomStartDate, 'yyyy-MM-dd') : undefined}
                        className="h-11 border-2 focus:ring-2 focus:ring-violet-500 transition-all w-full"
                      />
                    </div>
                  </div>
                </div>
              )}
              <CardContent className="p-6">
                {getFilteredLeaveRequests.length === 0 ? (
                  <div className="text-center py-16">
                    <div className="h-24 w-24 rounded-full bg-gradient-to-br from-indigo-100 to-purple-100 dark:from-indigo-900 dark:to-purple-900 flex items-center justify-center mx-auto mb-4">
                      <AlertCircle className="h-12 w-12 text-indigo-500 dark:text-indigo-400 opacity-50" />
                    </div>
                    <h3 className="text-lg font-semibold text-gray-700 dark:text-gray-300 mb-2">No Leave History</h3>
                    <p className="text-sm text-muted-foreground">No leave requests found for the selected period.</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {getFilteredLeaveRequests
                      .slice((myLeaveCurrentPage - 1) * myLeaveItemsPerPage, myLeaveCurrentPage * myLeaveItemsPerPage)
                      .map((request) => {
                        const daysCount = Math.ceil((request.endDate.getTime() - request.startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1;
                        const statusConfig = {
                          pending: {
                            bg: 'bg-amber-50 dark:bg-amber-950',
                            border: 'border-amber-200 dark:border-amber-800',
                            icon: Clock,
                            iconColor: 'text-amber-600 dark:text-amber-400',
                          },
                          approved: {
                            bg: 'bg-emerald-50 dark:bg-emerald-950',
                            border: 'border-emerald-200 dark:border-emerald-800',
                            icon: CheckCircle,
                            iconColor: 'text-emerald-600 dark:text-emerald-400',
                          },
                          rejected: {
                            bg: 'bg-red-50 dark:bg-red-950',
                            border: 'border-red-200 dark:border-red-800',
                            icon: XCircle,
                            iconColor: 'text-red-600 dark:text-red-400',
                          },
                        };
                        const config = statusConfig[request.status] || statusConfig.pending;
                        const StatusIcon = config.icon;

                        return (
                          <div
                            key={request.id}
                            className={`flex items-start justify-between gap-4 rounded-xl border ${config.border} bg-white dark:bg-slate-900 px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors`}
                          >
                            <div className="flex items-start gap-3 flex-1 min-w-0">
                              <div className={`mt-1 h-9 w-9 rounded-lg ${config.bg} flex items-center justify-center flex-shrink-0`}>
                                <StatusIcon className={`h-4 w-4 ${config.iconColor}`} />
                              </div>
                              <div className="space-y-1 flex-1 min-w-0">
                                <div className="flex flex-wrap items-center gap-2">
                                  <span className="text-sm font-semibold text-gray-900 dark:text-gray-100">
                                    {format(request.startDate, 'dd MMM yyyy')}
                                  </span>
                                  <span className="text-xs text-muted-foreground">to</span>
                                  <span className="text-sm font-semibold text-gray-900 dark:text-gray-100">
                                    {format(request.endDate, 'dd MMM yyyy')}
                                  </span>
                                  <Badge className={`${getLeaveTypeColor(request.type)} text-[10px] font-semibold capitalize`}>
                                    {request.type}
                                  </Badge>
                                  <span className="text-xs text-muted-foreground flex items-center gap-1">
                                    <Timer className="h-3 w-3" />
                                    {daysCount} {daysCount === 1 ? 'day' : 'days'}
                                  </span>
                                </div>
                                <p className="text-xs text-muted-foreground flex items-start gap-2">
                                  <FileText className="mt-0.5 h-3.5 w-3.5 flex-shrink-0" />
                                  <span className="line-clamp-2 break-words overflow-wrap-anywhere whitespace-pre-wrap">{request.reason}</span>
                                </p>
                              </div>
                            </div>
                            <div className="flex flex-col items-end gap-1">
                              <Badge
                                className={`px-3 py-1 text-xs font-bold capitalize ${getStatusBadgeStyle(request.status)}`}
                              >
                                {request.status}
                              </Badge>
                              {request.approvedBy && (
                                <span className="text-[10px] text-muted-foreground flex items-center gap-1">
                                  <User className="h-3 w-3" />
                                  <span>by {request.approvedBy}</span>
                                </span>
                              )}
                              {request.status === 'pending' && (
                                <div className="mt-1 flex items-center gap-1.5">
                                  <Button
                                    size="xs"
                                    className="h-7 px-2 text-[11px]"
                                    onClick={() => handleEditLeave(request)}
                                  >
                                    Edit
                                  </Button>
                                  <Button
                                    type="button"
                                    size="xs"
                                    variant="destructive"
                                    className="h-7 px-2 text-[11px]"
                                    onClick={(e) => {
                                      e.preventDefault();
                                      e.stopPropagation();
                                      handleDeleteLeave(request);
                                    }}
                                  >
                                    Delete
                                  </Button>
                                </div>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    {getFilteredLeaveRequests.length > 0 && (
                      <div className="mt-6 px-2">
                        <Pagination
                          currentPage={myLeaveCurrentPage}
                          totalPages={Math.ceil(getFilteredLeaveRequests.length / myLeaveItemsPerPage)}
                          totalItems={getFilteredLeaveRequests.length}
                          itemsPerPage={myLeaveItemsPerPage}
                          onPageChange={setMyLeaveCurrentPage}
                          onItemsPerPageChange={setMyLeaveItemsPerPage}
                          showItemsPerPage={true}
                          showEntriesInfo={true}
                        />
                      </div>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>

          </TabsContent>
        )}

        <TabsContent value="calendar">
          <Card className="border-0 shadow-lg">
            <CardHeader className="border-b bg-gradient-to-r from-slate-50 to-gray-50 dark:from-slate-900 dark:to-gray-900">
              <CardTitle className="text-xl font-semibold">Leave Calendar</CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              {/* Admin holiday management UI */}
              {user?.role === 'admin' && (
                <div className="mb-6 space-y-6 mt-4">
                  {/* Leave Allocation Configuration Panel */}
                  <div className="p-6 border-2 rounded-xl bg-gradient-to-r from-purple-50 via-indigo-50 to-blue-50 dark:from-purple-950 dark:via-indigo-950 dark:to-blue-950 shadow-lg">
                    <div className="flex items-start justify-between gap-3 mb-4">
                      <div>
                        <h3 className="font-bold text-lg mb-1 flex items-center gap-2">
                          <FileText className="h-6 w-6 text-purple-600" />
                          Leave Allocation Configuration
                        </h3>
                        <p className="text-sm text-muted-foreground">
                          Set the total annual leave and distribute it across different leave types. Changes apply to all users immediately.
                        </p>
                      </div>
                    </div>

                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4 mt-6">
                      <div className="space-y-2">
                        <Label className="font-semibold text-purple-700 dark:text-purple-300">
                          Total Annual Leave
                        </Label>
                        <Input
                          disabled
                          value={leaveAllocationConfig.total_annual_leave}
                          className="border-2 border-purple-200 dark:border-purple-800 bg-gray-100 dark:bg-gray-800 opacity-80 cursor-not-allowed font-bold"
                          placeholder="Calculated automatically"
                        />
                        <p className="text-xs text-muted-foreground">
                          Total days (Sick + Casual + Other)
                        </p>
                      </div>

                      <div className="space-y-2">
                        <Label className="font-semibold text-red-700 dark:text-red-300">
                          Sick Leave
                        </Label>
                        <Input
                          type="number"
                          min="0"
                          max="365"
                          value={leaveAllocationConfig.sick_leave_allocation}
                          onChange={(e) => {
                            const val = parseInt(e.target.value) || 0;
                            setLeaveAllocationConfig((prev) => ({
                              ...prev,
                              sick_leave_allocation: val,
                              total_annual_leave: val + prev.casual_leave_allocation + prev.other_leave_allocation,
                            }));
                          }}
                          className="border-2 border-red-200 dark:border-red-800 focus:border-red-500"
                          placeholder="e.g., 10"
                        />
                        <p className="text-xs text-muted-foreground">
                          Days allocated
                        </p>
                      </div>

                      <div className="space-y-2">
                        <Label className="font-semibold text-green-700 dark:text-green-300">
                          Casual Leave
                        </Label>
                        <Input
                          type="number"
                          min="0"
                          max="365"
                          value={leaveAllocationConfig.casual_leave_allocation}
                          onChange={(e) => {
                            const val = parseInt(e.target.value) || 0;
                            setLeaveAllocationConfig((prev) => ({
                              ...prev,
                              casual_leave_allocation: val,
                              total_annual_leave: prev.sick_leave_allocation + val + prev.other_leave_allocation,
                            }));
                          }}
                          className="border-2 border-green-200 dark:border-green-800 focus:border-green-500"
                          placeholder="e.g., 5"
                        />
                        <p className="text-xs text-muted-foreground">
                          Days allocated
                        </p>
                      </div>

                      <div className="space-y-2">
                        <Label className="font-semibold text-gray-700 dark:text-gray-300">
                          Other Leave
                        </Label>
                        <Input
                          type="number"
                          min="0"
                          max="365"
                          value={leaveAllocationConfig.other_leave_allocation}
                          onChange={(e) => {
                            const val = parseInt(e.target.value) || 0;
                            setLeaveAllocationConfig((prev) => ({
                              ...prev,
                              other_leave_allocation: val,
                              total_annual_leave: prev.sick_leave_allocation + prev.casual_leave_allocation + val,
                            }));
                          }}
                          className="border-2 border-gray-200 dark:border-gray-800 focus:border-gray-500"
                          placeholder="e.g., 0"
                        />
                        <p className="text-xs text-muted-foreground">
                          Days allocated
                        </p>
                      </div>
                    </div>

                    <div className="mt-6 p-4 bg-blue-50 dark:bg-blue-950 border border-blue-200 dark:border-blue-800 rounded-lg">
                      <p className="text-sm text-blue-800 dark:text-blue-200 text-center">
                        Note: Sick and Casual leave requests will deduct from the Total Annual Leave balance. The individual allocations (Sick and Casual) are for reference and tracking purposes.
                      </p>
                    </div>

                    <div className="mt-6 flex items-center gap-3">
                      <Button
                        onClick={handleSaveLeaveAllocationConfig}
                        disabled={isSavingLeaveConfig}
                        className="gap-2 bg-gradient-to-r from-purple-600 via-indigo-600 to-blue-600 hover:from-purple-700 hover:via-indigo-700 hover:to-blue-700 shadow-lg"
                      >
                        <CheckCircle className="h-4 w-4" />
                        {isSavingLeaveConfig ? 'Saving...' : 'Save Configuration'}
                      </Button>
                      <p className="text-sm text-muted-foreground">
                        Changes will apply to all users immediately
                      </p>
                    </div>
                  </div>

                  {user?.role === 'admin' && (
                    <div className="p-4 border rounded-lg bg-gradient-to-r from-amber-50 to-yellow-50 dark:from-amber-950 dark:to-yellow-950">
                      <h3 className="font-semibold mb-3 flex items-center gap-2">
                        Set Company Holidays
                      </h3>
                      <div className="space-y-3">
                        <div className="flex flex-col md:flex-row gap-6 items-start">
                          <div className="flex-shrink-0 mx-auto md:mx-0">
                            <HolidayCalendar
                              date={holidayForm.date}
                              onDateChange={(date) => date && setHolidayForm({ ...holidayForm, date })}
                              className="w-[280px]"
                            />
                          </div>
                          <div className="flex-1 space-y-4 w-full">
                            <div className="space-y-2">
                              <Label>Holiday Name</Label>
                              <Input
                                type="text"
                                placeholder="e.g., Diwali, New Year"
                                value={holidayForm.name}
                                onChange={e => setHolidayForm({ ...holidayForm, name: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                                className="bg-white dark:bg-slate-900"
                              />
                            </div>
                            <div className="space-y-2">
                              <Label>Description</Label>
                              <Textarea
                                placeholder="Description (optional) - e.g., Festival of Lights celebration"
                                value={holidayForm.description || ''}
                                onChange={e => setHolidayForm({ ...holidayForm, description: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                                rows={3}
                                className="resize-none bg-white dark:bg-slate-900"
                              />
                            </div>
                            <div className="space-y-2">
                              <Label>Recurring</Label>
                              <Select
                                value={holidayForm.is_recurring ? 'yes' : 'no'}
                                onValueChange={(value) => setHolidayForm({ ...holidayForm, is_recurring: value === 'yes' })}
                              >
                                <SelectTrigger className="bg-white dark:bg-slate-900">
                                  <SelectValue placeholder="Is Recurring?" />
                                </SelectTrigger>
                                <SelectContent>
                                  <SelectItem value="no">No</SelectItem>
                                  <SelectItem value="yes">Yes</SelectItem>
                                </SelectContent>
                              </Select>
                            </div>
                            <Button
                              onClick={handleAddHoliday}
                              className="w-full gap-2 bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-700 hover:to-rose-700 shadow-md"
                            >
                              Add Holiday
                            </Button>
                          </div>
                        </div>
                      </div>
                      <div className="mt-4">
                        <h4 className="font-medium mb-2">Current Holidays:</h4>
                        {holidays.length === 0 ? (
                          <p className="text-sm text-muted-foreground">No holidays configured yet.</p>
                        ) : (
                          <ul className="space-y-2">
                            {holidays.map(h => (
                              <li key={h.id || h.date.toISOString()} className="flex items-center justify-between gap-2 p-2 bg-white dark:bg-slate-800 rounded border">
                                <span className="flex-1">
                                  <strong>{h.name}</strong> - {format(h.date, 'MMMM dd, yyyy')}
                                  {h.description && <span className="text-sm text-muted-foreground ml-2">({h.description})</span>}
                                  {h.is_recurring && <Badge variant="secondary" className="ml-2 text-[10px]">Recurring</Badge>}
                                </span>
                                <Button
                                  size="sm"
                                  variant="destructive"
                                  onClick={() => h.id && handleRemoveHoliday(h.id)}
                                >
                                  Remove
                                </Button>
                              </li>
                            ))}
                          </ul>
                        )}
                      </div>
                    </div>
                  )}

                  <div className="p-4 border rounded-lg bg-gradient-to-r from-sky-50 to-indigo-50 dark:from-slate-900 dark:to-indigo-950">
                    <div className="flex items-start justify-between gap-3">
                      <div>
                        <h3 className="font-semibold mb-1 flex items-center gap-2">
                          Department Week-off Planner
                        </h3>
                        <p className="text-sm text-muted-foreground">
                          Define weekly off days for each department to keep schedules aligned.
                        </p>
                      </div>
                    </div>
                    <div className="mt-4 grid gap-4 md:grid-cols-3">
                      <div className="space-y-2">
                        <Label>Department</Label>
                        {departmentOptions.length > 0 ? (
                          <Select
                            value={weekOffForm.department}
                            onValueChange={(value) =>
                              setWeekOffForm((prev) => ({ ...prev, department: value }))
                            }
                          >
                            <SelectTrigger>
                              <SelectValue placeholder="Select department" />
                            </SelectTrigger>
                            <SelectContent>
                              {departmentOptions.map((dept) => (
                                <SelectItem key={dept} value={dept}>
                                  {dept}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        ) : (
                          <Input
                            placeholder="e.g., Engineering"
                            value={weekOffForm.department}
                            onChange={(e) =>
                              setWeekOffForm((prev) => ({ ...prev, department: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))
                            }
                          />
                        )}
                      </div>
                      <div className="space-y-2 md:col-span-2">
                        <Label>Weekly Off Days</Label>
                        <div className="flex flex-wrap gap-2">
                          {weekDayOptions.map((day) => {
                            const isSelected = weekOffForm.days.includes(day.value);
                            return (
                              <button
                                key={day.value}
                                type="button"
                                onClick={() =>
                                  setWeekOffForm((prev) => {
                                    const exists = prev.days.includes(day.value);
                                    const isAdminOrHR = ['admin', 'hr'].includes(user?.role || '');
                                    const limit = isAdminOrHR ? 7 : 2;

                                    const nextDays = exists
                                      ? prev.days.filter((d) => d !== day.value)
                                      : prev.days.length >= limit
                                        ? prev.days
                                        : [...prev.days, day.value];

                                    if (!exists && prev.days.length >= limit) {
                                      toast({
                                        title: 'Limit reached',
                                        description: isAdminOrHR
                                          ? 'You can select up to 7 weekly off days.'
                                          : 'You can only select up to two weekly off days.',
                                      });
                                    }
                                    return { ...prev, days: nextDays };
                                  })
                                }
                                className={`rounded-full px-3 py-1 text-sm border transition ${isSelected
                                  ? 'border-sky-500 bg-white text-sky-600 shadow-sm'
                                  : 'border-slate-300 text-slate-600 hover:bg-white'
                                  }`}
                              >
                                {day.label}
                              </button>
                            );
                          })}
                        </div>
                        <p className="text-xs text-muted-foreground">
                          Tip: Select up to two days if the department enjoys a long weekend.
                        </p>
                      </div>
                      <div className="space-y-2 flex flex-col justify-end md:col-span-3">
                        <Button
                          className="rounded-xl bg-gradient-to-r from-sky-600 to-indigo-600 hover:from-sky-700 hover:to-indigo-700 self-start"
                          onClick={handleSaveWeekOff}
                        >
                          Save Week-off
                        </Button>
                      </div>
                    </div>
                    <div className="mt-4">
                      <h4 className="font-medium mb-2">Active Week-off Rules</h4>
                      {Object.keys(weekOffConfig).length === 0 ? (
                        <p className="text-sm text-muted-foreground">
                          No department-specific week-offs defined yet.
                        </p>
                      ) : (
                        <div className="space-y-2">
                          {Object.entries(weekOffConfig).map(([dept, config]) => (
                            <div
                              key={dept}
                              className="flex items-center justify-between rounded-lg border border-slate-200 dark:border-slate-800 bg-white/70 dark:bg-slate-950/60 px-3 py-2 text-sm"
                            >
                              <div>
                                <p className="font-semibold text-slate-800 dark:text-slate-100">
                                  {dept}
                                </p>
                                <p className="text-muted-foreground text-xs">
                                  Weekly off: {config.days.map((day) => {
                                    const cleanDay = day.replace(/[^\p{L}]/gu, '').toLowerCase();
                                    return weekDayLabels[cleanDay] || day.replace(/[^\p{L}]/gu, '');
                                  }).join(', ')}
                                </p>
                              </div>
                              <Button
                                variant="ghost"
                                size="sm"
                                className="text-rose-500 hover:text-rose-600"
                                onClick={() => handleRemoveWeekOff(dept)}
                              >
                                Remove
                              </Button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              )}
              {/* Calendar with holidays highlighted */}
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 items-start">
                {/* Left Column: Calendar */}
                <div className="xl:col-span-5 space-y-6">
                  <div className="relative group p-4 rounded-3xl bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 shadow-2xl shadow-indigo-100 dark:shadow-none transition-all duration-300">
                    {/* Decorative Background Blobs */}
                    <div className="absolute top-0 left-0 -mt-4 -ml-4 w-24 h-24 bg-indigo-500/5 rounded-full blur-2xl group-hover:bg-indigo-500/10 transition-colors" />
                    <div className="absolute bottom-0 right-0 -mb-4 -mr-4 w-32 h-32 bg-purple-500/5 rounded-full blur-2xl group-hover:bg-purple-500/10 transition-colors" />

                    <div className="relative">
                      <CalendarWithSelect
                        key={`calendar-${holidays.length}-${Object.keys(weekOffConfig).length}`}
                        mode="single"
                        selected={selectedDate}
                        onSelect={handleDayClick}
                        currentMonth={displayedMonth}
                        onMonthChange={setDisplayedMonth}
                        className="rounded-2xl bg-transparent"
                        modifiers={{
                          holiday: holidays.map(h => h.date),
                          weekOff: (date) =>
                            userWeekOffDays.some(
                              (day) => weekDayIndexMap[day.toLowerCase()] === date.getDay(),
                            ),
                          leave: leaveRequests
                            .filter(r => r.status === 'approved')
                            .reduce((acc: Date[], r) => {
                              const start = new Date(r.startDate);
                              const end = new Date(r.endDate);
                              const curr = new Date(start);
                              while (curr <= end) {
                                acc.push(new Date(curr));
                                curr.setDate(curr.getDate() + 1);
                              }
                              return acc;
                            }, []),
                        }}
                        modifiersClassNames={{
                          holiday:
                            'bg-gradient-to-br from-rose-500 to-red-600 text-white font-bold hover:scale-110 hover:rotate-3 transition-all duration-300 shadow-md cursor-pointer ring-2 ring-red-200 dark:ring-red-900',
                          weekOff:
                            'week-off-day border-2 border-dashed border-sky-400 text-sky-600 font-bold bg-sky-50/50 hover:bg-sky-100 dark:bg-sky-900/10 dark:text-sky-400 transition-colors',
                          leave:
                            'bg-indigo-100 text-indigo-700 font-semibold border-2 border-indigo-200 hover:bg-indigo-200 dark:bg-indigo-900/30 dark:text-indigo-300 dark:border-indigo-800',
                        }}
                      />
                    </div>
                  </div>

                  {/* Enhanced Legend Card */}
                  <Card className="rounded-2xl border-0 shadow-lg bg-white dark:bg-slate-900 overflow-hidden">
                    <CardHeader className="pb-3 border-b border-slate-50 dark:border-slate-800 bg-slate-50/30">
                      <CardTitle className="text-sm font-bold flex items-center gap-2">
                        <AlertCircle className="h-4 w-4 text-blue-500" />
                        Color Guide
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="pt-4 space-y-4">
                      <div className="flex items-center gap-3">
                        <div className="h-4 w-4 rounded bg-gradient-to-br from-rose-500 to-red-600 shadow-sm" />
                        <span className="text-sm font-medium">Company Holidays</span>
                        <div className="flex-1 border-t border-dashed border-slate-200 dark:border-slate-800 mx-2" />
                        <span className="text-xs text-muted-foreground">Off Work</span>
                      </div>
                      <div className="flex items-center gap-3">
                        <div className="h-4 w-4 rounded border-2 border-dashed border-sky-400 bg-sky-50 dark:bg-sky-900/10" />
                        <span className="text-sm font-medium">Weekly-Off Days</span>
                        <div className="flex-1 border-t border-dashed border-slate-200 dark:border-slate-800 mx-2" />
                        <span className="text-xs text-muted-foreground">Department</span>
                      </div>
                      <div className="flex items-center gap-3">
                        <div className="h-4 w-4 rounded bg-indigo-100 border border-indigo-200 dark:bg-indigo-900/30" />
                        <span className="text-sm font-medium">Your Approved Leaves</span>
                        <div className="flex-1 border-t border-dashed border-slate-200 dark:border-slate-800 mx-2" />
                        <span className="text-xs text-muted-foreground">Private</span>
                      </div>
                    </CardContent>
                  </Card>
                </div>

                {/* Right Column: Month Details & Statistics */}
                <div className="xl:col-span-7 space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Month Statistics Header */}
                    <div className="p-6 rounded-3xl bg-gradient-to-br from-indigo-500 to-purple-600 text-white shadow-xl shadow-indigo-100 dark:shadow-none flex flex-col justify-between h-full">
                      <div className="flex items-center justify-between mb-4">
                        <div className="h-12 w-12 rounded-2xl bg-white/20 backdrop-blur-md flex items-center justify-center">
                          <CalendarIcon className="h-6 w-6 text-white" />
                        </div>
                        <Badge className="bg-white/20 hover:bg-white/30 border-0 text-white font-bold backdrop-blur-md">
                          {format(displayedMonth, 'yyyy')}
                        </Badge>
                      </div>
                      <div>
                        <h3 className="text-3xl font-black tracking-tight">{format(displayedMonth, 'MMMM')}</h3>
                        <p className="text-white/80 text-sm font-medium mt-1">Month overview and holidays</p>
                      </div>
                    </div>

                    {/* Quick Stats Grid */}
                    <div className="grid grid-cols-2 gap-4">
                      <div className="p-4 rounded-3xl bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-800/50 flex flex-col justify-center items-center text-center group hover:scale-[1.05] transition-transform">
                        <div className="text-3xl font-black text-rose-600 dark:text-rose-400 mb-1">
                          {holidays.filter(h => h.date.getMonth() === displayedMonth.getMonth()).length}
                        </div>
                        <div className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">Holidays</div>
                      </div>
                      <div className="p-4 rounded-3xl bg-sky-50 dark:bg-sky-900/10 border border-sky-100 dark:border-sky-800/50 flex flex-col justify-center items-center text-center group hover:scale-[1.05] transition-transform">
                        <div className="text-3xl font-black text-sky-600 dark:text-sky-400 mb-1">
                          {userWeekOffDays.length}
                        </div>
                        <div className="text-[10px] font-bold text-sky-500 uppercase tracking-widest">Off Days</div>
                      </div>
                    </div>
                  </div>

                  {/* Detailed Holiday List */}
                  <Card className="rounded-3xl border-0 shadow-xl bg-white dark:bg-slate-900 overflow-hidden">
                    <CardHeader className="pb-4 border-b border-slate-50 dark:border-slate-800">
                      <div className="flex items-center justify-between">
                        <CardTitle className="text-lg font-bold flex items-center gap-2">
                          <CalendarIcon className="h-5 w-5 text-red-500" />
                          Upcoming Festivals & Holidays
                        </CardTitle>
                      </div>
                    </CardHeader>
                    <CardContent className="pt-6">
                      {(() => {
                        const monthHolidays = holidays.filter(h =>
                          h.date.getFullYear() === displayedMonth.getFullYear() &&
                          h.date.getMonth() === displayedMonth.getMonth()
                        ).sort((a, b) => a.date.getTime() - b.date.getTime());

                        if (monthHolidays.length === 0) {
                          return (
                            <div className="flex flex-col items-center justify-center py-12 text-center">
                              <div className="h-20 w-20 rounded-full bg-slate-50 dark:bg-slate-800 flex items-center justify-center mb-4">
                                <CalendarIcon className="h-10 w-10 text-slate-300 dark:text-slate-600" />
                              </div>
                              <p className="text-slate-500 font-medium">No company holidays scheduled for this month</p>
                              <p className="text-xs text-slate-400 mt-1">Check back later for updates</p>
                            </div>
                          );
                        }

                        return (
                          <div className="grid gap-4">
                            {monthHolidays.map(h => (
                              <div
                                key={h.date.toISOString()}
                                className="group relative flex items-center gap-4 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-red-200 dark:hover:border-red-900 hover:bg-red-50/50 dark:hover:bg-red-900/10 transition-all duration-300 cursor-pointer"
                                onClick={() => {
                                  setSelectedHoliday(h);
                                  setIsHolidayDialogOpen(true);
                                }}
                              >
                                <div className="flex flex-col items-center justify-center h-16 w-16 rounded-xl bg-white dark:bg-slate-800 border-2 border-red-100 dark:border-red-900 shadow-sm group-hover:scale-110 transition-transform">
                                  <span className="text-[10px] font-bold text-red-500 uppercase">{format(h.date, 'MMM')}</span>
                                  <span className="text-2xl font-black text-slate-800 dark:text-white leading-none">{format(h.date, 'dd')}</span>
                                </div>
                                <div className="flex-1 min-w-0">
                                  <h4 className="font-bold text-slate-800 dark:text-slate-200 group-hover:text-red-600 transition-colors truncate">
                                    {h.name}
                                  </h4>
                                  <p className="text-xs text-muted-foreground mt-0.5 font-medium flex items-center gap-1">
                                    <Clock className="h-3 w-3" />
                                    {format(h.date, 'EEEE')}
                                  </p>
                                  {h.description && (
                                    <p className="text-xs text-slate-500 dark:text-slate-400 mt-1 line-clamp-1">{h.description}</p>
                                  )}
                                </div>
                                <Button size="icon" variant="ghost" className="rounded-full h-8 w-8 hover:bg-white dark:hover:bg-slate-800">
                                  <ChevronRight className="h-4 w-4 text-slate-400" />
                                </Button>
                              </div>
                            ))}
                          </div>
                        );
                      })()}
                    </CardContent>
                  </Card>

                  {/* Week-off Visibility for Management */}
                  {userWeekOffDays.length > 0 && (
                    <div className="p-5 rounded-3xl bg-gradient-to-r from-slate-50 to-indigo-50 dark:from-slate-900 dark:to-indigo-950 border border-indigo-100 dark:border-indigo-900 flex items-center gap-4">
                      <div className="h-12 w-12 rounded-2xl bg-white dark:bg-slate-800 flex items-center justify-center shadow-sm">
                        <Clock className="h-6 w-6 text-sky-600" />
                      </div>
                      <div>
                        <p className="text-xs font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider">Weekly-Off Reminder</p>
                        <p className="text-sm font-medium text-slate-700 dark:text-slate-300">
                          {user?.role === 'employee' ? (
                            <>Your department ({user?.department}) enjoys off on <span className="font-bold text-sky-600">{userWeekOffDays.map(d => weekDayLabels[d.toLowerCase()] || d).join(', ')}</span></>
                          ) : (
                            <>Management View: Showing all active department week-offs across the center</>
                          )}
                        </p>
                      </div>
                    </div>
                  )}
                </div>
              </div>

            </CardContent>

          </Card>
        </TabsContent>

        {(canApproveLeaves || canViewTeamLeaves) && (
          <TabsContent value="approvals">
            <Card className="border-0 shadow-lg">
              <CardHeader className="border-b bg-gradient-to-r from-slate-50 to-gray-50 dark:from-slate-900 dark:to-gray-900">
                <CardTitle className="text-xl font-semibold">
                  {canApproveLeaves ? 'Leave Approval Requests' : 'Team Leave Requests'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-6">
                  {(approvalRequests.length === 0) ? (
                    <div className="text-center py-8 text-muted-foreground">
                      <AlertCircle className="h-12 w-12 mx-auto mb-2 opacity-50" />
                      <p>No leave requests to display</p>
                    </div>
                  ) : (
                    paginatedApprovalRequests.map((request) => {
                      return (
                        <div
                          key={request.id}
                          id={`leave-request-${request.id}`}
                          className="border rounded-lg p-4 transition-all duration-300 hover:bg-slate-50 dark:hover:bg-slate-900 hover:shadow-md">
                          <div className="flex flex-col lg:flex-row lg:items-start gap-4">
                            <div className="space-y-3 flex-1 min-w-0">
                              <div className="flex items-center gap-2 flex-wrap">
                                <User className="h-4 w-4 flex-shrink-0" />
                                <span className="font-medium">{request.employeeName}</span>
                                {request.role && (
                                  <Badge variant="outline" className="text-[10px] uppercase font-bold text-slate-500 border-slate-300">
                                    {request.role}
                                  </Badge>
                                )}
                                <Badge className={getLeaveTypeColor(request.type)}>
                                  {request.type}
                                </Badge>
                                <span className="text-xs text-muted-foreground">
                                  ID: {request.employeeId}
                                </span>
                              </div>
                              <div className="flex items-center gap-4 text-sm text-muted-foreground flex-wrap">
                                <div className="flex items-center gap-1">
                                  <FileText className="h-3 w-3" />
                                  <span>{request.department}</span>
                                </div>
                                <div className="flex items-center gap-1">
                                  <CalendarDays className="h-3 w-3" />
                                  <span>
                                    {format(request.startDate, 'MMM dd')} - {format(request.endDate, 'MMM dd, yyyy')}
                                  </span>
                                </div>
                                <div className="flex items-center gap-1">
                                  <Clock className="h-3 w-3" />
                                  <span>
                                    {Math.ceil((request.endDate.getTime() - request.startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1} days
                                  </span>
                                </div>
                              </div>
                              <div className="text-sm space-y-1">
                                <span className="font-medium">Reason:</span>
                                <div className="mt-1 p-3 bg-slate-50 dark:bg-slate-800 rounded-md border border-slate-200 dark:border-slate-700 max-h-48 overflow-y-auto">
                                  <div className="text-slate-700 dark:text-slate-300 text-sm">
                                    <TruncatedText
                                      text={request.reason}
                                      maxLength={200}
                                      textClassName="whitespace-pre-wrap break-words"
                                    />
                                  </div>
                                </div>
                              </div>
                            </div>
                            <div className="flex items-center gap-2 flex-shrink-0">
                              {request.status === 'pending' && canApproveLeaves ? (
                                <>
                                  <Button
                                    size="sm"
                                    className="px-4 h-9 gap-2 bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-700 hover:to-emerald-700 text-white font-medium shadow-md hover:shadow-lg transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
                                    onClick={() => handleApproveReject(request.id, 'approved')}
                                    disabled={approvingLeaveId === request.id}
                                  >
                                    <CheckCircle className="h-4 w-4 flex-shrink-0" />
                                    <span className="whitespace-nowrap">
                                      {approvingLeaveId === request.id ? 'Processing...' : 'Approve'}
                                    </span>
                                  </Button>
                                  <Button
                                    size="sm"
                                    className="px-4 h-9 gap-2 bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-700 hover:to-rose-700 text-white font-medium shadow-md hover:shadow-lg transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
                                    onClick={() => handleApproveReject(request.id, 'rejected')}
                                    disabled={approvingLeaveId === request.id}
                                  >
                                    <XCircle className="h-4 w-4 flex-shrink-0" />
                                    <span className="whitespace-nowrap">
                                      {approvingLeaveId === request.id ? 'Processing...' : 'Reject'}
                                    </span>
                                  </Button>
                                </>
                              ) : (
                                <div className="flex flex-col gap-2 w-full">
                                  <Badge className={`w-full px-4 py-1.5 text-sm font-bold capitalize transition-all duration-300 text-center ${getStatusBadgeStyle(request.status)}`}>
                                    {request.status.charAt(0).toUpperCase() + request.status.slice(1)}
                                  </Badge>
                                  {request.status !== 'pending' && request.approvedBy && (
                                    <span className="text-xs text-muted-foreground text-center">
                                      by {request.approvedBy}
                                    </span>
                                  )}
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      );
                    }))}

                  {/* Pagination for Approval Requests */}
                  {approvalRequests.length > 0 && (
                    <div className="mt-6 px-2">
                      <Pagination
                        currentPage={approvalCurrentPage}
                        totalPages={approvalTotalPages}
                        totalItems={approvalRequests.length}
                        itemsPerPage={approvalItemsPerPage}
                        onPageChange={setApprovalCurrentPage}
                        onItemsPerPageChange={setApprovalItemsPerPage}
                        showItemsPerPage={true}
                        showEntriesInfo={true}
                      />
                    </div>
                  )}

                  <div className="pt-6 border-t mt-6">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="font-semibold">Recent Decisions</h3>
                      <div className="flex items-center gap-2">
                        <Select value={historyFilter} onValueChange={setHistoryFilter}>
                          <SelectTrigger className="w-[180px] h-9 bg-white dark:bg-gray-950">
                            <SelectValue placeholder="Select period" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="all">All History</SelectItem>
                            <SelectItem value="current_month">Current Month</SelectItem>
                            <SelectItem value="last_3_months">Last 3 Months</SelectItem>
                            <SelectItem value="last_6_months">Last 6 Months</SelectItem>
                            <SelectItem value="last_1_year">Last 1 Year</SelectItem>
                            <SelectItem value="custom">Custom Range</SelectItem>
                          </SelectContent>
                        </Select>
                        <Select value={historyStatusFilter} onValueChange={(val: any) => setHistoryStatusFilter(val)}>
                          <SelectTrigger className="w-[140px] h-9 bg-white dark:bg-gray-950">
                            <SelectValue placeholder="Status" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="all">All Status</SelectItem>
                            <SelectItem value="approved">Approved</SelectItem>
                            <SelectItem value="rejected">Rejected</SelectItem>
                          </SelectContent>
                        </Select>
                        <Select value={historyRoleFilter} onValueChange={(val: any) => setHistoryRoleFilter(val)}>
                          <SelectTrigger className="w-[140px] h-9 bg-white dark:bg-gray-950 text-xs">
                            <SelectValue placeholder="Role" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="all">All Roles</SelectItem>
                            {user?.role === 'admin' && <SelectItem value="hr">HR</SelectItem>}
                            {(user?.role === 'admin' || user?.role === 'hr') && (
                              <SelectItem value="manager">Manager</SelectItem>
                            )}
                            {(user?.role === 'admin' || user?.role === 'hr' || user?.role === 'manager') && (
                              <SelectItem value="team_lead">Team Lead</SelectItem>
                            )}
                            {(user?.role === 'admin' || user?.role === 'hr' || user?.role === 'manager') && (
                              <SelectItem value="employee">Employee</SelectItem>
                            )}
                          </SelectContent>
                        </Select>
                      </div>
                    </div>

                    {historyFilter === 'custom' && (
                      <div className="mb-4 p-3 bg-slate-50 dark:bg-slate-900 rounded-lg border">
                        <div className="flex items-center gap-3 flex-wrap">
                          <div className="flex-1 min-w-[150px]">
                            <Label className="text-xs mb-1">Start Date</Label>
                            <DatePicker
                              date={customHistoryStartDate}
                              onDateChange={setCustomHistoryStartDate}
                            />
                          </div>
                          <div className="flex-1 min-w-[150px]">
                            <Label className="text-xs mb-1">End Date</Label>
                            <DatePicker
                              date={customHistoryEndDate}
                              onDateChange={setCustomHistoryEndDate}
                            />
                          </div>
                        </div>
                      </div>
                    )}

                    {getFilteredApprovalHistory.length === 0 ? (
                      <div className="text-center py-6 text-muted-foreground bg-slate-50 dark:bg-slate-900 rounded-lg">
                        <AlertCircle className="h-8 w-8 mx-auto mb-2 opacity-50" />
                        <p className="text-sm">No decisions found for the selected period.</p>
                      </div>
                    ) : (
                      <div>
                        <div className="space-y-3">
                          {paginatedApprovalHistory.map((request) => (
                            <div key={`hist-${request.id}`} className="border rounded-lg p-3 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors">
                              <div className="text-sm flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                  <span className="font-medium">{request.employeeName}</span>
                                  {request.role && (
                                    <span className="text-[10px] uppercase font-bold text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">
                                      {request.role}
                                    </span>
                                  )}
                                  <Badge className={`${getLeaveTypeColor(request.type)} text-xs`}>
                                    {request.type}
                                  </Badge>
                                </div>
                                <div className="text-muted-foreground text-xs">
                                  {format(request.startDate, 'MMM dd')} - {format(request.endDate, 'MMM dd, yyyy')} â€¢ {request.department}
                                </div>
                              </div>
                              <div className="flex items-center gap-2">
                                <Badge className={`px-4 py-1.5 text-sm font-bold capitalize transition-all duration-300 ${getStatusBadgeStyle(request.status)}`}>
                                  {request.status}
                                </Badge>
                              </div>
                            </div>
                          ))}
                        </div>

                        {/* Pagination for Approval History */}
                        {getFilteredApprovalHistory.length > 0 && (
                          <div className="mt-6 px-2">
                            <Pagination
                              currentPage={historyCurrentPage}
                              totalPages={historyTotalPages}
                              totalItems={getFilteredApprovalHistory.length}
                              itemsPerPage={historyItemsPerPage}
                              onPageChange={setHistoryCurrentPage}
                              onItemsPerPageChange={setHistoryItemsPerPage}
                              showItemsPerPage={true}
                            />
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        )}
      </Tabs>

      {/* Edit Leave Dialog */}
      <Dialog
        open={isEditDialogOpen}
        onOpenChange={(open) => {
          setIsEditDialogOpen(open);
          if (!open) {
            setEditingLeave(null);
          }
        }}
      >
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Edit Leave Request</DialogTitle>
            <DialogDescription>
              Update your leave dates or reason. Only pending requests can be modified.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Start Date</Label>
                <DatePicker
                  date={editFormData.startDate}
                  onDateChange={(date) => date && setEditFormData(prev => ({ ...prev, startDate: date }))}
                  placeholder="Select start date"
                />
              </div>
              <div className="space-y-2">
                <Label className="text-sm font-semibold">End Date</Label>
                <DatePicker
                  date={editFormData.endDate}
                  onDateChange={(date) => date && setEditFormData(prev => ({ ...prev, endDate: date }))}
                  placeholder="Select end date"
                />
              </div>
            </div>
            <div>
              <Label>Reason *</Label>
              <Textarea
                maxLength={200}
                value={editFormData.reason}
                onChange={(e) => setEditFormData(prev => ({ ...prev, reason: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                rows={4}
                placeholder="Update the reason for your leave request (minimum 10 characters)."
                className={editFormData.reason.trim().length > 0 && editFormData.reason.trim().length < 10 ? 'border-red-500' : ''}
              />
              <div className="flex justify-between text-sm mt-1">
                <span className={`${editFormData.reason.trim().length < 10 ? 'text-red-500' : 'text-green-600'}`}>
                  {editFormData.reason.trim().length < 10
                    ? `${editFormData.reason.trim().length}/10 characters (minimum required)`
                    : `${editFormData.reason.trim().length}/200 characters`
                  }
                </span>
                {editFormData.reason.trim().length < 10 && editFormData.reason.trim().length > 0 && (
                  <span className="text-red-500 text-xs">Minimum 10 characters required</span>
                )}
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsEditDialogOpen(false)} disabled={isUpdatingLeave}>
              Cancel
            </Button>
            <Button onClick={handleEditSubmit} disabled={isUpdatingLeave || editFormData.reason.trim().length < 10}>
              {isUpdatingLeave ? 'Saving...' : 'Save Changes'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Leave Confirmation */}
      <AlertDialog
        open={isDeleteDialogOpen}
        onOpenChange={(open) => {
          if (!isDeletingLeave) {
            setIsDeleteDialogOpen(open);
            if (!open) {
              setLeaveToDelete(null);
            }
          }
        }}
      >
        <AlertDialogContent className="sm:max-w-md">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-full bg-gradient-to-br from-red-500 to-rose-600 flex items-center justify-center shadow-lg">
                <Trash2 className="h-5 w-5 text-white" />
              </div>
              Delete Leave Request
            </AlertDialogTitle>
            <AlertDialogDescription className="text-base">
              Are you sure you want to delete this leave request? This action cannot be undone.
              {leaveToDelete && (
                <div className="mt-4 p-4 bg-red-50 dark:bg-red-950 rounded-lg border-2 border-red-200 dark:border-red-800 space-y-2">
                  <div>
                    <p className="text-xs font-semibold text-red-600 dark:text-red-400 uppercase tracking-wide">Leave Details</p>
                    <p className="text-sm font-medium text-red-800 dark:text-red-200 mt-1">
                      {format(leaveToDelete.startDate, 'MMM dd, yyyy')} to {format(leaveToDelete.endDate, 'MMM dd, yyyy')}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs font-semibold text-red-600 dark:text-red-400 uppercase tracking-wide">Type</p>
                    <p className="text-sm font-medium text-red-800 dark:text-red-200 mt-1">
                      {leaveToDelete.type.charAt(0).toUpperCase() + leaveToDelete.type.slice(1)}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs font-semibold text-red-600 dark:text-red-400 uppercase tracking-wide">Reason</p>
                    <p className="text-sm text-red-700 dark:text-red-300 mt-1 line-clamp-2 break-words overflow-wrap-anywhere whitespace-pre-wrap">
                      {leaveToDelete.reason}
                    </p>
                  </div>
                </div>
              )}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="gap-2">
            <AlertDialogCancel
              disabled={isDeletingLeave}
              className="bg-gray-100 hover:bg-gray-200 text-gray-800 dark:bg-gray-800 dark:hover:bg-gray-700 dark:text-gray-100"
            >
              Cancel
            </AlertDialogCancel>
            <Button
              onClick={confirmDeleteLeave}
              disabled={isDeletingLeave}
              className="bg-gradient-to-r from-rose-500 to-red-600 hover:from-rose-600 hover:to-red-700 text-white font-semibold disabled:opacity-50 disabled:cursor-not-allowed gap-2"
            >
              {isDeletingLeave ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                  Deleting...
                </>
              ) : (
                <>
                  <Trash2 className="h-4 w-4" />
                  Delete Request
                </>
              )}
            </Button>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Holiday Details Dialog */}
      <Dialog open={isHolidayDialogOpen} onOpenChange={setIsHolidayDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-full bg-gradient-to-br from-red-500 to-rose-600 flex items-center justify-center shadow-lg">
                <CalendarIcon className="h-5 w-5 text-white" />
              </div>
              Holiday Information
            </DialogTitle>
          </DialogHeader>
          {selectedHoliday && (
            <div className="space-y-4 py-4">
              <div className="bg-gradient-to-r from-red-50 to-rose-50 dark:from-red-950 dark:to-rose-950 rounded-lg p-4 border-2 border-red-200 dark:border-red-800">
                <h3 className="text-2xl font-bold text-red-700 dark:text-red-300 mb-2">
                  {selectedHoliday.name}
                </h3>
                <div className="flex items-center gap-2 text-sm text-muted-foreground mb-3">
                  <CalendarDays className="h-4 w-4" />
                  <span className="font-semibold">{format(selectedHoliday.date, 'EEEE, MMMM dd, yyyy')}</span>
                </div>
                {selectedHoliday.description && (
                  <div className="mt-3 pt-3 border-t border-red-200 dark:border-red-800">
                    <p className="text-sm text-slate-700 dark:text-slate-300">
                      {selectedHoliday.description}
                    </p>
                  </div>
                )}
              </div>
              <div className="bg-slate-50 dark:bg-slate-900 rounded-lg p-3 text-sm text-muted-foreground">
                <p className="flex items-center gap-2">
                  <span className="h-2 w-2 rounded-full bg-red-500"></span>
                  This is a company-wide holiday. All offices will be closed.
                </p>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button
              onClick={() => setIsHolidayDialogOpen(false)}
              className="w-full bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-700 hover:to-rose-700"
            >
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React from 'react';
import { useEffect, useState } from 'react';
import { useLanguage } from '@/contexts/LanguageContext';
import { useAuth } from '@/contexts/AuthContext';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { ChevronLeft, ChevronRight as ChevronRightIcon } from 'lucide-react';
import {
  Users,
  Clock,
  CalendarDays,
  ClipboardList,
  AlertCircle,
  ChevronRight,
  Activity,
  Target,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { formatTimeIST, formatIST, nowIST } from '@/utils/timezone';
import { apiService, API_BASE_URL } from '@/lib/api';
import TruncatedText from '@/components/ui/TruncatedText';

interface TeamMemberStatus {
  name: string;
  status: 'present' | 'completed' | 'on-leave' | 'absent';
  task: string;
  progress: number;
  userId: string;
  isOnline: boolean;
}

const ManagerDashboard: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();
  const navigate = useNavigate();

  const [stats, setStats] = useState({
    teamMembers: 0,
    presentToday: 0,
    onLeave: 0,
    activeTasks: 0,
    completedTasks: 0,
    pendingApprovals: 0,
    teamPerformancePercent: 0,
    overdueItems: 0,
  });

  const [teamActivities, setTeamActivities] = useState<{ id: string; type: string; user: string; time: string; description: string; status: string; }[]>([]);
  const [teamPerformance, setTeamPerformance] = useState<{ team: string; lead: string; members: number; completion: number; }[]>([]);
  const [teamMembers, setTeamMembers] = useState<TeamMemberStatus[]>([]);
  const [isLoadingTeamMembers, setIsLoadingTeamMembers] = useState(false);
  const [activitiesPage, setActivitiesPage] = useState(1);
  const ACTIVITIES_PER_PAGE = 15;

  useEffect(() => {
    const loadDashboard = async () => {
      try {
        const [dashboardData, employees] = await Promise.all([
          apiService.getManagerDashboard(),
          apiService.getEmployees()
        ]);

        const data = dashboardData || {};

        // If activeTasks is 0, try to get actual count from tasks API
        let activeTasks = data.activeTasks || 0;
        let pendingApprovals = data.pendingApprovals || 0;

        if (activeTasks === 0) {
          try {
            const tasks = await apiService.getMyTasks();
            // Count tasks that are not completed
            activeTasks = tasks.filter((task: any) =>
              task.status !== 'Completed' &&
              task.status !== 'completed' &&
              task.status !== 'Cancelled' &&
              task.status !== 'cancelled'
            ).length;
          } catch (error) {
            console.log('Could not fetch tasks for count');
          }
        }

        // Create a map for quick lookup: Name -> { role, department, userId }
        const employeeMap: Record<string, { role: string; department: string; userId: string }> = {};
        employees.forEach((emp: any) => {
          const name = (emp.name || `${emp.first_name || ''} ${emp.last_name || ''}`).trim();
          const userId = String(emp.user_id || emp.userId || emp.id);
          employeeMap[name] = {
            role: (emp.role || '').toLowerCase(),
            department: (emp.department || '').trim().toLowerCase(),
            userId: userId
          };
          // Also map by User ID just in case
          employeeMap[userId] = employeeMap[name];
        });

        // Current User Info
        const userDept = (user?.department || '').trim().toLowerCase();
        const userId = String(user?.id);

        // Calculate team members count (Self + Employees only)
        // Logic: Count = 1 (Self) + Employees/TeamLeads in department. 
        // Excludes other Managers, Admins, etc.
        let teamMembersCount = data.teamMembers || 0;
        if (userDept) {
          const relevantEmployees = employees.filter((emp: any) => {
            const empDept = (emp.department || '').trim().toLowerCase();
            const role = (emp.role || '').toLowerCase();
            const uId = String(emp.user_id || emp.userId || emp.id);

            // Allow Self
            if (uId === userId) return true;

            // Allow Department + Role constraint
            return empDept === userDept && (role === 'employee' || role === 'team_lead');
          });
          teamMembersCount = relevantEmployees.length;
        }

        setStats({
          teamMembers: teamMembersCount,
          presentToday: data.presentToday || 0,
          onLeave: data.onLeave || 0,
          activeTasks,
          completedTasks: data.completedTasks || 0,
          pendingApprovals,
          teamPerformancePercent: data.teamPerformancePercent || 0,
          overdueItems: data.overdueItems || 0,
        });

        // Filter Team Activities
        const allActivities = data.teamActivities || [];
        const filteredActivities = allActivities.filter((activity: any) => {
          // Identify user from activity (it usually has a 'user' field containing name)
          const userName = (activity.user || '').trim();

          // Use our map to verify role and department
          const empInfo = employeeMap[userName];

          // If we can't find them, default to excluded (security first)
          // Exception: If the name matches current user's name (we might need to fetch user details to know name, 
          // or assume if it's not found in employee list it might be someone else, so safer to hide).
          if (!empInfo) {
            // Try to see if it's self by some other means or just hide
            return false;
          }

          // 1. Allow Self
          if (empInfo.userId === userId) return true;

          // 2. Check Dept & Role
          return empInfo.department === userDept && (empInfo.role === 'employee' || empInfo.role === 'team_lead');
        });

        setTeamActivities(filteredActivities);

        // Filter Team Performance (Teams list)
        // If the 'team' field matches user's department, show it or calculate from employees
        const now = nowIST();
        let performanceData = [];
        try {
          // Fetch detailed metrics to ensure we have the latest scores
          const metricsData = await apiService.getDepartmentMetrics({
            month: now.getMonth(),
            year: now.getFullYear()
          });

          if (metricsData && metricsData.departments) {
            const userDeptMetrics = metricsData.departments.find((d: any) => (d.department || '').toLowerCase() === userDept);
            if (userDeptMetrics) {
              performanceData.push({
                team: userDeptMetrics.department,
                lead: user?.name || 'You',
                members: teamMembersCount, // Use the count we calculated earlier
                completion: userDeptMetrics.performanceScore || 0
              });
            }
          }
        } catch (metricsError) {
          console.error('Failed to load department metrics for manager:', metricsError);
        }

        // If API data wasn't found or failed, fallback or empty
        if (performanceData.length === 0) {
          // Try to use dashboard data if available
          const allPerformance = data.teamPerformance || [];
          performanceData = allPerformance.filter((p: any) => {
            const pTeam = (p.team || '').trim().toLowerCase();
            return pTeam === userDept;
          });
        }
        setTeamPerformance(performanceData);

      } catch (error) {
        console.error('Failed to load dashboard:', error);
      }
    };

    loadDashboard();
  }, [user]);

  useEffect(() => {
    const fetchTeamMembersWithStatus = async () => {
      if (!user?.department) return;

      setIsLoadingTeamMembers(true);
      try {
        // Fetch all employees
        const employees = await apiService.getEmployees();
        const userDept = user.department.trim().toLowerCase();
        const userId = String(user.id);

        // Filter by department and STRICT roles (Employee, Team Lead, and Self)
        const departmentEmployees = employees.filter((emp: any) => {
          const empDept = (emp.department || '').trim().toLowerCase();
          const role = (emp.role || '').toLowerCase();
          const uId = String(emp.id || emp.user_id || '');

          // 1. Allow Self (Manager)
          if (uId === userId) return true;

          // 2. Allow Department Members (Employee / Team Lead ONLY)
          return empDept === userDept && (role === 'employee' || role === 'team_lead');
        });

        // Fetch all tasks and today's attendance in parallel
        const [tasks, attendanceRes] = await Promise.all([
          apiService.getMyTasks(),
          fetch(`${API_BASE_URL}/attendance/today`, {
            headers: {
              'Authorization': (() => {
                const token = localStorage.getItem('token');
                if (!token) return '';
                return token.startsWith('Bearer ') ? token : `Bearer ${token}`;
              })(),
              'Content-Type': 'application/json',
            }
          })
        ]);

        const attendanceData = attendanceRes.ok ? await attendanceRes.json() : [];

        // Create a map of attendance by user ID for quick lookup
        const attendanceMap: Record<string, any> = {};
        attendanceData.forEach((record: any) => {
          const uId = String(record.user_id || record.userId);
          attendanceMap[uId] = record;
        });

        // Process team members with their status and tasks
        const teamMembersData: TeamMemberStatus[] = await Promise.all(
          departmentEmployees.map(async (emp: any) => {
            const uId = String(emp.id || emp.user_id || '');

            // Get tasks assigned to this employee
            const employeeTasks = tasks.filter((task: any) => {
              // Handle both camelCase (frontend) and snake_case (backend) property names
              const assignedToVal = task.assignedTo !== undefined ? task.assignedTo : task.assigned_to;
              const assignedToList = Array.isArray(assignedToVal) ? assignedToVal : [assignedToVal];

              // Check if employee ID is in the assigned list (converting all to strings for safe comparison)
              return assignedToList.some((id: any) => String(id) === uId);
            });

            // Get active tasks (not completed or cancelled)
            const activeTasks = employeeTasks.filter((task: any) => {
              const status = (task.status || '').toLowerCase();
              return status !== 'completed' && status !== 'cancelled';
            });

            // Calculate progress based on completed vs total tasks
            const totalTasks = employeeTasks.length;
            const completedTasks = employeeTasks.filter((task: any) => (task.status || '').toLowerCase() === 'completed').length;
            const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

            // Get the most recent active task title
            const currentTask = activeTasks.length > 0
              ? activeTasks[0].title || 'No active task'
              : completedTasks > 0
                ? 'All tasks completed'
                : 'No tasks assigned';

            // Determine status based on actual attendance
            const attendanceRecord = attendanceMap[uId];
            let status: 'present' | 'completed' | 'on-leave' | 'absent' = 'absent';
            let isOnline = false;

            if (attendanceRecord) {
              const checkOutTime = attendanceRecord.check_out || attendanceRecord.checkOutTime;
              if (checkOutTime && checkOutTime !== 'null' && checkOutTime !== 'None') {
                status = 'completed';
                isOnline = false;
              } else {
                status = 'present';
                isOnline = true;
              }
            } else {
              status = 'absent';
              isOnline = false;
            }

            return {
              name: emp.name || 'Unknown',
              status,
              task: currentTask,
              progress,
              userId: uId,
              isOnline,
            };
          })
        );

        setTeamMembers(teamMembersData);
      } catch (error) {
        console.error('Failed to fetch team members:', error);
      } finally {
        setIsLoadingTeamMembers(false);
      }
    };

    fetchTeamMembersWithStatus();
  }, [user?.department]);

  // Calculate correct attendance status based on check-in time and grace period
  const getCorrectAttendanceStatus = (activity: any) => {
    if (activity.type !== 'check-in') {
      return activity.status;
    }

    // Default scheduled check-in time is 10:00 AM
    const SCHEDULED_CHECK_IN_HOUR = 10;
    const SCHEDULED_CHECK_IN_MINUTE = 0;
    const GRACE_PERIOD_MINUTES = 15;

    try {
      if (!activity.time) {
        return activity.status;
      }

      // Parse the check-in time
      const checkInDate = new Date(activity.time);
      const checkInHour = checkInDate.getHours();
      const checkInMinute = checkInDate.getMinutes();

      // Calculate scheduled check-in time in minutes
      const scheduledTimeInMinutes = SCHEDULED_CHECK_IN_HOUR * 60 + SCHEDULED_CHECK_IN_MINUTE;
      const checkInTimeInMinutes = checkInHour * 60 + checkInMinute;
      const gracePeriodEndInMinutes = scheduledTimeInMinutes + GRACE_PERIOD_MINUTES;

      // Determine status
      if (checkInTimeInMinutes <= gracePeriodEndInMinutes) {
        return 'on-time';
      } else {
        return 'late';
      }
    } catch (error) {
      return activity.status;
    }
  };

  return (
    <div className="space-y-6">
      <div className="relative overflow-hidden flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 p-8 rounded-3xl bg-white dark:bg-gray-900 border shadow-sm mt-1">
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 bg-teal-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-64 w-64 bg-cyan-500/5 rounded-full blur-3xl" />

        <div className="relative flex items-center gap-5">
          <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-teal-500 to-cyan-600 flex items-center justify-center shadow-lg shadow-teal-200 dark:shadow-none">
            <Target className="h-8 w-8 text-white" />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-gray-900 dark:text-gray-100">
              {t.common.welcome}, <span className="text-teal-600">{user?.name}</span>
            </h1>
            <p className="text-muted-foreground font-medium flex items-center gap-2 mt-1">
              <CalendarDays className="h-4 w-4 text-teal-500" />
              {formatIST(nowIST(), 'EEEE, MMMM dd, yyyy')}
            </p>
          </div>
        </div>

        <div className="relative flex gap-3">
          <Button
            onClick={() => navigate('/manager/tasks')}
            size="lg"
            className="rounded-xl px-6 h-12 bg-teal-600 hover:bg-teal-700 text-white shadow-lg shadow-teal-200 dark:shadow-none transition-all active:scale-95 gap-2"
          >
            <ClipboardList className="h-4 w-4" />
            Create Task
          </Button>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          {
            label: 'Total Members',
            value: stats.teamMembers,
            sub: 'Department Overview',
            icon: Users,
            color: 'blue',
            bg: 'bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400',
            cardBg: 'bg-blue-50/40 dark:bg-blue-950/10',
            borderColor: 'border-blue-300/80 dark:border-blue-700/50',
            hoverBorder: 'group-hover:border-blue-500 dark:group-hover:border-blue-400',

          },
          {
            label: 'Present Today',
            value: stats.presentToday,
            sub: 'Attendance Status',
            icon: Clock,
            color: 'emerald',
            bg: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400',
            cardBg: 'bg-emerald-50/40 dark:bg-emerald-950/10',
            borderColor: 'border-emerald-300/80 dark:border-emerald-700/50',
            hoverBorder: 'group-hover:border-emerald-500 dark:group-hover:border-emerald-400',
            path: '/manager/attendance',
            pathState: { viewMode: 'employee' }
          },
          {
            label: 'Active Tasks',
            value: stats.activeTasks,
            sub: `${stats.completedTasks} Done Today`,
            icon: ClipboardList,
            color: 'indigo',
            bg: 'bg-indigo-50 text-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400',
            cardBg: 'bg-indigo-50/40 dark:bg-indigo-950/10',
            borderColor: 'border-indigo-300/80 dark:border-indigo-700/50',
            hoverBorder: 'group-hover:border-indigo-500 dark:group-hover:border-indigo-400',
            path: '/manager/tasks'
          },
          {
            label: 'Pending Approvals',
            value: stats.pendingApprovals,
            sub: 'Awaiting Decisions',
            icon: AlertCircle,
            color: 'amber',
            bg: 'bg-amber-50 text-amber-600 dark:bg-amber-900/20 dark:text-amber-400',
            cardBg: 'bg-amber-50/40 dark:bg-amber-950/10',
            borderColor: 'border-amber-300/80 dark:border-amber-700/50',
            hoverBorder: 'group-hover:border-amber-500 dark:group-hover:border-amber-400',
            path: '/manager/leaves',
            pathState: { tab: 'approvals' }
          }
        ].map((item, i) => (
          <Card
            key={i}
            className={`border-2 ${item.borderColor} ${item.hoverBorder} shadow-sm ${item.cardBg} backdrop-blur-sm hover:shadow-md transition-all duration-300 group overflow-hidden relative ${item.path ? 'cursor-pointer' : ''}`}
            onClick={() => item.path && navigate(item.path, { state: item.pathState })}
          >
            {/* Background Accent */}
            <div className={`absolute -right-4 -top-4 w-24 h-24 rounded-full opacity-5 group-hover:opacity-10 transition-opacity ${item.bg.split(' ')[0]}`} />

            <CardContent className="p-5 relative">
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2.5 rounded-xl ${item.bg} shadow-sm group-hover:scale-110 transition-transform duration-300`}>
                  <item.icon className="h-5 w-5" />
                </div>
              </div>
              <div className="space-y-1.5">
                <h3 className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest leading-none">{item.label}</h3>
                <div className="text-2xl font-black text-gray-900 dark:text-gray-100 tracking-tight">{item.value}</div>
                <div className="inline-flex items-center gap-1.5 px-2 py-1 rounded-md bg-white/50 dark:bg-gray-900/30 border border-black/5 dark:border-white/5">
                  <div className={`h-1.5 w-1.5 rounded-full ${item.color === 'blue' ? 'bg-blue-500' :
                    item.color === 'emerald' ? 'bg-emerald-500' :
                      item.color === 'indigo' ? 'bg-indigo-500' :
                        'bg-amber-500'
                    }`} />
                  <span className="text-[10px] font-bold text-muted-foreground uppercase">{item.sub}</span>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Team Activities */}
        <Card className="lg:col-span-2 border-0 shadow-lg bg-gradient-to-br from-slate-50 to-gray-100 dark:from-slate-900 dark:to-gray-800">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-teal-500 to-cyan-600 flex items-center justify-center">
                <Activity className="h-5 w-5 text-white" />
              </div>
              {t.navigation.teamActivities}
            </CardTitle>
            <CardDescription className="text-base">Recent updates from your team</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            {teamActivities.length > 0 ? (
              <>
                {teamActivities
                  .slice((activitiesPage - 1) * ACTIVITIES_PER_PAGE, activitiesPage * ACTIVITIES_PER_PAGE)
                  .map((activity) => (
                    <div key={activity.id} className="flex items-start gap-3 p-3 rounded-lg border hover:bg-white/50 dark:hover:bg-gray-800/50 transition-colors">
                      <div className={`h-10 w-10 rounded-xl flex items-center justify-center flex-shrink-0 shadow-sm ${activity.type === 'task' ? 'bg-gradient-to-br from-blue-400 to-indigo-500' :
                        activity.type === 'leave' ? 'bg-gradient-to-br from-amber-400 to-orange-500' :
                          'bg-gradient-to-br from-green-400 to-emerald-500'
                        }`}>
                        {activity.type === 'task' && <ClipboardList className="h-5 w-5 text-white" />}
                        {activity.type === 'leave' && <CalendarDays className="h-5 w-5 text-white" />}
                        {activity.type === 'check-in' && <Clock className="h-5 w-5 text-white" />}
                      </div>
                      <div className="flex-1 space-y-1">
                        <p className="text-sm font-medium">{activity.user}</p>
                        <div className="text-xs text-muted-foreground">
                          <TruncatedText
                            text={activity.description || ''}
                            maxLength={50}
                            showToggle={false}
                          />
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-xs text-muted-foreground">
                          {formatTimeIST(activity.time, 'hh:mm a')}
                        </p>
                        <Badge
                          variant={
                            getCorrectAttendanceStatus(activity) === 'completed' || getCorrectAttendanceStatus(activity) === 'on-time' ? 'default' :
                              getCorrectAttendanceStatus(activity) === 'pending' ? 'secondary' :
                                getCorrectAttendanceStatus(activity) === 'late' ? 'destructive' :
                                  'outline'
                          }
                          className={`text-xs mt-1 ${getCorrectAttendanceStatus(activity) === 'late' ? 'bg-red-500' : ''
                            }`}
                        >
                          {getCorrectAttendanceStatus(activity) === 'on-time' ? 'On Time' :
                            getCorrectAttendanceStatus(activity) === 'late' ? 'Late' :
                              getCorrectAttendanceStatus(activity)}
                        </Badge>
                      </div>
                    </div>
                  ))}
                {teamActivities.length > ACTIVITIES_PER_PAGE && (
                  <div className="mt-4 pt-4 border-t flex items-center justify-center gap-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setActivitiesPage(p => Math.max(1, p - 1))}
                      disabled={activitiesPage === 1}
                      className="h-8 w-8 p-0"
                    >
                      <ChevronLeft className="h-4 w-4" />
                    </Button>
                    {Array.from({ length: Math.ceil(teamActivities.length / ACTIVITIES_PER_PAGE) }, (_, i) => i + 1).map((page) => (
                      <Button
                        key={page}
                        variant={activitiesPage === page ? "default" : "outline"}
                        size="sm"
                        onClick={() => setActivitiesPage(page)}
                        className="h-8 w-8 p-0"
                      >
                        {page}
                      </Button>
                    ))}
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setActivitiesPage(p => Math.min(Math.ceil(teamActivities.length / ACTIVITIES_PER_PAGE), p + 1))}
                      disabled={activitiesPage === Math.ceil(teamActivities.length / ACTIVITIES_PER_PAGE)}
                      className="h-8 w-8 p-0"
                    >
                      <ChevronRightIcon className="h-4 w-4" />
                    </Button>
                  </div>
                )}
              </>
            ) : (
              <p className="text-sm text-muted-foreground">No recent activities</p>
            )}
          </CardContent>
        </Card>

        {/* Team Leads Performance */}
        <Card className="border-0 shadow-lg bg-gradient-to-br from-slate-50 to-gray-100 dark:from-slate-900 dark:to-gray-800">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-xl">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center">
                <Target className="h-5 w-5 text-white" />
              </div>
              {t.navigation.teamPerformance}
            </CardTitle>
            <CardDescription className="text-base">Task completion by team</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {teamPerformance.length > 0 ? teamPerformance.map((team) => (
              <div key={`${team.team}-${team.lead}`} className="space-y-2">
                <div className="flex justify-between items-start">
                  <div>
                    <p className="font-medium text-sm">{team.team}</p>
                    <p className="text-xs text-muted-foreground">{team.lead} • {team.members} members</p>
                  </div>
                  <span className="text-sm font-semibold">{team.completion}%</span>
                </div>
                <Progress value={team.completion} className="h-2" />
              </div>
            )) : (
              <p className="text-sm text-muted-foreground">No performance data available</p>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Team Members Current Status */}
      <Card className="border-0 shadow-lg bg-gradient-to-br from-slate-50 to-gray-100 dark:from-slate-900 dark:to-gray-800">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-xl">
            <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-teal-500 to-cyan-600 flex items-center justify-center">
              <Users className="h-5 w-5 text-white" />
            </div>
            {t.navigation.teamMembers} Current Status
          </CardTitle>
          <CardDescription className="text-base">Current status and task progress</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {isLoadingTeamMembers ? (
            <p className="text-sm text-muted-foreground text-center py-4">{t.common.loadingTeamMembers}</p>
          ) : teamMembers.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-4">{t.common.noTeamMembers}</p>
          ) : (
            teamMembers.map((member) => (
              <div key={member.userId} className="p-3 rounded-lg border space-y-2">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`h-2.5 w-2.5 rounded-full ${member.isOnline ? 'bg-green-500 animate-pulse' : 'bg-gray-300'}`} />
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-medium text-sm">{member.name}</p>
                        <Badge variant={member.isOnline ? 'default' : 'secondary'} className={`h-4 px-1 text-[9px] ${member.isOnline ? 'bg-green-500' : 'opacity-70'}`}>
                          {member.isOnline ? 'Online' : 'Offline'}
                        </Badge>
                      </div>
                      <div className="text-xs text-muted-foreground flex-1 min-w-0">
                        <TruncatedText
                          text={member.task}
                          maxLength={35}
                          showToggle={false}
                        />
                      </div>
                    </div>
                  </div>
                  <Badge
                    variant={
                      member.status === 'present' || member.isOnline ? 'default' :
                        member.status === 'completed' ? 'secondary' :
                          member.status === 'on-leave' ? 'outline' :
                            'outline'
                    }
                    className={
                      member.status === 'present' || member.isOnline ? 'bg-green-500 hover:bg-green-600' :
                        member.status === 'completed' ? 'bg-blue-500 hover:bg-blue-600' :
                          ''
                    }
                  >
                    {member.isOnline ? 'Working' :
                      member.status === 'completed' ? 'Completed' :
                        member.status === 'on-leave' ? 'On Leave' :
                          'Absent'}
                  </Badge>
                </div>
                {(member.status === 'present' || member.status === 'completed') && (
                  <div className="space-y-1">
                    <div className="flex justify-between text-xs">
                      <span className="text-muted-foreground">Progress</span>
                      <span className="font-medium">{member.progress}%</span>
                    </div>
                    <Progress value={member.progress} className="h-1" />
                  </div>
                )}
              </div>
            ))
          )}
        </CardContent>
      </Card>

    </div>
  );
};

export default ManagerDashboard;

import React, { useState, useEffect } from 'react';
import {
    Video,
    Plus,
    Calendar,
    Users,
    ExternalLink,
    MoreVertical,
    Trash2,
    Edit2,
    Clock,
    Search,
    Filter,
    CheckCircle2,
    AlertCircle,
    Briefcase,
    Users2,
    Settings2,
    CalendarDays,
    FolderKanban
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { apiService } from '@/lib/api';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger
} from '@/components/ui/dialog';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger
} from '@/components/ui/tabs';
import { toast } from '@/components/ui/use-toast';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { format, isValid } from 'date-fns';

interface Meeting {
    id: number;
    title: string;
    description: string;
    start_time: string;
    end_time: string;
    meeting_url: string;
    created_by_name: string;
    created_by_id: number;
    participants?: {
        id: number;
        user_id: number;
        user_name: string;
    }[];
    type?: 'company' | 'team' | 'project' | 'one-to-one';
    team_name?: string;
    project_name?: string;
    team_id?: number;
    project_id?: number;
}

const MeetingsPage: React.FC = () => {
    const { user } = useAuth();
    const userRole = user?.role?.toLowerCase();

    // Permission definitions
    const isAdmin = userRole === 'admin';
    const isHR = userRole === 'hr';
    const isManager = userRole === 'manager';
    const isTeamLead = userRole === 'team_lead';

    const canCreateCompany = isAdmin;
    const canCreateTeam = isAdmin || isHR || isManager || isTeamLead;
    const canCreateProject = isAdmin || isHR || isManager || isTeamLead;
    const canCreateOneToOne = true; // All can create

    const [meetings, setMeetings] = useState<Meeting[]>([]);
    const [employees, setEmployees] = useState<any[]>([]);
    const [projects, setProjects] = useState<any[]>([]);
    const [departments, setDepartments] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
    const [selectedMeeting, setSelectedMeeting] = useState<Meeting | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    const [formData, setFormData] = useState({
        title: '',
        description: '',
        meeting_url: '',
        start_time: '',
        end_time: '',
        participant_ids: [] as number[],
        type: 'one-to-one' as 'company' | 'team' | 'project' | 'one-to-one',
        team_id: undefined as number | undefined,
        project_id: undefined as number | undefined,
    });

    const fetchData = async () => {
        try {
            setLoading(true);
            const [meetingsData, depts, projs, emps] = await Promise.all([
                apiService.getMeetings(),
                apiService.getDepartments().catch(() => []),
                apiService.getProjects().catch(() => []),
                apiService.getEmployees().catch(() => [])
            ]);

            setMeetings(Array.isArray(meetingsData) ? meetingsData : []);
            setDepartments(Array.isArray(depts) ? depts : (depts as any)?.departments || []);
            setProjects(Array.isArray(projs) ? projs : (projs as any)?.projects || []);
            setEmployees(Array.isArray(emps) ? emps : (emps as any)?.employees || []);
        } catch (error) {
            console.error('Failed to fetch data:', error);
            toast({
                title: "Error",
                description: "Failed to sync data from server.",
                variant: "destructive"
            });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const [searchQuery, setSearchQuery] = useState('');
    const [dateFilter, setDateFilter] = useState('');
    const [typeFilter, setTypeFilter] = useState('all');

    const filteredMeetings = meetings.filter(m => {
        if (!m || !m.title) return false;
        const matchesSearch = m.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            (m.description?.toLowerCase().includes(searchQuery.toLowerCase()) ?? false);

        // Date filtering
        let matchesDate = true;
        if (dateFilter && m.start_time && typeof m.start_time === 'string') {
            matchesDate = m.start_time.startsWith(dateFilter);
        }

        // Type filtering
        const mType = (m.type || 'one-to-one').toLowerCase();
        let matchesType = false;
        if (typeFilter === 'all') {
            matchesType = true;
        } else if (typeFilter === 'company') {
            matchesType = mType === 'company' || mType === 'team';
        } else {
            matchesType = mType === typeFilter;
        }

        return matchesSearch && matchesDate && matchesType;
    });

    const handleCreateMeeting = async () => {
        if (!formData.title || !formData.meeting_url || !formData.start_time || !formData.end_time) {
            toast({
                title: "Missing Information",
                description: "All fields are required to establish a sync node.",
                variant: "destructive"
            });
            return;
        }

        try {
            setIsSubmitting(true);
            const startDate = new Date(formData.start_time);
            const endDate = new Date(formData.end_time);

            if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
                throw new Error("Invalid temporal coordinates provided.");
            }

            // Construct payload
            const payload: any = {
                title: formData.title,
                description: formData.description,
                meeting_url: formData.meeting_url,
                start_time: startDate.toISOString(),
                end_time: endDate.toISOString(),
                participant_ids: formData.participant_ids,
                type: formData.type,
            };

            if (formData.type === 'team' && formData.team_id) {
                payload.team_id = formData.team_id;
            }

            if (selectedMeeting) {
                if (selectedMeeting.type === 'project' && formData.project_id) {
                    await apiService.updateProjectMeeting(formData.project_id, selectedMeeting.id, payload);
                } else {
                    await apiService.updateMeeting(selectedMeeting.id, payload);
                }
                toast({
                    title: "Sync Re-authorized",
                    description: "The meeting protocol has been successfully updated.",
                });
            } else {
                if (formData.type === 'project' && formData.project_id) {
                    await apiService.createProjectMeeting(formData.project_id, payload);
                } else {
                    await apiService.createMeeting(payload);
                }
                toast({
                    title: "Sync Authorized",
                    description: "The meeting protocol has been successfully established.",
                });
            }

            setIsCreateDialogOpen(false);
            resetForm();
            fetchData();
        } catch (error: any) {
            console.error('Operation failed:', error);
            toast({
                title: "Protocol Failure",
                description: error.message || "Failed to establish sync.",
                variant: "destructive"
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const resetForm = () => {
        setFormData({
            title: '',
            description: '',
            meeting_url: '',
            start_time: '',
            end_time: '',
            participant_ids: [],
            type: 'one-to-one',
            team_id: undefined,
            project_id: undefined,
        });
        setSelectedMeeting(null);
    };

    const openEditDialog = (meeting: Meeting) => {
        setSelectedMeeting(meeting);
        setFormData({
            title: meeting.title,
            description: meeting.description || '',
            meeting_url: meeting.meeting_url,
            // Format for datetime-local input: YYYY-MM-DDThh:mm
            start_time: meeting.start_time ? new Date(meeting.start_time).toISOString().slice(0, 16) : '',
            end_time: meeting.end_time ? new Date(meeting.end_time).toISOString().slice(0, 16) : '',
            participant_ids: meeting.participants?.map(p => p.user_id) || [],
            type: (meeting.type || 'one-to-one') as any,
            team_id: meeting.team_id,
            project_id: meeting.project_id,
        });
        setIsCreateDialogOpen(true);
    };

    const handleDeleteMeeting = async (meeting: Meeting) => {
        if (!confirm('Are you sure you want to terminate this sync node?')) return;
        try {
            if (meeting.type === 'project' && meeting.project_id) {
                await apiService.deleteProjectMeeting(meeting.project_id, meeting.id);
            } else {
                await apiService.deleteMeeting(meeting.id);
            }
            toast({
                title: "Node Terminated",
                description: "The meeting protocol has been successfully purged.",
            });
            fetchData();
        } catch (error: any) {
            toast({
                title: "Deletion Failure",
                description: error.message || "Failed to purge node.",
                variant: "destructive"
            });
        }
    };

    const getBadgeColor = (type: string) => {
        switch (type) {
            case 'company': return 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-400';
            case 'team': return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400';
            case 'project': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
            case 'one-to-one': return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400';
            default: return 'bg-slate-100 text-slate-700';
        }
    };

    const getDisplayName = (type: string) => {
        switch (type) {
            case 'company':
            case 'team': return 'Townhall Meeting';
            case 'project': return 'Project Meeting';
            case 'one-to-one': return 'One to One Meeting';
            default: return 'Meeting';
        }
    };

    const toggleParticipant = (userId: number) => {
        setFormData(prev => {
            const has = prev.participant_ids.includes(userId);
            return {
                ...prev,
                participant_ids: has
                    ? prev.participant_ids.filter(id => id !== userId)
                    : [...prev.participant_ids, userId]
            };
        });
    };

    return (
        <div className="flex-1 flex flex-col h-full bg-slate-50/50 dark:bg-slate-950/50 overflow-hidden">
            {/* Header Section */}
            <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-6 py-8">
                <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div className="flex items-center gap-5">
                        <div className="h-16 w-16 rounded-[2rem] bg-gradient-to-br from-blue-600 to-indigo-700 flex items-center justify-center shadow-xl shadow-blue-200 dark:shadow-none">
                            <Video className="h-8 w-8 text-white" />
                        </div>
                        <div>
                            <h1 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Meetings</h1>
                            <p className="text-slate-500 dark:text-slate-400 font-medium">Coordinate and collaborate across the organization</p>
                        </div>
                    </div>

                    <Dialog open={isCreateDialogOpen} onOpenChange={(open) => {
                        setIsCreateDialogOpen(open);
                        if (!open) resetForm();
                    }}>
                        <DialogTrigger asChild>
                            <Button className="h-12 px-6 rounded-2xl bg-blue-600 hover:bg-blue-700 text-white font-black text-xs uppercase tracking-widest shadow-lg shadow-blue-200 dark:shadow-none transition-all duration-300 transform hover:scale-105">
                                <Plus className="h-4 w-4 mr-2" />
                                Initiate Sync
                            </Button>
                        </DialogTrigger>
                        <DialogContent className="sm:max-w-[650px] rounded-[2rem] border-none shadow-2xl p-0 overflow-hidden">
                            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-8 text-white">
                                <DialogTitle className="text-2xl font-black uppercase tracking-tighter">
                                    {selectedMeeting ? 'Update Sync' : 'Sync Configuration'}
                                </DialogTitle>
                                <DialogDescription className="text-blue-100 font-medium opacity-80 uppercase text-[10px] tracking-widest mt-1">
                                    {selectedMeeting ? 'Re-authorize communication node.' : 'Establish a new communication node.'}
                                </DialogDescription>
                            </div>

                            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
                                <div className="grid grid-cols-2 gap-6">
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Meeting Type</Label>
                                        <Select
                                            value={formData.type || "one-to-one"}
                                            onValueChange={(v: any) => setFormData({ ...formData, type: v, team_id: undefined, project_id: undefined })}
                                        >
                                            <SelectTrigger className="rounded-xl h-11 border-slate-200">
                                                <SelectValue placeholder="Select type" />
                                            </SelectTrigger>
                                            <SelectContent className="rounded-xl">
                                                {canCreateCompany && <SelectItem value="company">Townhall (Company Wide)</SelectItem>}
                                                {canCreateTeam && <SelectItem value="team"> Team Specific</SelectItem>}
                                                {canCreateProject && <SelectItem value="project">Project Specific</SelectItem>}
                                                {canCreateOneToOne && <SelectItem value="one-to-one">One to One Meeting</SelectItem>}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Meeting Title</Label>
                                        <Input
                                            placeholder="Sync Title"
                                            className="rounded-xl h-11 border-slate-200 focus:ring-blue-500"
                                            value={formData.title}
                                            onChange={e => setFormData({ ...formData, title: e.target.value })}
                                        />
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-6">
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Start Time</Label>
                                        <Input
                                            type="datetime-local"
                                            className="rounded-xl h-11 border-slate-200"
                                            value={formData.start_time}
                                            onChange={e => setFormData({ ...formData, start_time: e.target.value })}
                                        />
                                    </div>
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">End Time</Label>
                                        <Input
                                            type="datetime-local"
                                            className="rounded-xl h-11 border-slate-200"
                                            value={formData.end_time}
                                            onChange={e => setFormData({ ...formData, end_time: e.target.value })}
                                        />
                                    </div>
                                </div>

                                {formData.type === 'team' && (
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Select Department</Label>
                                        <Select
                                            value={formData.team_id?.toString() || ""}
                                            onValueChange={(v) => setFormData({ ...formData, team_id: v ? parseInt(v) : undefined })}
                                        >
                                            <SelectTrigger className="rounded-xl h-11">
                                                <SelectValue placeholder="Choose Department" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {Array.isArray(departments) && departments.filter(Boolean).length > 0 ? departments.filter(Boolean).map((d: any) => (
                                                    <SelectItem key={d.id || d.department_id || Math.random()} value={(d.id || d.department_id)?.toString() || ""}>{d.name || "Unnamed Department"}</SelectItem>
                                                )) : (
                                                    <SelectItem disabled value="none">No active department nodes found.</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                )}

                                {formData.type === 'project' && (
                                    <div className="grid gap-2">
                                        <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Target Project</Label>
                                        <Select
                                            value={formData.project_id?.toString() || ""}
                                            onValueChange={(v) => setFormData({ ...formData, project_id: v ? parseInt(v) : undefined })}
                                        >
                                            <SelectTrigger className="rounded-xl h-11">
                                                <SelectValue placeholder="Choose Project" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {Array.isArray(projects) && projects.filter(Boolean).length > 0 ? projects.filter(Boolean).map((p: any) => (
                                                    <SelectItem key={p.project_id || p.id || Math.random()} value={(p.project_id || p.id)?.toString() || ""}>{p.name || "Unnamed Project"}</SelectItem>
                                                )) : (
                                                    <SelectItem disabled value="none">No active project nodes found.</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                )}

                                <div className="grid gap-2">
                                    <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Transmission URL</Label>
                                    <Input
                                        placeholder="https://meet.google.com/..."
                                        className="rounded-xl h-11 border-slate-200 font-medium"
                                        value={formData.meeting_url}
                                        onChange={e => setFormData({ ...formData, meeting_url: e.target.value })}
                                    />
                                </div>

                                <div className="grid gap-2">
                                    <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Tactical Brief / Agenda</Label>
                                    <Textarea
                                        placeholder="Outline the communication objectives..."
                                        className="rounded-xl border-slate-200 min-h-[80px]"
                                        value={formData.description}
                                        onChange={e => setFormData({ ...formData, description: e.target.value })}
                                    />
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-[10px] uppercase font-black text-slate-400 tracking-widest flex items-center justify-between">
                                        Assigned Assets / Participants
                                        <span className="text-blue-600 font-black">{formData.participant_ids.length} selected</span>
                                    </Label>
                                    <div className="grid grid-cols-2 gap-3 max-h-[200px] overflow-y-auto p-1 custom-scrollbar">
                                        {employees.filter(Boolean).map((emp: any) => (
                                            <div
                                                key={emp.id}
                                                onClick={() => toggleParticipant(emp.id)}
                                                className={`flex items-center gap-3 p-3 rounded-2xl cursor-pointer transition-all border ${formData.participant_ids.includes(emp.id)
                                                    ? 'bg-blue-50 border-blue-200 dark:bg-blue-900/20 dark:border-blue-800'
                                                    : 'hover:bg-slate-50 border-slate-100 dark:hover:bg-slate-800/50 dark:border-slate-800'
                                                    }`}
                                            >
                                                <div className="h-8 w-8 rounded-xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center overflow-hidden">
                                                    <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${emp.name || emp.id}`} alt="" className="h-full w-full object-cover" />
                                                </div>
                                                <span className="text-[10px] font-bold text-slate-700 dark:text-slate-300 truncate">{emp.name || "Unknown User"}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            <DialogFooter className="p-8 bg-slate-50 dark:bg-slate-900/50 flex !justify-center gap-3 border-t border-slate-100 dark:border-slate-800">
                                <Button variant="ghost" onClick={() => setIsCreateDialogOpen(false)} className="rounded-xl h-11 px-6 font-bold text-xs uppercase tracking-widest text-slate-400">Cancel</Button>
                                <Button disabled={isSubmitting} onClick={handleCreateMeeting} className="rounded-xl h-11 bg-blue-600 hover:bg-blue-700 text-white font-black text-xs uppercase tracking-widest px-10 shadow-lg shadow-blue-500/20">
                                    {isSubmitting ? 'Processing...' : (selectedMeeting ? 'Re-authorize Sync' : 'Authorize Sync')}
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 overflow-y-auto w-full custom-scrollbar">
                <div className="max-w-7xl mx-auto px-6 py-8">

                    {/* Quick Stats Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
                        {[
                            { label: 'Upcoming', val: meetings.length, icon: CalendarDays, color: 'blue' },
                            { label: 'Townhall Meeting', val: meetings.filter(m => m?.type === 'company' || m?.type === 'team').length, icon: Briefcase, color: 'indigo' },
                            { label: 'Project Meeting', val: meetings.filter(m => m?.type === 'project').length, icon: FolderKanban, color: 'emerald' },
                            { label: 'One to One Meeting', val: meetings.filter(m => m?.type === 'one-to-one').length, icon: Users, color: 'amber' },
                        ].map((stat, i) => (
                            <Card key={i} className="border-none shadow-sm bg-white dark:bg-slate-900 rounded-[2rem] overflow-hidden hover:shadow-md transition-all duration-300">
                                <CardContent className="p-6 flex items-center justify-between">
                                    <div>
                                        <p className="text-[10px] uppercase font-black text-slate-400 tracking-wider mb-1">{stat.label}</p>
                                        <h3 className="text-2xl font-black text-slate-900 dark:text-white">{stat.val}</h3>
                                    </div>
                                    <div className={`h-12 w-12 rounded-2xl bg-${stat.color}-50 dark:bg-${stat.color}-900/20 flex items-center justify-center text-${stat.color}-600 dark:text-${stat.color}-400`}>
                                        <stat.icon className="h-6 w-6" />
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>

                    <Tabs value={typeFilter} onValueChange={setTypeFilter} className="w-full">
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                            <TabsList className="h-14 p-1.5 rounded-[1.5rem] bg-white dark:bg-slate-900 shadow-sm border-none">
                                <TabsTrigger value="all" className="rounded-2xl px-8 font-black text-[10px] uppercase tracking-widest data-[state=active]:bg-slate-900 data-[state=active]:text-white">All Meetings</TabsTrigger>
                                <TabsTrigger value="company" className="rounded-2xl px-8 font-black text-[10px] uppercase tracking-widest data-[state=active]:bg-indigo-600 data-[state=active]:text-white">Townhall Meeting</TabsTrigger>
                                <TabsTrigger value="project" className="rounded-2xl px-8 font-black text-[10px] uppercase tracking-widest data-[state=active]:bg-blue-600 data-[state=active]:text-white">Project Meeting</TabsTrigger>
                                <TabsTrigger value="one-to-one" className="rounded-2xl px-8 font-black text-[10px] uppercase tracking-widest data-[state=active]:bg-amber-500 data-[state=active]:text-white">One to One Meeting</TabsTrigger>
                            </TabsList>

                            <div className="flex items-center gap-3">
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                                    <Input
                                        placeholder="Search meetings..."
                                        className="pl-9 h-11 w-[200px] rounded-2xl bg-white dark:bg-slate-900 border-none shadow-sm font-medium"
                                        value={searchQuery}
                                        onChange={e => setSearchQuery(e.target.value)}
                                    />
                                </div>
                                <div className="flex items-center bg-white dark:bg-slate-900 p-1.5 rounded-2xl shadow-sm">
                                    <Calendar className="h-4 w-4 text-slate-400 mx-2" />
                                    <Input
                                        type="date"
                                        className="h-8 w-[130px] border-none bg-transparent font-black text-[10px] uppercase p-0 focus-visible:ring-0"
                                        value={dateFilter}
                                        onChange={e => setDateFilter(e.target.value)}
                                    />
                                </div>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-11 w-11 rounded-2xl bg-white dark:bg-slate-900 shadow-sm border-none"
                                    onClick={() => { setSearchQuery(''); setDateFilter(''); setTypeFilter('all'); }}
                                >
                                    <Filter className="h-4 w-4" />
                                </Button>
                            </div>
                        </div>

                        <div className="mt-6">
                            <TabsContent value={typeFilter} className="m-0 focus-visible:ring-0">
                                {loading ? (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                        {[1, 2, 3].map(i => (
                                            <div key={i} className="h-64 rounded-[2.5rem] bg-slate-100 dark:bg-slate-900 animate-pulse border-none" />
                                        ))}
                                    </div>
                                ) : filteredMeetings.length === 0 ? (
                                    <div className="flex flex-col items-center justify-center py-24 bg-white dark:bg-slate-900 rounded-[3rem] shadow-sm border border-dashed border-slate-200 dark:border-slate-800">
                                        <div className="h-24 w-24 rounded-full bg-slate-50 dark:bg-slate-800/50 flex items-center justify-center mb-6">
                                            <Video className="h-10 w-10 text-slate-200" />
                                        </div>
                                        <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">No Meetings Found</h3>
                                        <p className="text-slate-400 text-sm font-medium mt-2">There are no active {typeFilter === 'all' ? '' : typeFilter} meetings for this selection.</p>
                                        <Button
                                            variant="outline"
                                            onClick={() => { setSearchQuery(''); setDateFilter(''); setTypeFilter('all'); }}
                                            className="mt-8 rounded-2xl border-blue-100 text-blue-600 font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 hover:text-white h-12 px-8"
                                        >
                                            Clear Filters
                                        </Button>
                                    </div>
                                ) : (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                                        {filteredMeetings.map((meeting) => (
                                            <Card key={meeting.id} className="group relative border-none shadow-sm bg-white dark:bg-slate-900 rounded-[2.5rem] overflow-hidden hover:shadow-2xl hover:shadow-blue-500/10 transition-all duration-500">
                                                <div className={`absolute top-0 left-0 right-0 h-1.5 ${getBadgeColor(meeting.type || 'company').split(' ')[0].replace('bg-', 'bg-')}`}></div>
                                                <CardHeader className="p-8 pb-4">
                                                    <div className="flex justify-between items-start mb-6">
                                                        <Badge className={`rounded-full px-4 py-1 font-black text-[9px] uppercase tracking-widest border-none ${getBadgeColor(meeting.type || 'company')}`}>
                                                            {getDisplayName(meeting.type || 'company')}
                                                        </Badge>
                                                        <DropdownMenu>
                                                            <DropdownMenuTrigger asChild>
                                                                <div className="h-10 w-10 rounded-2xl bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 opacity-0 group-hover:opacity-100 transition-all cursor-pointer hover:bg-slate-100">
                                                                    <MoreVertical className="h-4 w-4" />
                                                                </div>
                                                            </DropdownMenuTrigger>
                                                            <DropdownMenuContent align="end" className="rounded-xl border-slate-200">
                                                                {(isAdmin || Number(meeting.created_by_id) === Number(user?.id)) && (
                                                                    <>
                                                                        <DropdownMenuItem onClick={() => openEditDialog(meeting)} className="rounded-lg gap-2 font-bold text-xs uppercase tracking-wider py-3">
                                                                            <Edit2 className="h-3.5 w-3.5 text-blue-600" />
                                                                            Edit Protocol
                                                                        </DropdownMenuItem>
                                                                        <DropdownMenuItem onClick={() => handleDeleteMeeting(meeting)} className="rounded-lg gap-2 font-bold text-xs uppercase tracking-wider py-3 text-destructive">
                                                                            <Trash2 className="h-3.5 w-3.5" />
                                                                            Purge Node
                                                                        </DropdownMenuItem>
                                                                    </>
                                                                )}
                                                            </DropdownMenuContent>
                                                        </DropdownMenu>
                                                    </div>
                                                    <CardTitle className="text-xl font-black text-slate-900 dark:text-white mb-2 leading-tight tracking-tight">
                                                        {meeting.title}
                                                    </CardTitle>
                                                    <CardDescription className="text-slate-500 dark:text-slate-400 line-clamp-2 text-sm font-medium leading-relaxed">
                                                        {meeting.description}
                                                    </CardDescription>
                                                </CardHeader>

                                                <CardContent className="p-8 pt-0 space-y-6">
                                                    <div className="space-y-3 pt-2">
                                                        <div className="flex items-center gap-3 text-slate-600 dark:text-slate-400">
                                                            <div className="h-8 w-8 rounded-xl bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center text-blue-600">
                                                                <Calendar className="h-4 w-4" />
                                                            </div>
                                                            <span className="text-xs font-black uppercase tracking-tight">{meeting.start_time && isValid(new Date(meeting.start_time)) ? format(new Date(meeting.start_time), 'EEEE, MMM do') : 'TBD'}</span>
                                                        </div>
                                                        <div className="flex items-center gap-3 text-slate-600 dark:text-slate-400">
                                                            <div className="h-8 w-8 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 flex items-center justify-center text-indigo-600">
                                                                <Clock className="h-4 w-4" />
                                                            </div>
                                                            <span className="text-xs font-black tracking-tight">{meeting.start_time && isValid(new Date(meeting.start_time)) ? format(new Date(meeting.start_time), 'hh:mm a') : '--:--'} - {meeting.end_time && isValid(new Date(meeting.end_time)) ? format(new Date(meeting.end_time), 'hh:mm a') : '--:--'}</span>
                                                        </div>
                                                        {meeting.project_name && (
                                                            <div className="flex items-center gap-3 text-slate-600 dark:text-slate-400">
                                                                <div className="h-8 w-8 rounded-xl bg-emerald-50 dark:bg-emerald-900/20 flex items-center justify-center text-emerald-600">
                                                                    <Briefcase className="h-4 w-4" />
                                                                </div>
                                                                <span className="text-xs font-black tracking-tight uppercase">{meeting.project_name}</span>
                                                            </div>
                                                        )}
                                                    </div>

                                                    <div className="pt-6 border-t border-slate-50 dark:border-slate-800 flex items-center justify-between">
                                                        <div className="flex -space-x-3">
                                                            {meeting.participants?.filter(Boolean).slice(0, 3).map((p, i) => (
                                                                <div key={i} className="h-10 w-10 rounded-2xl border-4 border-white dark:border-slate-900 bg-slate-100 flex items-center justify-center overflow-hidden shadow-sm">
                                                                    <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${p.user_name || p.id}`} alt="" className="h-full w-full object-cover" />
                                                                </div>
                                                            ))}
                                                            {(meeting.participants?.length || 0) > 3 && (
                                                                <div className="h-10 w-10 rounded-2xl border-4 border-white dark:border-slate-900 bg-slate-900 text-[10px] text-white flex items-center justify-center font-black">
                                                                    +{meeting.participants!.length - 3}
                                                                </div>
                                                            )}
                                                            {(!meeting.participants || meeting.participants.length === 0) && (
                                                                <div className="h-10 w-10 rounded-2xl border-4 border-white dark:border-slate-900 bg-slate-100 flex items-center justify-center text-slate-400">
                                                                    <Users className="h-4 w-4" />
                                                                </div>
                                                            )}
                                                        </div>

                                                        <Button
                                                            asChild
                                                            className="rounded-2xl bg-slate-900 hover:bg-blue-600 text-white font-black text-[10px] uppercase tracking-widest px-6 h-11 transition-all shadow-lg shadow-slate-200 dark:shadow-none"
                                                        >
                                                            <a href={meeting.meeting_url} target="_blank" rel="noopener noreferrer">
                                                                Join Meeting
                                                                <ExternalLink className="ml-2 h-3.5 w-3.5" />
                                                            </a>
                                                        </Button>
                                                    </div>
                                                </CardContent>
                                            </Card>
                                        ))}
                                    </div>
                                )}
                            </TabsContent>
                        </div>
                    </Tabs>
                </div>
            </div>

            <style dangerouslySetInnerHTML={{
                __html: `
                .custom-scrollbar::-webkit-scrollbar { width: 6px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
                .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; }
            `}} />
        </div>
    );
};

export default MeetingsPage;

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLanguage } from '@/contexts/LanguageContext';
import { useTheme, ColorTheme } from '@/contexts/ThemeContext';
import { apiService } from '@/lib/api';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useToast } from '@/components/ui/use-toast';
import { Switch } from '@/components/ui/switch';
import {
  User,
  Mail,
  Phone,
  Briefcase,
  Building,
  MapPin,
  Calendar,
  Camera,
  Shield,
  Clock,
  Award,
  Target,
  TrendingUp,
  Palette,
  Check,
  Bell,
  BellOff,
} from 'lucide-react';
import { formatDateIST } from '@/utils/timezone';

const Profile: React.FC = () => {
  const { user, updateUser } = useAuth();
  const { t } = useLanguage();
  const { toast } = useToast();
  const { colorTheme, setColorTheme } = useTheme();
  const [editedUser, setEditedUser] = useState(user);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [employeeData, setEmployeeData] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [notificationsEnabled, setNotificationsEnabled] = useState(() => {
    const stored = localStorage.getItem('notificationsEnabled');
    return stored === null ? true : stored === 'true';
  });

  // Fetch employee data from database
  useEffect(() => {
    const fetchEmployeeData = async () => {
      if (!user?.email) return;

      try {
        setIsLoading(true);

        let currentEmployee = null;

        // If user is admin or HR, they can fetch all or specific. 
        // But for regular employees, apiService.getEmployees() will 403.
        // Better to always try fetching the specific employee record by ID first.
        try {
          currentEmployee = await apiService.getEmployeeById(user.id);
        } catch (err) {
          console.warn('Failed to fetch specific employee data, trying fallback:', err);
          // Fallback only for privileged roles
          if (['admin', 'hr', 'manager', 'team_lead'].includes(user.role)) {
            const employees = await apiService.getEmployees().catch(() => []);
            currentEmployee = employees.find((emp: any) =>
              emp.email === user.email || String(emp.employee_id) === String(user.id) || String(emp.id) === String(user.id)
            );
          }
        }

        if (currentEmployee) {
          setEmployeeData(currentEmployee);
          // Update editedUser with database data
          const joiningDateRaw = currentEmployee.joining_date || currentEmployee.created_at || user.joiningDate;
          const formattedJoiningDate = joiningDateRaw ? new Date(joiningDateRaw).toISOString().split('T')[0] : '';

          setEditedUser({
            ...user,
            id: currentEmployee.employee_id || currentEmployee.id || user.id,
            phone: currentEmployee.phone || user.phone,
            address: currentEmployee.address || user.address,
            department: currentEmployee.department || user.department,
            designation: currentEmployee.designation || user.designation,
            joiningDate: formattedJoiningDate,
            profilePhoto: currentEmployee.photo_url || user.profilePhoto,
          });
        }
      } catch (error) {
        console.error('Failed to fetch employee data:', error);
        toast({
          title: 'Error',
          description: 'Failed to load employee data',
          variant: 'destructive',
        });
      } finally {
        setIsLoading(false);
      }
    };

    fetchEmployeeData();
  }, [user?.email, user?.id]);

  const handleNotificationToggle = (enabled: boolean) => {
    setNotificationsEnabled(enabled);
    localStorage.setItem('notificationsEnabled', enabled.toString());
    toast({
      title: enabled ? 'Notifications Enabled' : 'Notifications Disabled',
      description: enabled
        ? 'You will now receive notifications.'
        : 'You will no longer receive notifications.',
    });
  };

  if (!user || !editedUser) return null;

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
          <p className="mt-4 text-muted-foreground">Loading profile...</p>
        </div>
      </div>
    );
  }

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const imageData = reader.result as string;
        setSelectedImage(imageData);
        updateUser({ ...editedUser, profilePhoto: imageData });
        toast({
          title: 'Profile Photo Updated',
          description: 'Your profile photo has been saved.',
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemovePhoto = () => {
    setSelectedImage(null);
    updateUser({ ...editedUser, profilePhoto: '' });
    toast({
      title: 'Profile Photo Removed',
      description: 'Your profile photo has been removed.',
    });
  };

  const getRoleBadgeColor = (role: string) => {
    const colors = {
      admin: 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300',
      hr: 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300',
      manager: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300',
      team_lead: 'bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-300',
      employee: 'bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-300',
    };
    return colors[role as keyof typeof colors] || colors.employee;
  };

  const stats = [
    { label: 'Total Tasks', value: '48', icon: Target, color: 'text-blue-500' },
    { label: 'Completed', value: '36', icon: Award, color: 'text-green-500' },
    { label: 'In Progress', value: '12', icon: TrendingUp, color: 'text-orange-500' },
    { label: 'Attendance', value: '95%', icon: Clock, color: 'text-purple-500' },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background/95 to-primary/5">
      <div className="w-full space-y-6">
        {/* Header Card */}
        <Card className="overflow-hidden border-0 shadow-xl bg-gradient-to-r from-primary/10 via-primary/5 to-transparent">
          <div className="relative h-32 bg-gradient-to-r from-primary via-primary/80 to-primary/60">
            <div className="absolute inset-0 bg-grid-white/10" />
          </div>
          <CardContent className="relative -mt-16 pb-6">
            <div className="flex flex-col md:flex-row items-center md:items-end gap-6">
              <div className="relative">
                <Avatar className="h-32 w-32 ring-4 ring-background shadow-xl">
                  <AvatarImage src={selectedImage || user.profilePhoto} alt={user.name} />
                  <AvatarFallback className="text-3xl font-bold bg-gradient-to-br from-primary to-primary/60 text-primary-foreground">
                    {user.name.split(' ').map(n => n[0]).join('')}
                  </AvatarFallback>
                </Avatar>
                <label className="absolute bottom-0 right-0 p-2 bg-primary rounded-full cursor-pointer hover:bg-primary/90 transition-colors shadow-lg">
                  <Camera className="h-5 w-5 text-primary-foreground" />
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleImageChange}
                    className="hidden"
                  />
                </label>
              </div>

              <div className="flex-1 text-center md:text-left space-y-2">
                <div className="flex flex-col md:flex-row items-center gap-3">
                  <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white sm:text-3xl">{user.name}</h1>
                  <Badge className={`${getRoleBadgeColor(user.role)} px-3 py-1`}>
                    <Shield className="h-3 w-3 mr-1" />
                    {t.roles[user.role]}
                  </Badge>
                </div>
                <p className="text-muted-foreground">{user.designation}</p>
                <div className="flex flex-wrap gap-4 justify-center md:justify-start text-sm text-muted-foreground">
                  <span className="flex items-center gap-1">
                    <Building className="h-4 w-4" />
                    {user.department}
                  </span>
                  <span className="flex items-center gap-1">
                    <Mail className="h-4 w-4" />
                    {user.email}
                  </span>
                  <span className="flex items-center gap-1">
                    <Calendar className="h-4 w-4" />
                    Joined {formatDateIST(user.joiningDate, 'MMM dd, yyyy')}
                  </span>
                </div>
              </div>

              <div className="flex gap-2">
                <Button onClick={handleRemovePhoto} variant="outline" className="shadow-lg">
                  Remove Photo
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {stats.map((stat, index) => (
            <Card key={index} className="border-0 shadow-lg hover:shadow-xl transition-shadow">
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">{stat.label}</p>
                    <p className="text-2xl font-bold mt-1">{stat.value}</p>
                  </div>
                  <div className={`p-3 rounded-full bg-background ${stat.color}`}>
                    <stat.icon className="h-6 w-6" />
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Main Content */}
        <Tabs defaultValue="personal" className="space-y-4">
          <TabsList className="grid w-full md:w-auto md:inline-grid grid-cols-3 bg-card">
            <TabsTrigger value="personal">Personal Info</TabsTrigger>
            <TabsTrigger value="professional">Professional</TabsTrigger>
            <TabsTrigger value="settings">Settings</TabsTrigger>
          </TabsList>

          <TabsContent value="personal" className="space-y-4">
            <Card className="border-0 shadow-lg">
              <CardHeader className="bg-gradient-to-r from-primary/5 to-transparent">
                <CardTitle className="flex items-center gap-2">
                  <User className="h-5 w-5 text-primary" />
                  Personal Information
                </CardTitle>
                <CardDescription>
                  Manage your personal details and contact information
                </CardDescription>
              </CardHeader>
              <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6">
                <div className="space-y-2">
                  <Label htmlFor="name">Full Name</Label>
                  <Input
                    id="name"
                    value={editedUser.name}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="email">Email Address</Label>
                  <Input
                    id="email"
                    type="email"
                    value={editedUser.email}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="phone">Phone Number</Label>
                  <Input
                    id="phone"
                    value={editedUser.phone || ''}
                    disabled
                    placeholder="+91 98765 43210"
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="address">Address</Label>
                  <Input
                    id="address"
                    value={editedUser.address || ''}
                    disabled
                    placeholder="Enter your address"
                    className="disabled:opacity-60"
                  />
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="professional" className="space-y-4">
            <Card className="border-0 shadow-lg">
              <CardHeader className="bg-gradient-to-r from-primary/5 to-transparent">
                <CardTitle className="flex items-center gap-2">
                  <Briefcase className="h-5 w-5 text-primary" />
                  Professional Information
                </CardTitle>
                <CardDescription>
                  Your role and department details
                </CardDescription>
              </CardHeader>
              <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6">
                <div className="space-y-2">
                  <Label htmlFor="employeeId">Employee ID</Label>
                  <Input
                    id="employeeId"
                    value={editedUser.id || employeeData?.employee_id || user.id}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="department">Department</Label>
                  <Input
                    id="department"
                    value={editedUser.department}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="designation">Designation</Label>
                  <Input
                    id="designation"
                    value={editedUser.designation}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="joiningDate">Joining Date</Label>
                  <Input
                    id="joiningDate"
                    type="date"
                    value={editedUser.joiningDate}
                    disabled
                    className="disabled:opacity-60"
                  />
                </div>
              </CardContent>
            </Card>

            <Card className="border-0 shadow-lg">
              <CardHeader className="bg-gradient-to-r from-primary/5 to-transparent">
                <CardTitle className="flex items-center gap-2">
                  <Target className="h-5 w-5 text-primary" />
                  About Me
                </CardTitle>
              </CardHeader>
              <CardContent className="pt-6">
                <Textarea
                  placeholder="Tell us about yourself, your skills, and experience..."
                  className="min-h-[120px] disabled:opacity-60"
                  disabled
                />
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="settings" className="space-y-4">
            <Card className="border-0 shadow-lg">
              <CardHeader className="bg-gradient-to-r from-primary/5 to-transparent">
                <CardTitle className="flex items-center gap-2">
                  <Shield className="h-5 w-5 text-primary" />
                  Quick Settings
                </CardTitle>
                <CardDescription>
                  Common account preferences and security options
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6 pt-6">
                <div className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-950/30 dark:to-indigo-950/30 p-6 rounded-xl border border-blue-200 dark:border-blue-800">
                  <div className="flex items-start gap-4">
                    <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center flex-shrink-0">
                      <Palette className="h-6 w-6 text-white" />
                    </div>
                    <div className="flex-1">
                      <h3 className="font-semibold text-lg mb-2">Customize Your Experience</h3>
                      <p className="text-sm text-muted-foreground mb-4">
                        Visit the Settings page to personalize your dashboard with color themes, language preferences, and more.
                      </p>
                      <Button
                        onClick={() => window.location.href = `/${user.role}/settings`}
                        className="bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700"
                      >
                        Go to Settings
                      </Button>
                    </div>
                  </div>
                </div>
                <div className="border-t pt-6"></div>
                <div className="flex items-center justify-between p-4 rounded-lg border bg-gradient-to-r from-blue-50/50 to-indigo-50/50 dark:from-blue-950/20 dark:to-indigo-950/20">
                  <div className="flex items-center gap-3">
                    {notificationsEnabled ? (
                      <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                        <Bell className="h-5 w-5 text-white" />
                      </div>
                    ) : (
                      <div className="h-10 w-10 rounded-lg bg-gray-400 dark:bg-gray-600 flex items-center justify-center">
                        <BellOff className="h-5 w-5 text-white" />
                      </div>
                    )}
                    <div>
                      <p className="font-medium">Push Notifications</p>
                      <p className="text-sm text-muted-foreground">
                        {notificationsEnabled ? 'Receive real-time updates' : 'Notifications are disabled'}
                      </p>
                    </div>
                  </div>
                  <Switch
                    checked={notificationsEnabled}
                    onCheckedChange={handleNotificationToggle}
                  />
                </div>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium">Two-Factor Authentication</p>
                    <p className="text-sm text-muted-foreground">Add an extra layer of security</p>
                  </div>
                  <Button variant="outline">Enable</Button>
                </div>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium">Email Notifications</p>
                    <p className="text-sm text-muted-foreground">Receive updates via email</p>
                  </div>
                  <Button variant="outline">Configure</Button>
                </div>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium">Change Password</p>
                    <p className="text-sm text-muted-foreground">Update your password regularly</p>
                  </div>
                  <Button variant="outline">Change</Button>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
};

export default Profile;

import React, { useEffect, useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Checkbox } from '@/components/ui/checkbox';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
    DialogDescription,
} from '@/components/ui/dialog';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { toast } from '@/hooks/use-toast';
import {
    Plus,
    Edit,
    Trash2,
    Search,
    Eye,
    Loader2,
    FolderKanban,
    Users,
    CheckCircle2,
    Clock,
    XCircle,
    UserPlus,
    UserMinus,
    ClipboardList,
    ChevronDown,
    ChevronUp,
    CalendarDays,
    LayoutGrid,
    ListIcon,
    AlertCircle,
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { apiService } from '@/lib/api';
import { formatDateIST } from '@/utils/timezone';

// ─────────────────────────────────────────
// Interfaces
// ─────────────────────────────────────────
interface ProjectMember {
    user_id: number;
    name: string;
    email?: string;
    role?: string;
}

interface ProjectTask {
    task_id?: number;
    id?: number;
    task_name: string;
    description?: string;
    assigned_to?: number;
    assigned_to_name?: string;
    due_date?: string;
    status: 'pending' | 'in-progress' | 'overdue' | 'completed' | 'cancelled' | 'todo';
}


interface Project {
    project_id: number;
    name: string;
    description?: string;
    start_date?: string;
    end_date?: string;
    status?: string;
    pic_name?: string;
    members?: ProjectMember[];
    tasks?: ProjectTask[];
}

interface Employee {
    user_id: number;
    name: string;
    email?: string;
    role?: string;
    department?: string;
}

const TASK_STATUSES = ['pending', 'in-progress', 'overdue', 'completed', 'cancelled', 'todo'] as const;
type TaskStatus = typeof TASK_STATUSES[number];

// Form-only type: supports multiple assignees per task row
interface TaskFormRow {
    task_name: string;
    description: string;
    assigned_to_ids: number[];
    due_date: string;
    status: TaskStatus;
}

const emptyTask = (): TaskFormRow => ({
    task_name: '',
    description: '',
    assigned_to_ids: [],
    due_date: '',
    status: 'pending',
});

// ─────────────────────────────────────────
// Status helpers
// ─────────────────────────────────────────
function TaskStatusBadge({ status }: { status: string }) {
    if (status === 'todo' || status === 'pending')
        return <Badge className="bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-0 gap-1 text-[11px]"><Clock className="h-3 w-3" />Pending</Badge>;
    if (status === 'in-progress')
        return <Badge className="bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 border-0 gap-1 text-[11px]"><Clock className="h-3 w-3" />In Progress</Badge>;
    if (status === 'overdue')
        return <Badge className="bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400 border-0 gap-1 text-[11px]"><AlertCircle className="h-3 w-3" />Overdue</Badge>;
    if (status === 'completed')
        return <Badge className="bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 border-0 gap-1 text-[11px]"><CheckCircle2 className="h-3 w-3" />Completed</Badge>;
    if (status === 'cancelled')
        return <Badge className="bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400 border-0 gap-1 text-[11px]"><XCircle className="h-3 w-3" />Cancelled</Badge>;
    return <Badge className="bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-0 gap-1 text-[11px]"><Clock className="h-3 w-3" />Pending</Badge>;
}

function statusColor(s?: string) {
    if (s === 'completed') return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400';
    if (s === 'cancelled') return 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400';
    if (s === 'on-hold') return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400';
    if (s === 'archived') return 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400';
    return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
}

// ─────────────────────────────────────────
// TaskRow sub-component with inline status
// ─────────────────────────────────────────
function TaskRow({
    task,
    canManageProjects,
    onStatusChange,
}: {
    task: ProjectTask;
    canManageProjects: boolean;
    onStatusChange: (taskId: number, status: string) => void;
}) {
    const id = task.task_id ?? task.id ?? 0;

    // Detect overdue automatically
    const isOverdue = useMemo(() => {
        if (task.status === 'completed' || task.status === 'cancelled') return false;
        if (!task.due_date) return false;
        const due = new Date(task.due_date);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        return due < today;
    }, [task.due_date, task.status]);

    const effectiveStatus = isOverdue ? 'overdue' : (task.status === 'todo' ? 'pending' : task.status);

    return (
        <TableRow className="hover:bg-slate-50/60 dark:hover:bg-slate-900/30 transition-colors">
            <TableCell className="pl-4">
                <p className="text-sm font-medium text-slate-800 dark:text-slate-100">{task.task_name}</p>
                {task.description && <p className="text-xs text-slate-400 mt-0.5">{task.description}</p>}
            </TableCell>
            <TableCell className="text-sm text-slate-600 dark:text-slate-300">
                <div className="flex items-center gap-1.5">
                    <div className="h-6 w-6 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center text-[10px] font-bold text-blue-700 dark:text-blue-400 flex-shrink-0">
                        {task.assigned_to_name?.[0]?.toUpperCase() || '?'}
                    </div>
                    {task.assigned_to_name || 'Unassigned'}
                </div>
            </TableCell>
            <TableCell className="text-sm text-slate-500">
                {task.due_date ? formatDateIST(task.due_date, 'MMM dd, yyyy') : '—'}
            </TableCell>
            <TableCell>
                {canManageProjects ? (
                    <Select
                        value={task.status === 'todo' ? 'pending' : task.status}
                        onValueChange={(v) => onStatusChange(id, v)}
                    >
                        <SelectTrigger className="h-7 w-32 text-xs border-slate-200 dark:border-slate-700">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent side="bottom">
                            <SelectItem value="pending">
                                <span className="flex items-center gap-1.5 text-amber-600 font-medium"><Clock className="h-3 w-3" />Pending</span>
                            </SelectItem>
                            <SelectItem value="in-progress">
                                <span className="flex items-center gap-1.5 text-blue-600 font-medium"><Clock className="h-3 w-3" />In Progress</span>
                            </SelectItem>
                            <SelectItem value="overdue">
                                <span className="flex items-center gap-1.5 text-red-600 font-medium"><AlertCircle className="h-3 w-3" />Overdue</span>
                            </SelectItem>
                            <SelectItem value="completed">
                                <span className="flex items-center gap-1.5 text-emerald-600 font-medium"><CheckCircle2 className="h-3 w-3" />Completed</span>
                            </SelectItem>
                            <SelectItem value="cancelled">
                                <span className="flex items-center gap-1.5 text-slate-500 font-medium"><XCircle className="h-3 w-3" />Cancelled</span>
                            </SelectItem>
                        </SelectContent>
                    </Select>
                ) : (
                    <TaskStatusBadge status={effectiveStatus} />
                )}
                {isOverdue && task.status !== 'completed' && task.status !== 'cancelled' && !canManageProjects && (
                    <div className="mt-1">
                        <Badge className="bg-red-50 text-red-600 dark:bg-red-900/20 border-0 text-[9px] height-auto py-0 px-1">AUTO OVERDUE</Badge>
                    </div>
                )}
            </TableCell>
        </TableRow>
    );
}

// ─────────────────────────────────────────
// Project Card component (expandable)
// ─────────────────────────────────────────
function ProjectCard({
    project,
    canManageProjects,
    isDeleting,
    onEdit,
    onDelete,
    onManageMembers,
    onAssignTasks,
    onTaskStatusChange,
}: {
    project: Project;
    canManageProjects: boolean;
    isDeleting: number | null;
    onEdit: () => void;
    onDelete: () => void;
    onManageMembers: () => void;
    onAssignTasks: () => void;
    onTaskStatusChange: (projectId: number, taskId: number, status: string) => void;
}) {
    const [expanded, setExpanded] = useState(false);
    const tasks = project.tasks || [];
    const members = project.members || [];
    const todoCount = tasks.filter(t => t.status === 'todo').length;
    const completedCount = tasks.filter(t => t.status === 'completed').length;
    const cancelledCount = tasks.filter(t => t.status === 'cancelled').length;

    return (
        <Card className="border border-slate-200 dark:border-slate-700 rounded-2xl shadow-sm hover:shadow-md transition-shadow overflow-hidden">
            <CardContent className="p-0">
                {/* ── Card Header ── */}
                <div className="p-5">
                    <div className="flex items-start justify-between gap-3">
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                                <h3 className="font-bold text-slate-900 dark:text-white text-base truncate">{project.name}</h3>
                                <Badge className={`capitalize border-0 text-[10px] px-2 py-0.5 ${statusColor(project.status)}`}>
                                    {project.status || 'Active'}
                                </Badge>
                            </div>
                            {project.description && (
                                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1 line-clamp-2">{project.description}</p>
                            )}
                            {/* Dates */}
                            {(project.start_date || project.end_date) && (
                                <div className="flex items-center gap-3 mt-2 text-xs text-slate-400">
                                    <span className="flex items-center gap-1"><CalendarDays className="h-3 w-3" />
                                        {project.start_date ? formatDateIST(project.start_date, 'MMM dd, yyyy') : '—'}
                                        {' → '}
                                        {project.end_date ? formatDateIST(project.end_date, 'MMM dd, yyyy') : '—'}
                                    </span>
                                </div>
                            )}
                        </div>

                        {/* Actions */}
                        <div className="flex items-center gap-1 flex-shrink-0">
                            {canManageProjects && (
                                <>
                                    <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-blue-50 hover:text-blue-600" title="Manage Team Members" onClick={onManageMembers}>
                                        <UserPlus className="h-4 w-4" />
                                    </Button>
                                    <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-amber-50 hover:text-amber-600" title="Assign Tasks" onClick={onAssignTasks}>
                                        <ClipboardList className="h-4 w-4" />
                                    </Button>
                                    <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-green-50 hover:text-green-600" title="Edit Project" onClick={onEdit}>
                                        <Edit className="h-4 w-4" />
                                    </Button>
                                    <Button
                                        variant="ghost" size="icon"
                                        className="h-8 w-8 hover:bg-red-50 hover:text-red-600"
                                        title="Delete Project"
                                        disabled={isDeleting === project.project_id}
                                        onClick={onDelete}
                                    >
                                        {isDeleting === project.project_id
                                            ? <Loader2 className="h-4 w-4 animate-spin" />
                                            : <Trash2 className="h-4 w-4" />}
                                    </Button>
                                </>
                            )}
                        </div>
                    </div>

                    {/* ── Summary pills ── */}
                    <div className="flex items-center gap-3 mt-3 flex-wrap">
                        {/* Members */}
                        <div className="flex items-center gap-1.5 bg-slate-100 dark:bg-slate-800 px-2.5 py-1 rounded-full">
                            <Users className="h-3.5 w-3.5 text-slate-500" />
                            <span className="text-xs font-medium text-slate-600 dark:text-slate-300">
                                {members.length} Member{members.length !== 1 ? 's' : ''}
                            </span>
                        </div>

                        {/* Task counts */}
                        {tasks.length > 0 && (
                            <>
                                <div className="flex items-center gap-1.5 bg-amber-50 dark:bg-amber-900/20 px-2.5 py-1 rounded-full">
                                    <Clock className="h-3.5 w-3.5 text-amber-500" />
                                    <span className="text-xs font-medium text-amber-600 dark:text-amber-400">{tasks.filter(t => t.status === 'todo' || t.status === 'pending').length} Pending</span>
                                </div>
                                <div className="flex items-center gap-1.5 bg-emerald-50 dark:bg-emerald-900/20 px-2.5 py-1 rounded-full">
                                    <CheckCircle2 className="h-3.5 w-3.5 text-emerald-500" />
                                    <span className="text-xs font-medium text-emerald-600 dark:text-emerald-400">{completedCount} Done</span>
                                </div>
                                {cancelledCount > 0 && (
                                    <div className="flex items-center gap-1.5 bg-red-50 dark:bg-red-900/20 px-2.5 py-1 rounded-full">
                                        <XCircle className="h-3.5 w-3.5 text-red-400" />
                                        <span className="text-xs font-medium text-red-500 dark:text-red-400">{cancelledCount} Cancelled</span>
                                    </div>
                                )}
                            </>
                        )}

                        {/* Expand toggle */}
                        {(tasks.length > 0 || members.length > 0) && (
                            <button
                                onClick={() => setExpanded(e => !e)}
                                className="ml-auto flex items-center gap-1 text-xs text-violet-600 dark:text-violet-400 font-semibold hover:underline"
                            >
                                {expanded ? <><ChevronUp className="h-3.5 w-3.5" />Hide details</> : <><ChevronDown className="h-3.5 w-3.5" />View details</>}
                            </button>
                        )}
                    </div>
                </div>

                {/* ── Expanded section ── */}
                {expanded && (
                    <div className="border-t border-slate-100 dark:border-slate-800">
                        {/* Members row */}
                        {members.length > 0 && (
                            <div className="px-5 py-3 border-b border-slate-100 dark:border-slate-800">
                                <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2 flex items-center gap-1.5">
                                    <Users className="h-3.5 w-3.5" /> Team Members
                                </p>
                                <div className="flex flex-wrap gap-2">
                                    {members.map(m => (
                                        <div key={m.user_id} className="flex items-center gap-1.5 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 px-2.5 py-1 rounded-full">
                                            <div className="h-5 w-5 rounded-full bg-blue-500 flex items-center justify-center text-[9px] font-bold text-white">
                                                {m.name[0]?.toUpperCase()}
                                            </div>
                                            <span className="text-xs font-medium text-blue-700 dark:text-blue-300">{m.name}</span>
                                            {m.role && <span className="text-[10px] text-blue-400 capitalize">({m.role})</span>}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Tasks table */}
                        {tasks.length > 0 && (
                            <div>
                                <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider px-5 pt-3 mb-2 flex items-center gap-1.5">
                                    <ClipboardList className="h-3.5 w-3.5" /> Tasks
                                </p>
                                <div className="overflow-x-auto">
                                    <Table>
                                        <TableHeader>
                                            <TableRow className="bg-slate-50/80 dark:bg-slate-900/40">
                                                <TableHead className="pl-4 text-xs">Task</TableHead>
                                                <TableHead className="text-xs">Assigned To</TableHead>
                                                <TableHead className="text-xs">Due Date</TableHead>
                                                <TableHead className="text-xs">Status</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {tasks.map((task, idx) => (
                                                <TaskRow
                                                    key={task.task_id ?? task.id ?? idx}
                                                    task={task}
                                                    canManageProjects={canManageProjects}
                                                    onStatusChange={(taskId, status) =>
                                                        onTaskStatusChange(project.project_id, taskId, status)
                                                    }
                                                />
                                            ))}
                                        </TableBody>
                                    </Table>
                                </div>
                            </div>
                        )}

                        {tasks.length === 0 && (
                            <div className="py-6 text-center text-xs text-slate-400">No tasks assigned yet.</div>
                        )}
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

// ─────────────────────────────────────────
// Main Page
// ─────────────────────────────────────────
export default function ProjectManagement() {
    const { user } = useAuth();

    const [projects, setProjects] = useState<Project[]>([]);
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [isLoading, setIsLoading] = useState(false);
    const [isCreating, setIsCreating] = useState(false);
    const [isUpdating, setIsUpdating] = useState(false);
    const [isDeleting, setIsDeleting] = useState<number | null>(null);

    // Dialogs
    const [selectedProject, setSelectedProject] = useState<Project | null>(null);
    const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
    const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
    const [isMemberDialogOpen, setIsMemberDialogOpen] = useState(false);
    const [isTaskDialogOpen, setIsTaskDialogOpen] = useState(false);

    // Create/Edit form
    const [formData, setFormData] = useState({ name: '', description: '', start_date: '', end_date: '', status: 'active' });
    // Multi-select members (for create)
    const [selectedMemberIds, setSelectedMemberIds] = useState<number[]>([]);
    const [memberSearch, setMemberSearch] = useState('');
    // Task list (for create + assign dialog)
    const [taskList, setTaskList] = useState<TaskFormRow[]>([emptyTask()]);
    // Manage members dialog
    const [addMemberId, setAddMemberId] = useState('');

    // ── Fetch ──
    const fetchProjects = async () => {
        setIsLoading(true);
        try {
            const data = await apiService.getProjects();
            setProjects(Array.isArray(data) ? data : data?.projects || []);
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to load projects', variant: 'destructive' });
        } finally {
            setIsLoading(false);
        }
    };

    const fetchEmployees = async () => {
        try {
            const data = await apiService.getEmployees();
            setEmployees((Array.isArray(data) ? data : []).map((e: any) => ({
                user_id: e.user_id || e.id,
                name: e.name,
                email: e.email,
                role: e.role,
                department: e.department,
            })));
        } catch (_) { }
    };

    useEffect(() => { fetchProjects(); fetchEmployees(); }, []);

    const filteredProjects = useMemo(() =>
        projects.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                p.description?.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesStatus = statusFilter === 'all' || (p.status || 'active') === statusFilter;
            return matchesSearch && matchesStatus;
        }), [projects, searchQuery, statusFilter]);

    // ── Helpers ──
    const resetForm = () => {
        setFormData({ name: '', description: '', start_date: '', end_date: '', status: 'active' });
        setSelectedMemberIds([]);
        setMemberSearch('');
        setTaskList([emptyTask()]);
        setAddMemberId('');
    };

    const toggleMember = (id: number) =>
        setSelectedMemberIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const addTaskRow = () => setTaskList(prev => [...prev, emptyTask()]);
    const updateTaskRow = (index: number, field: keyof TaskFormRow, value: any) =>
        setTaskList(prev => prev.map((t, i) => i === index ? { ...t, [field]: value } : t));
    const toggleTaskAssignee = (index: number, userId: number) =>
        setTaskList(prev => prev.map((t, i) => {
            if (i !== index) return t;
            const ids = t.assigned_to_ids.includes(userId)
                ? t.assigned_to_ids.filter(id => id !== userId)
                : [...t.assigned_to_ids, userId];
            return { ...t, assigned_to_ids: ids };
        }));
    const removeTaskRow = (index: number) => {
        if (taskList.length === 1) return;
        setTaskList(prev => prev.filter((_, i) => i !== index));
    };

    const assignableEmployees = useMemo(() => {
        if (!user) return [];
        return employees.filter(e => {
            if (String(e.user_id) === String(user.id)) return true; // Can always assign to self
            if (user.role === 'admin' || user.role === 'hr') return true; // Admin/HR to everyone
            if (user.role === 'manager') return ['team_lead', 'employee'].includes(e.role || ''); // Manager to TL/Emp
            if (user.role === 'team_lead') return e.role === 'employee'; // TL to Emp
            return false; // Employee to no one
        });
    }, [employees, user]);

    const filteredMemberOptions = useMemo(() =>
        assignableEmployees.filter(e => e.name.toLowerCase().includes(memberSearch.toLowerCase())),
        [assignableEmployees, memberSearch]);

    // ── Handlers ──
    const handleCreate = async () => {
        if (!formData.name.trim()) {
            toast({ title: 'Error', description: 'Project name is required', variant: 'destructive' });
            return;
        }
        setIsCreating(true);
        try {
            // Fan-out: one task per (task, assignee) pair
            const expandedTasks: any[] = [];
            for (const t of taskList) {
                if (!t.task_name.trim() || t.assigned_to_ids.length === 0) continue;
                for (const uid of t.assigned_to_ids) {
                    expandedTasks.push({
                        task_name: t.task_name,
                        description: t.description,
                        assigned_to: uid,
                        due_date: t.due_date || undefined,
                        status: t.status,
                    });
                }
            }
            const payload = {
                ...formData,
                member_ids: selectedMemberIds,
                tasks: expandedTasks,
            };
            await apiService.createProject(payload);
            toast({ title: 'Success', description: 'Project created successfully' });
            setIsCreateDialogOpen(false);
            resetForm();
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to create project', variant: 'destructive' });
        } finally {
            setIsCreating(false);
        }
    };

    const handleUpdate = async () => {
        if (!selectedProject || !formData.name.trim()) {
            toast({ title: 'Error', description: 'Project name is required', variant: 'destructive' });
            return;
        }
        setIsUpdating(true);
        try {
            await apiService.updateProject(selectedProject.project_id, formData);
            toast({ title: 'Success', description: 'Project updated' });
            setIsEditDialogOpen(false);
            resetForm();
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to update project', variant: 'destructive' });
        } finally {
            setIsUpdating(false);
        }
    };

    const handleDelete = async (projectId: number) => {
        if (!confirm('Delete this project? This cannot be undone.')) return;
        setIsDeleting(projectId);
        try {
            await apiService.deleteProject(projectId);
            toast({ title: 'Success', description: 'Project deleted' });
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to delete project', variant: 'destructive' });
        } finally {
            setIsDeleting(null);
        }
    };

    const handleAddMember = async () => {
        if (!selectedProject || !addMemberId) {
            toast({ title: 'Error', description: 'Please select an employee', variant: 'destructive' });
            return;
        }
        try {
            await apiService.addProjectMember(selectedProject.project_id, Number(addMemberId));
            toast({ title: 'Success', description: 'Member added' });
            setAddMemberId('');
            const updated = await apiService.getProject(selectedProject.project_id);
            setSelectedProject(updated);
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to add member', variant: 'destructive' });
        }
    };

    const handleRemoveMember = async (userId: number) => {
        if (!selectedProject) return;
        try {
            await apiService.removeProjectMember(selectedProject.project_id, userId);
            toast({ title: 'Success', description: 'Member removed' });
            const updated = await apiService.getProject(selectedProject.project_id);
            setSelectedProject(updated);
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to remove member', variant: 'destructive' });
        }
    };

    const handleAssignTasks = async () => {
        if (!selectedProject) return;
        const validTasks = taskList.filter(t => t.task_name.trim() && t.assigned_to_ids.length > 0);
        if (!validTasks.length) {
            toast({ title: 'Error', description: 'Add at least one task with a name and at least one assignee', variant: 'destructive' });
            return;
        }
        setIsUpdating(true);
        try {
            // Fan-out: one API call per (task, employee) pair
            for (const task of validTasks) {
                for (const uid of task.assigned_to_ids) {
                    await apiService.createProjectTask(selectedProject.project_id, {
                        task_name: task.task_name,
                        description: task.description,
                        assigned_to: uid,
                        due_date: task.due_date || undefined,
                        status: task.status,
                    });
                }
            }
            toast({ title: 'Success', description: 'Tasks assigned successfully' });
            setIsTaskDialogOpen(false);
            setTaskList([emptyTask()]);
            const updated = await apiService.getProject(selectedProject.project_id);
            setSelectedProject(updated);
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to assign tasks', variant: 'destructive' });
        } finally {
            setIsUpdating(false);
        }
    };

    const handleTaskStatusChange = async (projectId: number, taskId: number, status: string) => {
        try {
            await apiService.updateProjectTaskStatus(projectId, taskId, status);
            toast({ title: 'Success', description: 'Task status updated' });
            fetchProjects();
        } catch (err: any) {
            toast({ title: 'Error', description: err.message || 'Failed to update task status', variant: 'destructive' });
        }
    };

    const canManageProjects = user?.role === 'admin' || user?.role === 'hr' || user?.role === 'manager';

    // ─────────────────────────────────────────
    // Task form — Admin/HR only, multi-assignee
    // ─────────────────────────────────────────
    const TaskFormSection = ({ teamOnly = false }: { teamOnly?: boolean }) => {
        const assignOptions = teamOnly && selectedMemberIds.length > 0
            ? assignableEmployees.filter(e => selectedMemberIds.includes(e.user_id))
            : assignableEmployees;

        return (
            <div className="space-y-3">
                {taskList.map((task, index) => (
                    <div key={index} className="p-3 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 space-y-2">
                        {/* Row 1: name, due date, status, remove */}
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-2">
                            <Input
                                placeholder="Task name *"
                                value={task.task_name}
                                onChange={e => updateTaskRow(index, 'task_name', e.target.value)}
                                className="md:col-span-2"
                            />
                            <Input
                                type="date"
                                value={task.due_date || ''}
                                onChange={e => updateTaskRow(index, 'due_date', e.target.value)}
                            />
                            <div className="flex gap-2">
                                <Select value={task.status} onValueChange={v => updateTaskRow(index, 'status', v as TaskStatus)}>
                                    <SelectTrigger className="flex-1">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="pending">
                                            <span className="flex items-center gap-1.5 text-amber-600"><Clock className="h-3 w-3" />Pending</span>
                                        </SelectItem>
                                        <SelectItem value="in-progress">
                                            <span className="flex items-center gap-1.5 text-blue-600"><Clock className="h-3 w-3" />In Progress</span>
                                        </SelectItem>
                                        <SelectItem value="overdue">
                                            <span className="flex items-center gap-1.5 text-red-600"><AlertCircle className="h-3 w-3" />Overdue</span>
                                        </SelectItem>
                                        <SelectItem value="completed">
                                            <span className="flex items-center gap-1.5 text-emerald-600"><CheckCircle2 className="h-3 w-3" />Completed</span>
                                        </SelectItem>
                                        <SelectItem value="cancelled">
                                            <span className="flex items-center gap-1.5 text-slate-500"><XCircle className="h-3 w-3" />Cancelled</span>
                                        </SelectItem>
                                    </SelectContent>
                                </Select>
                                {taskList.length > 1 && (
                                    <Button variant="ghost" size="icon" className="h-9 w-9 hover:bg-red-50 hover:text-red-600" onClick={() => removeTaskRow(index)}>
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                )}
                            </div>
                        </div>
                        {/* Description */}
                        <Input
                            placeholder="Description (optional)"
                            value={task.description || ''}
                            onChange={e => updateTaskRow(index, 'description', e.target.value)}
                        />
                        {/* Multi-employee assignee */}
                        <div className="space-y-1.5">
                            <div className="flex items-center justify-between">
                                <p className="text-xs font-semibold text-slate-600 dark:text-slate-400">
                                    Assign to employees *
                                    <span className="ml-1 text-slate-400 font-normal">(tick one or more)</span>
                                </p>
                                {task.assigned_to_ids.length > 0 && (
                                    <Badge className="text-[10px] bg-violet-100 text-violet-700 dark:bg-violet-900/40 dark:text-violet-300 border-0">
                                        {task.assigned_to_ids.length} selected
                                    </Badge>
                                )}
                            </div>
                            <div className="max-h-36 overflow-y-auto border border-slate-200 dark:border-slate-700 rounded-lg divide-y divide-slate-100 dark:divide-slate-800 bg-white dark:bg-slate-950">
                                {assignOptions.length === 0 ? (
                                    <p className="text-xs text-slate-400 text-center py-3">
                                        {teamOnly ? 'Select team members in Step 2 first.' : 'No employees available.'}
                                    </p>
                                ) : assignOptions.map(emp => (
                                    <label
                                        key={emp.user_id}
                                        className="flex items-center gap-2.5 px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-900 cursor-pointer transition-colors"
                                    >
                                        <Checkbox
                                            checked={task.assigned_to_ids.includes(emp.user_id)}
                                            onCheckedChange={() => toggleTaskAssignee(index, emp.user_id)}
                                            className="data-[state=checked]:bg-violet-600 data-[state=checked]:border-violet-600"
                                        />
                                        <div className="h-6 w-6 rounded-full bg-gradient-to-br from-violet-400 to-indigo-500 flex items-center justify-center text-[10px] font-bold text-white flex-shrink-0">
                                            {emp.name[0]?.toUpperCase()}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <span className="text-sm font-medium text-slate-800 dark:text-slate-200">{emp.name}</span>
                                            {emp.role && <span className="text-xs text-slate-400 ml-1.5 capitalize">({emp.role})</span>}
                                        </div>
                                    </label>
                                ))}
                            </div>
                        </div>
                    </div>
                ))}
                <Button variant="outline" size="sm" onClick={addTaskRow} className="gap-1 w-full border-dashed">
                    <Plus className="h-3.5 w-3.5" /> Add Another Task
                </Button>
            </div>
        );
    };

    // ─────────────────────────────────────────
    // Render
    // ─────────────────────────────────────────
    return (
        <div className="space-y-6 min-h-screen">
            {/* ── Header Card ── */}
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-md border border-slate-200 dark:border-slate-700">
                <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
                    <div className="flex items-start gap-4">
                        <div className="h-12 w-12 rounded-2xl bg-violet-600 flex items-center justify-center flex-shrink-0 shadow-md shadow-violet-200 dark:shadow-violet-900">
                            <FolderKanban className="h-6 w-6 text-white" />
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Project Management</h1>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">Build teams, assign tasks, and track progress.</p>
                        </div>
                    </div>
                    {canManageProjects && (
                        <Button
                            className="gap-2 rounded-full bg-violet-600 hover:bg-violet-700 text-white shadow-md shadow-violet-200 dark:shadow-violet-900"
                            onClick={() => { resetForm(); setIsCreateDialogOpen(true); }}
                        >
                            <Plus className="h-4 w-4" />
                            <span className="hidden sm:inline">New Project</span>
                            <span className="sm:hidden">New</span>
                        </Button>
                    )}
                </div>
                <div className="flex flex-col sm:flex-row gap-3 mt-4">
                    <div className="relative max-w-sm flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Search projects..."
                            className="pl-9 rounded-xl"
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <Select value={statusFilter} onValueChange={setStatusFilter}>
                        <SelectTrigger className="w-[160px] rounded-xl h-10">
                            <SelectValue placeholder="Filter by status" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Projects</SelectItem>
                            <SelectItem value="active">Active</SelectItem>
                            <SelectItem value="on-hold">On Hold</SelectItem>
                            <SelectItem value="completed">Completed</SelectItem>
                            <SelectItem value="cancelled">Cancelled</SelectItem>
                            <SelectItem value="archived">Archived</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* ── Stats ── */}
            <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
                {[
                    { label: 'Total Projects', value: projects.length, color: 'from-violet-500 to-purple-600', icon: FolderKanban },
                    { label: 'Active', value: projects.filter(p => !p.status || p.status === 'active').length, color: 'from-blue-500 to-indigo-600', icon: Clock },
                    { label: 'Completed', value: projects.filter(p => p.status === 'completed').length, color: 'from-emerald-500 to-teal-600', icon: CheckCircle2 },
                    { label: 'Archived', value: projects.filter(p => p.status === 'archived').length, color: 'from-slate-500 to-slate-600', icon: Trash2 },
                    { label: 'Total Tasks', value: projects.reduce((a, p) => a + (p.tasks?.length || 0), 0), color: 'from-amber-500 to-orange-600', icon: ClipboardList },
                ].map(s => (
                    <Card key={s.label} className="border-0 shadow-md rounded-2xl overflow-hidden">
                        <CardContent className="p-4 flex items-center gap-3">
                            <div className={`bg-gradient-to-br ${s.color} h-10 w-10 rounded-xl flex items-center justify-center flex-shrink-0 shadow-md`}>
                                <s.icon className="h-5 w-5 text-white" />
                            </div>
                            <div>
                                <p className="text-2xl font-bold text-slate-900 dark:text-white">{s.value}</p>
                                <p className="text-xs text-slate-500 dark:text-slate-400">{s.label}</p>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            {/* ── Projects Grid ── */}
            {isLoading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-violet-500" />
                </div>
            ) : filteredProjects.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <FolderKanban className="h-14 w-14 mb-3 opacity-20" />
                    <p className="text-sm font-medium">No projects found</p>
                    {canManageProjects && (
                        <Button variant="outline" className="mt-4 gap-1" onClick={() => { resetForm(); setIsCreateDialogOpen(true); }}>
                            <Plus className="h-4 w-4" /> Create your first project
                        </Button>
                    )}
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-4">
                    {filteredProjects.map(project => (
                        <ProjectCard
                            key={project.project_id}
                            project={project}
                            canManageProjects={canManageProjects}
                            isDeleting={isDeleting}
                            onEdit={() => {
                                setSelectedProject(project);
                                setFormData({
                                    name: project.name,
                                    description: project.description || '',
                                    start_date: project.start_date?.split('T')[0] || '',
                                    end_date: project.end_date?.split('T')[0] || '',
                                    status: project.status || 'active',
                                });
                                setIsEditDialogOpen(true);
                            }}
                            onDelete={() => handleDelete(project.project_id)}
                            onManageMembers={() => { setSelectedProject(project); setIsMemberDialogOpen(true); }}
                            onAssignTasks={() => { setSelectedProject(project); setTaskList([emptyTask()]); setIsTaskDialogOpen(true); }}
                            onTaskStatusChange={handleTaskStatusChange}
                        />
                    ))}
                </div>
            )}

            {/* ══════════════════════════════════════
          CREATE PROJECT DIALOG
         ══════════════════════════════════════ */}
            <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
                <DialogContent className="max-w-3xl max-h-[92vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2 text-lg">
                            <FolderKanban className="h-5 w-5 text-violet-500" />
                            Create New Project
                        </DialogTitle>
                        <DialogDescription>Set up project details, build your team, and assign tasks all in one step.</DialogDescription>
                    </DialogHeader>

                    <div className="space-y-5 py-2">
                        {/* ── Project Details ── */}
                        <div className="space-y-4">
                            <div className="flex items-center gap-2 text-sm font-semibold text-slate-700 dark:text-slate-300">
                                <span className="flex h-5 w-5 rounded-full bg-violet-100 dark:bg-violet-900/50 text-violet-600 text-xs items-center justify-center font-bold">1</span>
                                Project Details
                            </div>
                            <div className="grid gap-4 pl-7">
                                <div className="space-y-1.5">
                                    <Label htmlFor="cp_name">Project Name *</Label>
                                    <Input id="cp_name" placeholder="e.g., Website Redesign" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                                </div>
                                <div className="space-y-1.5">
                                    <Label>Description</Label>
                                    <Textarea placeholder="Brief overview of the project..." rows={2} value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                                    <div className="space-y-1.5">
                                        <Label>Start Date</Label>
                                        <Input type="date" value={formData.start_date} onChange={e => setFormData({ ...formData, start_date: e.target.value })} />
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label>End Date</Label>
                                        <Input type="date" value={formData.end_date} onChange={e => setFormData({ ...formData, end_date: e.target.value })} />
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label>Status</Label>
                                        <Select value={formData.status} onValueChange={v => setFormData({ ...formData, status: v })}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="active">Active</SelectItem>
                                                <SelectItem value="on-hold">On Hold</SelectItem>
                                                <SelectItem value="completed">Completed</SelectItem>
                                                <SelectItem value="cancelled">Cancelled</SelectItem>
                                                <SelectItem value="archived">Archived</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* ── Team Members ── */}
                        <div className="space-y-3 border-t pt-4">
                            <div className="flex items-center gap-2 text-sm font-semibold text-slate-700 dark:text-slate-300">
                                <span className="flex h-5 w-5 rounded-full bg-blue-100 dark:bg-blue-900/50 text-blue-600 text-xs items-center justify-center font-bold">2</span>
                                Build Your Team
                                {selectedMemberIds.length > 0 && (
                                    <Badge className="ml-1 bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300 border-0 text-xs">
                                        {selectedMemberIds.length} selected
                                    </Badge>
                                )}
                            </div>
                            <div className="pl-7 space-y-2">
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
                                    <Input
                                        placeholder="Search employees..."
                                        className="pl-8 h-9 text-sm"
                                        value={memberSearch}
                                        onChange={e => setMemberSearch(e.target.value)}
                                    />
                                </div>
                                <div className="max-h-44 overflow-y-auto border border-slate-200 dark:border-slate-700 rounded-xl divide-y divide-slate-100 dark:divide-slate-800">
                                    {filteredMemberOptions.length === 0 ? (
                                        <p className="text-xs text-center text-slate-400 py-4">No employees found</p>
                                    ) : filteredMemberOptions.map(emp => (
                                        <label
                                            key={emp.user_id}
                                            className="flex items-center gap-3 px-3 py-2.5 hover:bg-slate-50 dark:hover:bg-slate-900 cursor-pointer transition-colors"
                                        >
                                            <Checkbox
                                                checked={selectedMemberIds.includes(emp.user_id)}
                                                onCheckedChange={() => toggleMember(emp.user_id)}
                                                className="data-[state=checked]:bg-blue-600 data-[state=checked]:border-blue-600"
                                            />
                                            <div className="h-7 w-7 rounded-full bg-gradient-to-br from-blue-400 to-indigo-500 flex items-center justify-center text-xs font-bold text-white flex-shrink-0">
                                                {emp.name[0]?.toUpperCase()}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <p className="text-sm font-medium text-slate-800 dark:text-slate-200 truncate">{emp.name}</p>
                                                {(emp.role || emp.department) && (
                                                    <p className="text-xs text-slate-400 truncate capitalize">{[emp.role, emp.department].filter(Boolean).join(' · ')}</p>
                                                )}
                                            </div>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {/* ── Tasks ── */}
                        <div className="space-y-3 border-t pt-4">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-sm font-semibold text-slate-700 dark:text-slate-300">
                                    <span className="flex h-5 w-5 rounded-full bg-amber-100 dark:bg-amber-900/50 text-amber-600 text-xs items-center justify-center font-bold">3</span>
                                    Assign Tasks <span className="text-slate-400 font-normal text-xs">(Optional)</span>
                                </div>
                            </div>
                            <div className="pl-7">
                                <TaskFormSection teamOnly />
                            </div>
                        </div>
                    </div>

                    <DialogFooter className="gap-2">
                        <Button variant="outline" onClick={() => setIsCreateDialogOpen(false)}>Cancel</Button>
                        <Button onClick={handleCreate} disabled={isCreating} className="bg-violet-600 hover:bg-violet-700">
                            {isCreating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Create Project
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* ══════════════════════════════════════
          EDIT PROJECT DIALOG
         ══════════════════════════════════════ */}
            <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
                <DialogContent className="max-w-lg">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Edit className="h-5 w-5 text-blue-500" /> Edit Project
                        </DialogTitle>
                        <DialogDescription>Update details for: {selectedProject?.name}</DialogDescription>
                    </DialogHeader>
                    <div className="grid gap-4 py-2">
                        <div className="space-y-1.5">
                            <Label>Project Name *</Label>
                            <Input value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                        </div>
                        <div className="space-y-1.5">
                            <Label>Description</Label>
                            <Textarea rows={3} value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                            <div className="space-y-1.5">
                                <Label>Start Date</Label>
                                <Input type="date" value={formData.start_date} onChange={e => setFormData({ ...formData, start_date: e.target.value })} />
                            </div>
                            <div className="space-y-1.5">
                                <Label>End Date</Label>
                                <Input type="date" value={formData.end_date} onChange={e => setFormData({ ...formData, end_date: e.target.value })} />
                            </div>
                        </div>
                        <div className="space-y-1.5">
                            <Label>Status</Label>
                            <Select value={formData.status} onValueChange={v => setFormData({ ...formData, status: v })}>
                                <SelectTrigger><SelectValue /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="active">Active</SelectItem>
                                    <SelectItem value="on-hold">On Hold</SelectItem>
                                    <SelectItem value="completed">Completed</SelectItem>
                                    <SelectItem value="cancelled">Cancelled</SelectItem>
                                    <SelectItem value="archived">Archived</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsEditDialogOpen(false)}>Cancel</Button>
                        <Button onClick={handleUpdate} disabled={isUpdating}>
                            {isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Update Project
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* ══════════════════════════════════════
          MANAGE MEMBERS DIALOG
         ══════════════════════════════════════ */}
            <Dialog open={isMemberDialogOpen} onOpenChange={setIsMemberDialogOpen}>
                <DialogContent className="max-w-md">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Users className="h-5 w-5 text-blue-500" /> Manage Team Members
                        </DialogTitle>
                        <DialogDescription>Add or remove members from: {selectedProject?.name}</DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4">
                        <div className="flex gap-2">
                            <Select value={addMemberId} onValueChange={setAddMemberId}>
                                <SelectTrigger className="flex-1">
                                    <SelectValue placeholder="Select employee to add..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {assignableEmployees
                                        .filter(e => !selectedProject?.members?.some(m => m.user_id === e.user_id))
                                        .map(e => (
                                            <SelectItem key={e.user_id} value={String(e.user_id)}>
                                                {e.name} {e.role ? `· ${e.role}` : ''}
                                            </SelectItem>
                                        ))}
                                </SelectContent>
                            </Select>
                            <Button onClick={handleAddMember} className="gap-1 bg-blue-600 hover:bg-blue-700 flex-shrink-0">
                                <UserPlus className="h-4 w-4" /> Add
                            </Button>
                        </div>
                        <div>
                            <p className="text-xs text-muted-foreground uppercase font-semibold tracking-wider mb-2">
                                Current Members ({selectedProject?.members?.length || 0})
                            </p>
                            {!selectedProject?.members?.length
                                ? <p className="text-sm text-slate-400 text-center py-4">No members yet.</p>
                                : (
                                    <div className="space-y-2 max-h-56 overflow-y-auto">
                                        {selectedProject.members.map(m => (
                                            <div key={m.user_id} className="flex items-center justify-between bg-slate-50 dark:bg-slate-900 px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700">
                                                <div className="flex items-center gap-2.5">
                                                    <div className="h-8 w-8 rounded-full bg-gradient-to-br from-blue-400 to-indigo-500 flex items-center justify-center text-xs font-bold text-white">
                                                        {m.name[0]?.toUpperCase()}
                                                    </div>
                                                    <div>
                                                        <p className="text-sm font-medium">{m.name}</p>
                                                        {m.role && <p className="text-xs text-slate-400 capitalize">{m.role}</p>}
                                                    </div>
                                                </div>
                                                <Button variant="ghost" size="icon" className="h-7 w-7 hover:bg-red-50 hover:text-red-600" onClick={() => handleRemoveMember(m.user_id)}>
                                                    <UserMinus className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        ))}
                                    </div>
                                )}
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsMemberDialogOpen(false)}>Done</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* ══════════════════════════════════════
          ASSIGN TASKS DIALOG
         ══════════════════════════════════════ */}
            <Dialog open={isTaskDialogOpen} onOpenChange={setIsTaskDialogOpen}>
                <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <ClipboardList className="h-5 w-5 text-amber-500" /> Assign Tasks
                        </DialogTitle>
                        <DialogDescription>
                            Assign tasks to team members of: {selectedProject?.name}
                        </DialogDescription>
                    </DialogHeader>

                    {/* Show current members for context */}
                    {selectedProject?.members && selectedProject.members.length > 0 && (
                        <div className="flex flex-wrap gap-1.5 pb-3 border-b">
                            <span className="text-xs text-slate-400 self-center">Team:</span>
                            {selectedProject.members.map(m => (
                                <Badge key={m.user_id} variant="secondary" className="text-xs">{m.name}</Badge>
                            ))}
                        </div>
                    )}

                    <TaskFormSection teamOnly={false} />

                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsTaskDialogOpen(false)}>Cancel</Button>
                        <Button onClick={handleAssignTasks} disabled={isUpdating} className="bg-amber-600 hover:bg-amber-700">
                            {isUpdating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Assign Tasks
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  FileText,
  Download,
  TrendingUp,
  TrendingDown,
  Users,
  Clock,
  Target,
  Award,
  Calendar,
  BarChart3,
  PieChart,
  Activity,
  Filter,
  FileSpreadsheet,
  Star,
  Edit,
  Check,
  ChevronsUpDown,
  Loader2,
  Calendar as CalendarIcon
} from 'lucide-react';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { apiService, API_BASE_URL } from '@/lib/api';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from '@/components/ui/command';
import { cn } from '@/lib/utils';
import { useLanguage } from '@/contexts/LanguageContext';
import { useAuth } from '@/contexts/AuthContext';
import { nowIST, formatIST } from '@/utils/timezone';
import { toast } from '@/hooks/use-toast';
import RatingDialog, { EmployeeRating } from '@/components/rating/RatingDialog';
import ExportDialog from '@/components/reports/ExportDialog';
import V2Overlay from '@/components/ui/V2Overlay';

interface EmployeePerformance {
  id: string;
  employeeId: string;
  name: string;
  department: string;
  role: string;
  attendanceScore: number;
  taskCompletionRate: number;
  productivity: number;
  qualityScore: number;
  overallRating: number;
  month: string;
  completedTasks?: number;
  totalTasks?: number;
  attendanceDays?: number;
  workingDays?: number;
  taskEfficiency?: number;
}

interface DepartmentMetrics {
  department: string;
  totalEmployees: number;
  avgProductivity: number;
  avgAttendance: number;
  tasksCompleted: number;
  tasksPending: number;
  performanceScore: number;
}

const CORE_DEPARTMENTS = [
  'Engineering',
  'Product',
  'Design',
  'Marketing',
  'Sales',
  'HR',
  'Human Resources',
  'Finance',
  'Operations',
  'Legal',
  'Customer Support',
  'IT',
  'Administration',
  'Management'
];

export default function Reports() {
  const { t } = useLanguage();
  const { user } = useAuth();
  const currentDate = nowIST();
  const [selectedMonth, setSelectedMonth] = useState(currentDate.getMonth().toString());
  const [selectedYear, setSelectedYear] = useState(currentDate.getFullYear().toString());
  const [selectedDepartment, setSelectedDepartment] = useState('all');
  const [yearOpen, setYearOpen] = useState(false);

  // Check URL for tab parameter
  const urlParams = new URLSearchParams(window.location.search);
  const tabParam = urlParams.get('tab');
  const [selectedReportType, setSelectedReportType] = useState(tabParam || 'performance');
  const [ratingDialogOpen, setRatingDialogOpen] = useState(false);
  const [selectedEmployee, setSelectedEmployee] = useState<EmployeePerformance | null>(null);
  const [employeeRatings, setEmployeeRatings] = useState<Record<string, EmployeeRating>>({});
  const [expandedDepartments, setExpandedDepartments] = useState<Set<string>>(new Set());
  const [exportDialogOpen, setExportDialogOpen] = useState(false);
  const [exportEmployee, setExportEmployee] = useState<{ id: string; name: string } | null>(null);

  // State for API data
  const [employeePerformance, setEmployeePerformance] = useState<EmployeePerformance[]>([]);
  const [departmentMetrics, setDepartmentMetrics] = useState<DepartmentMetrics[]>([]);
  const [executiveSummary, setExecutiveSummary] = useState<any>(null);
  const [departments, setDepartments] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Leave report states
  const [leaveStartDate, setLeaveStartDate] = useState(formatIST(new Date(parseInt(selectedYear), parseInt(selectedMonth), 1), 'yyyy-MM-dd'));
  const [leaveEndDate, setLeaveEndDate] = useState(formatIST(new Date(parseInt(selectedYear), parseInt(selectedMonth) + 1, 0), 'yyyy-MM-dd'));
  const [leaveDepartment, setLeaveDepartment] = useState('all');
  const [leaveFormat, setLeaveFormat] = useState<'pdf' | 'csv'>('pdf');

  // Load ratings from localStorage on mount
  useEffect(() => {
    const savedRatings = localStorage.getItem('employeeRatings');
    if (savedRatings) {
      setEmployeeRatings(JSON.parse(savedRatings));
    }
  }, []);

  // Save ratings to localStorage whenever they change
  useEffect(() => {
    if (Object.keys(employeeRatings).length > 0) {
      localStorage.setItem('employeeRatings', JSON.stringify(employeeRatings));
    }
  }, [employeeRatings]);

  // Load departments list once on mount
  useEffect(() => {
    loadDepartments();
  }, []);

  // Load report data when filters change
  useEffect(() => {
    loadReportData();
  }, [selectedMonth, selectedYear, selectedDepartment]);

  const loadDepartments = async () => {
    try {
      const data = await apiService.getReportDepartments();
      if (data && data.departments) {
        // Unique and sorted departments
        const deptList = Array.from(new Set(data.departments))
          .filter(Boolean)
          .sort() as string[];
        setDepartments(deptList);
      }
    } catch (error) {
      console.error('Failed to load departments list:', error);
    }
  };

  const loadReportData = async () => {
    setIsLoading(true);
    try {
      const month = parseInt(selectedMonth) + 1; // Convert to 1-indexed for API
      const year = parseInt(selectedYear);
      const departmentParam = selectedDepartment !== 'all' ? selectedDepartment : undefined;

      // Fetch all data in parallel using apiService
      const [empData, deptData, summaryData] = await Promise.all([
        apiService.getEmployeePerformance({
          month,
          year,
          department: departmentParam
        }),
        apiService.getDepartmentMetrics({ month, year }),
        apiService.getExecutiveSummary({ month, year }),
      ]);

      // Handle employee performance
      if (empData && empData.employees) {
        const rawEmployees = empData.employees || [];

        // Map raw API data to EmployeePerformance interface with robust fallbacks
        const employees = rawEmployees.map((emp: any): EmployeePerformance => ({
          id: emp.id || emp.user_id || emp.employeeId || '',
          employeeId: emp.employeeId || emp.employee_id || emp.id || '',
          name: emp.name || 'Unknown',
          department: emp.department || emp.department_name || 'No Department',
          role: emp.role || 'Staff',
          attendanceScore: Math.round(emp.attendanceScore || emp.attendance_score || 0),
          taskCompletionRate: Math.round(emp.taskCompletionRate || emp.task_completion_rate || emp.taskCompletionScore || emp.task_completion_score || 0),
          productivity: emp.productivity || emp.productivity_score || 0,
          qualityScore: emp.qualityScore || emp.quality_score || 0,
          overallRating: emp.overallRating || emp.overall_rating || 0,
          month: emp.month || selectedMonth,
          completedTasks: emp.completedTasks || emp.completed_tasks || 0,
          totalTasks: emp.totalTasks || emp.total_tasks || 0,
          attendanceDays: emp.attendanceDays || emp.attendance_days || 0,
          workingDays: emp.workingDays || emp.working_days || 0,
          taskEfficiency: emp.taskEfficiency || emp.task_efficiency || 0
        }));

        setEmployeePerformance(employees);
      } else {
        setEmployeePerformance([]);
      }

      // Handle department metrics
      if (deptData && deptData.departments) {
        setDepartmentMetrics(deptData.departments);

        // Update departments list if it's still empty or to ensure we have any new ones from metrics
        if (departments.length === 0) {
          const metricsDepts = deptData.departments.map((d: any) => d.department).filter(Boolean);
          const employeeDepts = empData?.employees?.map((e: any) => e.department || e.department_name).filter(Boolean) || [];

          const allDepts = Array.from(new Set([...metricsDepts, ...employeeDepts]))
            .filter(dept => dept && !dept.includes(','))
            .sort() as string[];

          setDepartments(allDepts);
        }
      } else {
        setDepartmentMetrics([]);
      }

      // Handle executive summary
      if (summaryData) {
        setExecutiveSummary(summaryData);
      } else {
        setExecutiveSummary(null);
      }
    } catch (error) {
      console.error('Failed to load report data:', error);
      setEmployeePerformance([]);
      setDepartmentMetrics([]);
      setExecutiveSummary(null);
      toast({
        title: 'Error',
        description: 'Failed to load report data. Please check if backend is running.',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleSaveRating = (rating: EmployeeRating) => {
    setEmployeeRatings(prev => ({
      ...prev,
      [rating.employeeId]: rating
    }));
  };

  const openRatingDialog = (employee: EmployeePerformance) => {
    setSelectedEmployee(employee);
    setRatingDialogOpen(true);
  };

  const getEmployeeRating = (employeeId: string) => {
    return employeeRatings[employeeId];
  };

  const calculateProductivity = (employeeId: string) => {
    const rating = getEmployeeRating(employeeId);
    if (!rating) return 0;
    return (rating.productivityRating / 5) * 100;
  };

  const calculateQualityScore = (employeeId: string) => {
    const rating = getEmployeeRating(employeeId);
    if (!rating) return 0;
    return (rating.qualityRating / 5) * 100;
  };

  const calculateOverallRating = (employee: EmployeePerformance) => {
    const productivity = calculateProductivity(employee.employeeId);
    const qualityScore = calculateQualityScore(employee.employeeId);

    // If no manual ratings exist, return 0
    if (productivity === 0 || qualityScore === 0) return 0;

    // Calculate average of all 4 metrics
    return Math.round(
      (employee.attendanceScore + employee.taskCompletionRate + productivity + qualityScore) / 4
    );
  };

  // Calculate overall score for Elite Performers (uses available metrics)
  const calculateEliteScore = (employee: EmployeePerformance) => {
    const productivity = calculateProductivity(employee.employeeId);
    const qualityScore = calculateQualityScore(employee.employeeId);

    // Always use attendance and task completion as base metrics
    const baseScore = (employee.attendanceScore || 0) + (employee.taskCompletionRate || 0);

    // If manual ratings exist, include them in the calculation
    if (productivity > 0 && qualityScore > 0) {
      return Math.round(
        (baseScore + productivity + qualityScore) / 4
      );
    }

    // Otherwise, use attendance and task completion only (weighted average)
    return Math.round(baseScore / 2);
  };

  // Calculate top 5 performers with enriched data
  const topPerformers = React.useMemo(() => {
    if (!employeePerformance || employeePerformance.length === 0) {
      // Fallback to executive summary top performers if general performance is empty
      const apiPerformers = executiveSummary?.topPerformers;
      if (apiPerformers && Array.isArray(apiPerformers)) {
        return apiPerformers
          .map((p: any) => ({
            employeeId: p.employeeId || p.id || '',
            name: p.name || '',
            department: p.department || '',
            role: p.role || '',
            taskCompletionScore: Math.round(p.taskCompletionScore || p.taskCompletionRate || 0),
            attendanceScore: Math.round(p.attendanceScore || 0),
            completedTasks: p.completedTasks || 0,
            taskEfficiency: p.taskEfficiency || Math.round(p.taskCompletionScore || p.taskCompletionRate || 0),
            score: Math.round(p.score || p.overallRating || 0),
          }))
          .filter(p => p.name && p.score > 0)
          .sort((a, b) => b.score - a.score)
          .slice(0, 5);
      }
      return [];
    }

    // Merge detailed performance (including local ratings) with executive summary data
    const enrichedPerformers = employeePerformance
      .map(emp => {
        // Find matching summary data for this employee to get task counts
        const summaryData = executiveSummary?.topPerformers?.find(
          (p: any) => (p.employeeId || p.id) === emp.employeeId
        );

        const productivity = calculateProductivity(emp.employeeId);
        const qualityScore = calculateQualityScore(emp.employeeId);
        const score = calculateEliteScore(emp);

        return {
          employeeId: emp.employeeId,
          name: emp.name,
          department: emp.department,
          role: emp.role,
          taskCompletionScore: Math.round(emp.taskCompletionRate || 0),
          attendanceScore: Math.round(emp.attendanceScore || 0),
          completedTasks: summaryData?.completedTasks || emp.completedTasks || 0,
          taskEfficiency: summaryData?.taskEfficiency || emp.taskEfficiency || Math.round(emp.taskCompletionRate || 0),
          score: score,
          productivity,
          qualityScore,
        };
      })
      .filter(p => p.name && p.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);

    return enrichedPerformers;
  }, [employeePerformance, employeeRatings, executiveSummary]);

  const filteredPerformance = employeePerformance;

  // Group employees by department - Filtering for Core Departments if applicable
  const employeesByDepartment = React.useMemo(() => {
    const grouped: Record<string, EmployeePerformance[]> = {};

    // Check if we have any active Core Departments detected
    const hasCoreDepts = departments.length > 0 && departments.every(d =>
      CORE_DEPARTMENTS.some(core => core.toLowerCase() === d.toLowerCase())
    );

    filteredPerformance.forEach(emp => {
      const dept = emp.department || 'No Department';

      // If we are enforcing Core Departments, skip employees not in those departments
      if (hasCoreDepts) {
        const isCore = CORE_DEPARTMENTS.some(core => core.toLowerCase() === dept.toLowerCase());
        if (!isCore) return;
      }

      if (!grouped[dept]) {
        grouped[dept] = [];
      }

      // Merge with executive summary data to ensure we have the latest task metrics
      // This matches the logic used in topPerformers to get accurate task counts
      const summaryData = executiveSummary?.topPerformers?.find(
        (p: any) => (p.employeeId || p.id) === emp.employeeId
      );

      const enrichedEmp = {
        ...emp,
        completedTasks: summaryData?.completedTasks || emp.completedTasks || 0,
        taskEfficiency: summaryData?.taskEfficiency || emp.taskEfficiency || Math.round(emp.taskCompletionRate || 0)
      };

      grouped[dept].push(enrichedEmp);
    });
    return grouped;
  }, [filteredPerformance, departments]);

  const toggleDepartment = (department: string) => {
    setExpandedDepartments(prev => {
      const newSet = new Set(prev);
      if (newSet.has(department)) {
        newSet.delete(department);
      } else {
        newSet.add(department);
      }
      return newSet;
    });
  };

  const expandAllDepartments = () => {
    setExpandedDepartments(new Set(Object.keys(employeesByDepartment)));
  };

  const collapseAllDepartments = () => {
    setExpandedDepartments(new Set());
  };

  const getPerformanceColor = (score: number) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-blue-600';
    if (score >= 40) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getPerformanceBadge = (score: number) => {
    if (score >= 80) return { variant: 'default' as const, text: 'Excellent' };
    if (score >= 60) return { variant: 'secondary' as const, text: 'Good' };
    if (score >= 40) return { variant: 'outline' as const, text: 'Average' };
    return { variant: 'destructive' as const, text: 'Poor' };
  };

  const openExportDialog = (employee?: { id: string; name: string }) => {
    setExportEmployee(employee || null);
    setExportDialogOpen(true);
  };

  const handleQuickExport = async (format: 'csv' | 'pdf' = 'csv') => {
    try {
      // Generate full report with current filters
      // Generate full report with current filters
      const startDate = new Date(parseInt(selectedYear), parseInt(selectedMonth), 1);
      const endDate = new Date(parseInt(selectedYear), parseInt(selectedMonth) + 1, 0);

      const params = new URLSearchParams({
        format: format,
        start_date: `${selectedYear}-${String(parseInt(selectedMonth) + 1).padStart(2, '0')}-01`,
        end_date: `${selectedYear}-${String(parseInt(selectedMonth) + 1).padStart(2, '0')}-${String(endDate.getDate()).padStart(2, '0')}`,
      });

      if (selectedDepartment !== 'all') {
        // If department filter is applied, we need to get all employees from that department
        // The backend will filter by employee_id, so we'll let it handle all employees
      }

      const token = localStorage.getItem('token');
      const headers = {
        'Authorization': token ? (token.startsWith('Bearer ') ? token : `Bearer ${token}`) : '',
      };
      const response = await fetch(`${API_BASE_URL}/reports/export?${params}`, { headers });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        console.error('Export failed:', response.status, errorText);
        throw new Error(`Export failed: ${response.status}`);
      }

      // Download the file
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;

      const monthName = formatIST(new Date(parseInt(selectedYear), parseInt(selectedMonth)), 'MMMM');
      const filename = `performance_report_${monthName}_${selectedYear}.${format}`;

      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);

      toast({
        title: 'Success',
        description: `Full report generated successfully as ${format.toUpperCase()}`,
      });
    } catch (error) {
      console.error('Export error:', error);
      toast({
        title: 'Error',
        description: 'Failed to generate report. Please try again.',
        variant: 'destructive',
      });
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50 dark:from-slate-900 dark:via-slate-800 dark:to-slate-900 relative">
      {!['admin', 'hr', 'manager', 'team_lead', 'employee'].includes(user?.role || '') && <V2Overlay fallbackPath="/dashboard" />}
      <div className="w-full space-y-6 pb-20">
        {/* Header Section - aligned with other modern pages */}
        <div className="relative overflow-hidden flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 p-6 sm:p-8 rounded-3xl bg-white dark:bg-slate-900 border border-slate-200/70 dark:border-slate-800 shadow-sm mt-1">
          <div className="absolute top-0 right-0 -mr-16 -mt-16 h-40 w-40 bg-blue-500/5 rounded-full blur-3xl" />
          <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-40 w-40 bg-indigo-500/5 rounded-full blur-3xl" />

          <div className="relative flex items-center gap-4">
            <div className="h-14 w-14 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-200/60 dark:shadow-none">
              <FileText className="h-7 w-7 text-white" />
            </div>
            <div>
              <h1 className="text-2xl sm:text-3xl font-extrabold tracking-tight text-slate-900 dark:text-white">
                Performance Reports
              </h1>
              <p className="text-sm sm:text-base text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
                <Calendar className="h-4 w-4 text-blue-500" />
                <span>{formatIST(currentDate, 'EEEE, dd MMM yyyy')}</span>
              </p>
            </div>
          </div>

          <div className="relative flex flex-wrap items-center gap-2 sm:gap-3">
            <Select value={selectedMonth} onValueChange={setSelectedMonth}>
              <SelectTrigger className="w-[140px] h-10 text-sm bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700">
                <Calendar className="h-4 w-4 mr-1.5 text-slate-400" />
                <SelectValue placeholder="Month" />
              </SelectTrigger>
              <SelectContent>
                {["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"].map((month, i) => (
                  <SelectItem key={i} value={i.toString()} className="text-sm">{month}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Popover open={yearOpen} onOpenChange={setYearOpen}>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  role="combobox"
                  aria-expanded={yearOpen}
                  className="w-[120px] justify-between h-10 text-sm bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700"
                >
                  {selectedYear}
                  <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-[120px] p-0">
                <Command>
                  <CommandInput placeholder="Search..." className="h-9" />
                  <CommandList>
                    <CommandEmpty>No year found.</CommandEmpty>
                    <CommandGroup>
                      {/* Fixed height for scrollable dropdown */}
                      <div className="max-h-[200px] overflow-y-auto custom-scrollbar">
                        {Array.from({ length: 2040 - 2016 + 1 }, (_, i) => (2040 - i).toString()).map((year) => (
                          <CommandItem
                            key={year}
                            value={year}
                            onSelect={(currentValue) => {
                              setSelectedYear(currentValue);
                              setYearOpen(false);
                            }}
                          >
                            <Check
                              className={cn(
                                "mr-2 h-4 w-4",
                                selectedYear === year ? "opacity-100" : "opacity-0"
                              )}
                            />
                            {year}
                          </CommandItem>
                        ))}
                      </div>
                    </CommandGroup>
                  </CommandList>
                </Command>
              </PopoverContent>
            </Popover>

            <Select value={selectedDepartment} onValueChange={setSelectedDepartment}>
              <SelectTrigger className="w-[160px] h-10 text-sm bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-left">
                <Filter className="h-4 w-4 mr-1.5 text-slate-400" />
                <SelectValue placeholder="Department" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all" className="text-sm">All Departments</SelectItem>
                {departments.map(dept => (
                  <SelectItem key={dept} value={dept} className="text-sm">{dept}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>


        {/* Tabs Navigation */}
        <Tabs value={selectedReportType} onValueChange={setSelectedReportType} className="space-y-4">
          <TabsList className="flex items-center gap-1 bg-slate-100/50 dark:bg-slate-800/50 p-1 rounded-lg w-fit border border-slate-200/50 dark:border-slate-700/50">
            <TabsTrigger
              value="performance"
              className="h-9 text-sm font-medium px-4 rounded-md data-[state=active]:bg-white dark:data-[state=active]:bg-slate-700 data-[state=active]:text-blue-600 dark:data-[state=active]:text-blue-400 data-[state=active]:shadow-sm transition-all"
            >
              <Users className="h-4 w-4 mr-1.5" />
              Employee Performance
            </TabsTrigger>
            <TabsTrigger
              value="department"
              className="h-9 text-sm font-medium px-4 rounded-md data-[state=active]:bg-white dark:data-[state=active]:bg-slate-700 data-[state=active]:text-purple-600 dark:data-[state=active]:text-purple-400 data-[state=active]:shadow-sm transition-all"
            >
              <PieChart className="h-4 w-4 mr-1.5" />
              Department Metrics
            </TabsTrigger>
            <TabsTrigger
              value="summary"
              className="h-9 text-sm font-medium px-4 rounded-md data-[state=active]:bg-white dark:data-[state=active]:bg-slate-700 data-[state=active]:text-emerald-600 dark:data-[state=active]:text-emerald-400 data-[state=active]:shadow-sm transition-all"
            >
              <BarChart3 className="h-4 w-4 mr-1.5" />
              Executive Summary
            </TabsTrigger>
            <TabsTrigger
              value="leave"
              className="h-9 text-sm font-medium px-4 rounded-md data-[state=active]:bg-white dark:data-[state=active]:bg-slate-700 data-[state=active]:text-orange-600 dark:data-[state=active]:text-orange-400 data-[state=active]:shadow-sm transition-all"
            >
              <CalendarIcon className="h-4 w-4 mr-1.5" />
              Leave Reports
            </TabsTrigger>
          </TabsList>

          <TabsContent value="performance" className="mt-0 outline-none">
            <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
                <div>
                  <h2 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white">Individual Performance</h2>
                  <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">Comprehensive behavior and task analysis per team member</p>
                </div>
                <Button
                  onClick={() => openExportDialog()}
                  variant="outline"
                  size="sm"
                  className="h-8 text-xs font-medium gap-1.5"
                >
                  <Download className="h-3.5 w-3.5" />
                  Export
                </Button>
              </div>

              <div className="p-4 sm:p-6 pb-10">
                {isLoading ? (
                  <div className="text-center py-12">
                    <div className="animate-spin rounded-full h-12 w-12 border-4 border-blue-500 border-t-transparent mx-auto"></div>
                    <p className="mt-4 text-muted-foreground">Loading employee performance data...</p>
                  </div>
                ) : filteredPerformance.length === 0 ? (
                  <div className="text-center py-12">
                    <div className="mx-auto w-16 h-16 bg-slate-100 dark:bg-slate-700 rounded-full flex items-center justify-center mb-4">
                      <Users className="h-8 w-8 text-slate-400" />
                    </div>
                    <p className="text-lg font-medium text-slate-700 dark:text-slate-300">No employee data available</p>
                    <p className="text-sm text-muted-foreground mt-2">Try selecting a different month, year range, or department.</p>
                  </div>
                ) : (
                  <div className="space-y-6">
                    {/* Expand/Collapse All Buttons */}
                    <div className="flex justify-end gap-1.5 mb-4">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={expandAllDepartments}
                        className="h-7 text-xs font-medium uppercase tracking-wider text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white"
                      >
                        Expand All
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={collapseAllDepartments}
                        className="h-7 text-xs font-medium uppercase tracking-wider text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white"
                      >
                        Collapse All
                      </Button>
                    </div>

                    {/* Department Groups */}
                    <div className="space-y-3">
                      {Object.entries(employeesByDepartment).map(([department, employees]) => {
                        const isExpanded = expandedDepartments.has(department);
                        const deptAvgScore = Math.round(
                          employees.reduce((sum, emp) => sum + calculateOverallRating(emp), 0) / employees.length
                        );

                        return (
                          <div key={department} className="border border-slate-100 dark:border-slate-800 rounded-lg overflow-hidden transition-all">
                            {/* Department Header - Clickable */}
                            <button
                              onClick={() => toggleDepartment(department)}
                              className="w-full flex items-center justify-between px-4 py-3 bg-slate-50/50 dark:bg-slate-800/30 hover:bg-slate-100/50 dark:hover:bg-slate-800/50 transition-colors"
                            >
                              <div className="flex items-center gap-3">
                                <div className="p-1.5 bg-blue-50 dark:bg-blue-900/30 rounded-md">
                                  <Users className="h-3.5 w-3.5 text-blue-600 dark:text-blue-400" />
                                </div>
                                <div className="text-left">
                                  <h3 className="text-lg font-black tracking-tight text-slate-800 dark:text-white">{department}</h3>
                                  <p className="text-sm font-medium text-slate-500 dark:text-slate-400">
                                    {employees.length} {employees.length === 1 ? 'member' : 'members'} • Performance Avg {deptAvgScore}%
                                  </p>
                                </div>
                              </div>
                              <div className="flex items-center gap-2">
                                <Badge className={`h-6 text-xs uppercase font-bold tracking-tighter ${getPerformanceBadge(deptAvgScore).variant === 'default' ? 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20' : getPerformanceBadge(deptAvgScore).variant === 'secondary' ? 'bg-amber-500/10 text-amber-600 border-amber-500/20' : 'bg-red-500/10 text-red-600 border-red-500/20'} border`}>
                                  {getPerformanceBadge(deptAvgScore).text}
                                </Badge>
                                <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`}>
                                  <svg className="w-3.5 h-3.5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                  </svg>
                                </div>
                              </div>
                            </button>

                            {/* Employee List - Collapsible */}
                            {isExpanded && (
                              <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800 space-y-3">
                                {employees.map((employee) => {
                                  const productivity = calculateProductivity(employee.employeeId);
                                  const qualityScore = calculateQualityScore(employee.employeeId);
                                  const overallRating = calculateOverallRating(employee);
                                  const badge = getPerformanceBadge(overallRating);
                                  const rating = getEmployeeRating(employee.employeeId);
                                  const hasRating = !!rating;

                                  return (
                                    <div
                                      key={employee.id}
                                      className="group bg-white dark:bg-slate-900/50 rounded-lg border border-slate-100 dark:border-slate-800 p-3 sm:p-4 hover:border-blue-200 dark:hover:border-blue-800 transition-all hover:shadow-sm"
                                    >
                                      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
                                        <div className="flex items-center gap-2.5">
                                          <div className="w-9 h-9 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-700 dark:text-slate-300 font-bold text-xs ring-2 ring-white dark:ring-slate-800 shadow-sm">
                                            {employee.name.charAt(0)}
                                          </div>
                                          <div>
                                            <h3 className="font-bold text-xl tracking-tight text-slate-800 dark:text-white leading-tight">{employee.name}</h3>
                                            <p className="text-sm font-medium text-slate-500 dark:text-slate-400 mt-0.5">
                                              ID: {employee.employeeId} • {employee.role}
                                            </p>
                                          </div>
                                        </div>
                                        <div className="flex items-center gap-1.5 self-end sm:self-auto">
                                          <Badge
                                            variant={badge.variant}
                                            className={`h-6 text-xs uppercase font-bold tracking-tighter ${badge.variant === 'default' ? 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20' : badge.variant === 'secondary' ? 'bg-amber-500/10 text-amber-600 border-amber-500/20' : 'bg-red-500/10 text-red-600 border-red-500/20'} border shadow-none`}
                                          >
                                            {badge.text}
                                          </Badge>
                                          <Button
                                            size="sm"
                                            variant="ghost"
                                            onClick={() => openRatingDialog(employee)}
                                            className="h-8 px-3 text-xs font-medium text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20"
                                          >
                                            <Edit className="h-4 w-4 mr-1.5" />
                                            {hasRating ? 'Update' : 'Rate'}
                                          </Button>
                                          <Button
                                            size="sm"
                                            variant="ghost"
                                            onClick={() => openExportDialog({ id: employee.employeeId, name: employee.name })}
                                            className="h-8 px-3 text-xs font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800"
                                          >
                                            <Download className="h-4 w-4 mr-1.5" />
                                            Export
                                          </Button>
                                        </div>
                                      </div>
                                      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-2">
                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Clock className="h-4 w-4 text-blue-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Attendance</p>
                                          </div>
                                          <div className="flex items-baseline gap-1">
                                            <span className={`text-2xl font-black ${getPerformanceColor(employee.attendanceScore)}`}>
                                              {employee.attendanceScore}
                                            </span>
                                            <span className="text-xs text-slate-400 font-medium">%</span>
                                          </div>
                                          <Progress value={employee.attendanceScore} className="h-1 mt-1.5 bg-slate-200 dark:bg-slate-700" />
                                        </div>

                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Target className="h-4 w-4 text-emerald-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Tasks %</p>
                                          </div>
                                          <div className="flex items-baseline gap-1">
                                            <span className={`text-2xl font-black ${getPerformanceColor(employee.taskCompletionRate)}`}>
                                              {employee.taskCompletionRate}
                                            </span>
                                            <span className="text-xs text-slate-400 font-medium">%</span>
                                          </div>
                                          <Progress value={employee.taskCompletionRate} className="h-1 mt-1.5 bg-slate-200 dark:bg-slate-700" />
                                        </div>

                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Check className="h-4 w-4 text-orange-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Tasks</p>
                                          </div>
                                          <div className="flex items-baseline gap-1">
                                            <span className="text-2xl font-black text-slate-700 dark:text-slate-300">
                                              {employee.completedTasks || 0}
                                            </span>
                                            <span className="text-xs text-slate-400 font-medium">/ {employee.totalTasks || 0}</span>
                                          </div>
                                        </div>

                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Calendar className="h-4 w-4 text-indigo-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Days</p>
                                          </div>
                                          <div className="flex items-baseline gap-1">
                                            <span className="text-2xl font-black text-slate-700 dark:text-slate-300">
                                              {employee.attendanceDays || 0}
                                            </span>
                                            <span className="text-xs text-slate-400 font-medium">/ {employee.workingDays || 0}</span>
                                          </div>
                                        </div>

                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Activity className="h-4 w-4 text-purple-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Productivity</p>
                                          </div>
                                          {hasRating ? (
                                            <>
                                              <div className="flex items-baseline gap-1">
                                                <span className={`text-2xl font-black ${getPerformanceColor(productivity)}`}>
                                                  {Math.round(productivity)}
                                                </span>
                                                <span className="text-xs text-slate-400 font-medium">%</span>
                                              </div>
                                              <div className="flex gap-0.5 mt-1">
                                                {[1, 2, 3, 4, 5].map((star) => (
                                                  <Star
                                                    key={star}
                                                    className={`h-2.5 w-2.5 ${star <= rating.productivityRating
                                                      ? 'fill-amber-400 text-amber-400'
                                                      : 'text-slate-200 dark:text-slate-700'
                                                      }`}
                                                  />
                                                ))}
                                              </div>
                                            </>
                                          ) : (
                                            <p className="text-xs text-slate-400 py-1">N/A</p>
                                          )}
                                        </div>

                                        <div className="bg-slate-50/50 dark:bg-slate-800/20 rounded-lg p-2.5 border border-slate-100/50 dark:border-slate-800/50">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <Award className="h-4 w-4 text-pink-500" />
                                            <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Quality</p>
                                          </div>
                                          {hasRating ? (
                                            <>
                                              <div className="flex items-baseline gap-1">
                                                <span className={`text-2xl font-black ${getPerformanceColor(qualityScore)}`}>
                                                  {Math.round(qualityScore)}
                                                </span>
                                                <span className="text-xs text-slate-400 font-medium">%</span>
                                              </div>
                                              <div className="flex gap-0.5 mt-1">
                                                {[1, 2, 3, 4, 5].map((star) => (
                                                  <Star
                                                    key={star}
                                                    className={`h-2.5 w-2.5 ${star <= rating.qualityRating
                                                      ? 'fill-amber-400 text-amber-400'
                                                      : 'text-slate-200 dark:text-slate-700'
                                                      }`}
                                                  />
                                                ))}
                                              </div>
                                            </>
                                          ) : (
                                            <p className="text-xs text-slate-400 py-1">N/A</p>
                                          )}
                                        </div>

                                        <div className="bg-blue-600 rounded-lg p-2.5 shadow-sm col-span-2 md:col-span-4 lg:col-span-1">
                                          <div className="flex items-center gap-1.5 mb-1.5">
                                            <BarChart3 className="h-4 w-4 text-white/80" />
                                            <p className="text-sm font-bold text-white/80 uppercase tracking-widest">Score</p>
                                          </div>
                                          <div className="flex items-baseline gap-1">
                                            <span className="text-3xl font-black text-white">
                                              {overallRating > 0 ? overallRating : '-'}
                                            </span>
                                            <span className="text-xs text-white/70 font-semibold">%</span>
                                          </div>
                                          <Progress value={overallRating} className="h-1 mt-1.5 bg-white/20" />
                                        </div>
                                      </div>
                                      {hasRating && (
                                        <div className="mt-3 pt-3 border-t border-slate-100 dark:border-slate-800 grid grid-cols-1 md:grid-cols-2 gap-3">
                                          <div className="bg-indigo-50/30 dark:bg-indigo-900/10 rounded-xl p-3 border border-indigo-100/50 dark:border-indigo-900/30">
                                            <p className="text-xs font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                                              <Activity className="h-3 w-3" />
                                              Productivity Feedback
                                            </p>
                                            <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed italic whitespace-pre-wrap">{rating.productivityDescription}</p>
                                          </div>
                                          <div className="bg-amber-50/30 dark:bg-amber-900/10 rounded-xl p-3 border border-amber-100/50 dark:border-amber-900/30">
                                            <p className="text-xs font-bold text-amber-600 dark:text-amber-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                                              <Award className="h-3 w-3" />
                                              Quality Assessment
                                            </p>
                                            <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed italic whitespace-pre-wrap">{rating.qualityDescription}</p>
                                          </div>
                                        </div>
                                      )}
                                    </div>
                                  );
                                })}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </TabsContent>

          <TabsContent value="department" className="mt-0 outline-none">
            <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
                <div>
                  <h2 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white">Department Overview</h2>
                  <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">Comparative analytics and cross-department efficiency metrics</p>
                </div>
                <Button
                  onClick={() => openExportDialog()}
                  variant="outline"
                  size="sm"
                  className="h-8 text-xs font-medium gap-1.5"
                >
                  <Download className="h-3.5 w-3.5" />
                  Export
                </Button>
              </div>
              <div className="p-4 pb-10">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {departmentMetrics
                    .filter((dept) => {
                      // Filter for Core Departments (case-insensitive)
                      return CORE_DEPARTMENTS.some(core => core.toLowerCase() === dept.department.toLowerCase());
                    })
                    .map((dept) => {
                      const badge = getPerformanceBadge(dept.performanceScore);
                      return (
                        <div
                          key={dept.department}
                          className="bg-slate-50/50 dark:bg-slate-800/30 rounded-lg border border-slate-100 dark:border-slate-800/50 p-4 hover:border-blue-200 dark:hover:border-blue-800 transition-all"
                        >
                          <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center gap-3">
                              <div className="p-2 bg-purple-50 dark:bg-purple-900/30 rounded-lg">
                                <Users className="h-5 w-5 text-purple-600 dark:text-purple-400" />
                              </div>
                              <h3 className="text-lg font-black tracking-tight text-slate-800 dark:text-white truncate max-w-[150px]">{dept.department}</h3>
                            </div>
                            <Badge variant={badge.variant} className="h-6 text-xs shadow-none uppercase font-bold tracking-tighter">
                              {badge.text}
                            </Badge>
                          </div>

                          <div className="space-y-3">
                            <div className="flex justify-between items-center px-3 py-2.5 bg-white dark:bg-slate-900 rounded-lg border border-slate-100/50 dark:border-slate-800/50 shadow-sm">
                              <span className="text-sm font-bold text-slate-500 flex items-center gap-2">
                                <Users className="h-4 w-4" />
                                Department Members
                              </span>
                              <span className="text-lg font-black text-slate-900 dark:text-white">{dept.totalEmployees}</span>
                            </div>

                            <div className="grid grid-cols-2 gap-2">
                              <div className="p-2.5 bg-purple-50/50 dark:bg-purple-900/10 rounded-md">
                                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-1">Productivity</p>
                                <p className={`text-lg font-black ${getPerformanceColor(dept.avgProductivity)}`}>
                                  {dept.avgProductivity}%
                                </p>
                              </div>
                              <div className="p-2.5 bg-blue-50/50 dark:bg-blue-900/10 rounded-md">
                                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-1">Attendance</p>
                                <p className={`text-lg font-black ${getPerformanceColor(dept.avgAttendance)}`}>
                                  {dept.avgAttendance}%
                                </p>
                              </div>
                            </div>

                            <div className="grid grid-cols-2 gap-2">
                              <div className="p-2.5 bg-emerald-50/50 dark:bg-emerald-900/10 rounded-md">
                                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-1">Completed</p>
                                <p className="text-lg font-black text-emerald-600">{dept.tasksCompleted}</p>
                              </div>
                              <div className="p-2.5 bg-amber-50/50 dark:bg-amber-900/10 rounded-md">
                                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-1">Pending</p>
                                <p className="text-lg font-black text-amber-600">{dept.tasksPending}</p>
                              </div>
                            </div>

                            <div className="pt-2">
                              <div className="flex justify-between items-center mb-1.5">
                                <span className="text-sm font-black text-slate-500 uppercase tracking-widest">Efficiency Score</span>
                                <span className={`text-xl font-black ${getPerformanceColor(dept.performanceScore)}`}>
                                  {dept.performanceScore}%
                                </span>
                              </div>
                              <Progress value={dept.performanceScore} className="h-1 bg-slate-100 dark:bg-slate-800" />
                            </div>
                          </div>
                        </div>
                      );
                    })}
                </div>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="summary" className="mt-0 outline-none">
            {isLoading ? (
              <div className="text-center py-12">
                <div className="animate-spin rounded-full h-8 w-8 border-4 border-emerald-500 border-t-transparent mx-auto"></div>
                <p className="mt-4 text-xs text-slate-500">Loading summary...</p>
              </div>
            ) : (
              <div className="space-y-8 pb-10">
                {/* Quick Stats */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                  <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                    <div className="flex items-center gap-2.5 mb-3">
                      <div className="p-1.5 bg-blue-50 dark:bg-blue-900/30 rounded-md">
