                                                        <Input type="text" className="h-10 bg-white dark:bg-slate-800" {...form.register("otherAllowanceAnnual")} onInput={(e) => e.currentTarget.value = e.currentTarget.value.replace(/[^0-9\s.]/g, '')} />
                                                    </div>
