                                                    </div>
                                                </div>


                                            </CardContent>
                                        </Card>
                                    </TabsContent>
                                </Tabs>


                                {/* Section 3: Live Calculation Breakdown */}
                                <Card className="border-0 shadow-lg bg-green-50/30 dark:bg-green-950/10">
                                    <CardHeader className="bg-white/60 dark:bg-slate-800/60">
