                                                    <h4 className="font-bold text-sm text-slate-900 dark:text-white">Salary Annexure</h4>
                                                    <div className="flex items-center gap-2 mt-1">
                                                        <Badge variant="secondary" className="text-[9px] font-black uppercase tracking-tighter h-4.5 bg-purple-50 text-purple-700 dark:bg-purple-900/40 dark:text-purple-400 border-none px-2">Current CTC Structure</Badge>
                                                        <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-100 dark:border-emerald-800/50">
                                                            <div className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />
                                                            <span className="text-[9px] text-emerald-600 dark:text-emerald-400 font-black uppercase tracking-tighter">Active</span>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-2">
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={handleDownloadAnnexure}
                                                    className="h-11 w-11 rounded-xl hover:bg-purple-600 hover:text-white transition-all transform hover:scale-110 active:scale-95 shadow-sm border-2 border-purple-100 dark:border-purple-900/50"
                                                    title="Download Annexure"
                                                >
                                                    <Download className="h-5 w-5" />
                                                </Button>
                                                {isAdminOrHr && (
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={handleSendAnnexure}
                                                        disabled={isAnnexureSending}
                                                        className={`h-11 w-11 rounded-xl transition-all transform hover:scale-110 active:scale-95 shadow-sm ${isAnnexureSending ? 'bg-slate-100' : 'hover:bg-blue-500 hover:text-white'}`}
                                                        title="Email to Employee"
                                                    >
                                                        {isAnnexureSending ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className={`h-5 w-5 ${!isAnnexureSending && 'text-blue-500 group-hover/item:text-inherit'}`} />}
                                                    </Button>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-8 p-4 rounded-2xl bg-blue-50/50 dark:bg-blue-900/10 border border-blue-100/50 dark:border-blue-800/30">
                                    <div className="flex gap-3">
                                        <AlertCircle className="h-5 w-5 text-blue-500 shrink-0" />
                                        <p className="text-[11px] text-blue-700 dark:text-blue-300 font-medium leading-relaxed">
                                            Foundation documents are issued during the hiring process. If you notice any discrepancies, please reach out to the HR department immediately.
                                        </p>
                                    </div>
                                </div>
                            </div>

                        </div>

                        {/* Increment Journey - Right Side */}
                        <div className="lg:col-span-7 space-y-6">
                            <div className="relative overflow-hidden rounded-3xl bg-white dark:bg-gray-900 border border-slate-200/50 dark:border-slate-800/50 shadow-xl p-6 group h-full flex flex-col">
                                <div className="absolute bottom-0 right-0 -mr-20 -mb-20 h-80 w-80 bg-emerald-500/5 rounded-full blur-3xl group-hover:bg-emerald-500/10 transition-all duration-700" />

                                <div className="relative flex justify-between items-start mb-8">
                                    <div className="flex items-center gap-5">
                                        <div className="h-14 w-14 rounded-2xl bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center shadow-lg shadow-emerald-200 dark:shadow-none transform group-hover:-rotate-6 transition-transform">
                                            <TrendingUp className="h-7 w-7 text-white" />
                                        </div>
                                        <div>
                                            <h3 className="text-xl font-bold text-slate-900 dark:text-white tracking-tight">Growth Journey</h3>
                                            <div className="flex items-center gap-2 mt-0.5">
                                                <div className="h-1.5 w-4 rounded-full bg-emerald-500" />
                                                <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest">Revision & Increment Letters</p>
                                            </div>
                                        </div>
                                    </div>
                                    {increments.length > 0 && (
                                        <div className="flex flex-col items-end">
                                            <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Total Growth</span>
                                            <span className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">
                                                +{increments.reduce((acc, inc) => acc + inc.increment_percentage, 0).toFixed(1)}%
                                            </span>
                                        </div>
                                    )}
                                </div>

                                <div className="relative flex-1 space-y-4 max-h-[500px] overflow-y-auto px-8 pt-10 scrollbar-thin scrollbar-thumb-slate-200 dark:scrollbar-thumb-slate-800 scrollbar-track-transparent">
                                    {sortedIncrements.length > 0 ? (
                                        <div className="space-y-4">
                                            {sortedIncrements
                                                .slice((growthPage - 1) * growthPerPage, growthPage * growthPerPage)
                                                .map((inc, index) => {
                                                    const effectiveDate = new Date(inc.effective_date);
                                                    const createdDate = new Date(inc.created_at);
                                                    const isLatest = index === 0 && growthPage === 1;

                                                    return (
                                                        <div key={inc.id} className={`group/inc relative p-5 rounded-2xl border-2 transition-all duration-300 ${isLatest
                                                            ? 'bg-gradient-to-br from-emerald-50/80 to-teal-50/80 dark:from-emerald-900/20 dark:to-teal-900/20 border-emerald-200 dark:border-emerald-800/50 shadow-md shadow-emerald-500/5 scale-[1.02] z-10'
                                                            : 'bg-white dark:bg-gray-800/30 border-slate-50 dark:border-slate-800 hover:border-emerald-100 hover:bg-slate-50/50 dark:hover:bg-slate-800/50'
                                                            }`}>
                                                            {isLatest && (
                                                                <div className="absolute -top-3 left-6">
                                                                    <Badge className="bg-emerald-600 text-white border-none text-[8px] font-black uppercase tracking-widest px-2 shadow-lg shadow-emerald-600/20">Active Revision</Badge>
                                                                </div>
                                                            )}

                                                            <div className="flex justify-between items-center">
                                                                <div className="flex items-center gap-4">
                                                                    <div className={`h-12 w-12 rounded-xl flex items-center justify-center border-2 transition-all ${isLatest
                                                                        ? 'bg-white dark:bg-slate-950 border-emerald-400/30 shadow-inner group-hover/inc:rotate-12'
                                                                        : 'bg-slate-50 dark:bg-slate-800/80 border-slate-100 dark:border-slate-700'
                                                                        }`}>
                                                                        <FileText className={`h-6 w-6 ${isLatest ? 'text-emerald-600' : 'text-slate-400'}`} />
                                                                    </div>
                                                                    <div>
                                                                        <div className="flex items-center gap-3">
                                                                            <h4 className={`font-bold text-sm ${isLatest ? 'text-slate-900 dark:text-white' : 'text-slate-700 dark:text-slate-300'}`}>
                                                                                Revision: {effectiveDate.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}
                                                                            </h4>
                                                                            <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${isLatest ? 'bg-emerald-600 text-white' : 'bg-emerald-100 text-emerald-700'} transition-all`}>
                                                                                <TrendingUp className="h-3 w-3" />
                                                                                <span className="text-[10px] font-black uppercase tracking-tighter">+{inc.increment_percentage}%</span>
                                                                            </div>
                                                                        </div>
                                                                        <div className="flex items-center gap-2 mt-1.5">
                                                                            <Badge variant="outline" className="text-[8px] border-slate-200 dark:border-slate-700 font-bold uppercase tracking-tighter h-4 px-1">{inc.reason}</Badge>
                                                                            <span className="text-[9px] text-muted-foreground font-medium">• Issued on {createdDate.toLocaleDateString()}</span>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                                <div className="flex gap-2">
                                                                    <Button
                                                                        variant="outline"
                                                                        size="sm"
                                                                        onClick={() => handleDownloadIncrementLetter(inc.id.toString(), inc.effective_date)}
                                                                        className={`h-10 px-4 rounded-xl border-2 transition-all font-bold ${isLatest
                                                                            ? 'bg-white dark:bg-slate-900 border-emerald-200 hover:bg-emerald-600 hover:border-emerald-600 hover:text-white'
                                                                            : 'border-slate-100 dark:border-slate-800 hover:bg-slate-900 dark:hover:bg-slate-100 hover:text-white dark:hover:text-black hover:border-transparent'
                                                                            }`}
                                                                    >
                                                                        <Download className="h-4 w-4 mr-2" />
                                                                        <span className="text-[11px]">Download</span>
                                                                    </Button>
                                                                    {isAdminOrHr && (
                                                                        <Button
                                                                            variant="ghost"
                                                                            size="sm"
                                                                            onClick={() => handleSendIncrementLetter(inc.id.toString())}
                                                                            className={`h-10 w-10 rounded-xl transition-all ${isLatest ? 'hover:bg-emerald-600 hover:text-white' : 'hover:bg-slate-100 dark:hover:bg-slate-800'} text-emerald-600`}
                                                                            title="Email to Employee"
                                                                        >
                                                                            <Send className="h-4 w-4" />
                                                                        </Button>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </div>
                                                    );
                                                })}

                                            {sortedIncrements.length > growthPerPage && (
                                                <div className="mt-6 pt-4 border-t border-slate-100 dark:border-slate-800">
                                                    <Pagination
                                                        currentPage={growthPage}
                                                        totalPages={Math.ceil(sortedIncrements.length / growthPerPage)}
                                                        totalItems={sortedIncrements.length}
                                                        itemsPerPage={growthPerPage}
                                                        onPageChange={setGrowthPage}
                                                        showItemsPerPage={false}
                                                    />
                                                </div>
                                            )}
                                        </div>
                                    ) : (
                                        <div className="flex flex-col items-center justify-center py-20 text-center flex-1">
                                            <div className="relative mb-6">
                                                <div className="absolute inset-0 bg-emerald-500/10 rounded-full blur-2xl animate-pulse" />
                                                <div className="relative h-20 w-20 rounded-3xl bg-slate-50 dark:bg-slate-800/50 flex items-center justify-center border-2 border-slate-100 dark:border-slate-700">
                                                    <History className="h-10 w-10 text-slate-300" />
                                                </div>
                                            </div>
                                            <h4 className="text-lg font-bold text-slate-900 dark:text-white">Growth Journey Awaits</h4>
                                            <div className="mt-2 space-y-1">
                                                <p className="text-xs text-muted-foreground max-w-[280px]">Your professional growth records will be cataloged here sequentially.</p>
                                                <div className="flex items-center justify-center gap-2 mt-4">
                                                    <CheckCircle2 className="h-3 w-3 text-emerald-500" />
                                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">Verified by HR Operations</span>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </TabsContent>


                {isAdminOrHr && (
                    <TabsContent value="history" className="space-y-6 pt-4">
                        <div className="relative overflow-hidden rounded-3xl bg-white dark:bg-gray-900 border border-slate-200/50 dark:border-slate-800/50 shadow-xl overflow-x-hidden">
                            <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 bg-indigo-500/5 rounded-full blur-3xl" />

                            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row items-center justify-between gap-4 relative z-10">
                                <div className="flex items-center gap-4">
                                    <div className="h-12 w-12 rounded-2xl bg-indigo-50 text-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400 flex items-center justify-center shadow-inner">
                                        <History className="h-6 w-6" />
                                    </div>
                                    <div>
                                        <h3 className="text-lg font-black text-slate-800 dark:text-white tracking-tight">Revision Timeline</h3>
                                        <p className="text-[10px] text-indigo-600 font-bold uppercase tracking-widest">Growth Tracking & Historical Data</p>
                                    </div>
                                </div>
                                {canEdit && (
                                    <Button onClick={() => setShowIncrementForm(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl px-6 shadow-lg shadow-indigo-600/20 transition-all hover:scale-105 active:scale-95">
                                        <Plus className="mr-2 h-4 w-4" /> New Increment
                                    </Button>
                                )}
                            </div>

                            <div className="overflow-x-auto">
                                <Table>
                                    <TableHeader className="bg-slate-50/50 dark:bg-slate-800/50">
                                        <TableRow className="border-b border-slate-100 dark:border-slate-800 hover:bg-transparent">
                                            <TableHead className="font-black text-[10px] uppercase tracking-widest pl-8 py-5">Date & Impact</TableHead>
                                            <TableHead className="font-black text-[10px] uppercase tracking-widest py-5">CTC Transformation</TableHead>
                                            <TableHead className="font-black text-[10px] uppercase tracking-widest py-5 text-center">Growth Factor</TableHead>
                                            <TableHead className="font-black text-[10px] uppercase tracking-widest py-5">Reasoning</TableHead>
                                            <TableHead className="text-right font-black text-[10px] uppercase tracking-widest pr-8 py-5">Actions</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {increments.length === 0 ? (
                                            <TableRow>
                                                <TableCell colSpan={5} className="h-48 text-center">
                                                    <div className="flex flex-col items-center justify-center text-muted-foreground italic">
                                                        <History className="h-10 w-10 mb-3 opacity-20" />
                                                        <p className="text-sm font-medium">No previous growth records found in our archives.</p>
                                                    </div>
                                                </TableCell>
                                            </TableRow>
                                        ) : (
                                            increments
                                                .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
                                                .map((inc, idx) => {
                                                    const effectiveDate = new Date(inc.effective_date);
                                                    const createdDate = new Date(inc.created_at);
                                                    const isTop = idx === 0;

                                                    return (
                                                        <TableRow key={inc.id} className="group hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-all border-b border-slate-50 dark:border-slate-800 last:border-0">
                                                            <TableCell className="pl-8 py-5">
                                                                <div className="flex items-center gap-4">
                                                                    <div className={`h-2.5 w-2.5 rounded-full ${isTop ? 'bg-indigo-600 animate-pulse ring-4 ring-indigo-600/10' : 'bg-slate-300 dark:bg-slate-700'}`} />
                                                                    <div>
                                                                        <div className="font-black text-sm text-slate-800 dark:text-white leading-none mb-1.5">{effectiveDate.toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' })}</div>
                                                                        <div className="text-[9px] text-muted-foreground font-black uppercase tracking-tighter">Effective From</div>
                                                                    </div>
                                                                </div>
                                                            </TableCell>
                                                            <TableCell className="py-5">
                                                                <div className="flex flex-col gap-1">
                                                                    <span className="text-[10px] text-slate-400 font-bold line-through flex items-center gap-1.5 leading-none">
                                                                        {formatCurrency(inc.previous_salary)}
                                                                    </span>
                                                                    <span className="text-sm font-black text-emerald-600 dark:text-emerald-400 flex items-center gap-1.5 leading-none">
                                                                        {formatCurrency(inc.new_salary)}
                                                                        <TrendingUp className="h-3 w-3" />
                                                                    </span>
                                                                </div>
                                                            </TableCell>
                                                            <TableCell className="py-5">
                                                                <div className="flex justify-center">
                                                                    <Badge className="bg-emerald-600 text-white dark:bg-emerald-500 font-black border-none text-[10px] rounded-full px-3 py-0.5 shadow-sm">
                                                                        +{inc.increment_percentage}%
                                                                    </Badge>
                                                                </div>
                                                            </TableCell>
                                                            <TableCell className="py-5">
                                                                <div className="max-w-[200px]">
                                                                    <p className="text-xs font-bold text-slate-600 dark:text-slate-400 truncate group-hover:whitespace-normal group-hover:overflow-visible transition-all">{inc.reason}</p>
                                                                    <p className="text-[8px] text-muted-foreground font-black uppercase tracking-tighter mt-1 opacity-0 group-hover:opacity-100 transition-opacity">Record UUID: {inc.id.toString().slice(0, 8)}...</p>
                                                                </div>
                                                            </TableCell>
                                                            <TableCell className="text-right pr-8 py-5">
                                                                <div className="flex justify-end gap-2 opacity-100 scale-100 transition-all origin-right">
                                                                    <Button
                                                                        variant="ghost"
                                                                        size="sm"
                                                                        onClick={() => handleViewIncrementDetail(inc.id.toString())}
                                                                        className="h-9 w-9 p-0 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 border border-slate-100 dark:border-slate-800 transition-all shadow-sm"
                                                                        title="View Details"
                                                                    >
                                                                        <EyeIcon className="h-4 w-4 text-emerald-600" />
                                                                    </Button>
                                                                    <Button
                                                                        variant="ghost"
                                                                        size="sm"
                                                                        onClick={() => handleDownloadIncrementLetter(inc.id.toString(), inc.effective_date)}
                                                                        className="h-9 w-9 p-0 rounded-xl hover:bg-slate-900 dark:hover:bg-slate-100 hover:text-white dark:hover:text-black border border-transparent hover:border-slate-800 transition-all shadow-sm"
                                                                        title="Download Official Letter"
                                                                    >
                                                                        <Download className="h-4 w-4" />
                                                                    </Button>
                                                                    {isAdminOrHr && (
                                                                        <Button
                                                                            variant="ghost"
                                                                            size="sm"
                                                                            onClick={() => handleSendIncrementLetter(inc.id.toString())}
                                                                            className="h-9 w-9 p-0 rounded-xl hover:bg-indigo-600 hover:text-white border border-transparent transition-all shadow-sm text-indigo-600"
                                                                            title="Dispatch to Email"
                                                                        >
                                                                            <Send className="h-4 w-4" />
                                                                        </Button>
                                                                    )}
                                                                </div>
                                                            </TableCell>
                                                        </TableRow>
                                                    );
                                                })
                                        )}
                                    </TableBody>
                                </Table>
                            </div>

                            <div className="p-4 bg-slate-50/50 dark:bg-slate-800/30 border-t border-slate-100 dark:border-slate-800 text-[9px] font-black text-muted-foreground uppercase tracking-[0.2em] text-center">
                                End of Official Growth Logs
                            </div>
                        </div>
                    </TabsContent>
                )}
            </Tabs >

            {/* Bank Details Edit Dialog */}
            < Dialog open={isBankEditDialogOpen} onOpenChange={setIsBankEditDialogOpen} >
                <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <CreditCard className="h-5 w-5 text-blue-500" />
                            Edit Bank & Payment Details
                        </DialogTitle>
                        <DialogDescription>
                            Update bank information, payment mode, and statutory details. This will not affect salary structure calculations.
                        </DialogDescription>
                    </DialogHeader>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 py-4">
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <Label htmlFor="bank_name">Bank Name</Label>
                                <Input
                                    id="bank_name"
                                    value={bankForm.bank_name}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, bank_name: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                                    placeholder="Enter bank name"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="bank_account">Account Number</Label>
                                <Input
                                    id="bank_account"
                                    value={bankForm.bank_account}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, bank_account: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                                    placeholder="Enter account number"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="ifsc_code">IFSC Code</Label>
                                <Input
                                    id="ifsc_code"
                                    value={bankForm.ifsc_code}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, ifsc_code: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                                    placeholder="Enter IFSC code"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="uan_number">UAN Number</Label>
                                <Input
                                    id="uan_number"
                                    value={bankForm.uan_number}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, uan_number: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                                    placeholder="Enter UAN number"
                                />
                            </div>
                        </div>

                        <div className="space-y-4">
                            <div className="space-y-2">
                                <Label htmlFor="payment_mode">Payment Mode</Label>
                                <Select
                                    value={bankForm.payment_mode}
                                    onValueChange={(value) => setBankForm(prev => ({ ...prev, payment_mode: value }))}
                                >
                                    <SelectTrigger>
                                        <SelectValue placeholder="Select payment mode" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="Bank Transfer">Bank Transfer</SelectItem>
                                        <SelectItem value="Cash">Cash</SelectItem>
                                        <SelectItem value="Cheque">Cheque</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="working_days_per_month">Working Days per Month</Label>
                                <Input
                                    id="working_days_per_month"
                                    type="number"
                                    max="31"
                                    value={bankForm.working_days_per_month}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, working_days_per_month: e.target.value === '' ? '' : parseInt(e.target.value) }))}
                                    placeholder="e.g. 26"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="other_deduction_annual">Other Deduction (Annual ₹)</Label>
                                <Input
                                    id="other_deduction_annual"
                                    type="number"
                                    value={bankForm.other_deduction_annual}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, other_deduction_annual: e.target.value === '' ? '' : parseFloat(e.target.value) }))}
                                    placeholder="Annual deduction amount"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="pf_annual">PF (Annual ₹)</Label>
                                <Input
                                    id="pf_annual"
                                    type="number"
                                    value={bankForm.pf_annual}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, pf_annual: e.target.value === '' ? '' : parseFloat(e.target.value) }))}
                                    placeholder="Annual PF amount"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="pf_no">PF Number</Label>
                                <Input
                                    id="pf_no"
                                    value={bankForm.pf_no}
                                    onChange={(e) => setBankForm(prev => ({ ...prev, pf_no: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') }))}
                                    placeholder="Enter PF number"
                                />
                            </div>
                        </div>
                    </div>

                    <DialogFooter>
                        <Button
                            variant="outline"
                            onClick={() => setIsBankEditDialogOpen(false)}
                            disabled={isUpdatingBank}
                        >
                            Cancel
                        </Button>
                        <Button
                            onClick={handleUpdateBankDetails}
                            disabled={isUpdatingBank}
                            className="bg-blue-600 hover:bg-blue-700"
                        >
                            {isUpdatingBank ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Updating...
                                </>
                            ) : (
                                <>
                                    <Save className="mr-2 h-4 w-4" />
                                    Update Details
                                </>
                            )}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog >

            {/* Inline Increment Form */}
            {
                showIncrementForm && (
                    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                        <div className="bg-white dark:bg-gray-900 rounded-xl shadow-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
                            <div className="p-6 border-b border-gray-200 dark:border-gray-700">
                                <div className="flex items-center justify-between">
                                    <h2 className="text-xl font-bold">Process Salary Increment</h2>
                                    <Button variant="ghost" size="sm" onClick={() => setShowIncrementForm(false)}>
                                        ×
                                    </Button>
                                </div>
                            </div>

                            <form onSubmit={incrementForm.handleSubmit(handleCreateIncrement)} className="p-6 space-y-6">
                                <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-lg">
                                    <p className="text-sm text-muted-foreground">Current Annual CTC</p>
                                    <p className="text-xl font-bold">
                                        {new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(currentCtc)}
                                    </p>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Increment Amount (₹)</Label>
                                        <Input
                                            type="number"
                                            onChange={handleAmountChange}
                                            value={incrementForm.watch('incrementAmount')}
                                            placeholder="Enter increment amount"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Percentage (%)</Label>
                                        <Input
                                            type="number"
                                            step="0.01"
                                            onChange={handlePercentChange}
                                            value={incrementForm.watch('incrementPercentage')}
                                            placeholder="Enter percentage"
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label>New Annual CTC (₹)</Label>
                                    <Input
                                        type="number"
                                        onChange={handleNewCtcChange}
                                        value={incrementForm.watch('newCtc')}
                                        className="text-lg font-bold text-green-600"
                                        placeholder="Enter new CTC"
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Variable Pay Type</Label>
                                        <Controller
                                            name="variablePayType"
                                            control={incrementForm.control}
                                            render={({ field }) => (
                                                <Select onValueChange={field.onChange} value={field.value}>
                                                    <SelectTrigger>
                                                        <SelectValue placeholder="Select Type" />
                                                    </SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="none">No Variable Pay</SelectItem>
                                                        <SelectItem value="fixed">Fixed Amount</SelectItem>
                                                        <SelectItem value="percentage">Percentage</SelectItem>
                                                    </SelectContent>
                                                </Select>
                                            )}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Variable Pay</Label>
                                        <Input
                                            type="number"
                                            {...incrementForm.register('variablePayValue', { valueAsNumber: true })}
                                            placeholder="Enter variable pay"
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label>Effective Date</Label>
                                    <Input
                                        type="date"
                                        {...incrementForm.register('effectiveDate')}
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label>Reason / Remarks</Label>
                                    <Textarea
                                        {...incrementForm.register('reason', {
                                            onChange: (e) => {
                                                e.target.value = e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '');
                                            }
                                        })}
                                        placeholder="e.g. Annual Appraisal, Promotion, etc."
                                        rows={3}
                                    />
                                </div>

                                <div className="flex gap-3 pt-4">
                                    <Button
                                        type="button"
                                        variant="outline"
                                        onClick={() => setShowIncrementForm(false)}
                                        className="flex-1"
                                    >
                                        Cancel
                                    </Button>
                                    <Button
                                        type="submit"
                                        disabled={isCreatingIncrement}
                                        className="flex-1 bg-green-600 hover:bg-green-700"
                                    >
                                        {isCreatingIncrement ? (
                                            <>
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                Processing...
                                            </>
                                        ) : (
                                            <>
                                                <TrendingUp className="mr-2 h-4 w-4" />
                                                Process Increment
                                            </>
                                        )}
                                    </Button>
                                </div>
                            </form>
                        </div>
                    </div>
                )
            }

            {/* Audit & Compliance Footer */}
            <div className="mt-8 border-t pt-6 text-center text-xs text-muted-foreground">
                <p className="font-medium">Confidential & Proprietary</p>
                <p className="mt-1">Salary calculations follow company payroll policy. Values shown are subject to verification.</p>
                {displaySalaryData?.updatedAt && (
                    <p className="mt-1 text-gray-400">
                        Record ID: {displaySalaryData.id} • Last synced: {new Date(displaySalaryData.updatedAt).toLocaleString()}
                    </p>
                )}
            </div>

            {/* Increment Detail Dialog */}
            <Dialog open={isViewingIncrement} onOpenChange={setIsViewingIncrement}>
                <DialogContent className="sm:max-w-[500px] border-none shadow-2xl p-0 overflow-hidden rounded-[2rem]">
                    <div className="bg-gradient-to-br from-indigo-600 to-purple-700 p-8 text-white relative">
                        <div className="absolute top-0 right-0 p-6 opacity-20">
                            <TrendingUp className="h-24 w-24 rotate-12" />
                        </div>
                        <DialogHeader>
                            <DialogTitle className="text-2xl font-black tracking-tight flex items-center gap-3">
                                <History className="h-6 w-6" />
                                Growth Details
                            </DialogTitle>
                            <DialogDescription className="text-indigo-100 font-bold uppercase tracking-widest text-[10px] mt-1">
                                Official Increment Record
                            </DialogDescription>
                        </DialogHeader>
                    </div>

                    <div className="p-8 space-y-6 bg-white dark:bg-slate-900">
                        {isLoadingIncrementDetail ? (
                            <div className="py-12 flex flex-col items-center justify-center space-y-4">
                                <Loader2 className="h-10 w-10 animate-spin text-indigo-600" />
                                <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Retrieving Secure Data...</p>
                            </div>
                        ) : selectedIncrementDetail ? (
                            <div className="space-y-6">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-4 rounded-2xl bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800">
                                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Previous CTC</p>
                                        <p className="text-lg font-black text-slate-600 dark:text-slate-400">{formatCurrency(selectedIncrementDetail.previous_salary)}</p>
                                    </div>
                                    <div className="p-4 rounded-2xl bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-800/50">
                                        <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1">New CTC</p>
                                        <p className="text-lg font-black text-emerald-700 dark:text-emerald-400">{formatCurrency(selectedIncrementDetail.new_salary)}</p>
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex items-center justify-between py-3 border-b border-slate-50 dark:border-slate-800">
                                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hike Amount</span>
                                        <span className="text-sm font-black text-indigo-600">{formatCurrency(selectedIncrementDetail.increment_amount)}</span>
                                    </div>
                                    <div className="flex items-center justify-between py-3 border-b border-slate-50 dark:border-slate-800">
                                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Growth %</span>
                                        <Badge className="bg-indigo-600 text-white font-black rounded-full px-3">{selectedIncrementDetail.increment_percentage}%</Badge>
                                    </div>
                                    <div className="flex items-center justify-between py-3 border-b border-slate-50 dark:border-slate-800">
                                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Effective From</span>
                                        <span className="text-sm font-black text-slate-800 dark:text-white">{new Date(selectedIncrementDetail.effective_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
                                    </div>
                                </div>

                                <div className="p-4 rounded-2xl bg-slate-900 text-white shadow-xl shadow-slate-900/20">
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Revision Reason</p>
                                    <p className="text-sm font-medium leading-relaxed italic">"{selectedIncrementDetail.reason}"</p>
                                </div>

                                <div className="pt-2 text-[9px] text-center text-slate-400 font-bold uppercase tracking-[0.2em]">
                                    System ID: {selectedIncrementDetail.id}
                                </div>
                            </div>
                        ) : (
                            <div className="py-8 text-center text-slate-500 italic">No record data found.</div>
                        )}

                        <DialogFooter className="pt-4 flex !justify-center">
                            <Button
                                onClick={() => setIsViewingIncrement(false)}
                                className="w-full rounded-xl bg-slate-100 hover:bg-slate-200 text-slate-900 font-bold dark:bg-slate-800 dark:text-white dark:hover:bg-slate-700 h-10 transition-all border-none"
                            >
                                Close Details
                            </Button>
                        </DialogFooter>
                    </div>
                </DialogContent>
            </Dialog>

            {/* Offer Letter Download Dialog */}
            <Dialog open={isOfferLetterDialogOpen} onOpenChange={setIsOfferLetterDialogOpen}>
                <DialogContent className="sm:max-w-[500px]">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <FileText className="h-5 w-5 text-blue-600" />
                            Download Offer Letter
                        </DialogTitle>
                        <DialogDescription>
                            Please provide the required dates to generate the offer letter.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label htmlFor="letter_date" className="flex items-center gap-1">
                                Letter Date <span className="text-red-500">*</span>
                                <span className="text-xs text-muted-foreground font-normal">(required)</span>
                            </Label>
                            <Input
                                id="letter_date"
                                type="date"
                                value={offerLetterForm.letter_date}
                                onChange={(e) => setOfferLetterForm({ ...offerLetterForm, letter_date: e.target.value })}
                                className="w-full"
                                required
                            />
                            <p className="text-xs text-muted-foreground">
                                Letter creation date (YYYY-MM-DD)
                            </p>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="joining_date" className="flex items-center gap-1">
                                Joining Date <span className="text-red-500">*</span>
                                <span className="text-xs text-muted-foreground font-normal">(required)</span>
                            </Label>
                            <Input
                                id="joining_date"
                                type="date"
                                value={offerLetterForm.joining_date}
                                onChange={(e) => setOfferLetterForm({ ...offerLetterForm, joining_date: e.target.value })}
                                className="w-full"
                                min={offerLetterForm.letter_date || undefined}
                                required
                            />
                            <p className="text-xs text-muted-foreground">
                                Joining date (YYYY-MM-DD). Must be same or later than letter date.
                            </p>
                            {offerLetterForm.letter_date && offerLetterForm.joining_date &&
                                new Date(offerLetterForm.joining_date) < new Date(offerLetterForm.letter_date) && (
                                    <p className="text-xs text-red-500 flex items-center gap-1">
                                        <AlertCircle className="h-3 w-3" />
                                        Joining date must be same or later than letter date.
                                    </p>
                                )}
                        </div>
                    </div>
                    <DialogFooter>
                        <Button
                            variant="outline"
                            onClick={() => setIsOfferLetterDialogOpen(false)}
                            disabled={isDownloadingOfferLetter}
                        >
                            Cancel
                        </Button>
                        <Button
                            onClick={handleDownloadOfferLetter}
                            disabled={isDownloadingOfferLetter || !offerLetterForm.letter_date || !offerLetterForm.joining_date}
                            className="bg-blue-600 hover:bg-blue-700"
                        >
                            {isDownloadingOfferLetter ? (
                                <>
                                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                    Downloading...
                                </>
                            ) : (
                                <>
                                    <Download className="h-4 w-4 mr-2" />
                                    Download
                                </>
                            )}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div >
    );
};

export default SalaryDetails;

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLanguage } from '@/contexts/LanguageContext';
import { apiService } from '@/lib/api';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from '@/hooks/use-toast';
import { Calendar, CalendarDays, Clock, Users, Plus, Edit, Trash2, UserPlus, ArrowRight, AlertCircle, RefreshCw, Search } from 'lucide-react';
import { format, addDays } from 'date-fns';
import { formatIST, formatDateIST, nowIST } from '@/utils/timezone';

interface Shift {
  shift_id: number;
  name: string;
  start_time: string;
  end_time: string;
  department: string | null;
  description: string | null;
  is_active: boolean;
}

interface User {
  user_id: number;
  name: string;
  email: string;
  employee_id: string | null;
  department: string | null;
  designation: string | null;
}

interface ShiftAssignment {
  assignment_id: number;
  user_id: number;
  shift_id: number;
  assignment_date: string;
  assigned_by: number | null;
  notes: string | null;
  is_reassigned: boolean;
  user?: User;
  shift?: Shift;
}

interface DepartmentSchedule {
  department: string;
  date: string;
  shifts: Array<{
    shift: Shift;
    assignments: ShiftAssignment[];
    total_assigned: number;
  }>;
  users_on_leave: User[];
  unassigned_users: User[];
}

interface DepartmentScheduleRange {
  department: string;
  start_date: string;
  end_date: string;
  days: DepartmentSchedule[];
}

export default function ShiftScheduleManagement() {
  const { user } = useAuth();
  const { t } = useLanguage();
  const [shifts, setShifts] = useState<Shift[]>([]);
  const [schedule, setSchedule] = useState<DepartmentSchedule | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>(formatDateIST(new Date(), 'yyyy-MM-dd'));
  const [viewMode, setViewMode] = useState<'daily' | 'weekly'>('daily');
  const [weekStartDate, setWeekStartDate] = useState<string>(formatDateIST(new Date(), 'yyyy-MM-dd'));
  const [weekEndDate, setWeekEndDate] = useState<string>(formatDateIST(addDays(new Date(), 6), 'yyyy-MM-dd'));
  const [weeklySchedule, setWeeklySchedule] = useState<DepartmentScheduleRange | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isDeleting, setIsDeleting] = useState<number | null>(null);
  const [isWeeklyLoading, setIsWeeklyLoading] = useState(false);

  // Dialogs
  const [isShiftDialogOpen, setIsShiftDialogOpen] = useState(false);
  const [isEditShiftDialogOpen, setIsEditShiftDialogOpen] = useState(false);
  const [isAssignDialogOpen, setIsAssignDialogOpen] = useState(false);
  const [isReassignDialogOpen, setIsReassignDialogOpen] = useState(false);
  const [selectedShift, setSelectedShift] = useState<Shift | null>(null);
  const [selectedAssignment, setSelectedAssignment] = useState<ShiftAssignment | null>(null);
  const [selectedUsers, setSelectedUsers] = useState<number[]>([]);

  // Form data
  const [shiftFormData, setShiftFormData] = useState({
    name: '',
    start_time: '09:00',
    end_time: '18:00',
    description: '',
    is_active: true,
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDepartmentFilter, setSelectedDepartmentFilter] = useState('all');
  const [departmentsList, setDepartmentsList] = useState<string[]>([]);
  const [assignFormData, setAssignFormData] = useState({
    shift_id: 0,
    assignment_date: selectedDate,
    notes: '',
  });

  useEffect(() => {
    if (user?.role === 'admin' || user?.role === 'hr') {
      loadDepartments();
    }
  }, [user]);

  const loadDepartments = async () => {
    try {
      const data = await apiService.getDepartments();
      setDepartmentsList((data || []).map((d: any) => d.name));
    } catch (error) {
      console.error('Failed to load departments:', error);
    }
  };
  useEffect(() => {
    loadShifts();
    loadSchedule();
  }, [selectedDate]);

  const loadShifts = async () => {
    try {
      setIsLoading(true);
      const data = await apiService.getShifts();
      setShifts((data || []).filter((s: Shift) => s.is_active));
    } catch (error: any) {
      // Only show toast for non-network errors
      if (error.message && !error.message.includes('Cannot connect to backend')) {
        toast({
          title: 'Error',
          description: error.message || 'Failed to load shifts',
          variant: 'destructive',
        });
      }
      // Set empty array on error to prevent UI issues
      setShifts([]);
    } finally {
      setIsLoading(false);
    }
  };

  const loadSchedule = async () => {
    try {
      setIsLoading(true);
      const data = await apiService.getDepartmentSchedule(selectedDate);
      setSchedule(data);
    } catch (error: any) {
      // Only show toast for non-network errors
      if (error.message && !error.message.includes('Cannot connect to backend')) {
        toast({
          title: 'Error',
          description: error.message || 'Failed to load schedule',
          variant: 'destructive',
        });
      }
      // Set null on error to prevent UI issues
      setSchedule(null);
    } finally {
      setIsLoading(false);
    }
  };

  const filteredDailySchedule = useMemo(() => {
    if (!schedule) return null;

    const query = searchTerm.toLowerCase();

    // Filter shifts based on assignments
    const filteredShifts = schedule.shifts.map(shiftData => {
      const filteredAssignments = shiftData.assignments.filter(assignment => {
        const userName = assignment.user?.name?.toLowerCase() || '';
        const empId = assignment.user?.employee_id?.toLowerCase() || '';
        const matchesSearch = userName.includes(query) || empId.includes(query);
        const matchesDept = selectedDepartmentFilter === 'all' || assignment.user?.department === selectedDepartmentFilter;
        return matchesSearch && matchesDept;
      });

      return {
        ...shiftData,
        assignments: filteredAssignments,
        total_assigned: filteredAssignments.length
      };
    });

    // Filter unassigned users
    const filteredUnassigned = schedule.unassigned_users.filter(user => {
      const userName = user.name.toLowerCase();
      const empId = user.employee_id?.toLowerCase() || '';
      const matchesSearch = userName.includes(query) || empId.includes(query);
      const matchesDept = selectedDepartmentFilter === 'all' || user.department === selectedDepartmentFilter;
      return matchesSearch && matchesDept;
    });

    // Filter users on leave
    const filteredLeaves = schedule.users_on_leave.filter(user => {
      const userName = user.name.toLowerCase();
      const empId = user.employee_id?.toLowerCase() || '';
      const matchesSearch = userName.includes(query) || empId.includes(query);
      const matchesDept = selectedDepartmentFilter === 'all' || user.department === selectedDepartmentFilter;
      return matchesSearch && matchesDept;
    });

    return {
      ...schedule,
      shifts: filteredShifts,
      unassigned_users: filteredUnassigned,
      users_on_leave: filteredLeaves
    };
  }, [schedule, searchTerm, selectedDepartmentFilter]);

  const loadWeeklySchedule = async () => {
    if (!weekStartDate) {
      toast({
        title: 'Validation Error',
        description: 'Please select a start date for the week',
        variant: 'destructive',
      });
      return;
    }

    try {
      setIsWeeklyLoading(true);
      const data = await apiService.getDepartmentScheduleWeek(weekStartDate, weekEndDate);
      setWeeklySchedule(data);
    } catch (error: any) {
      if (error.message && !error.message.includes('Cannot connect to backend')) {
        toast({
          title: 'Error',
          description: error.message || 'Failed to load weekly schedule',
          variant: 'destructive',
        });
      }
      setWeeklySchedule(null);
    } finally {
      setIsWeeklyLoading(false);
    }
  };

  const validateShiftData = () => {
    if (!shiftFormData.name || !shiftFormData.start_time || !shiftFormData.end_time) {
      toast({
        title: 'Validation Error',
        description: 'Please fill in all required fields',
        variant: 'destructive',
      });
      return false;
    }

    // Validate time format (HH:MM)
    const timeRegex = /^([01]?[0-9]|2[0-3]):[0-5][0-9]$/;
    if (!timeRegex.test(shiftFormData.start_time) || !timeRegex.test(shiftFormData.end_time)) {
      toast({
        title: 'Validation Error',
        description: 'Please enter valid time in HH:MM format',
        variant: 'destructive',
      });
      return false;
    }

    // Validate shift duration (supports overnight shifts)
    const [startHour, startMin] = shiftFormData.start_time.split(':').map(Number);
    const [endHour, endMin] = shiftFormData.end_time.split(':').map(Number);
    const startMinutes = startHour * 60 + startMin;
    const endMinutes = endHour * 60 + endMin;
    let durationMinutes = endMinutes - startMinutes;

    if (durationMinutes <= 0) {
      durationMinutes += 24 * 60; // allow overnight shifts by wrapping to next day
    }

    if (durationMinutes <= 0) {
      toast({
        title: 'Validation Error',
        description: 'Shift duration must be greater than 0 minutes',
        variant: 'destructive',
      });
      return false;
    }

    return true;
  };

  const resetShiftForm = () => {
    setShiftFormData({
      name: '',
      start_time: '09:00',
      end_time: '18:00',
      description: '',
      is_active: true,
    });
    setSelectedShift(null);
  };

  const openEditDialog = (shift: Shift) => {
    setSelectedShift(shift);
    setShiftFormData({
      name: shift.name,
      start_time: shift.start_time,
      end_time: shift.end_time,
      description: shift.description || '',
      is_active: shift.is_active,
    });
    setIsEditShiftDialogOpen(true);
  };

  const handleCreateShift = async () => {
    if (!validateShiftData()) return;

    try {
      setIsCreating(true);
      console.log('Creating shift with data:', shiftFormData);

      // Add timeout to prevent hanging
      const timeoutPromise = new Promise((_, reject) =>
        setTimeout(() => reject(new Error('Request timeout: Backend server may not be responding')), 10000)
      );

      const createPromise = apiService.createShift(shiftFormData);
      const result = await Promise.race([createPromise, timeoutPromise]);

      console.log('Shift created successfully:', result);
      toast({
        title: 'Success',
        description: 'Shift created successfully',
      });
      setIsShiftDialogOpen(false);
      resetShiftForm();
      loadShifts();
    } catch (error: any) {
      console.error('Error creating shift:', error);
      const errorMessage = error.message || 'Failed to create shift';
      toast({
        title: 'Error',
        description: errorMessage,
        variant: 'destructive',
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleUpdateShift = async () => {
    if (!selectedShift || !validateShiftData()) return;

    try {
      setIsUpdating(true);
      console.log('Updating shift:', selectedShift.shift_id, shiftFormData);

      const timeoutPromise = new Promise((_, reject) =>
        setTimeout(() => reject(new Error('Request timeout: Backend server may not be responding')), 10000)
      );

      const updatePromise = apiService.updateShift(selectedShift.shift_id, shiftFormData);
      const result = await Promise.race([updatePromise, timeoutPromise]);

      console.log('Shift updated successfully:', result);
      toast({
        title: 'Success',
        description: 'Shift updated successfully',
      });
      setIsEditShiftDialogOpen(false);
      resetShiftForm();
      loadShifts();
    } catch (error: any) {
      console.error('Error updating shift:', error);
      const errorMessage = error.message || 'Failed to update shift';
      toast({
        title: 'Error',
        description: errorMessage,
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDeleteShift = async (shiftId: number) => {
    if (!confirm('Are you sure you want to delete this shift? This action cannot be undone.')) {
      return;
    }

    try {
      setIsDeleting(shiftId);
      await apiService.deleteShift(shiftId);
      toast({
        title: 'Success',
        description: 'Shift deleted successfully',
      });
      loadShifts();
    } catch (error: any) {
      console.error('Error deleting shift:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to delete shift',
        variant: 'destructive',
      });
    } finally {
      setIsDeleting(null);
    }
  };

  const handleAssignShift = async () => {
    if (!assignFormData.shift_id || !selectedUsers.length) {
      toast({
        title: 'Validation Error',
        description: 'Please select a shift and at least one user',
        variant: 'destructive',
      });
      return;
    }

    try {
      setIsCreating(true);
      if (selectedUsers.length === 1) {
        await apiService.assignShift({
          user_id: selectedUsers[0],
          shift_id: assignFormData.shift_id,
          assignment_date: assignFormData.assignment_date,
          notes: assignFormData.notes || undefined,
        });
      } else {
        await apiService.bulkAssignShift({
          user_ids: selectedUsers,
          shift_id: assignFormData.shift_id,
          assignment_date: assignFormData.assignment_date,
          notes: assignFormData.notes || undefined,
        });
      }
      toast({
        title: 'Success',
        description: 'Shift assigned successfully',
      });
      setIsAssignDialogOpen(false);
      setSelectedUsers([]);
      setAssignFormData({
        shift_id: 0,
        assignment_date: selectedDate,
        notes: '',
      });
      loadSchedule();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to assign shift',
        variant: 'destructive',
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleReassignShift = async (assignmentId: number, newShiftId: number) => {
    try {
      await apiService.updateShiftAssignment(assignmentId, {
        shift_id: newShiftId,
      });
      toast({
        title: 'Success',
        description: 'Shift reassigned successfully',
      });
      setIsReassignDialogOpen(false);
      loadSchedule();
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to reassign shift',
        variant: 'destructive',
      });
    }
  };

  const handleDeleteAssignment = async (assignmentId: number) => {
    if (!assignmentId || assignmentId <= 0) {
      toast({
        title: 'Error',
        description: 'Invalid assignment ID',
        variant: 'destructive',
      });
      return;
    }

    if (!confirm('Are you sure you want to remove this shift assignment?')) {
      return;
    }

    try {
      console.log('Deleting assignment with ID:', assignmentId);
      await apiService.deleteShiftAssignment(assignmentId);
      toast({
        title: 'Success',
        description: 'Assignment removed successfully',
      });
      loadSchedule();
    } catch (error: any) {
      console.error('Error deleting assignment:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to remove assignment',
        variant: 'destructive',
      });
    }
  };

  const openAssignDialog = (shiftId?: number) => {
    if (shiftId) {
      setAssignFormData({ ...assignFormData, shift_id: shiftId });
    }
    // Ensure shifts are loaded before opening dialog
    if (shifts.length === 0) {
      loadShifts();
    }
    setIsAssignDialogOpen(true);
  };

  const openReassignDialog = (assignment: ShiftAssignment) => {
    setSelectedAssignment(assignment);
    setIsReassignDialogOpen(true);
  };

  const getAvailableUsers = () => {
    if (!schedule) return [];
    const assignedUserIds = new Set(
      schedule.shifts.flatMap(s => s.assignments.map(a => a.user_id))
    );
    return schedule.unassigned_users.filter(u => !assignedUserIds.has(u.user_id));
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white sm:text-3xl flex items-center gap-3">
            <Clock className="h-8 w-8 text-blue-600" />
            Shift Schedule Management
          </h1>
          <p className="text-muted-foreground mt-1">
            Manage shift schedules and assignments for your department
          </p>
        </div>
        <Dialog open={isShiftDialogOpen} onOpenChange={(open) => {
          setIsShiftDialogOpen(open);
          if (!open) resetShiftForm();
        }}>
          <DialogTrigger asChild>
            <Button className="gap-2 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 shadow-md">
              <Plus className="h-4 w-4" />
              Create Shift
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Create New Shift</DialogTitle>
              <DialogDescription>
                Define a new shift for your department
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name">Shift Name *</Label>
                <Input
                  id="name"
                  value={shiftFormData.name}
                  onChange={(e) => setShiftFormData({ ...shiftFormData, name: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                  placeholder="e.g., Morning Shift, Evening Shift"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="start_time">Start Time *</Label>
                  <Input
                    id="start_time"
                    type="time"
                    value={shiftFormData.start_time}
                    onChange={(e) => setShiftFormData({ ...shiftFormData, start_time: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="end_time">End Time *</Label>
                  <Input
                    id="end_time"
                    type="time"
                    value={shiftFormData.end_time}
                    onChange={(e) => setShiftFormData({ ...shiftFormData, end_time: e.target.value })}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="description">Description</Label>
                <Input
                  id="description"
                  value={shiftFormData.description}
                  onChange={(e) => setShiftFormData({ ...shiftFormData, description: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                  placeholder="Optional description"
                />
              </div>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => {
                  setIsShiftDialogOpen(false);
                  resetShiftForm();
                }}>
                  Cancel
                </Button>
                <Button onClick={handleCreateShift} disabled={isCreating}>
                  {isCreating ? 'Creating...' : 'Create Shift'}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* Edit Shift Dialog */}
        <Dialog open={isEditShiftDialogOpen} onOpenChange={(open) => {
          setIsEditShiftDialogOpen(open);
          if (!open) resetShiftForm();
        }}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Edit Shift</DialogTitle>
              <DialogDescription>
                Update shift details for your department
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="edit_name">Shift Name *</Label>
                <Input
                  id="edit_name"
                  value={shiftFormData.name}
                  onChange={(e) => setShiftFormData({ ...shiftFormData, name: e.target.value })}
                  placeholder="e.g., Morning Shift, Evening Shift"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="edit_start_time">Start Time *</Label>
                  <Input
                    id="edit_start_time"
                    type="time"
                    value={shiftFormData.start_time}
                    onChange={(e) => setShiftFormData({ ...shiftFormData, start_time: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="edit_end_time">End Time *</Label>
                  <Input
                    id="edit_end_time"
                    type="time"
                    value={shiftFormData.end_time}
                    onChange={(e) => setShiftFormData({ ...shiftFormData, end_time: e.target.value })}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="edit_description">Description</Label>
                <Input
                  id="edit_description"
                  value={shiftFormData.description}
                  onChange={(e) => setShiftFormData({ ...shiftFormData, description: e.target.value })}
                  placeholder="Optional description"
                />
              </div>
              <div className="flex items-center gap-2">
                <input
                  type="checkbox"
                  id="edit_is_active"
                  checked={shiftFormData.is_active}
                  onChange={(e) => setShiftFormData({ ...shiftFormData, is_active: e.target.checked })}
                  className="h-4 w-4 rounded border-gray-300"
                />
                <Label htmlFor="edit_is_active" className="cursor-pointer">
                  Active Shift
                </Label>
              </div>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => {
                  setIsEditShiftDialogOpen(false);
                  resetShiftForm();
                }}>
                  Cancel
                </Button>
                <Button onClick={handleUpdateShift} disabled={isUpdating}>
                  {isUpdating ? 'Updating...' : 'Update Shift'}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <Tabs value={viewMode} onValueChange={(value) => setViewMode(value as 'daily' | 'weekly')} className="space-y-6">
        <TabsList>
          <TabsTrigger value="daily">Daily View</TabsTrigger>
          <TabsTrigger value="weekly">Weekly View</TabsTrigger>
        </TabsList>

        <TabsContent value="daily" className="space-y-6">
          {/* Date Selector */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="h-5 w-5" />
                Select Date
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap items-end gap-4">
                <div className="flex flex-col gap-2">
                  <Label htmlFor="daily_date" className="text-sm font-medium text-slate-700 dark:text-slate-300">Select Date</Label>
                  <Input
                    id="daily_date"
                    type="date"
                    value={selectedDate}
                    onChange={(e) => setSelectedDate(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                    className="w-[200px] h-11"
                  />
                </div>
                {(user?.role === 'admin' || user?.role === 'hr') && (
                  <div className="flex flex-col gap-2">
                    <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Department</Label>
                    <Select value={selectedDepartmentFilter} onValueChange={setSelectedDepartmentFilter}>
                      <SelectTrigger className="w-[180px] h-11">
                        <SelectValue placeholder="All Departments" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="all">All Departments</SelectItem>
                        {departmentsList.map(dept => (
                          <SelectItem key={dept} value={dept}>{dept}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                )}
                <div className="flex flex-col gap-2 flex-1 min-w-[200px]">
                  <Label className="text-sm font-medium text-slate-700 dark:text-slate-300">Search User</Label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <Input
                      placeholder="Search by name, ID..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, ''))}
                      className="pl-10 h-11"
                    />
                  </div>
                </div>
                <Button onClick={loadSchedule} variant="outline" className="h-11 shadow-sm">
                  Load Schedule
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Empty State - No Schedule Data */}
          {!schedule && !isLoading && (
            <Card>
              <CardContent className="py-12 text-center">
                <AlertCircle className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">No Schedule Data</h3>
                <p className="text-muted-foreground mb-4">
                  Unable to load shift schedule. Please check your connection and try again.
                </p>
                <Button onClick={() => { loadShifts(); loadSchedule(); }} variant="outline">
                  Retry
                </Button>
              </CardContent>
            </Card>
          )}

          {/* Schedule View */}
          {filteredDailySchedule && (
            <Tabs defaultValue="schedule" className="space-y-4">
              <TabsList>
                <TabsTrigger value="schedule">Shift Schedule</TabsTrigger>
                <TabsTrigger value="leaves">On Leave</TabsTrigger>
                <TabsTrigger value="unassigned">Unassigned Users</TabsTrigger>
              </TabsList>

              <TabsContent value="schedule" className="space-y-4">
                {filteredDailySchedule.shifts.map((shiftData) => (
                  <Card key={shiftData.shift.shift_id}>
                    <CardHeader>
                      <div className="flex items-center justify-between">
                        <div>
                          <CardTitle className="flex items-center gap-2">
                            <Clock className="h-5 w-5" />
                            {shiftData.shift.name}
                          </CardTitle>
                          <CardDescription>
                            {shiftData.shift.start_time} - {shiftData.shift.end_time}
                            {shiftData.shift.description && ` • ${shiftData.shift.description}`}
                          </CardDescription>
                        </div>
                        <div className="flex items-center gap-2">
                          <Badge variant="secondary">
                            {shiftData.total_assigned} assigned
                          </Badge>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => openAssignDialog(shiftData.shift.shift_id)}
                          >
                            <UserPlus className="h-4 w-4 mr-2" />
                            Assign Users
                          </Button>
                        </div>
                      </div>
                    </CardHeader>
                    <CardContent>
                      {shiftData.assignments.length > 0 ? (
                        <Table>
                          <TableHeader>
                            <TableRow>
                              <TableHead>Employee</TableHead>
                              <TableHead>Employee ID</TableHead>
                              <TableHead>Designation</TableHead>
                              <TableHead>Notes</TableHead>
                              <TableHead>Actions</TableHead>
                            </TableRow>
                          </TableHeader>
                          <TableBody>
                            {shiftData.assignments.map((assignment) => (
                              <TableRow key={assignment.assignment_id}>
                                <TableCell className="font-medium">
                                  {assignment.user?.name || 'Unknown'}
                                </TableCell>
                                <TableCell>{assignment.user?.employee_id || 'N/A'}</TableCell>
                                <TableCell>{assignment.user?.designation || 'N/A'}</TableCell>
                                <TableCell>{assignment.notes || '-'}</TableCell>
                                <TableCell>
                                  <div className="flex items-center gap-2">
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      onClick={() => openReassignDialog(assignment)}
                                    >
                                      <ArrowRight className="h-3 w-3 mr-1" />
                                      Reassign
                                    </Button>
                                    <Button
                                      size="sm"
                                      variant="destructive"
                                      onClick={() => handleDeleteAssignment(assignment.assignment_id)}
                                    >
                                      <Trash2 className="h-3 w-3" />
                                    </Button>
                                  </div>
                                </TableCell>
                              </TableRow>
                            ))}
                          </TableBody>
                        </Table>
                      ) : (
                        <div className="text-center py-8 text-muted-foreground">
                          No assignments for this shift
                        </div>
                      )}
                    </CardContent>
                  </Card>
                ))}
              </TabsContent>

              <TabsContent value="leaves">
                <Card>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <AlertCircle className="h-5 w-5 text-orange-500" />
                      Users on Leave
                    </CardTitle>
                    <CardDescription>
                      Users who are on approved leave for {formatDateIST(selectedDate, 'MMM dd, yyyy')}
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    {filteredDailySchedule.users_on_leave.length > 0 ? (
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead>Name</TableHead>
                            <TableHead>Employee ID</TableHead>
                            <TableHead>Designation</TableHead>
                            <TableHead>Status</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {filteredDailySchedule.users_on_leave.map((user) => (
                            <TableRow key={user.user_id}>
                              <TableCell className="font-medium">{user.name}</TableCell>
                              <TableCell>{user.employee_id || 'N/A'}</TableCell>
                              <TableCell>{user.designation || 'N/A'}</TableCell>
                              <TableCell>
                                <Badge variant="outline" className="text-orange-600">
                                  On Leave
                                </Badge>
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    ) : (
                      <div className="text-center py-8 text-muted-foreground">
                        No users on leave for this date
                      </div>
                    )}
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="unassigned">
                <Card>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <Users className="h-5 w-5 text-blue-500" />
                      Unassigned Users
                    </CardTitle>
                    <CardDescription>
                      Users who are not assigned to any shift for {formatDateIST(selectedDate, 'MMM dd, yyyy')}
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    {filteredDailySchedule.unassigned_users.length > 0 ? (
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead>Name</TableHead>
                            <TableHead>Employee ID</TableHead>
                            <TableHead>Designation</TableHead>
                            <TableHead>Actions</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {filteredDailySchedule.unassigned_users.map((user) => (
                            <TableRow key={user.user_id}>
                              <TableCell className="font-medium">{user.name}</TableCell>
                              <TableCell>{user.employee_id || 'N/A'}</TableCell>
                              <TableCell>{user.designation || 'N/A'}</TableCell>
                              <TableCell>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => {
                                    setSelectedUsers([user.user_id]);
                                    setIsAssignDialogOpen(true);
                                  }}
                                >
                                  <UserPlus className="h-3 w-3 mr-1" />
                                  Assign
                                </Button>
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    ) : (
                      <div className="text-center py-8 text-muted-foreground">
                        All users are assigned to shifts
                      </div>
                    )}
                  </CardContent>
                </Card>
              </TabsContent>
            </Tabs>
          )}
        </TabsContent>

        <TabsContent value="weekly" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CalendarDays className="h-5 w-5" />
                Select Week Range
              </CardTitle>
              <CardDescription>
                Choose the start and end dates to generate a weekly calendar of shifts.
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap items-end gap-4">
                <div className="flex flex-col gap-2">
                  <Label htmlFor="week_start" className="text-sm font-medium text-slate-700 dark:text-slate-300">Week Start *</Label>
                  <Input
                    id="week_start"
                    type="date"
                    value={weekStartDate}
                    onChange={(e) => {
                      setWeekStartDate(e.target.value);
                      if (!weekEndDate) {
                        setWeekEndDate(format(addDays(new Date(e.target.value), 6), 'yyyy-MM-dd'));
                      }
                    }}
                    className="w-[200px] h-11"
                  />
                </div>
                <div className="flex flex-col gap-2">
                  <Label htmlFor="week_end" className="text-sm font-medium text-slate-700 dark:text-slate-300">Week End</Label>
                  <Input
                    id="week_end"
                    type="date"
                    value={weekEndDate}
                    min={weekStartDate}
                    onChange={(e) => setWeekEndDate(e.target.value)}
                    className="w-[200px] h-11"
                  />
                </div>
                <Button onClick={loadWeeklySchedule} disabled={isWeeklyLoading} className="h-11 shadow-sm">
                  {isWeeklyLoading ? 'Loading...' : 'Load Weekly Schedule'}
                </Button>
              </div>
            </CardContent>
          </Card>

          {isWeeklyLoading && (
            <Card>
              <CardContent className="py-12 text-center text-muted-foreground">
                <RefreshCw className="h-8 w-8 mx-auto mb-3 animate-spin opacity-50" />
                Generating weekly schedule...
              </CardContent>
            </Card>
          )}

          {!isWeeklyLoading && weeklySchedule && (
            <div className="space-y-4">
              <Card className="border border-dashed">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <CalendarDays className="h-5 w-5" />
                    {formatDateIST(weeklySchedule.start_date, 'MMM dd, yyyy')} - {formatDateIST(weeklySchedule.end_date, 'MMM dd, yyyy')}
                  </CardTitle>
                  <CardDescription>
                    {weeklySchedule.days.length} days of coverage • {weeklySchedule.department} department
                  </CardDescription>
                </CardHeader>
              </Card>

              {weeklySchedule.days.map((day) => (
                <Card key={day.date}>
                  <CardHeader>
                    <div className="flex items-center justify-between">
                      <div>
                        <CardTitle className="flex items-center gap-2">
                          <Calendar className="h-5 w-5" />
                          {formatDateIST(day.date, 'EEEE, MMM dd')}
                        </CardTitle>
                        <CardDescription>
                          {day.shifts.length} shifts • {day.users_on_leave.length} on leave
                        </CardDescription>
                      </div>
                      <Badge variant="secondary">
                        {day.unassigned_users.length} unassigned
                      </Badge>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    {day.shifts.map((shiftData) => (
                      <div key={`${day.date}-${shiftData.shift.shift_id}`} className="rounded-lg border p-4 space-y-3">
                        <div className="flex items-center justify-between">
                          <div>
                            <p className="font-semibold">{shiftData.shift.name}</p>
                            <p className="text-sm text-muted-foreground">
                              {shiftData.shift.start_time} - {shiftData.shift.end_time}
                              {shiftData.shift.description && ` • ${shiftData.shift.description}`}
                            </p>
                          </div>
                          <Badge variant="outline">{shiftData.total_assigned} assigned</Badge>
                        </div>
                        {shiftData.assignments.length > 0 ? (
                          <div className="space-y-2">
                            {shiftData.assignments.map((assignment) => (
                              <div key={assignment.assignment_id} className="flex items-center justify-between rounded-md bg-muted/50 px-3 py-2 text-sm">
                                <div>
                                  <p className="font-medium">{assignment.user?.name || 'Unknown'}</p>
                                  <p className="text-muted-foreground text-xs">
                                    {assignment.user?.designation || 'N/A'}
                                  </p>
                                </div>
                                <span className="text-xs text-muted-foreground">{assignment.user?.employee_id || 'N/A'}</span>
                              </div>
                            ))}
                          </div>
                        ) : (
                          <p className="text-sm text-muted-foreground">No assignments for this shift</p>
                        )}
                      </div>
                    ))}
                  </CardContent>
                </Card>
              ))}
            </div>
          )}

          {!isWeeklyLoading && !weeklySchedule && (
            <Card>
              <CardContent className="py-12 text-center text-muted-foreground">
                Select a start date and generate a weekly schedule to see coverage.
              </CardContent>
            </Card>
          )}
        </TabsContent>
      </Tabs>

      {/* All Shifts List */}
      <Card className="border-2 border-blue-100 dark:border-blue-900 shadow-lg">
        <CardHeader className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-950 dark:to-indigo-950">
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2 text-xl">
                <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-md">
                  <Clock className="h-5 w-5 text-white" />
                </div>
                All Shifts ({shifts.length})
              </CardTitle>
              <CardDescription className="mt-2">
                View and manage all shifts for your department
              </CardDescription>
            </div>
            <Button onClick={loadShifts} variant="outline" size="sm" disabled={isLoading} className="shadow-sm">
              <RefreshCw className={`h-4 w-4 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
              Refresh
            </Button>
          </div>
        </CardHeader>
        <CardContent className="pt-6">
          {isLoading ? (
            <div className="text-center py-12 text-muted-foreground">
              <RefreshCw className="h-8 w-8 mx-auto mb-3 animate-spin opacity-50" />
              <p>Loading shifts...</p>
            </div>
          ) : shifts.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {shifts.map((shift) => (
                <Card key={shift.shift_id} className="border-l-4 border-l-blue-500 hover:shadow-lg transition-all duration-300 hover:scale-[1.02] bg-gradient-to-br from-white to-blue-50/50 dark:from-gray-900 dark:to-blue-950/20">
                  <CardHeader className="pb-3">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-lg font-semibold">{shift.name}</CardTitle>
                      <Badge variant={shift.is_active ? "default" : "secondary"} className="shadow-sm">
                        {shift.is_active ? "Active" : "Inactive"}
                      </Badge>
                    </div>
                    <CardDescription className="text-sm">
                      {shift.department || "Global Shift"}
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-3">
                      <div className="flex items-center gap-2 text-sm bg-blue-50 dark:bg-blue-950/30 px-3 py-2 rounded-lg">
                        <Clock className="h-4 w-4 text-blue-600 dark:text-blue-400" />
                        <span className="font-semibold text-blue-700 dark:text-blue-300">{shift.start_time}</span>
                        <span className="text-muted-foreground">-</span>
                        <span className="font-semibold text-blue-700 dark:text-blue-300">{shift.end_time}</span>
                      </div>
                      {shift.description && (
                        <p className="text-sm text-muted-foreground italic">{shift.description}</p>
                      )}
                      <div className="flex items-center gap-2 pt-2 border-t">
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => openEditDialog(shift)}
                          className="flex-1 hover:bg-blue-50 hover:border-blue-300 hover:text-blue-700 transition-colors"
                        >
                          <Edit className="h-3 w-3 mr-1" />
                          Edit
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => handleDeleteShift(shift.shift_id)}
                          disabled={isDeleting === shift.shift_id}
                          className="flex-1 hover:bg-red-600 transition-colors"
                        >
                          <Trash2 className="h-3 w-3 mr-1" />
                          {isDeleting === shift.shift_id ? 'Deleting...' : 'Delete'}
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <div className="text-center py-12 text-muted-foreground">
              <Clock className="h-16 w-16 mx-auto mb-4 opacity-30" />
              <p className="text-lg font-medium mb-2">No shifts created yet</p>
              <p className="text-sm">Create your first shift to get started</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Assign Users Dialog */}
      <Dialog open={isAssignDialogOpen} onOpenChange={setIsAssignDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Assign Users to Shift</DialogTitle>
            <DialogDescription>
              Select users to assign to a shift
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="shift_select">Shift *</Label>
              {shifts.length === 0 ? (
                <div className="p-3 rounded-lg border border-yellow-200 bg-yellow-50 dark:bg-yellow-950/20 dark:border-yellow-800">
                  <p className="text-sm text-yellow-800 dark:text-yellow-200">
                    No shifts available. Please create a shift first.
                  </p>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={loadShifts}
                    className="mt-2"
                  >
                    Reload Shifts
                  </Button>
                </div>
              ) : (
                <Select
                  value={assignFormData.shift_id.toString()}
                  onValueChange={(value) => setAssignFormData({ ...assignFormData, shift_id: parseInt(value) })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select a shift" />
                  </SelectTrigger>
                  <SelectContent>
                    {shifts.map((shift) => (
                      <SelectItem key={shift.shift_id} value={shift.shift_id.toString()}>
                        {shift.name} ({shift.start_time} - {shift.end_time})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="assignment_date">Date *</Label>
              <Input
                id="assignment_date"
                type="date"
                value={assignFormData.assignment_date}
                onChange={(e) => setAssignFormData({ ...assignFormData, assignment_date: e.target.value })}
              />
            </div>
            <div className="space-y-2">
              <Label>Available Users</Label>
              <div className="border rounded-lg p-4 max-h-60 overflow-y-auto">
                {getAvailableUsers().map((user) => (
                  <div key={user.user_id} className="flex items-center justify-between py-2 border-b last:border-b-0">
                    <div>
                      <div className="font-medium">{user.name}</div>
                      <div className="text-sm text-muted-foreground">
                        {user.employee_id || 'N/A'} • {user.designation || 'N/A'}
                      </div>
                    </div>
                    <Button
                      size="sm"
                      variant={selectedUsers.includes(user.user_id) ? 'default' : 'outline'}
                      onClick={() => {
                        if (selectedUsers.includes(user.user_id)) {
                          setSelectedUsers(selectedUsers.filter(id => id !== user.user_id));
                        } else {
                          setSelectedUsers([...selectedUsers, user.user_id]);
                        }
                      }}
                    >
                      {selectedUsers.includes(user.user_id) ? 'Selected' : 'Select'}
                    </Button>
                  </div>
                ))}
                {getAvailableUsers().length === 0 && (
                  <div className="text-center py-4 text-muted-foreground">
                    No available users
                  </div>
                )}
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="notes">Notes (Optional)</Label>
              <Input
                id="notes"
                value={assignFormData.notes}
                onChange={(e) => setAssignFormData({ ...assignFormData, notes: e.target.value.replace(/[^\p{L}\p{N}\p{P}\p{Z}\p{M}]/gu, '') })}
                placeholder="Optional notes about this assignment"
              />
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setIsAssignDialogOpen(false)}>
                Cancel
              </Button>
              <Button onClick={handleAssignShift} disabled={isCreating || !selectedUsers.length}>
                {isCreating ? 'Assigning...' : `Assign ${selectedUsers.length} User(s)`}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Reassign Dialog */}
      <Dialog open={isReassignDialogOpen} onOpenChange={setIsReassignDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Reassign Shift</DialogTitle>
            <DialogDescription>
              Move this user to a different shift
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {selectedAssignment && (
              <>
                <div className="p-4 bg-muted rounded-lg">
                  <div className="font-medium">{selectedAssignment.user?.name}</div>
                  <div className="text-sm text-muted-foreground">
                    Currently assigned to: {selectedAssignment.shift?.name}
                  </div>
                </div>
                <div className="space-y-2">
                  <Label>New Shift *</Label>
                  <Select
                    onValueChange={(value) => {
                      if (selectedAssignment) {
                        handleReassignShift(selectedAssignment.assignment_id, parseInt(value));
                      }
                    }}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select a new shift" />
                    </SelectTrigger>
                    <SelectContent>
                      {shifts
                        .filter(s => s.shift_id !== selectedAssignment.shift_id)
                        .map((shift) => (
                          <SelectItem key={shift.shift_id} value={shift.shift_id.toString()}>
                            {shift.name} ({shift.start_time} - {shift.end_time})
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                </div>
              </>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLanguage } from '@/contexts/LanguageContext';
import { apiService } from '@/lib/api';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from '@/hooks/use-toast';
import { Calendar, Clock, Users, CalendarDays, ChevronLeft, ChevronRight } from 'lucide-react';
import { format, addDays, subDays, startOfWeek, endOfWeek, eachDayOfInterval, isSameDay } from 'date-fns';
import { formatIST, formatDateIST, nowIST } from '@/utils/timezone';

interface Shift {
  shift_id: number;
  name: string;
  start_time: string;
  end_time: string;
  department: string | null;
  description: string | null;
  is_active: boolean;
}

interface ShiftAssignment {
  assignment_id: number;
  user_id: number;
  shift_id: number;
  assignment_date: string;
  assigned_by: number | null;
  notes: string | null;
  is_reassigned: boolean;
  shift?: Shift;
}

interface UserShiftSchedule {
  user: {
    user_id: number;
    name: string;
    email: string;
    employee_id: string | null;
    department: string | null;
    designation: string | null;
  };
  assignments: ShiftAssignment[];
  upcoming_shifts: ShiftAssignment[];
  past_shifts: ShiftAssignment[];
}

export default function TeamShifts() {
  const { user } = useAuth();
  const { t } = useLanguage();
  const [schedule, setSchedule] = useState<UserShiftSchedule | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [viewMode, setViewMode] = useState<'week' | 'month'>('week');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  useEffect(() => {
    loadSchedule();
  }, [startDate, endDate]);

  useEffect(() => {
    if (viewMode === 'week') {
      const weekStart = startOfWeek(currentDate, { weekStartsOn: 1 });
      const weekEnd = endOfWeek(currentDate, { weekStartsOn: 1 });
      setStartDate(format(weekStart, 'yyyy-MM-dd'));
      setEndDate(format(weekEnd, 'yyyy-MM-dd'));
    } else {
      const monthStart = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
      const monthEnd = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);
      setStartDate(format(monthStart, 'yyyy-MM-dd'));
      setEndDate(format(monthEnd, 'yyyy-MM-dd'));
    }
  }, [currentDate, viewMode]);

  const loadSchedule = async () => {
    if (!startDate || !endDate) return;

    try {
      setIsLoading(true);
      const data = await apiService.getMyShiftSchedule(startDate, endDate);
      setSchedule(data);
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to load shift schedule',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const navigateDate = (direction: 'prev' | 'next') => {
    if (viewMode === 'week') {
      setCurrentDate(addDays(currentDate, direction === 'next' ? 7 : -7));
    } else {
      const newDate = new Date(currentDate);
      newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
      setCurrentDate(newDate);
    }
  };

  const getWeekDays = () => {
    const weekStart = startOfWeek(currentDate, { weekStartsOn: 1 });
    return eachDayOfInterval({ start: weekStart, end: endOfWeek(currentDate, { weekStartsOn: 1 }) });
  };

  const getMonthDays = () => {
    const monthStart = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
    const monthEnd = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);
    return eachDayOfInterval({ start: monthStart, end: monthEnd });
  };

  const getAssignmentForDate = (date: Date) => {
    if (!schedule) return null;
    const dateStr = format(date, 'yyyy-MM-dd');
    return schedule.assignments.find(a => a.assignment_date === dateStr);
  };

  const getStatusBadge = (assignment: ShiftAssignment | null) => {
    if (!assignment) return null;
    const assignmentDate = new Date(assignment.assignment_date);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    assignmentDate.setHours(0, 0, 0, 0);

    if (assignmentDate < today) {
      return <Badge variant="outline" className="bg-gray-100">Past</Badge>;
    } else if (assignmentDate.getTime() === today.getTime()) {
      return <Badge className="bg-blue-500">Today</Badge>;
    } else {
      return <Badge variant="secondary">Upcoming</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white sm:text-3xl flex items-center gap-3">
            <CalendarDays className="h-8 w-8 text-blue-600" />
            Shift Schedule
          </h1>
          <p className="text-muted-foreground mt-1">
            View your assigned shifts and schedule
          </p>
        </div>
      </div>

      {/* View Controls */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <Calendar className="h-5 w-5" />
              Schedule View
            </CardTitle>
            <div className="flex items-center gap-2">
              <Button
                variant={viewMode === 'week' ? 'default' : 'outline'}
                size="sm"
                onClick={() => setViewMode('week')}
              >
                Week
              </Button>
              <Button
                variant={viewMode === 'month' ? 'default' : 'outline'}
                size="sm"
                onClick={() => setViewMode('month')}
              >
                Month
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between mb-4">
            <Button
              variant="outline"
              size="sm"
              onClick={() => navigateDate('prev')}
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <div className="text-center">
              <div className="font-semibold text-lg">
                {viewMode === 'week'
                  ? `Week of ${format(startOfWeek(currentDate, { weekStartsOn: 1 }), 'MMM dd')}`
                  : format(currentDate, 'MMMM yyyy')}
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setCurrentDate(new Date())}
                className="text-xs"
              >
                Today
              </Button>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => navigateDate('next')}
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Schedule Display */}
      {isLoading ? (
        <Card>
          <CardContent className="py-12 text-center">
            <div className="text-muted-foreground">Loading schedule...</div>
          </CardContent>
        </Card>
      ) : schedule ? (
        <Tabs defaultValue="calendar" className="space-y-4">
          <TabsList>
            <TabsTrigger value="calendar">Calendar View</TabsTrigger>
            <TabsTrigger value="upcoming">Upcoming Shifts</TabsTrigger>
            <TabsTrigger value="past">Past Shifts</TabsTrigger>
          </TabsList>

          <TabsContent value="calendar">
            <Card>
              <CardHeader>
                <CardTitle>Calendar View</CardTitle>
                <CardDescription>
                  {viewMode === 'week' ? 'Weekly' : 'Monthly'} shift schedule
                </CardDescription>
              </CardHeader>
              <CardContent>
                {viewMode === 'week' ? (
                  <div className="grid grid-cols-7 gap-2">
                    {getWeekDays().map((day) => {
                      const assignment = getAssignmentForDate(day);
                      const isToday = isSameDay(day, new Date());
                      return (
                        <div
                          key={day.toISOString()}
                          className={`border rounded-lg p-3 min-h-[120px] ${isToday ? 'bg-blue-50 dark:bg-blue-950 border-blue-300' : ''
                            }`}
                        >
                          <div className="text-sm font-medium mb-2">
                            {format(day, 'EEE')}
                          </div>
                          <div className="text-xs text-muted-foreground mb-2">
                            {format(day, 'MMM dd')}
                          </div>
                          {assignment ? (
                            <div className="space-y-1">
                              <div className="text-xs font-semibold">
                                {assignment.shift?.name}
                              </div>
                              <div className="text-xs text-muted-foreground">
                                {assignment.shift?.start_time} - {assignment.shift?.end_time}
                              </div>
                              {getStatusBadge(assignment)}
                            </div>
                          ) : (
                            <div className="text-xs text-muted-foreground">No shift</div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="grid grid-cols-7 gap-2">
                    <div className="col-span-7 grid grid-cols-7 gap-2 mb-2">
                      {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map((day) => (
                        <div key={day} className="text-center text-sm font-semibold py-2">
                          {day}
                        </div>
                      ))}
                    </div>
                    {getMonthDays().map((day) => {
                      const assignment = getAssignmentForDate(day);
                      const isToday = isSameDay(day, new Date());
                      return (
                        <div
                          key={day.toISOString()}
                          className={`border rounded-lg p-2 min-h-[80px] ${isToday ? 'bg-blue-50 dark:bg-blue-950 border-blue-300' : ''
                            }`}
                        >
                          <div className="text-xs font-medium mb-1">
                            {format(day, 'd')}
                          </div>
                          {assignment && (
                            <div className="text-xs">
                              <div className="font-semibold truncate">
                                {assignment.shift?.name}
                              </div>
                              <div className="text-muted-foreground">
                                {assignment.shift?.start_time}
                              </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="upcoming">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Clock className="h-5 w-5" />
                  Upcoming Shifts
                </CardTitle>
                <CardDescription>
                  Your scheduled shifts in the future
                </CardDescription>
              </CardHeader>
              <CardContent>
                {schedule.upcoming_shifts.length > 0 ? (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Date</TableHead>
                        <TableHead>Shift</TableHead>
                        <TableHead>Time</TableHead>
                        <TableHead>Notes</TableHead>
                        <TableHead>Status</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {schedule.upcoming_shifts.map((assignment) => (
                        <TableRow key={assignment.assignment_id}>
                          <TableCell className="font-medium">
                            {formatDateIST(assignment.assignment_date, 'MMM dd, yyyy')}
                          </TableCell>
                          <TableCell>{assignment.shift?.name || 'N/A'}</TableCell>
                          <TableCell>
                            {assignment.shift?.start_time} - {assignment.shift?.end_time}
                          </TableCell>
                          <TableCell>{assignment.notes || '-'}</TableCell>
                          <TableCell>{getStatusBadge(assignment)}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    No upcoming shifts scheduled
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="past">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <CalendarDays className="h-5 w-5" />
                  Past Shifts
                </CardTitle>
                <CardDescription>
                  Your completed shift assignments
                </CardDescription>
              </CardHeader>
              <CardContent>
                {schedule.past_shifts.length > 0 ? (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Date</TableHead>
                        <TableHead>Shift</TableHead>
                        <TableHead>Time</TableHead>
                        <TableHead>Notes</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {schedule.past_shifts.map((assignment) => (
                        <TableRow key={assignment.assignment_id}>
                          <TableCell className="font-medium">
                            {formatDateIST(assignment.assignment_date, 'MMM dd, yyyy')}
                          </TableCell>
                          <TableCell>{assignment.shift?.name || 'N/A'}</TableCell>
                          <TableCell>
                            {assignment.shift?.start_time} - {assignment.shift?.end_time}
                          </TableCell>
                          <TableCell>{assignment.notes || '-'}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    No past shifts found
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <div className="text-muted-foreground">No shift schedule available</div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLanguage } from '@/contexts/LanguageContext';
import { useNotifications } from '@/contexts/NotificationContext';
import { Task as BaseTask, UserRole } from '@/types';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Pagination } from '@/components/ui/pagination';
import { useToast } from '@/hooks/use-toast';
import TruncatedText from '@/components/ui/TruncatedText';
import {
  Plus,
  Clock,
  CheckCircle2,
  AlertCircle,
  Pause,
  PlayCircle,
